globalThis.__BQ = {"atomModelleri":{"ilkokul":{"kolay":[{"q":"Dalton atom modelini en basit haliyle neye benzetir?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='80' r='46' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>Dalton: dolu top</text></svg>","steps":[{"t":"İçi dolu","a":"berk küre","d":"Dalton atomu içi dolu, küçük bir topa (berk küre) benzetmiştir."},{"t":"Bölünmez","a":"en küçük parça","d":"Ona göre bu top daha küçük parçalara ayrılamaz."}],"ans":"Dalton, atomu içi dolu ve bölünemez küçük bir topa (berk küre) benzetmiştir."},{"q":"Thomson'ın atom modeli hangi yiyeceğe benzetilir?","fig":"<svg viewBox='0 0 320 165'><circle cx='160' cy='80' r='48' fill='#f4d03f' stroke='#1a2b45'/><circle cx='135' cy='65' r='6' fill='#2b6be0'/><circle cx='182' cy='72' r='6' fill='#2b6be0'/><circle cx='150' cy='100' r='6' fill='#2b6be0'/><circle cx='185' cy='98' r='6' fill='#2b6be0'/><text x='160' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>üzümlü kek</text></svg>","steps":[{"t":"Kek gibi","a":"üzümlü kek","d":"Thomson atomu üzümlü keke benzetmiştir."},{"t":"Üzümler","a":"elektronlar","d":"Kekin içine serpiştirilmiş üzümler elektronları temsil eder."}],"ans":"Thomson'ın modeli, elektronların gömülü olduğu üzümlü keke benzetilir."},{"q":"Rutherford'a göre atomun ortasında ne vardır?","steps":[{"t":"Orta bölge","a":"çekirdek","d":"Rutherford atomun ortasında küçük ve yoğun bir çekirdek olduğunu söylemiştir."},{"t":"Çevre","a":"elektronlar","d":"Çekirdeğin çevresinde elektronlar dolaşır."}],"ans":"Rutherford'a göre atomun ortasında küçük, yoğun bir çekirdek vardır."},{"q":"Bohr'a göre elektronlar nasıl dizilir?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='88' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='88' r='32' fill='none' stroke='#1a2b45'/><circle cx='160' cy='88' r='58' fill='none' stroke='#1a2b45'/><circle cx='192' cy='88' r='5' fill='#2b6be0'/><circle cx='160' cy='30' r='5' fill='#2b6be0'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>Bohr yörüngeleri</text></svg>","steps":[{"t":"Yörünge","a":"halka yol","d":"Bohr'a göre elektronlar çekirdek çevresinde belirli halkalarda (yörüngelerde) döner."},{"t":"Düzenli","a":"gezegen gibi","d":"Her elektron kendi yolunda, gezegenlerin Güneş'i dolanması gibi düzenli döner."}],"ans":"Bohr'a göre elektronlar çekirdek çevresinde belirli yörüngelerde (halkalarda) düzenli döner."},{"q":"Atom modelleri zamanla neden değişmiştir?","steps":[{"t":"Yeni deney","a":"yeni bilgi","d":"Bilim insanları yeni deneyler yaptıkça atom hakkında yeni bilgiler öğrendi."},{"t":"Daha doğru","a":"model gelişti","d":"Bu yeni bilgiler eski modeli düzeltip daha doğru bir model getirdi."}],"ans":"Yeni deneyler yeni bilgiler verdiği için atom modeli zamanla gelişerek değişmiştir."}],"zor":[{"q":"Dalton ile Thomson modeli arasındaki en büyük fark nedir?","steps":[{"t":"Dalton","a":"dolu top","d":"Dalton atomu içi dolu, parçasız bir top sandı."},{"t":"Thomson","a":"elektron ekledi","d":"Thomson atomun içinde elektron denilen küçük taneler olduğunu gösterdi."}],"ans":"Dalton atomu boş bir top sanırken, Thomson içinde elektronlar olduğunu ekledi."},{"q":"Rutherford altın levha deneyinde neyi keşfetti?","fig":"<svg viewBox='0 0 320 175'><rect x='150' y='35' width='8' height='100' fill='#f4d03f' stroke='#1a2b45'/><circle cx='154' cy='85' r='5' fill='#e0552b'/><line x1='28' y1='85' x2='150' y2='85' stroke='#2b6be0' stroke-width='2'/><line x1='158' y1='85' x2='288' y2='85' stroke='#2b6be0' stroke-width='2'/><line x1='154' y1='85' x2='245' y2='40' stroke='#e0552b' stroke-width='2'/><text x='45' y='75' font-size='10' fill='#1a2b45'>ışınlar</text><text x='154' y='152' font-size='9' text-anchor='middle' fill='#1a2b45'>altın levha</text></svg>","steps":[{"t":"Deney","a":"ışın gönderdi","d":"Rutherford ince altın levhaya küçük yüklü tanecikler gönderdi."},{"t":"Geri sekti","a":"çekirdek var","d":"Bazı tanecikler geri sekti; bu, ortada küçük yoğun bir çekirdek olduğunu gösterdi."}],"ans":"Rutherford altın levha deneyiyle atomun ortasında küçük, yoğun bir çekirdek olduğunu keşfetti."},{"q":"Bohr modeli Rutherford modeline göre hangi yeniliği getirdi?","steps":[{"t":"Rutherford","a":"çekirdek + boşluk","d":"Rutherford çekirdeği buldu ama elektronların nasıl döndüğünü tam açıklamadı."},{"t":"Bohr","a":"belirli yörünge","d":"Bohr, elektronların gelişigüzel değil belirli yörüngelerde döndüğünü ekledi."}],"ans":"Bohr, elektronların belirli yörüngelerde düzenli döndüğünü göstererek modeli geliştirdi."},{"q":"Modern (bugünkü) atom modelinde elektronların yeri için ne söylenir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='85' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='130' cy='65' r='3' fill='#2b6be0'/><circle cx='195' cy='75' r='3' fill='#2b6be0'/><circle cx='150' cy='115' r='3' fill='#2b6be0'/><circle cx='185' cy='110' r='3' fill='#2b6be0'/><circle cx='205' cy='100' r='3' fill='#2b6be0'/><text x='160' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>elektron bulutu</text></svg>","steps":[{"t":"Kesin yer yok","a":"tam bilinmez","d":"Modern modelde elektronun tam yeri kesin olarak bilinemez."},{"t":"Bulut gibi","a":"olası bölge","d":"Elektronun bulunabileceği yerler bir bulut gibi olası bölgeler olarak düşünülür."}],"ans":"Modern modelde elektronun tam yeri bilinmez; bulunma olasılığı olan bir bulut bölgesi olarak düşünülür."},{"q":"Atom modellerinin doğru sırası nasıldır?","steps":[{"t":"İlk modeller","a":"Dalton, Thomson","d":"Önce Dalton'ın dolu küresi, sonra Thomson'ın üzümlü kek modeli gelir."},{"t":"Sonraki modeller","a":"Rutherford, Bohr, modern","d":"Ardından Rutherford çekirdeği, Bohr yörüngeleri ve en son modern model gelir."}],"ans":"Sıra: Dalton → Thomson → Rutherford → Bohr → modern modeldir."}]},"ortaokul":{"kolay":[{"q":"Dalton atom modelinin temel görüşü ve eksiği nedir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='82' r='50' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='155' font-size='12' text-anchor='middle' fill='#1a2b45'>içi dolu berk küre</text></svg>","steps":[{"t":"Görüşü","a":"bölünmez küre","d":"Dalton'a göre atom içi dolu, bölünemeyen en küçük yapı taşıdır."},{"t":"Eksiği","a":"içyapı yok","d":"Atomun içinde proton, elektron gibi parçacıklar olduğunu açıklayamadı."}],"ans":"Dalton atomu bölünemez dolu küre saydı; eksiği atomun içyapısını açıklayamamasıdır."},{"q":"Thomson modelinde atomun yükü nasıl dağılmıştır?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='80' r='52' fill='#f4d03f' stroke='#1a2b45'/><circle cx='130' cy='65' r='6' fill='#2b6be0'/><circle cx='185' cy='70' r='6' fill='#2b6be0'/><circle cx='150' cy='100' r='6' fill='#2b6be0'/><circle cx='190' cy='95' r='6' fill='#2b6be0'/><text x='160' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>(+) hamur, gömülü e⁻</text></svg>","steps":[{"t":"Artı bölge","a":"yayılmış (+)","d":"Thomson'a göre artı yük atomun her yerine yayılmıştır (kek hamuru gibi)."},{"t":"Elektronlar","a":"gömülü e⁻","d":"Eksi yüklü elektronlar bu artı kütlenin içine gömülüdür."}],"ans":"Thomson modelinde artı yük tüm atoma yayılmış, eksi elektronlar bunun içine gömülmüştür."},{"q":"Rutherford modeline göre atomun çekirdeği ve çevresi nasıldır?","steps":[{"t":"Çekirdek","a":"küçük, yoğun, (+)","d":"Atomun ortasında küçük, ağır ve artı yüklü bir çekirdek bulunur."},{"t":"Çevre","a":"büyük boşluk","d":"Çekirdeğin çevresi büyük oranda boşluktur; elektronlar bu boşlukta dolaşır."}],"ans":"Rutherford modelinde merkezde küçük yoğun bir çekirdek, çevresinde elektronların dolaştığı büyük boşluk vardır."},{"q":"Bohr modelinde enerji düzeyi (yörünge) ne demektir?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='88' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='88' r='30' fill='none' stroke='#1a2b45'/><circle cx='160' cy='88' r='56' fill='none' stroke='#1a2b45'/><circle cx='190' cy='88' r='5' fill='#2b6be0'/><circle cx='160' cy='32' r='5' fill='#2b6be0'/><text x='195' y='102' font-size='10' fill='#1a2b45'>K</text><text x='160' y='26' font-size='10' text-anchor='middle' fill='#1a2b45'>L</text></svg>","steps":[{"t":"Belirli yörünge","a":"enerji düzeyi","d":"Elektronlar çekirdek çevresinde belirli enerjili yörüngelerde (katmanlarda) bulunur."},{"t":"Kararlı yol","a":"enerji yaymaz","d":"Elektron kendi yörüngesinde dururken enerji kaybetmez, kararlıdır."}],"ans":"Bohr'a göre enerji düzeyi, elektronların belirli enerjide ve kararlı şekilde döndüğü yörüngedir."},{"q":"Atom modellerinin tarihsel sırası ve son gelen model nedir?","steps":[{"t":"Sıra","a":"Dalton'dan moderne","d":"Dalton → Thomson → Rutherford → Bohr sırasıyla modeller gelişir."},{"t":"Son model","a":"modern (orbital)","d":"En son ve en gelişmiş model, elektronu bulut/orbital ile açıklayan modern modeldir."}],"ans":"Sıra Dalton → Thomson → Rutherford → Bohr → modern modeldir; en gelişmiş olanı modern modeldir."}],"zor":[{"q":"Thomson, Dalton modelini hangi keşifle değiştirmek zorunda kaldı?","steps":[{"t":"Keşif","a":"elektron","d":"Thomson, atomdan kopan eksi yüklü elektronları keşfetti."},{"t":"Sonuç","a":"atom bölünebilir","d":"Bu keşif, Dalton'ın 'atom bölünemez' görüşünü çürüttü ve atomun içyapısı olduğunu gösterdi."}],"ans":"Thomson elektronu keşfederek atomun bölünebildiğini gösterdi ve Dalton'ın dolu küre modelini değiştirdi."},{"q":"Rutherford deneyinde taneciklerin çoğu neden düz geçti, azı neden geri sekti?","fig":"<svg viewBox='0 0 320 180'><rect x='150' y='30' width='7' height='110' fill='#f4d03f' stroke='#1a2b45'/><circle cx='153' cy='85' r='6' fill='#e0552b'/><line x1='25' y1='70' x2='290' y2='70' stroke='#2b6be0' stroke-width='2'/><line x1='25' y1='100' x2='290' y2='100' stroke='#2b6be0' stroke-width='2'/><line x1='153' y1='85' x2='240' y2='35' stroke='#e0552b' stroke-width='2'/><text x='40' y='62' font-size='9' fill='#1a2b45'>çoğu düz geçer</text></svg>","steps":[{"t":"Düz geçenler","a":"boşluk","d":"Atomun çoğu boşluk olduğu için tanecikler çoğunlukla sapmadan geçti."},{"t":"Geri sekenler","a":"çekirdeğe çarptı","d":"Çok azı, küçük ve yoğun artı çekirdeğe yaklaşıp ondan itilerek geri sekti."}],"ans":"Atom çoğunlukla boşluk olduğundan tanecikler düz geçti; küçük yoğun çekirdeğe rastlayan azı geri sekti."},{"q":"Bohr modeli, Rutherford modelinin hangi eksikliğini gidermiştir?","steps":[{"t":"Rutherford eksiği","a":"kararsızlık","d":"Rutherford modelinde dönen elektronun enerji kaybedip çekirdeğe düşmesi beklenir; atom kararsız görünür."},{"t":"Bohr çözümü","a":"kararlı yörünge","d":"Bohr, belirli yörüngelerde elektronun enerji yaymadan kararlı kaldığını öne sürdü."}],"ans":"Bohr, elektronun belirli yörüngelerde enerji yaymadan kararlı dönmesini açıklayarak kararsızlık sorununu giderdi."},{"q":"Modern atom modeli Bohr modelinden hangi yönüyle ayrılır?","fig":"<svg viewBox='0 0 320 170'><circle cx='90' cy='85' r='8' fill='#e0552b'/><circle cx='90' cy='85' r='38' fill='none' stroke='#1a2b45'/><circle cx='128' cy='85' r='4' fill='#2b6be0'/><text x='90' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>Bohr: yörünge</text><circle cx='235' cy='85' r='8' fill='#e0552b'/><circle cx='210' cy='70' r='3' fill='#2b6be0'/><circle cx='258' cy='78' r='3' fill='#2b6be0'/><circle cx='225' cy='105' r='3' fill='#2b6be0'/><circle cx='255' cy='100' r='3' fill='#2b6be0'/><text x='235' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>modern: bulut</text></svg>","steps":[{"t":"Bohr","a":"kesin yörünge","d":"Bohr elektronu çizgisel, kesin bir yörüngede dönüyor sayar."},{"t":"Modern","a":"olasılık bulutu","d":"Modern modelde elektronun yeri kesin değildir; bulunma olasılığı yüksek bölgeler (orbital) vardır."}],"ans":"Modern model, Bohr'un kesin yörüngesi yerine elektronu olasılıkla bulunduğu bir bulut (orbital) olarak ele alır."},{"q":"Her yeni atom modeli bir öncekinin neyini korur, neyini düzeltir?","steps":[{"t":"Korunan","a":"doğru kısımlar","d":"Yeni model, eski modelin deneylerle doğrulanan kısımlarını korur (örneğin çekirdeğin varlığı)."},{"t":"Düzeltilen","a":"eksik/yanlış kısım","d":"Yeni deneylerle uyuşmayan eksik kısımlar düzeltilir, böylece model gerçeğe yaklaşır."}],"ans":"Her yeni model eski modelin doğru yanlarını korur, eksik veya yanlış yanlarını yeni deneylerle düzeltir."}]},"lise":{"kolay":[{"q":"Dalton atom teorisinin temel varsayımları ve en önemli eksiği nedir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='80' r='52' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='155' font-size='12' text-anchor='middle' fill='#1a2b45'>bölünemez dolu küre</text></svg>","steps":[{"t":"Varsayım","a":"bölünmez küre","d":"Dalton'a göre atom içi dolu, bölünemez berk küredir ve aynı elementin atomları özdeştir."},{"t":"Eksik","a":"atom altı yok","d":"Atomun proton, nötron, elektron gibi atom altı parçacıklardan oluştuğunu açıklayamaması en önemli eksiğidir."}],"ans":"Dalton atomu bölünemez özdeş küre saydı; en önemli eksiği atom altı parçacıkları açıklayamamasıdır."},{"q":"Thomson (üzümlü kek) modeli atomun yapısını nasıl tanımlar ve eksiği nedir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='80' r='52' fill='#f4d03f' stroke='#1a2b45'/><circle cx='128' cy='62' r='6' fill='#2b6be0'/><circle cx='186' cy='68' r='6' fill='#2b6be0'/><circle cx='150' cy='100' r='6' fill='#2b6be0'/><circle cx='192' cy='95' r='6' fill='#2b6be0'/><text x='160' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>(+) hamur, gömülü e⁻</text></svg>","steps":[{"t":"Yapı","a":"yayılmış (+) + e⁻","d":"Artı yük atomun tümüne homojen yayılmış, elektronlar bunun içine gömülmüştür; atom nötrdür."},{"t":"Eksik","a":"çekirdek yok","d":"Modelde yoğun bir çekirdek öngörülmediğinden Rutherford deneyi sonuçlarını açıklayamaz."}],"ans":"Thomson modeli atomu, elektronların gömüldüğü homojen artı yüklü bir küre olarak tanımlar; eksiği çekirdeği öngörmemesidir."},{"q":"Rutherford'un altın levha (saçılma) deneyinin sonuçları nasıl yorumlanır?","fig":"<svg viewBox='0 0 320 180'><rect x='150' y='25' width='7' height='120' fill='#f4d03f' stroke='#1a2b45'/><circle cx='153' cy='85' r='6' fill='#e0552b'/><line x1='25' y1='70' x2='290' y2='70' stroke='#2b6be0' stroke-width='2'/><line x1='25' y1='100' x2='290' y2='100' stroke='#2b6be0' stroke-width='2'/><line x1='153' y1='85' x2='235' y2='35' stroke='#e0552b' stroke-width='2'/><line x1='153' y1='85' x2='80' y2='45' stroke='#e0552b' stroke-width='2'/><text x='35' y='62' font-size='9' fill='#1a2b45'>α taneleri</text></svg>","steps":[{"t":"Çoğu düz geçti","a":"atom çoğu boşluk","d":"α taneciklerinin çoğu sapmadan geçti; bu, atomun büyük kısmının boş olduğunu gösterir."},{"t":"Azı saptı/sekti","a":"yoğun (+) çekirdek","d":"Çok azının büyük açıyla sapması, kütle ve artı yükün küçük yoğun bir çekirdekte toplandığını gösterir."}],"ans":"Deney, atomun çoğunun boş, kütle ve artı yükün ise küçük yoğun bir çekirdekte toplandığını ortaya koyar."},{"q":"Bohr atom modelinin temel varsayımları ve açıkladığı gözlem nedir?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='90' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='90' r='28' fill='none' stroke='#1a2b45'/><circle cx='160' cy='90' r='50' fill='none' stroke='#1a2b45'/><circle cx='160' cy='90' r='70' fill='none' stroke='#1a2b45'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>kararlı enerji düzeyleri</text></svg>","steps":[{"t":"Varsayım","a":"kuantlı yörünge","d":"Elektron yalnız belirli enerjili yörüngelerde bulunur, burada enerji yaymaz; geçişte foton alıp verir."},{"t":"Açıklama","a":"çizgi spektrumu","d":"Bu varsayım, hidrojenin kesikli çizgi spektrumunu enerji düzeyleri arası geçişlerle başarıyla açıklar."}],"ans":"Bohr'a göre elektron belirli kararlı düzeylerde döner, geçişte foton alıp verir; bu model hidrojen çizgi spektrumunu açıklar."},{"q":"Modern (kuantum) atom modelinde orbital kavramı ne anlama gelir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='83' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='128' cy='63' r='3' fill='#2b6be0'/><circle cx='190' cy='70' r='3' fill='#2b6be0'/><circle cx='148' cy='105' r='3' fill='#2b6be0'/><circle cx='195' cy='100' r='3' fill='#2b6be0'/><circle cx='205' cy='78' r='3' fill='#2b6be0'/><circle cx='120' cy='90' r='3' fill='#2b6be0'/><text x='160' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>orbital = olasılık bölgesi</text></svg>","steps":[{"t":"Olasılık","a":"kesin yer yok","d":"Modern modelde elektronun konumu kesin bilinemez; yalnızca bulunma olasılığı tanımlanır."},{"t":"Orbital","a":"yoğun bölge","d":"Orbital, elektronun bulunma olasılığının en yüksek olduğu üç boyutlu uzay bölgesidir."}],"ans":"Modern modelde orbital, elektronun bulunma olasılığının en yüksek olduğu uzay bölgesidir."}],"zor":[{"q":"Thomson modeli neden çekirdeği öngörmedi ve bu hangi deneyle çürütüldü?","steps":[{"t":"Modelin varsayımı","a":"yayılmış (+) yük","d":"Thomson modelinde artı yük ve kütle atoma homojen dağıtılmıştır; yoğun bir merkez yoktur."},{"t":"Çürütme","a":"altın levha deneyi","d":"Rutherford deneyinde bazı α taneciklerinin büyük açıyla sapması, yoğun bir çekirdeğin varlığını kanıtlayıp modeli çürüttü."}],"ans":"Thomson modeli yükü homojen yaydığı için çekirdeği öngörmedi; Rutherford'un altın levha deneyi yoğun çekirdeği gösterip modeli çürüttü."},{"q":"Rutherford modelinin klasik fizikle çelişen kararsızlık sorunu nedir?","steps":[{"t":"Klasik beklenti","a":"enerji yayar","d":"Klasik fiziğe göre çekirdek çevresinde dolanan yüklü elektron sürekli ışıma yaparak enerji kaybetmelidir."},{"t":"Sonuç","a":"çekirdeğe düşme","d":"Enerji kaybeden elektron spiral çizerek çekirdeğe düşmeli; bu, atomların neden kararlı olduğunu açıklayamaz."}],"ans":"Rutherford modelinde dönen elektron klasik fiziğe göre enerji yayıp çekirdeğe düşmeliydi; model atomun kararlılığını açıklayamaz."},{"q":"Bohr modeli hidrojen spektrumunu açıklarken çok elektronlu atomlarda neden yetersiz kalır?","steps":[{"t":"Başarı","a":"tek elektron","d":"Bohr modeli tek elektronlu hidrojende enerji düzeyleri arası geçişlerle çizgi spektrumunu doğru verir."},{"t":"Yetersizlik","a":"elektron-elektron etkisi","d":"Çok elektronlu atomlarda elektronlar arası itmeler ve karmaşık etkileşimler hesaba katılmadığından model spektrumu doğru açıklayamaz."}],"ans":"Bohr modeli yalnız tek elektronlu hidrojeni açıklar; çok elektronlu atomlarda elektronlar arası etkileşimleri içermediğinden yetersiz kalır."},{"q":"Modern atom modeli hangi iki temel ilkeye dayanır ve Bohr'dan farkı nedir?","fig":"<svg viewBox='0 0 320 175'><circle cx='90' cy='85' r='8' fill='#e0552b'/><circle cx='90' cy='85' r='36' fill='none' stroke='#1a2b45'/><circle cx='126' cy='85' r='4' fill='#2b6be0'/><text x='90' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>Bohr: kesin yörünge</text><circle cx='235' cy='85' r='8' fill='#e0552b'/><circle cx='208' cy='68' r='3' fill='#2b6be0'/><circle cx='260' cy='78' r='3' fill='#2b6be0'/><circle cx='222' cy='106' r='3' fill='#2b6be0'/><circle cx='256' cy='100' r='3' fill='#2b6be0'/><text x='235' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>modern: orbital</text></svg>","steps":[{"t":"İlkeler","a":"dalga-tanecik + belirsizlik","d":"Modern model, elektronun dalga-tanecik ikiliğine (de Broglie) ve Heisenberg belirsizlik ilkesine dayanır."},{"t":"Fark","a":"yörünge → orbital","d":"Bohr kesin yörünge varsayarken, modern model elektronu olasılıkla bulunduğu orbital ile tanımlar."}],"ans":"Modern model dalga-tanecik ikiliği ve belirsizlik ilkesine dayanır; Bohr'un kesin yörüngesi yerine olasılıksal orbitali kullanır."},{"q":"Atom modellerinin gelişimi bilimsel bilginin doğası hakkında ne öğretir?","steps":[{"t":"Sınanabilirlik","a":"deneyle test","d":"Her model deneysel verilerle sınanır; uymayan kısımlar değiştirilir, model kesin/değişmez değildir."},{"t":"Birikimli ilerleme","a":"daha kapsayıcı model","d":"Eski modelin doğruları korunup eksikleri giderilerek daha kapsayıcı modele ulaşılır; bilgi birikerek ilerler."}],"ans":"Bilimsel bilginin deneyle sınanan, eksikleri görüldükçe gelişen ve birikimli şekilde ilerleyen bir yapıya sahip olduğunu öğretir."}]}},"atomNedir":{"ilkokul":{"kolay":[{"q":"Çevremizdeki her şeyi oluşturan çok küçük yapı taşının adı nedir?","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='60' width='70' height='50' fill='#cfd8e8' stroke='#1a2b45'/><text x='75' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>madde</text><text x='150' y='90' font-size='16' text-anchor='middle' fill='#1a2b45'>→</text><circle cx='235' cy='75' r='8' fill='#e0552b'/><circle cx='255' cy='90' r='8' fill='#e0552b'/><circle cx='240' cy='98' r='8' fill='#e0552b'/><text x='240' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>atomlar</text></svg>","steps":[{"t":"Madde nedir","a":"yer kaplayan her şey","d":"Etrafımızda gördüğümüz su, taş, hava gibi yer kaplayan her şeye madde denir."},{"t":"Yapı taşı","a":"atom","d":"Bütün maddeler çok küçük yapı taşlarından oluşur ve bu yapı taşına atom denir."}],"ans":"Her şeyi oluşturan en küçük yapı taşına atom denir."},{"q":"Atomlar büyük mü yoksa çok küçük müdür?","steps":[{"t":"Boyut","a":"çok küçük","d":"Atomlar gözle göremeyeceğimiz kadar küçüktür."},{"t":"Karşılaştırma","a":"toz tanesinden bile küçük","d":"Bir toz tanesinin içinde bile sayamayacağımız kadar çok atom vardır."}],"ans":"Atomlar gözle görülemeyecek kadar çok küçüktür."},{"q":"Bir bardak suyun içinde atom var mıdır?","steps":[{"t":"Su da madde","a":"evet madde","d":"Su da bir maddedir, çünkü yer kaplar ve ağırlığı vardır."},{"t":"Atomdan oluşur","a":"su atomlardan oluşur","d":"Her madde gibi su da çok küçük atomlardan oluşur."}],"ans":"Evet, bir bardak su sayısız küçük atomdan oluşur."},{"q":"Demir bir çivi ile tahta bir kalem aynı şeyden mi yapılmıştır?","steps":[{"t":"İkisi de madde","a":"madde","d":"Hem çivi hem kalem birer maddedir."},{"t":"Atomdan oluşur","a":"farklı atomlar","d":"İkisi de atomlardan oluşur ama içlerindeki atom türleri farklıdır."}],"ans":"İkisi de atomlardan oluşur, ama içlerindeki atom çeşitleri birbirinden farklıdır."},{"q":"Atomları neden gözümüzle göremeyiz?","steps":[{"t":"Çok küçük","a":"gözle görülmez","d":"Atomlar gözümüzün seçebileceğinden çok daha küçüktür."},{"t":"Yardımcı araç","a":"özel mikroskop","d":"Atomları ancak çok güçlü özel araçlarla incelenebilir."}],"ans":"Atomlar gözle görülemeyecek kadar küçük olduğu için onları doğrudan göremeyiz."}],"zor":[{"q":"Bir kum tanesi mi yoksa bir atom mu daha küçüktür?","steps":[{"t":"Kum tanesi","a":"görülebilir","d":"Bir kum tanesini gözümüzle görebiliriz, demek ki çok küçük değildir."},{"t":"Atom","a":"çok daha küçük","d":"Atom, kum tanesinin içinde milyonlarca tanesi bulunan çok daha küçük bir yapıdır."}],"ans":"Atom, kum tanesinden çok çok daha küçüktür; bir kum tanesinde milyonlarca atom vardır."},{"q":"Bir maddeyi küçük parçalara böle böle gidersek en sonunda neye ulaşırız?","steps":[{"t":"Bölme","a":"gittikçe küçülür","d":"Bir maddeyi sürekli daha küçük parçalara ayırabiliriz."},{"t":"En küçük parça","a":"atom","d":"En sonunda o maddenin özelliğini taşıyan en küçük yapı taşına, yani atoma ulaşırız."}],"ans":"Bir maddeyi böle böle gidince sonunda maddenin en küçük yapı taşı olan atoma ulaşırız."},{"q":"Hava boş gibi görünür; havada atom var mıdır?","steps":[{"t":"Hava da madde","a":"evet","d":"Hava görünmese de yer kaplar ve bir maddedir; balonu şişirebilmemiz bunu gösterir."},{"t":"Atomdan oluşur","a":"gaz atomları","d":"Hava, gözle görülmeyen çok küçük atom ve taneciklerden oluşur."}],"ans":"Evet, boş görünse de hava çok küçük atom ve taneciklerden oluşur."},{"q":"İnsan vücudu da atomlardan oluşur mu?","steps":[{"t":"Vücut madde","a":"madde","d":"Bizim vücudumuz da yer kaplar ve ağırlığı olan bir maddedir."},{"t":"Atomdan oluşur","a":"sayısız atom","d":"Kemiklerimiz, kanımız, derimiz hepsi sayısız küçük atomdan oluşur."}],"ans":"Evet, insan vücudu da sayısız küçük atomdan oluşur."},{"q":"Bilim insanları çok eski zamanlardan beri atom hakkında ne düşünmüştür?","steps":[{"t":"Eski fikir","a":"en küçük parça","d":"Çok eski zamanlarda bile insanlar maddenin bölünemeyen en küçük bir parçası olabileceğini düşündü."},{"t":"Bugünkü bilgi","a":"atom","d":"Bugün bu en küçük yapı taşına atom diyoruz ve onu daha iyi tanıyoruz."}],"ans":"İnsanlar eskiden beri maddenin en küçük bir yapı taşı olduğunu düşünmüş; bugün ona atom diyoruz."}]},"ortaokul":{"kolay":[{"q":"Atom nedir ve maddeyle ilişkisi nasıldır?","steps":[{"t":"Tanım","a":"maddenin yapı taşı","d":"Atom, bütün maddeleri oluşturan en küçük temel yapı taşıdır."},{"t":"İlişki","a":"madde = atom topluluğu","d":"Her madde, bir araya gelmiş çok sayıda atomdan oluşur."}],"ans":"Atom, maddeyi oluşturan en küçük yapı taşıdır; tüm maddeler atomlardan meydana gelir."},{"q":"Atomların boyutu hakkında ne söylenebilir?","steps":[{"t":"Ölçek","a":"son derece küçük","d":"Atomlar metrenin milyarda biri mertebesinde, gözle görülemeyecek kadar küçüktür."},{"t":"Sonuç","a":"çıplak gözle görülmez","d":"Bu yüzden tek bir atomu çıplak gözle ya da sıradan mikroskopla göremeyiz."}],"ans":"Atomlar son derece küçüktür; tek bir atom çıplak gözle görülemez."},{"q":"Saf altın ile saf bakır farklı maddelerdir; bu farkın temel nedeni nedir?","steps":[{"t":"Yapı taşı","a":"atom","d":"İki madde de atomlardan oluşur."},{"t":"Atom türü farkı","a":"farklı atomlar","d":"Altını altın yapan atomlar ile bakırı bakır yapan atomlar birbirinden farklı türdedir."}],"ans":"Altın ve bakır farklıdır çünkü onları oluşturan atom türleri birbirinden farklıdır."},{"q":"Maddenin katı, sıvı ve gaz hâllerinin hepsi atomlardan mı oluşur?","steps":[{"t":"Hâller","a":"katı-sıvı-gaz","d":"Buz, su ve su buharı aynı maddenin üç farklı hâlidir."},{"t":"Ortak yapı","a":"hepsi atom","d":"Hangi hâlde olursa olsun madde yine atom ve taneciklerden oluşur; değişen taneciklerin diziliş ve hareketidir."}],"ans":"Evet, maddenin katı, sıvı ve gaz hâllerinin hepsi atomlardan oluşur; sadece taneciklerin düzeni değişir."},{"q":"Bir maddeyi gittikçe daha küçük parçalara ayırdığımızda en küçük birim ne olur?","steps":[{"t":"Bölme süreci","a":"küçülen parçalar","d":"Bir maddeyi parçalara ayırdıkça parçalar küçülür."},{"t":"Sınır","a":"atom","d":"O maddenin kimyasal özelliğini taşıyan en küçük birime ulaşırız; bu birim atomdur."}],"ans":"Bir maddeyi bölmenin ulaşabileceği en küçük yapı taşı atomdur."}],"zor":[{"q":"Atomlar bu kadar küçükken bir maddeyi gözle görebilmemiz nasıl açıklanır?","steps":[{"t":"Tek atom","a":"görülemez","d":"Tek bir atom gözle görülemeyecek kadar küçüktür."},{"t":"Çok sayıda atom","a":"birikince görünür","d":"Görebildiğimiz en küçük madde parçasında bile sayılamayacak kadar çok atom bir aradadır; bu yığın gözle görünür."}],"ans":"Tek atom görülmez; ancak çok sayıda atom bir araya geldiğinde oluşan madde yığını gözle görülebilir hale gelir."},{"q":"'Her şey atomlardan oluşur' ifadesi neyi kapsar?","steps":[{"t":"Kapsam","a":"tüm maddeler","d":"Canlı-cansız, katı-sıvı-gaz fark etmeksizin bütün maddeler atomlardan oluşur."},{"t":"İstisna düşüncesi","a":"madde olmayan","d":"Işık ya da ses gibi madde olmayan şeyler atomlardan oluşmaz; ifade yalnızca maddeler için geçerlidir."}],"ans":"İfade bütün maddeleri (canlı-cansız her türlü maddeyi) kapsar; ışık-ses gibi madde olmayanları kapsamaz."},{"q":"Aynı tür atomlardan ve farklı tür atomlardan oluşan maddeler arasındaki fark nedir?","steps":[{"t":"Tek tür atom","a":"element","d":"Yalnızca tek çeşit atomdan oluşan saf maddeye element denir (örneğin demir)."},{"t":"Farklı tür atom","a":"bileşik","d":"Birbirine bağlanmış farklı türde atomlardan oluşan maddeye ise bileşik denir (örneğin su)."}],"ans":"Tek tür atomdan oluşan madde element, farklı tür atomların birleşmesiyle oluşan madde ise bileşiktir."},{"q":"Bir demir çubuğu eritip şeklini değiştirdiğimizde atomlarına ne olur?","steps":[{"t":"Erime","a":"hâl değişimi","d":"Erime, maddenin katıdan sıvıya geçtiği fiziksel bir değişimdir."},{"t":"Atomlar","a":"değişmez","d":"Demir atomları erime sırasında yok olmaz ya da başka atoma dönüşmez; yalnızca dizilişleri ve hareketleri değişir."}],"ans":"Erimede demir atomları değişmez; yalnızca taneciklerin düzeni ve hareketi değiştiği için demir yine demir kalır."},{"q":"Atomun var olduğu fikrine bilim nasıl ulaşmıştır?","steps":[{"t":"Gözlem ve deney","a":"dolaylı kanıt","d":"Bilim insanları maddenin davranışını gözleyip deneyler yaparak atomun varlığına dair kanıtlar buldu."},{"t":"Model geliştirme","a":"atom modeli","d":"Bu kanıtlardan yola çıkarak maddenin atomlardan oluştuğu fikrini açıklayan modeller geliştirdiler."}],"ans":"Bilim, maddenin davranışını açıklayan deney ve gözlemlerden yola çıkarak atomun varlığı fikrine ulaşmıştır."}]},"lise":{"kolay":[{"q":"Modern kimyada atom nasıl tanımlanır ve neden 'temel yapı taşı' sayılır?","steps":[{"t":"Tanım","a":"elementin en küçük birimi","d":"Atom, bir elementin kimyasal özelliğini taşıyan ve kimyasal yollarla daha basit parçalara ayrılamayan en küçük birimidir."},{"t":"Temel yapı taşı","a":"madde inşası","d":"Tüm maddeler atomların belirli düzen ve sayılarda bir araya gelmesiyle oluştuğu için atom maddenin temel yapı taşı kabul edilir."}],"ans":"Atom, bir elementin kimyasal özelliğini taşıyan en küçük birimdir; tüm maddeler atomlardan oluştuğu için temel yapı taşıdır."},{"q":"Atomun büyüklük mertebesi nedir ve bu neden günlük deneyimimize ters görünür?","steps":[{"t":"Boyut mertebesi","a":"yaklaşık 10⁻¹⁰ m","d":"Bir atomun çapı yaklaşık 0,1 nanometre (10⁻¹⁰ m) düzeyindedir."},{"t":"Günlük algı","a":"sürekli madde","d":"Atomlar çok küçük ve çok sayıda olduğundan madde bize boşluksuz ve sürekli görünür; oysa tanecikli yapıdadır."}],"ans":"Atom yaklaşık 10⁻¹⁰ m çapındadır; bu kadar küçük ve çok sayıda olduğu için madde bize sürekli (tanecikli olmayan) görünür."},{"q":"Atom ile molekül kavramları arasındaki ilişki nedir?","fig":"<svg viewBox='0 0 320 160'><circle cx='70' cy='80' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='70' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>atom</text><circle cx='210' cy='80' r='16' fill='#e0552b' stroke='#1a2b45'/><circle cx='180' cy='100' r='11' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='240' cy='100' r='11' fill='#cfd8e8' stroke='#1a2b45'/><line x1='210' y1='80' x2='180' y2='100' stroke='#1a2b45'/><line x1='210' y1='80' x2='240' y2='100' stroke='#1a2b45'/><text x='210' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>molekül (H₂O)</text></svg>","steps":[{"t":"Atom","a":"temel birim","d":"Atom, maddenin kimyasal kimliğini taşıyan en küçük yapı taşıdır."},{"t":"Molekül","a":"bağlı atom grubu","d":"Molekül, iki ya da daha çok atomun kimyasal bağlarla birleşmesiyle oluşan tanecik grubudur (örneğin H₂O, O₂)."}],"ans":"Atom maddenin temel yapı taşıdır; molekül ise birden çok atomun kimyasal bağlarla birleşmesiyle oluşan tanecik grubudur."},{"q":"'Madde tanecikli yapıdadır' ifadesi atom kavramıyla nasıl ilişkilendirilir?","steps":[{"t":"Tanecikli yapı","a":"boşluklu","d":"Madde sürekli değil, tanecikler ve aralarındaki boşluklardan oluşur."},{"t":"Taneciklerin temeli","a":"atom","d":"Bu taneciklerin temelinde atomlar bulunur; atomlar tek başına ya da molekül/iyon halinde maddeyi oluşturur."}],"ans":"Madde sürekli değil tanecikli ve boşlukludur; bu taneciklerin temelinde maddenin yapı taşı olan atomlar bulunur."},{"q":"Bir element örneği ile o elementi oluşturan atom arasındaki fark nedir?","steps":[{"t":"Element örneği","a":"makroskobik madde","d":"Elinizdeki bir parça bakır, gözle görülen, ölçülebilen makroskobik bir madde örneğidir."},{"t":"Atom","a":"mikroskobik yapı taşı","d":"O bakır parçasını oluşturan tek bir bakır atomu ise gözle görülemeyen mikroskobik yapı taşıdır."}],"ans":"Element örneği gözle görülen makroskobik maddedir; atom ise o maddeyi oluşturan, görülemeyen mikroskobik yapı taşıdır."}],"zor":[{"q":"Bir kömür parçasının kütlesinin tamamına yakını karbon atomlarındaysa, kütle ile atom sayısı arasındaki ilişki nasıl kurulur?","steps":[{"t":"Mol kavramı","a":"6,02·10²³ tane","d":"1 mol madde 6,02·10²³ tanecik (atom) içerir; bu Avogadro sayısıdır."},{"t":"Kütle-tane ilişkisi","a":"mol üzerinden","d":"12 g karbon yaklaşık 1 mol, yani 6,02·10²³ karbon atomu demektir; kütle arttıkça atom sayısı orantılı artar."}],"ans":"Kütle ile atom sayısı mol üzerinden ilişkilidir; örneğin 12 g karbon ≈ 1 mol = 6,02·10²³ atom içerir."},{"q":"Atomlar gözle görülemezken atomun varlığına dair bilimsel güven neye dayanır?","steps":[{"t":"Dolaylı kanıtlar","a":"tutarlı deneyler","d":"Sabit oranlar yasası, katlı oranlar ve gaz davranışları gibi pek çok deney atom varsayımıyla tutarlı sonuçlar verir."},{"t":"Doğrudan görüntüleme","a":"taramalı mikroskop","d":"Taramalı tünelleme mikroskobu gibi ileri tekniklerle atomların konumları günümüzde görüntülenebilmektedir."}],"ans":"Atomun varlığı hem onunla tutarlı çok sayıda deneye hem de ileri mikroskoplarla elde edilen doğrudan görüntülere dayanır."},{"q":"'Atom kimyasal yolla bölünemez' denir; bu ifade ile çekirdek tepkimeleri nasıl bağdaştırılır?","steps":[{"t":"Kimyasal sınır","a":"elektron düzeyi","d":"Kimyasal tepkimeler atomların elektronlarını ilgilendirir; atomun çekirdek kimliği değişmez, dolayısıyla atom kimyasal yolla bölünmez sayılır."},{"t":"Çekirdek tepkimesi","a":"farklı süreç","d":"Çekirdek tepkimelerinde proton/nötron sayısı değişir ve atom başka elemente dönüşebilir; ancak bu kimyasal değil nükleer bir süreçtir."}],"ans":"Atom kimyasal yolla bölünemez; bölünme yalnızca çekirdeği değiştiren nükleer (kimyasal olmayan) tepkimelerde gerçekleşir."},{"q":"Maddenin korunumu ilkesi, atom kavramıyla nasıl temellendirilir?","steps":[{"t":"İlke","a":"kütle korunur","d":"Kimyasal bir tepkimede toplam kütle değişmez; tepken kütlesi ürün kütlesine eşittir."},{"t":"Atom temeli","a":"atom sayısı sabit","d":"Çünkü tepkimede atomlar yok olmaz ya da yoktan var olmaz; yalnızca yeniden düzenlenir, böylece atom türü ve sayısı korunur."}],"ans":"Kütle korunur çünkü kimyasal tepkimede atomlar yok olmayıp yalnızca yeniden düzenlenir; atom türü ve sayısı sabit kalır."},{"q":"Evrendeki çeşitliliğe rağmen sınırlı sayıda atom türünün bu kadar farklı maddeyi oluşturabilmesi nasıl açıklanır?","steps":[{"t":"Sınırlı tür","a":"elementler","d":"Doğada görece az sayıda farklı atom türü (element) vardır."},{"t":"Kombinasyon","a":"çok sayıda dizilim","d":"Bu atomların farklı sayı, oran ve düzenlerde birleşmesi sayısız farklı madde oluşturur; tıpkı az sayıda harften sonsuz kelime kurulması gibi."}],"ans":"Sınırlı sayıda atom türü, farklı sayı ve düzenlerde birleşerek sayısız madde oluşturur; çeşitlilik bağlanma kombinasyonlarından doğar."}]}},"atomNoKutleNo":{"ilkokul":{"kolay":[{"q":"Atom numarası bir atomun neyini gösterir?","steps":[{"t":"Gösterdiği sayı","a":"proton sayısı","d":"Atom numarası, atomun çekirdeğindeki proton sayısını gösterir."},{"t":"Kimlik","a":"element belli olur","d":"Proton sayısı, hangi element olduğunu söyleyen kimlik gibidir."}],"ans":"Atom numarası, bir atomun çekirdeğindeki proton sayısını gösterir."},{"q":"Çekirdekte hangi iki tanecik bulunur?","fig":"<svg viewBox='0 0 300 160'><circle cx='150' cy='80' r='34' fill='none' stroke='#1a2b45'/><circle cx='138' cy='72' r='8' fill='#e0552b'/><circle cx='162' cy='72' r='8' fill='#e0552b'/><circle cx='138' cy='92' r='8' fill='#5b6b85'/><circle cx='162' cy='92' r='8' fill='#5b6b85'/><text x='150' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>proton (kırmızı) + nötron (gri)</text></svg>","steps":[{"t":"Birinci tanecik","a":"proton","d":"Çekirdekte artı yüklü protonlar bulunur."},{"t":"İkinci tanecik","a":"nötron","d":"Çekirdekte ayrıca yüksüz nötronlar bulunur."}],"ans":"Çekirdekte protonlar (artı yüklü) ve nötronlar (yüksüz) bulunur."},{"q":"Kütle numarası neyin toplamıdır?","steps":[{"t":"Toplanan tanecikler","a":"proton + nötron","d":"Kütle numarası, çekirdekteki proton sayısı ile nötron sayısının toplamıdır."},{"t":"Kısaca","a":"A = p + n","d":"Kütle numarası A ile gösterilir; A = proton + nötron."}],"ans":"Kütle numarası, çekirdekteki proton ve nötron sayılarının toplamıdır (A = p + n)."},{"q":"Atom numarası 6 olan bir atomun kaç protonu vardır?","steps":[{"t":"Atom numarası","a":"= proton","d":"Atom numarası proton sayısına eşittir."},{"t":"Sonuç","a":"6 proton","d":"Atom numarası 6 ise atomun 6 protonu vardır (bu karbondur)."}],"ans":"Atom numarası 6 olan atomun 6 protonu vardır."},{"q":"7 protonu ve 7 nötronu olan bir atomun kütle numarası kaçtır?","steps":[{"t":"Toplam yap","a":"7 + 7","d":"Kütle numarası proton ile nötronun toplamıdır; 7 + 7 yapılır."},{"t":"Sonuç","a":"14","d":"7 + 7 = 14, yani kütle numarası 14'tür."}],"ans":"7 proton ve 7 nötronu olan atomun kütle numarası 14'tür."}],"zor":[{"q":"Kütle numarası 12 ve proton sayısı 6 olan atomun nötron sayısı kaçtır?","steps":[{"t":"Kural","a":"n = A − p","d":"Nötron sayısı, kütle numarasından proton sayısı çıkarılarak bulunur."},{"t":"Hesap","a":"12 − 6 = 6","d":"12 − 6 = 6, yani atomda 6 nötron vardır."}],"ans":"Kütle numarası 12, proton sayısı 6 olan atomun nötron sayısı 12 − 6 = 6'dır."},{"q":"İki atomun proton sayısı aynı ama nötron sayısı farklıysa bunlara ne denir?","steps":[{"t":"Aynı proton","a":"aynı element","d":"Proton sayısı aynı olduğundan iki atom da ayni elementtir."},{"t":"Farklı nötron","a":"izotop","d":"Nötron sayıları farklı olan aynı elementin atomlarına izotop denir."}],"ans":"Proton sayısı aynı, nötron sayısı farklı olan aynı elementin atomlarına izotop denir."},{"q":"Nötr bir atomda proton sayısı ile elektron sayısı nasıldır?","fig":"<svg viewBox='0 0 300 165'><circle cx='150' cy='80' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='85' font-size='11' text-anchor='middle' fill='#fff'>+</text><circle cx='150' cy='80' r='45' fill='none' stroke='#1a2b45'/><circle cx='195' cy='80' r='5' fill='#2b6be0'/><circle cx='105' cy='80' r='5' fill='#2b6be0'/><text x='150' y='155' font-size='11' text-anchor='middle' fill='#1a2b45'>artı = eksi (nötr)</text></svg>","steps":[{"t":"Yük dengesi","a":"eşit","d":"Nötr atomda artı yük (proton) ile eksi yük (elektron) sayıları eşittir."},{"t":"Sonuç","a":"p = e","d":"Bu yüzden nötr atomda proton sayısı elektron sayısına eşittir."}],"ans":"Nötr bir atomda proton sayısı elektron sayısına eşittir (p = e)."},{"q":"Atom numarası 11 olan sodyumun kütle numarası 23 ise nötron sayısı kaçtır?","steps":[{"t":"Kural","a":"n = A − p","d":"Nötron sayısı, kütle numarasından proton (atom numarası) çıkarılarak bulunur."},{"t":"Hesap","a":"23 − 11 = 12","d":"23 − 11 = 12, yani sodyum atomunda 12 nötron vardır."}],"ans":"Sodyumun (atom no 11, kütle no 23) nötron sayısı 23 − 11 = 12'dir."},{"q":"Bir elementin kimliğini (hangi element olduğunu) belirleyen sayı hangisidir?","steps":[{"t":"Kimlik sayısı","a":"atom numarası","d":"Bir atomun hangi element olduğunu proton sayısı, yani atom numarası belirler."},{"t":"Nötron etkisi","a":"kimliği değiştirmez","d":"Nötron sayısı değişse bile (izotop) proton sayısı aynı kaldıkça element değişmez."}],"ans":"Bir elementin kimliğini atom numarası (proton sayısı) belirler; nötron sayısı kimliği değiştirmez."}]},"ortaokul":{"kolay":[{"q":"Atom numarası (Z) neyi ifade eder ve element kimliğiyle ilişkisi nedir?","steps":[{"t":"Tanım","a":"proton sayısı","d":"Atom numarası Z, çekirdekteki proton sayısına eşittir."},{"t":"Kimlik","a":"elementi belirler","d":"Her elementin proton sayısı farklıdır; bu yüzden Z elementin kimliğini belirler."}],"ans":"Atom numarası Z, proton sayısına eşittir ve her element için farklı olduğundan elementin kimliğini belirler."},{"q":"Kütle numarası (A) nasıl hesaplanır?","fig":"<svg viewBox='0 0 300 160'><circle cx='150' cy='80' r='36' fill='none' stroke='#1a2b45'/><circle cx='136' cy='70' r='8' fill='#e0552b'/><circle cx='160' cy='70' r='8' fill='#e0552b'/><circle cx='136' cy='92' r='8' fill='#5b6b85'/><circle cx='160' cy='92' r='8' fill='#5b6b85'/><text x='150' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>A = proton + nötron</text></svg>","steps":[{"t":"Toplam","a":"p + n","d":"Kütle numarası, proton sayısı ile nötron sayısının toplamıdır."},{"t":"Formül","a":"A = p + n","d":"Elektronlar çok hafif olduğundan kütleye katılmaz; A yalnızca proton ve nötrondan oluşur."}],"ans":"Kütle numarası A, proton ve nötron sayılarının toplamıdır: A = p + n."},{"q":"Nötron sayısı atom numarası ve kütle numarasından nasıl bulunur?","steps":[{"t":"Düzenleme","a":"A = p + n","d":"A = p + n eşitliğinde n yalnız bırakılır."},{"t":"Formül","a":"n = A − Z","d":"Nötron sayısı, kütle numarasından atom numarası çıkarılarak bulunur: n = A − Z."}],"ans":"Nötron sayısı, kütle numarasından atom numarası çıkarılarak bulunur: n = A − Z."},{"q":"Atom numarası 17, kütle numarası 35 olan klorun proton, nötron ve elektron sayıları nedir?","steps":[{"t":"Proton ve elektron","a":"17 ve 17","d":"Atom numarası 17 olduğundan 17 proton vardır; nötr atomda elektron sayısı da 17'dir."},{"t":"Nötron","a":"35 − 17 = 18","d":"Nötron = A − Z = 35 − 17 = 18'dir."}],"ans":"Klorda 17 proton, 17 elektron ve 35 − 17 = 18 nötron bulunur."},{"q":"İzotop nedir? Örnek vererek açıklayınız.","steps":[{"t":"Tanım","a":"aynı p, farklı n","d":"İzotoplar, proton sayısı aynı ama nötron sayısı farklı olan aynı elementin atomlarıdır."},{"t":"Örnek","a":"karbon-12 ve karbon-14","d":"Karbon-12 (6 proton, 6 nötron) ile karbon-14 (6 proton, 8 nötron) aynı elementin izotoplarıdır."}],"ans":"İzotop, proton sayısı aynı ama nötron sayısı farklı atomlardır; örneğin karbon-12 ve karbon-14 karbonun izotoplarıdır."}],"zor":[{"q":"Karbon-12 ve karbon-14 izotoplarının proton, nötron ve elektron sayılarını karşılaştırınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='80' cy='75' r='30' fill='none' stroke='#1a2b45'/><circle cx='70' cy='68' r='6' fill='#e0552b'/><circle cx='90' cy='68' r='6' fill='#e0552b'/><circle cx='70' cy='84' r='6' fill='#5b6b85'/><circle cx='90' cy='84' r='6' fill='#5b6b85'/><text x='80' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>C-12: 6p, 6n</text><circle cx='235' cy='75' r='30' fill='none' stroke='#1a2b45'/><circle cx='225' cy='66' r='6' fill='#e0552b'/><circle cx='245' cy='66' r='6' fill='#e0552b'/><circle cx='225' cy='84' r='6' fill='#5b6b85'/><circle cx='245' cy='84' r='6' fill='#5b6b85'/><circle cx='235' cy='52' r='6' fill='#5b6b85'/><text x='235' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>C-14: 6p, 8n</text></svg>","steps":[{"t":"Ortak özellik","a":"6 proton, 6 e⁻","d":"Her ikisi de karbon olduğundan 6 protona ve nötr halde 6 elektrona sahiptir."},{"t":"Farklı özellik","a":"nötron 6 ve 8","d":"Karbon-12'de 12 − 6 = 6 nötron, karbon-14'te 14 − 6 = 8 nötron vardır; nötron sayıları farklıdır."}],"ans":"İkisinin de 6 protonu ve 6 elektronu vardır; karbon-12'de 6, karbon-14'te 8 nötron bulunur (izotop)."},{"q":"Bir atomun proton, nötron ve elektron sayısı sırasıyla 19, 20, 19 ise atom numarası, kütle numarası ve yük durumu nedir?","steps":[{"t":"Atom ve kütle no","a":"Z=19, A=39","d":"Atom numarası proton sayısına eşittir (Z = 19); kütle numarası A = p + n = 19 + 20 = 39'dur."},{"t":"Yük","a":"nötr","d":"Proton (19) ile elektron (19) eşit olduğundan atom nötrdür, yüklü değildir (potasyum)."}],"ans":"Atom numarası 19, kütle numarası 39'dur; proton ve elektron eşit olduğundan atom nötrdür (potasyum-39)."},{"q":"Bir atomda 8 proton, 10 nötron ve 8 elektron varsa kütle numarası ve element nedir?","steps":[{"t":"Kütle numarası","a":"8 + 10 = 18","d":"Kütle numarası A = p + n = 8 + 10 = 18'dir."},{"t":"Element","a":"oksijen","d":"Proton sayısı (atom numarası) 8 olan element oksijendir; bu atom oksijen-18 izotopudur."}],"ans":"Kütle numarası 18'dir ve atom numarası 8 olduğundan element oksijendir (oksijen-18)."},{"q":"Klorun iki izotopu olan ³⁵Cl ve ³⁷Cl arasındaki tek fark nedir ve kimyasal özellikleri neden aynıdır?","steps":[{"t":"Tek fark","a":"nötron sayısı","d":"³⁵Cl'de 35 − 17 = 18, ³⁷Cl'de 37 − 17 = 20 nötron vardır; tek fark nötron sayısıdır."},{"t":"Kimya aynı","a":"e⁻ dizilimi aynı","d":"Her ikisinin de proton ve elektron sayısı 17 olduğundan değerlik elektron dizilimi aynıdır; kimyasal özellikleri bu yüzden özdeştir."}],"ans":"İki izotop yalnızca nötron sayısında (18 ve 20) farklıdır; proton ve elektron sayıları aynı olduğundan kimyasal özellikleri özdeştir."},{"q":"Atom numarası 12 ve kütle numarası 24 olan magnezyum, 2 elektron verip Mg²⁺ olduğunda proton, nötron ve elektron sayıları ne olur?","steps":[{"t":"Proton ve nötron","a":"12 ve 12","d":"İyonlaşma çekirdeği değiştirmez; proton 12, nötron A − Z = 24 − 12 = 12 olarak kalır."},{"t":"Elektron","a":"12 − 2 = 10","d":"2 elektron verildiğinden elektron sayısı 10'a düşer; yük = 12 − 10 = +2 (Mg²⁺) olur."}],"ans":"Mg²⁺'da 12 proton ve 12 nötron değişmeden kalır, elektron sayısı 10'a düşer; yük +2 olur."}]},"lise":{"kolay":[{"q":"Atom numarası Z'nin proton sayısı, element kimliği ve nötr atomda elektron sayısıyla ilişkisi nedir?","steps":[{"t":"Z = proton","a":"element kimliği","d":"Atom numarası Z proton sayısına eşittir ve her element için benzersiz olduğundan elementin kimliğini belirler."},{"t":"Nötr atom","a":"Z = elektron","d":"Nötr atomda proton ile elektron eşit olduğundan elektron sayısı da Z'ye eşittir."}],"ans":"Z proton sayısına eşittir, elementin kimliğini belirler ve nötr atomda elektron sayısına da eşittir."},{"q":"Kütle numarası A'nın tanımı nedir ve elektronlar neden A'ya katılmaz?","steps":[{"t":"Tanım","a":"A = p + n","d":"Kütle numarası, çekirdekteki proton ve nötron sayılarının toplamıdır."},{"t":"Elektron etkisi","a":"çok hafif","d":"Elektronun kütlesi protonun yaklaşık 1/1836'sı kadardır; ihmal edilebilecek kadar küçük olduğundan A'ya katılmaz."}],"ans":"Kütle numarası A = p + n'dir; elektronlar çok hafif (protonun yaklaşık 1/1836'sı) olduğundan kütle numarasına katılmaz."},{"q":"₁₇³⁵Cl gösteriminde hangi sayı atom, hangisi kütle numarasıdır ve nötron sayısı kaçtır?","fig":"<svg viewBox='0 0 300 150'><text x='150' y='90' font-size='52' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='95' y='62' font-size='26' text-anchor='middle' fill='#e0552b'>35</text><text x='95' y='110' font-size='26' text-anchor='middle' fill='#2b6be0'>17</text><text x='150' y='135' font-size='12' text-anchor='middle' fill='#1a2b45'>üst: A=35   alt: Z=17</text></svg>","steps":[{"t":"Gösterim","a":"alt: Z, üst: A","d":"Sembolün solunda alttaki sayı atom numarası (Z = 17), üstteki sayı kütle numarasıdır (A = 35)."},{"t":"Nötron","a":"35 − 17 = 18","d":"Nötron sayısı n = A − Z = 35 − 17 = 18'dir."}],"ans":"Alttaki 17 atom numarası (Z), üstteki 35 kütle numarasıdır (A); nötron sayısı 35 − 17 = 18'dir."},{"q":"İzotop kavramını tanımlayıp neden izotopların kimyasal özelliklerinin aynı olduğunu açıklayınız.","steps":[{"t":"Tanım","a":"aynı Z, farklı A","d":"İzotoplar aynı proton sayısına (Z) ama farklı nötron sayısına (dolayısıyla farklı A'ya) sahip aynı elementin atomlarıdır."},{"t":"Kimya","a":"e⁻ dizilimi aynı","d":"Proton sayısı aynı olduğundan elektron sayısı ve değerlik dizilimi de aynıdır; kimyasal davranışı belirleyen elektronlar aynı olduğundan kimyasal özellikleri özdeştir."}],"ans":"İzotop, aynı Z'ye fakat farklı nötron sayısına sahip atomlardır; elektron dizilimleri aynı olduğundan kimyasal özellikleri özdeştir."},{"q":"Bir atomda 26 proton, 30 nötron ve 23 elektron varsa atom numarası, kütle numarası ve yükü nedir?","steps":[{"t":"Z ve A","a":"26 ve 56","d":"Atom numarası proton sayısına eşittir (Z = 26, demir); kütle numarası A = 26 + 30 = 56'dır."},{"t":"Yük","a":"26 − 23 = +3","d":"Yük = proton − elektron = 26 − 23 = +3; bu tanecik Fe³⁺ iyonudur."}],"ans":"Atom numarası 26, kütle numarası 56'dır; yük 26 − 23 = +3, yani tanecik Fe³⁺ iyonudur."}],"zor":[{"q":"Bir elementin ortalama atom kütlesi, izotop kütleleri ve bollukları kullanılarak nasıl hesaplanır? Klor için örnekleyiniz.","steps":[{"t":"Yöntem","a":"ağırlıklı ortalama","d":"Ortalama atom kütlesi, her izotopun kütlesinin bolluk yüzdesiyle çarpılıp toplanmasıyla bulunur."},{"t":"Klor hesabı","a":"≈ 35,5","d":"³⁵Cl (%75) ve ³⁷Cl (%25) için: 35 · 0,75 + 37 · 0,25 = 26,25 + 9,25 = 35,5'tir."}],"ans":"Ortalama atom kütlesi izotop kütlelerinin bolluklarıyla ağırlıklı ortalamasıdır; klor için 35 · 0,75 + 37 · 0,25 = 35,5 çıkar."},{"q":"Atom numarası aynı, kütle numarası farklı taneciklerin izotop; kütle numarası aynı, atom numarası farklı taneciklerin izobar olması ne anlama gelir?","steps":[{"t":"İzotop","a":"aynı Z","d":"İzotoplarda proton sayısı (Z) aynı, nötron sayısı (ve A) farklıdır; örneğin ¹²C ve ¹⁴C aynı elementtir."},{"t":"İzobar","a":"aynı A","d":"İzobarlarda kütle numarası A aynı, atom numarası Z farklıdır; bunlar farklı elementlerdir (örneğin ⁴⁰Ar ve ⁴⁰Ca)."}],"ans":"İzotoplar aynı Z'ye sahip aynı elementtir (n farklı); izobarlar ise aynı A'ya sahip farklı elementlerdir (Z farklı)."},{"q":"S²⁻ iyonunda 16 proton, 16 nötron ve 18 elektron varsa kütle numarasını, yükü ve atomdan farkını açıklayınız.","steps":[{"t":"Kütle numarası","a":"16 + 16 = 32","d":"Kütle numarası yalnız çekirdeğe bağlıdır: A = p + n = 16 + 16 = 32'dir; iyonlaşma A'yı değiştirmez."},{"t":"Yük ve fark","a":"16 − 18 = −2","d":"Yük = proton − elektron = 16 − 18 = −2; nötr S atomuna göre 2 elektron fazlası olduğundan S²⁻ anyonudur."}],"ans":"Kütle numarası 32'dir (çekirdek değişmez); yük 16 − 18 = −2, yani nötr atomdan 2 elektron fazlası olan S²⁻ anyonudur."},{"q":"Nötron sayısı = A − Z formülü, izotop sembolü ₉₂²³⁵U için nasıl uygulanır ve U-235 ile U-238 arasındaki fark nedir?","steps":[{"t":"U-235 nötronu","a":"235 − 92 = 143","d":"Uranyum atom numarası 92'dir; U-235'te nötron = A − Z = 235 − 92 = 143'tür."},{"t":"U-238 ile fark","a":"3 nötron","d":"U-238'de nötron = 238 − 92 = 146'dır; iki izotop arasında 146 − 143 = 3 nötron farkı vardır, proton sayısı aynıdır."}],"ans":"U-235'in nötron sayısı 235 − 92 = 143'tür; U-238 (146 nötron) ile aralarında yalnızca 3 nötronluk fark vardır, ikisi de 92 protonludur (izotop)."},{"q":"İki nötr atomun atom numaraları farklı ama kütle numaraları eşitse (izobar), proton, nötron ve elektron sayıları nasıl karşılaştırılır? ⁴⁰₁₈Ar ve ⁴⁰₂₀Ca için açıklayınız.","steps":[{"t":"Proton ve elektron","a":"18 ve 20","d":"Argon 18, kalsiyum 20 protonludur; nötr olduklarından elektron sayıları da sırasıyla 18 ve 20'dir, yani farklıdır."},{"t":"Nötron","a":"22 ve 20","d":"Ar'da n = 40 − 18 = 22, Ca'da n = 40 − 20 = 20'dir; kütle numaraları eşit (40) olmasına rağmen nötron sayıları farklıdır."}],"ans":"Ar (18 p, 22 n, 18 e) ile Ca (20 p, 20 n, 20 e) farklı elementlerdir; kütle numaraları eşit olsa da proton, nötron ve elektron sayıları farklıdır (izobar)."}]}},"atomYapisi":{"ilkokul":{"kolay":[{"q":"Atomun tam ortasındaki bölgeye ne denir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='90' r='55' fill='none' stroke='#1a2b45'/><circle cx='215' cy='90' r='5' fill='#2b6be0'/><text x='160' y='170' font-size='11' text-anchor='middle' fill='#1a2b45'>çekirdek ve elektron</text></svg>","steps":[{"t":"Orta bölge","a":"çekirdek","d":"Atomun tam ortasındaki küçük ama ağır bölgeye çekirdek denir."},{"t":"Çevre","a":"elektronlar","d":"Çekirdeğin etrafında küçük elektronlar bulunur."}],"ans":"Atomun ortasındaki bölgeye çekirdek denir."},{"q":"Çekirdeğin etrafında dolaşan küçük taneciklere ne ad verilir?","steps":[{"t":"Çevredeki tanecik","a":"elektron","d":"Çekirdeğin çevresinde dönen çok küçük taneciklere elektron denir."},{"t":"Yer","a":"çekirdek dışında","d":"Elektronlar çekirdeğin içinde değil, çevresinde bulunur."}],"ans":"Çekirdeğin etrafında dolaşan taneciklere elektron denir."},{"q":"Atomun çekirdeği mi yoksa elektronları mı daha ağırdır?","steps":[{"t":"Çekirdek","a":"ağır kısım","d":"Atomun ağırlığının neredeyse tamamı çekirdektedir."},{"t":"Elektron","a":"çok hafif","d":"Elektronlar çekirdeğe göre çok daha hafiftir."}],"ans":"Atomun çekirdeği, elektronlarından çok daha ağırdır."},{"q":"Bir atomun çekirdeği atomun neresinde bulunur?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='60' fill='none' stroke='#1a2b45' stroke-dasharray='4 3'/><circle cx='160' cy='90' r='11' fill='#e0552b'/><text x='160' y='170' font-size='11' text-anchor='middle' fill='#1a2b45'>çekirdek ortadadır</text></svg>","steps":[{"t":"Konum","a":"tam orta","d":"Çekirdek atomun tam ortasında, merkezde bulunur."},{"t":"Çevresi","a":"elektron yolu","d":"Çevresinde ise elektronların dolaştığı bölge vardır."}],"ans":"Çekirdek atomun tam ortasında (merkezinde) bulunur."},{"q":"Atomun çoğu dolu mudur yoksa boşluk mudur?","steps":[{"t":"Çekirdek küçük","a":"orta minik","d":"Çekirdek atoma göre çok küçük bir yer kaplar."},{"t":"Geniş alan","a":"boşluk","d":"Çekirdek ile elektronlar arasındaki geniş alan boşluktur."}],"ans":"Atomun çoğu boşluktur; ortada küçük bir çekirdek, çevresinde elektronlar vardır."}],"zor":[{"q":"Çekirdeğin içinde hangi tanecikler bulunur?","steps":[{"t":"Birinci tanecik","a":"proton","d":"Çekirdeğin içinde proton denilen tanecikler bulunur."},{"t":"İkinci tanecik","a":"nötron","d":"Protonların yanında bir de nötron denilen tanecikler vardır."}],"ans":"Çekirdeğin içinde proton ve nötron adı verilen tanecikler bulunur."},{"q":"Elektronlar çekirdekten neden uçup gitmez?","steps":[{"t":"Çekim","a":"çekirdek çeker","d":"Çekirdek, çevresindeki elektronları kendine doğru çeker."},{"t":"Sonuç","a":"yakın durur","d":"Bu çekme sayesinde elektronlar uzaklaşmaz, çekirdeğin çevresinde kalır."}],"ans":"Çekirdek elektronları kendine doğru çektiği için elektronlar uçup gitmeden çevresinde dolaşır."},{"q":"Atomu çok büyük bir stadyuma benzetsek, çekirdek neye benzer?","steps":[{"t":"Stadyum","a":"koca atom","d":"Atomun tamamını kocaman bir stadyum gibi düşünelim."},{"t":"Çekirdek","a":"ortadaki küçük top","d":"Çekirdek, bu büyük stadyumun tam ortasındaki küçücük bir top kadar yer kaplar."}],"ans":"Atom bir stadyum kadar büyük olsaydı, çekirdek ortadaki küçücük bir top kadar küçük kalırdı."},{"q":"Çekirdek ile elektronlar arasındaki bölge için ne söyleyebiliriz?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='10' fill='#e0552b'/><circle cx='160' cy='90' r='35' fill='none' stroke='#1a2b45'/><circle cx='160' cy='90' r='62' fill='none' stroke='#1a2b45'/><circle cx='195' cy='90' r='4' fill='#2b6be0'/><circle cx='160' cy='28' r='4' fill='#2b6be0'/><text x='160' y='172' font-size='10' text-anchor='middle' fill='#1a2b45'>arada geniş boşluk</text></svg>","steps":[{"t":"Bölge","a":"geniş boşluk","d":"Çekirdek ile elektronlar arasında geniş bir boşluk vardır."},{"t":"Elektron hareketi","a":"boşlukta döner","d":"Elektronlar bu boşlukta çekirdeğin çevresinde dolaşır."}],"ans":"Çekirdek ile elektronlar arasında geniş bir boşluk vardır; elektronlar bu boşlukta dolaşır."},{"q":"Bir atomda en az kaç çeşit tanecik bulunabilir ve adları nedir?","steps":[{"t":"Çekirdektekiler","a":"proton, nötron","d":"Çekirdekte proton ve nötron bulunur."},{"t":"Çevredeki","a":"elektron","d":"Çekirdeğin çevresinde de elektron bulunur."}],"ans":"Bir atomda proton, nötron ve elektron olmak üzere üç çeşit tanecik bulunur."}]},"ortaokul":{"kolay":[{"q":"Atomun genel yapısı hangi iki ana bölgeden oluşur?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='92' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='40' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='66' fill='none' stroke='#1a2b45'/><circle cx='200' cy='92' r='5' fill='#2b6be0'/><circle cx='160' cy='26' r='5' fill='#2b6be0'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>çekirdek + katmanlar</text></svg>","steps":[{"t":"Birinci bölge","a":"çekirdek","d":"Atomun merkezinde proton ve nötronu barındıran çekirdek bulunur."},{"t":"İkinci bölge","a":"katmanlar","d":"Çekirdeğin çevresinde elektronların bulunduğu katmanlar (enerji düzeyleri) vardır."}],"ans":"Atom; merkezdeki çekirdek ile çevresindeki elektron katmanlarından oluşur."},{"q":"Atomun temel tanecikleri ve yükleri nelerdir?","steps":[{"t":"Yüklü tanecikler","a":"proton (+), elektron (−)","d":"Proton artı (+) yüklü, elektron eksi (−) yüklüdür."},{"t":"Yüksüz tanecik","a":"nötron","d":"Nötronun yükü yoktur, yani yüksüzdür (nötr)."}],"ans":"Atomun temel tanecikleri proton (+), nötron (yüksüz) ve elektron (−)dir."},{"q":"Çekirdekte hangi tanecikler bulunur ve bu bölge neden ağırdır?","steps":[{"t":"Çekirdek tanecikleri","a":"proton ve nötron","d":"Çekirdekte proton ve nötron bulunur."},{"t":"Ağırlık nedeni","a":"kütle burada","d":"Proton ve nötron elektrondan çok ağır olduğundan atom kütlesinin neredeyse tamamı çekirdektedir."}],"ans":"Çekirdekte proton ve nötron bulunur; bunlar ağır olduğu için atom kütlesinin neredeyse tamamı çekirdektedir."},{"q":"Nötr bir atomda proton ve elektron sayıları arasında nasıl bir ilişki vardır?","steps":[{"t":"Yükler","a":"(+) ve (−) eşit","d":"Nötr atomda artı yük (proton) sayısı eksi yük (elektron) sayısına eşittir."},{"t":"Sonuç","a":"p = e","d":"Bu eşitlik sayesinde atomun toplam yükü sıfır, yani nötr olur."}],"ans":"Nötr bir atomda proton sayısı elektron sayısına eşittir (p = e), bu yüzden atom yüksüzdür."},{"q":"Elektronlar çekirdeğin etrafında nasıl bulunur?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='92' r='10' fill='#e0552b'/><circle cx='160' cy='92' r='32' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='58' fill='none' stroke='#1a2b45'/><circle cx='192' cy='92' r='5' fill='#2b6be0'/><circle cx='160' cy='34' r='5' fill='#2b6be0'/><circle cx='160' cy='150' r='5' fill='#2b6be0'/><text x='196' y='106' font-size='10' fill='#1a2b45'>K</text><text x='160' y='28' font-size='10' text-anchor='middle' fill='#1a2b45'>L</text></svg>","steps":[{"t":"Katmanlar","a":"enerji düzeyi","d":"Elektronlar çekirdeğin çevresinde belirli katmanlarda (K, L, M ...) bulunur."},{"t":"Dolma sırası","a":"içten dışa","d":"Elektronlar önce çekirdeğe en yakın katmanı doldurur, sonra dış katmanlara geçer."}],"ans":"Elektronlar çekirdeğin çevresinde belirli katmanlarda, içten dışa doğru dizilerek bulunur."}],"zor":[{"q":"Bir atomun proton sayısı 6, nötron sayısı 6 ise nötr hâlde kaç elektronu vardır?","steps":[{"t":"Nötrlük kuralı","a":"p = e","d":"Nötr atomda elektron sayısı proton sayısına eşittir."},{"t":"Sonuç","a":"6 elektron","d":"Proton sayısı 6 olduğundan nötr atomun elektron sayısı da 6 olur (nötron sayısının yükle ilgisi yoktur)."}],"ans":"Nötr atomun elektron sayısı proton sayısına eşittir; bu nedenle 6 elektronu vardır."},{"q":"Atomun kütlesi neden neredeyse tamamen çekirdekte toplanmıştır?","steps":[{"t":"Tanecik kütleleri","a":"p ≈ n ≫ e","d":"Proton ve nötronun kütlesi birbirine yakın ve büyüktür; elektron ise bunlardan yaklaşık 1836 kat hafiftir."},{"t":"Sonuç","a":"çekirdek = kütle","d":"Bu yüzden atom kütlesi neredeyse tamamen çekirdekteki proton ve nötronlardan gelir; elektronların katkısı ihmal edilir."}],"ans":"Proton ve nötron elektrondan çok daha ağır olduğundan atom kütlesi neredeyse tamamen çekirdekte toplanmıştır."},{"q":"Bir atomdaki proton sayısı o atomun hangi özelliğini belirler?","steps":[{"t":"Proton sayısı","a":"kimlik","d":"Bir atomun çekirdeğindeki proton sayısı, o atomun hangi element olduğunu belirler."},{"t":"Örnek","a":"6 proton = karbon","d":"Örneğin 6 protonu olan her atom karbondur; proton sayısı değişirse element de değişir."}],"ans":"Bir atomdaki proton sayısı, o atomun hangi element olduğunu (kimliğini) belirler."},{"q":"Yükü olmayan tanecik hangisidir ve çekirdekteki görevi nedir?","steps":[{"t":"Yüksüz tanecik","a":"nötron","d":"Çekirdekteki nötronun elektriksel yükü yoktur."},{"t":"Görevi","a":"çekirdeği bir arada tutar","d":"Nötronlar, aynı yükteki protonların birbirini itmesine karşı çekirdeğin kararlı kalmasına yardımcı olur."}],"ans":"Yüksüz tanecik nötrondur; çekirdekte protonları bir arada tutarak çekirdeğin kararlılığına katkı sağlar."},{"q":"Bir atomdan elektron eksilir veya eklenirse ne oluşur?","steps":[{"t":"Elektron kaybı","a":"(+) iyon","d":"Atom elektron kaybederse eksi yükü azalır, net yükü artı olur ve katyon (pozitif iyon) oluşur."},{"t":"Elektron kazanımı","a":"(−) iyon","d":"Atom elektron kazanırsa eksi yükü artar, net yükü eksi olur ve anyon (negatif iyon) oluşur."}],"ans":"Elektron kaybeden atom (+) yüklü, elektron kazanan atom (−) yüklü iyon hâline gelir."}]},"lise":{"kolay":[{"q":"Atomun genel yapısı temel parçacıkları ve özellikleri açısından nasıl özetlenir?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='92' r='14' fill='#e0552b' stroke='#1a2b45'/><circle cx='154' cy='88' r='4' fill='#e0552b'/><circle cx='166' cy='96' r='4' fill='#5b6b85'/><circle cx='160' cy='92' r='42' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='68' fill='none' stroke='#1a2b45'/><circle cx='202' cy='92' r='5' fill='#2b6be0'/><circle cx='160' cy='24' r='5' fill='#2b6be0'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>p⁺, n, e⁻</text></svg>","steps":[{"t":"Çekirdek parçacıkları","a":"proton, nötron","d":"Çekirdekte artı yüklü proton (p⁺) ve yüksüz nötron (n) bulunur; bunlara nükleon denir."},{"t":"Çevre parçacığı","a":"elektron","d":"Çekirdek çevresindeki orbitallerde eksi yüklü elektron (e⁻) bulunur; kütlesi nükleona göre ihmal edilebilir."}],"ans":"Atom, çekirdekteki proton (+) ve nötron (yüksüz) ile çevredeki elektronlardan (−) oluşur; kütle çekirdekte, hacim ise elektron bölgesindedir."},{"q":"Atom numarası ve kütle numarası nasıl tanımlanır?","steps":[{"t":"Atom numarası","a":"proton sayısı","d":"Atom numarası (Z), çekirdekteki proton sayısına eşittir ve elementin kimliğini belirler."},{"t":"Kütle numarası","a":"p + n","d":"Kütle numarası (A), proton ve nötron sayılarının toplamıdır: A = Z + N."}],"ans":"Atom numarası proton sayısına (Z) eşittir; kütle numarası ise proton ve nötron sayısının toplamıdır (A = p + n)."},{"q":"Nötr bir atomda yükler nasıl dengelenir ve iyon nasıl oluşur?","steps":[{"t":"Nötr atom","a":"p = e","d":"Nötr atomda proton sayısı elektron sayısına eşittir, net yük sıfırdır."},{"t":"İyonlaşma","a":"e alış-verişi","d":"Atom elektron verirse katyon (+), elektron alırsa anyon (−) oluşur; proton sayısı değişmez."}],"ans":"Nötr atomda proton sayısı elektron sayısına eşittir; elektron verince katyon, alınca anyon oluşur, proton sayısı sabit kalır."},{"q":"Çekirdeğin atom hacmine göre boyutu hakkında ne söylenebilir?","steps":[{"t":"Boyut oranı","a":"çok küçük çekirdek","d":"Çekirdeğin çapı atom çapının yaklaşık on binde biri kadardır; atomun büyük kısmı boşluktur."},{"t":"Yoğunluk sonucu","a":"yüksek yoğunluk","d":"Tüm kütle bu küçük çekirdekte toplandığından çekirdeğin yoğunluğu son derece yüksektir."}],"ans":"Çekirdek atom hacminin çok küçük bir kısmını kaplar (yaklaşık on binde biri), bu yüzden atom çoğunlukla boşluk, çekirdek ise aşırı yoğundur."},{"q":"İzotop kavramı atomun yapısı açısından nasıl açıklanır?","steps":[{"t":"Ortak özellik","a":"aynı proton","d":"İzotoplar aynı elementin atomlarıdır; proton (atom) sayıları eşittir."},{"t":"Fark","a":"farklı nötron","d":"Nötron sayıları farklı olduğundan kütle numaraları farklıdır, ancak kimyasal özellikleri benzerdir."}],"ans":"İzotoplar proton sayısı aynı, nötron (dolayısıyla kütle numarası) farklı atomlardır; kimyasal özellikleri benzer kalır."}],"zor":[{"q":"Bir iyonun ⁴⁰Ca²⁺ gösteriminde proton, nötron ve elektron sayıları nasıl bulunur? (Ca için Z = 20)","steps":[{"t":"Proton ve nötron","a":"p=20, n=20","d":"Atom numarası Z = 20 olduğundan proton sayısı 20'dir; kütle numarası 40 olduğundan nötron sayısı 40 − 20 = 20'dir."},{"t":"Elektron","a":"e = 18","d":"2+ yükü 2 elektron eksiği demektir; nötr Ca'da 20 elektron olurdu, iyonda 20 − 2 = 18 elektron vardır."}],"ans":"⁴⁰Ca²⁺ iyonunda 20 proton, 20 nötron ve 18 elektron bulunur."},{"q":"Atom kütlesinin büyük çoğunluğunun çekirdekte olması, atom yoğunluğu hakkında niçin yanıltıcı sonuç verir?","steps":[{"t":"Çekirdek yoğunluğu","a":"aşırı yüksek","d":"Kütle çok küçük çekirdekte toplandığından çekirdeğin yoğunluğu olağanüstü yüksektir."},{"t":"Atom yoğunluğu","a":"düşük","d":"Atomun büyük kısmı boşluk olduğundan atomun ortalama yoğunluğu, çekirdeğin yoğunluğundan kat kat düşüktür; ikisi karıştırılmamalıdır."}],"ans":"Çekirdek aşırı yoğundur ama atom çoğunlukla boşluk olduğu için atomun ortalama yoğunluğu çok daha düşüktür; çekirdek yoğunluğu atom yoğunluğunu temsil etmez."},{"q":"Aynı yükteki protonlar birbirini iterken çekirdek nasıl kararlı kalabilir?","steps":[{"t":"İtme kuvveti","a":"elektriksel itme","d":"Çekirdekteki protonlar artı yüklü olduğundan birbirini elektriksel olarak iter."},{"t":"Çekirdek kuvveti","a":"güçlü çekim","d":"Çok kısa menzilli güçlü çekirdek kuvveti, bu itmeyi yenerek proton ve nötronları bir arada tutar; nötronlar bu çekime katkı sağlayıp çekirdeği kararlı kılar."}],"ans":"Protonların elektriksel itmesini, kısa menzilli güçlü çekirdek kuvveti yener; nötronların katkısıyla bu kuvvet çekirdeği bir arada tutar."},{"q":"Bir atomun kimyasal kimliği neden proton sayısıyla belirlenir, nötron ya da elektron sayısıyla değil?","steps":[{"t":"Proton sayısı","a":"değişmez kimlik","d":"Proton sayısı değişirse atom başka bir elemente dönüşür; bu yüzden element kimliğini proton sayısı belirler."},{"t":"Diğerleri","a":"izotop ve iyon","d":"Nötron sayısı değişince izotop, elektron sayısı değişince iyon oluşur; element aynı kalır, yalnızca kütle ya da yük değişir."}],"ans":"Proton sayısı değişince element değişir; nötron değişimi izotop, elektron değişimi iyon verir ama elementi değiştirmez, bu yüzden kimliği proton sayısı belirler."},{"q":"Atom yapısının 'çekirdek çevresinde olasılık bölgeleri' biçiminde tanımlanması, kütle ve hacim dağılımı hakkında ne söyler?","steps":[{"t":"Kütle dağılımı","a":"çekirdekte yoğun","d":"Kütle, çok küçük hacimli çekirdekte (proton ve nötronlarda) yoğunlaşmıştır."},{"t":"Hacim dağılımı","a":"orbitallerde","d":"Atomun hacmini ise elektronların bulunma olasılığının yüksek olduğu orbital bölgeleri belirler; yani atomun 'büyüklüğü' elektron bulutundan gelir."}],"ans":"Atomun kütlesi küçük hacimli çekirdekte yoğunlaşmıştır; hacmini ise elektronların olasılık bölgeleri (orbitaller) belirler, yani büyüklük elektron bulutundan gelir."}]}},"aufbauHund":{"ilkokul":{"kolay":[{"q":"Bir sinema salonunda insanlar önce en öndeki, en kolay oturulan koltuklara oturur. Atomda elektronlar da önce kolay (düşük enerjili) yerlere mi yerleşir?","steps":[{"t":"Sinema benzetmesi","a":"önce ön koltuk","d":"Sinemada insanlar önce kolay ulaşılan ön koltuklara oturur."},{"t":"Atomda karşılığı","a":"önce düşük enerji","d":"Elektronlar da önce çekirdeğe yakın, düşük enerjili yerlere yerleşir."}],"ans":"Evet; elektronlar önce düşük enerjili (çekirdeğe yakın) yerlere yerleşir, tıpkı öndeki koltukların önce dolması gibi."},{"q":"Bir merdiveni çıkarken önce alt basamağa mı yoksa üst basamağa mı basarız?","steps":[{"t":"Merdiveni düşün","a":"alt basamak","d":"Merdiven çıkarken önce en alt basamağa basarız."},{"t":"Elektronlar","a":"önce alt enerji","d":"Elektronlar da önce en alttaki (en düşük enerjili) basamağı doldurur."}],"ans":"Önce alt basamağa basarız; elektronlar da önce en düşük enerjili basamağı doldurur."},{"q":"Bir otobüste yan yana iki kişilik koltuklar var. Yeni binenler önce boş çift koltuklara mı, yoksa yanına oturmaya mı başlar?","steps":[{"t":"Otobüsü düşün","a":"önce boş koltuk","d":"İnsanlar genelde önce tamamen boş koltuğa oturur, yabancı yanına sonra oturur."},{"t":"Elektronlar","a":"önce ayrı ayrı","d":"Elektronlar da eşit yerlere önce birer birer, ayrı ayrı yerleşir."}],"ans":"Önce boş koltuklara; elektronlar da eşit yerlere önce birer birer, ayrı ayrı yerleşir."},{"q":"Bir eve önce en alt kata mı yoksa en üst kata mı eşya taşınır kolaylık olsun diye?","steps":[{"t":"Kolaylık","a":"alt kat","d":"Alt kata eşya taşımak daha kolaydır, daha az enerji ister."},{"t":"Elektron sırası","a":"önce alt","d":"Elektronlar da önce alt (düşük enerjili) katı doldurur."}],"ans":"Önce alt kata; elektronlar da düşük enerjili yeri önce doldurur çünkü bu daha kolaydır."},{"q":"Atomda elektronları yerleştirirken belli bir sıra var mıdır, yoksa rastgele mi yerleşirler?","steps":[{"t":"Düzeni düşün","a":"belli bir sıra","d":"Elektronlar gelişigüzel değil, belli bir sırayla yerleşir."},{"t":"Sıra","a":"düşükten yükseğe","d":"Önce düşük enerjili yerler, sonra yüksek enerjili yerler dolar."}],"ans":"Belli bir sıra vardır; elektronlar düşük enerjiden yükseğe doğru sırayla yerleşir."}],"zor":[{"q":"İki kişilik bir otobüs koltuğuna ilk oturan biri ayağını sağa koyuyorsa, yanına oturan rahat etmek için ayağını nasıl koyar?","steps":[{"t":"Karşıt düşün","a":"ters yöne","d":"İki kişi rahat etmek için genelde ters yönlere bakar/durur."},{"t":"Elektron spini","a":"zıt spin","d":"Aynı orbitaldeki iki elektron da zıt yönde döner (zıt spin)."}],"ans":"Yanına oturan ters yöne döner; aynı orbitaldeki iki elektron da zıt yönde (zıt spin) bulunur."},{"q":"Bir sırada 3 boş çift-koltuk var ve 3 kişi binecek. Bu 3 kişi önce ne yapar: aynı koltuğa mı sıkışır, yoksa ayrı ayrı mı oturur?","steps":[{"t":"Rahatı seç","a":"ayrı ayrı","d":"İnsanlar rahat olmak için önce her biri ayrı koltuğa oturur."},{"t":"Elektronlar","a":"birer birer","d":"3 eşit orbitale 3 elektron da önce birer birer, ayrı ayrı yerleşir."}],"ans":"Ayrı ayrı otururlar; 3 eşit orbitale 3 elektron da önce birer birer yerleşir, sonra eşleşir."},{"q":"Bir binada 1. kat tamamen dolmadan 2. kata çıkılır mı?","steps":[{"t":"Sırayı düşün","a":"önce 1. kat dolar","d":"Genelde önce alt kat dolar, sonra üst kata çıkılır."},{"t":"Elektronlar","a":"alttan başla","d":"Elektronlar da önce düşük enerjili düzeyi doldurur, sonra üste geçer."}],"ans":"Genelde önce alt kat dolar; elektronlar da düşük enerjili düzeyi önce doldurup sonra üste geçer."},{"q":"İki elektron aynı küçük eve (orbitale) girmek zorundaysa, ikisi de aynı yöne mi döner?","steps":[{"t":"Aynı evi düşün","a":"yer dar","d":"Aynı orbitalde sadece 2 elektron bulunabilir."},{"t":"Dönüş yönü","a":"zıt yön","d":"Bu iki elektron aynı yöne değil, zıt yöne döner."}],"ans":"Hayır; aynı orbitaldeki iki elektron zıt yöne döner (biri yukarı, biri aşağı spin)."},{"q":"Atomdaki en düşük enerjili ilk ev (orbital) hangisidir: 1s mi, 2s mi?","steps":[{"t":"Enerjiyi karşılaştır","a":"1s daha düşük","d":"1s, çekirdeğe en yakın ve en düşük enerjili orbitaldir."},{"t":"İlk dolan","a":"1s","d":"Bu yüzden elektronlar önce 1s'i doldurur, sonra 2s'e geçer."}],"ans":"En düşük enerjili ilk orbital 1s'tir; elektronlar önce onu doldurur, sonra 2s'e geçer."}]},"ortaokul":{"kolay":[{"q":"Elektronların önce düşük enerjili orbitalleri doldurmasını söyleyen kuralın adı nedir?","steps":[{"t":"Dolma sırası","a":"düşükten yükseğe","d":"Elektronlar önce en düşük enerjili orbitalden başlayarak yerleşir."},{"t":"Kuralı adlandır","a":"Aufbau ilkesi","d":"Bu kurala <b>Aufbau (yapım) ilkesi</b> denir."}],"ans":"Bu kurala Aufbau ilkesi denir; elektronlar önce düşük enerjili orbitalleri doldurur."},{"q":"Bir atomda ilk dolan orbital hangisidir?","steps":[{"t":"En düşük enerji","a":"1s","d":"1s orbitali çekirdeğe en yakın ve en düşük enerjili orbitaldir."},{"t":"İlk dolar","a":"1s","d":"Bu yüzden elektronlar önce 1s'i doldurur."}],"ans":"Bir atomda ilk dolan orbital 1s orbitalidir."},{"q":"Aynı orbitaldeki iki elektronun spinleri (dönüş yönleri) nasıl olmalıdır?","steps":[{"t":"Aynı orbital","a":"2 elektron","d":"Bir orbitalde en fazla 2 elektron bulunur."},{"t":"Spin durumu","a":"zıt spin","d":"Bu iki elektronun spinleri zıt olmalıdır; biri +½, biri −½."}],"ans":"Aynı orbitaldeki iki elektronun spinleri zıttır (biri +½, biri −½)."},{"q":"Eş enerjili (örneğin 2p) orbitallere elektronlar önce nasıl yerleşir?","steps":[{"t":"Eş enerji","a":"3 p orbitali","d":"2p alt kabuğunda enerjileri eşit 3 orbital vardır."},{"t":"Yerleşme","a":"önce birer birer","d":"Elektronlar önce her orbitale birer tane yerleşir, sonra eşleşmeye başlar."}],"ans":"Eş enerjili orbitallere elektronlar önce birer birer (ayrı ayrı) yerleşir; bu Hund kuralıdır."},{"q":"Hidrojen atomunun (1 elektron) elektron dizilimi nasıl yazılır?","steps":[{"t":"Elektron sayısı","a":"1 elektron","d":"Hidrojenin 1 elektronu vardır."},{"t":"Yerleştir","a":"1s¹","d":"Bu tek elektron en düşük enerjili 1s orbitaline yerleşir: 1s¹."}],"ans":"Hidrojenin elektron dizilimi 1s¹'dir."}],"zor":[{"q":"Aufbau ilkesine göre orbitallerin dolma sırasını ilk altı orbital için yazınız.","steps":[{"t":"Sırayı düşün","a":"düşük enerjiden","d":"Orbitaller artan enerjiye göre dolar."},{"t":"Sırayı yaz","a":"1s 2s 2p 3s 3p 4s","d":"İlk altı orbital sırası: 1s, 2s, 2p, 3s, 3p, 4s biçimindedir."}],"ans":"Dolma sırası: 1s, 2s, 2p, 3s, 3p, 4s şeklindedir (4s, 3d'den önce dolar)."},{"q":"Oksijen atomunun (8 elektron) elektron dizilimini yazınız.","steps":[{"t":"Sırayla doldur","a":"1s 2s 2p","d":"8 elektron sırayla 1s, 2s ve 2p orbitallerine yerleşir."},{"t":"Dizilimi yaz","a":"1s² 2s² 2p⁴","d":"1s²(2) + 2s²(2) + 2p⁴(4) = 8 elektron olur."}],"ans":"Oksijenin elektron dizilimi 1s² 2s² 2p⁴'tür (toplam 8 elektron)."},{"q":"Karbon atomunun 2p² diziliminde iki elektron nasıl yerleşir (Hund kuralı)?","steps":[{"t":"Eş orbitaller","a":"3 p orbitali","d":"2p alt kabuğunda enerjileri eşit 3 orbital vardır."},{"t":"Hund kuralı","a":"ayrı ayrı","d":"İki elektron aynı orbitale eşleşmez; farklı iki orbitale paralel spinle yerleşir."}],"ans":"Karbonun 2p² elektronları, Hund kuralı gereği iki ayrı p orbitaline paralel spinle (tek tek) yerleşir."},{"q":"Pauli dışarlama ilkesi, bir orbitaldeki elektronlar için neyi söyler?","steps":[{"t":"İlke","a":"aynı olamaz","d":"Pauli ilkesine göre bir atomda iki elektronun dört kuantum sayısı aynı olamaz."},{"t":"Orbitalde sonuç","a":"zıt spin, en çok 2","d":"Aynı orbitaldeki iki elektron zıt spinli olmalı; bu yüzden orbital en fazla 2 elektron alır."}],"ans":"Pauli ilkesine göre aynı orbitaldeki iki elektron zıt spinli olmalıdır; bu nedenle bir orbital en fazla 2 elektron alır."},{"q":"Sodyum atomunun (11 elektron) elektron dizilimini yazınız.","steps":[{"t":"Sırayla doldur","a":"1s 2s 2p 3s","d":"11 elektron sırayla 1s, 2s, 2p ve 3s orbitallerine yerleşir."},{"t":"Dizilimi yaz","a":"1s² 2s² 2p⁶ 3s¹","d":"1s²(2) + 2s²(2) + 2p⁶(6) + 3s¹(1) = 11 elektron olur."}],"ans":"Sodyumun elektron dizilimi 1s² 2s² 2p⁶ 3s¹'dir (toplam 11 elektron)."}]},"lise":{"kolay":[{"q":"Aufbau (yapım) ilkesi elektron yerleşimi için neyi söyler?","steps":[{"t":"Temel kural","a":"düşük enerjiden","d":"Aufbau ilkesine göre elektronlar önce en düşük enerjili orbitalleri doldurur."},{"t":"Yükselen sıra","a":"artan enerji","d":"Orbitaller enerjileri artan sırayla dolar: 1s, 2s, 2p, 3s, 3p, 4s, 3d, ..."}],"ans":"Aufbau ilkesine göre elektronlar orbitalleri en düşük enerjiden başlayarak artan enerji sırasıyla doldurur."},{"q":"Pauli dışarlama ilkesi bir orbitaldeki elektronlar için ne şartı koyar?","steps":[{"t":"İlke","a":"dört sayı aynı olamaz","d":"Bir atomda iki elektronun dört kuantum sayısı aynı anda aynı olamaz."},{"t":"Orbitalde sonuç","a":"zıt spinli 2 e⁻","d":"Aynı orbitaldeki iki elektron ancak zıt spinle (+½ ve −½) bulunabilir; orbital en çok 2 elektron alır."}],"ans":"Pauli ilkesine göre bir orbitalde en çok 2 elektron, o da zıt spinli (+½ ve −½) olarak bulunabilir."},{"q":"Hund kuralı eş enerjili orbitallere elektronların nasıl yerleştiğini söyler?","steps":[{"t":"Kural","a":"önce tek tek","d":"Eş enerjili (dejenere) orbitallere elektronlar önce birer birer, paralel spinle yerleşir."},{"t":"Sonra eşleşme","a":"sonra ters spin","d":"Tüm orbitaller yarı dolduktan sonra elektronlar zıt spinle eşleşmeye başlar."}],"ans":"Hund kuralına göre eş enerjili orbitallere elektronlar önce birer birer ve paralel spinle yerleşir, sonra eşleşir."},{"q":"Azot atomunun (7 elektron) elektron dizilimi nasıl yazılır?","steps":[{"t":"Sırayla doldur","a":"1s 2s 2p","d":"7 elektron sırayla 1s, 2s ve 2p orbitallerine yerleşir."},{"t":"Dizilimi yaz","a":"1s² 2s² 2p³","d":"1s²(2) + 2s²(2) + 2p³(3) = 7 elektron olur."}],"ans":"Azotun elektron dizilimi 1s² 2s² 2p³'tür (toplam 7 elektron)."},{"q":"Aufbau sırasında 4s orbitali neden 3d'den önce dolar?","steps":[{"t":"n+ℓ kuralı","a":"küçük olan önce","d":"Orbitaller n+ℓ değeri küçük olandan başlayarak dolar."},{"t":"Karşılaştır","a":"4s=4, 3d=5","d":"4s için n+ℓ = 4+0 = 4, 3d için n+ℓ = 3+2 = 5'tir; 4 küçük olduğundan 4s önce dolar."}],"ans":"4s'in n+ℓ değeri (4) 3d'ninkinden (5) küçük olduğu için 4s, 3d'den önce dolar."}],"zor":[{"q":"Demir atomunun (Z = 26) elektron dizilimini Aufbau sırasına göre yazınız.","steps":[{"t":"Dolma sırası","a":"... 4s 3d","d":"Aufbau sırası: 1s, 2s, 2p, 3s, 3p, 4s, 3d biçimindedir."},{"t":"Elektronları yerleştir","a":"26 elektron","d":"1s²(2) 2s²(2) 2p⁶(6) 3s²(2) 3p⁶(6) 4s²(2) 3d⁶(6) toplam 26 elektron eder."},{"t":"Dizilimi yaz","a":"...4s² 3d⁶","d":"Tam dizilim 1s² 2s² 2p⁶ 3s² 3p⁶ 4s² 3d⁶'dır."}],"ans":"Demirin (Z=26) elektron dizilimi 1s² 2s² 2p⁶ 3s² 3p⁶ 4s² 3d⁶'dır."},{"q":"Azot atomunun 2p³ alt kabuğundaki elektronların yerleşimini Hund kuralıyla açıklayıp orbital şemasını yorumlayınız.","fig":"<svg viewBox='0 0 320 90'><rect x='70' y='30' width='34' height='32' fill='none' stroke='#1a2b45' stroke-width='1.5'/><rect x='110' y='30' width='34' height='32' fill='none' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='30' width='34' height='32' fill='none' stroke='#1a2b45' stroke-width='1.5'/><line x1='87' y1='58' x2='87' y2='36' stroke='#2b6be0' stroke-width='2'/><polygon points='87,36 83,43 91,43' fill='#2b6be0'/><line x1='127' y1='58' x2='127' y2='36' stroke='#2b6be0' stroke-width='2'/><polygon points='127,36 123,43 131,43' fill='#2b6be0'/><line x1='167' y1='58' x2='167' y2='36' stroke='#2b6be0' stroke-width='2'/><polygon points='167,36 163,43 171,43' fill='#2b6be0'/><text x='127' y='82' font-size='10' text-anchor='middle' fill='#1a2b45'>paralel spin</text></svg>","steps":[{"t":"Eş orbitaller","a":"3 p orbitali","d":"2p alt kabuğunda enerjileri eşit (dejenere) 3 orbital vardır."},{"t":"Hund uygulaması","a":"birer birer","d":"3 elektron, 3 orbitale birer tane ve paralel spinle yerleşir; eşleşme olmaz."},{"t":"Sonuç","a":"3 yarı dolu","d":"Azotta 2p³, üç yarı dolu paralel spinli orbital içerir; bu kararlı yarı dolu durumdur."}],"ans":"Hund kuralı gereği azotun 2p³ elektronları üç p orbitaline birer birer, paralel spinle (↑ ↑ ↑) yerleşir; üç orbital de yarı dolu ve eşleşmemiştir."},{"q":"Krom atomunun (Z = 24) elektron diziliminin neden beklenenden farklı (4s¹ 3d⁵) olduğunu açıklayınız.","steps":[{"t":"Beklenen dizilim","a":"4s² 3d⁴","d":"Basit Aufbau ile [Ar] 4s² 3d⁴ beklenir."},{"t":"Kararlılık etkisi","a":"yarı dolu d","d":"Yarı dolu 3d⁵ ve yarı dolu 4s¹ düzeni, ekstra kararlılık sağladığı için bir elektron 4s'ten 3d'ye geçer."},{"t":"Gerçek dizilim","a":"4s¹ 3d⁵","d":"Krom'un gerçek dizilimi [Ar] 4s¹ 3d⁵'tir."}],"ans":"Yarı dolu 3d⁵ alt kabuğu ek kararlılık sağladığından bir 4s elektronu 3d'ye geçer; krom'un dizilimi beklenen 4s² 3d⁴ yerine [Ar] 4s¹ 3d⁵'tir."},{"q":"Bir elektron dizilimini soy gaz kısaltmasıyla yazma yöntemini, kalsiyum (Z = 20) üzerinde gösteriniz.","steps":[{"t":"Önceki soy gaz","a":"argon","d":"Kalsiyumdan önceki soy gaz argondur (Z = 18, [Ar] = 1s² 2s² 2p⁶ 3s² 3p⁶)."},{"t":"Kalan elektronlar","a":"2 elektron","d":"20 − 18 = 2 elektron, argon çekirdeğinden sonra 4s'e yerleşir."},{"t":"Kısaltmayı yaz","a":"[Ar] 4s²","d":"Kalsiyumun kısa dizilimi [Ar] 4s²'dir."}],"ans":"Kalsiyumun (Z=20) kısaltılmış dizilimi [Ar] 4s²'dir; [Ar] iç 18 elektronu, 4s² ise kalan 2 değerlik elektronunu gösterir."},{"q":"Aufbau, Pauli ve Hund kurallarının her birinin elektron yerleşimindeki görevini tek bir örnekle (karbon, Z = 6) açıklayınız.","fig":"<svg viewBox='0 0 320 100'><text x='30' y='25' font-size='10' fill='#1a2b45'>1s</text><rect x='55' y='12' width='28' height='22' fill='none' stroke='#1a2b45' stroke-width='1.2'/><line x1='64' y1='30' x2='64' y2='16' stroke='#2b6be0' stroke-width='1.8'/><line x1='74' y1='16' x2='74' y2='30' stroke='#e0552b' stroke-width='1.8'/><text x='30' y='60' font-size='10' fill='#1a2b45'>2s</text><rect x='55' y='47' width='28' height='22' fill='none' stroke='#1a2b45' stroke-width='1.2'/><line x1='64' y1='65' x2='64' y2='51' stroke='#2b6be0' stroke-width='1.8'/><line x1='74' y1='51' x2='74' y2='65' stroke='#e0552b' stroke-width='1.8'/><text x='110' y='60' font-size='10' fill='#1a2b45'>2p</text><rect x='135' y='47' width='24' height='22' fill='none' stroke='#1a2b45' stroke-width='1.2'/><rect x='163' y='47' width='24' height='22' fill='none' stroke='#1a2b45' stroke-width='1.2'/><rect x='191' y='47' width='24' height='22' fill='none' stroke='#1a2b45' stroke-width='1.2'/><line x1='147' y1='65' x2='147' y2='51' stroke='#2b6be0' stroke-width='1.8'/><line x1='175' y1='65' x2='175' y2='51' stroke='#2b6be0' stroke-width='1.8'/></svg>","steps":[{"t":"Aufbau","a":"sıra: 1s 2s 2p","d":"Karbonun 6 elektronu en düşük enerjiden başlayarak 1s, 2s, 2p sırasıyla yerleşir: 1s² 2s² 2p²."},{"t":"Pauli","a":"zıt spin","d":"1s ve 2s orbitallerindeki ikişer elektron zıt spinlidir (↑↓); hiçbir orbitalde dört sayı aynı değildir."},{"t":"Hund","a":"2p² ayrı ayrı","d":"Son iki elektron 2p'de eşleşmez; iki ayrı orbitale paralel spinle (↑ ↑) yerleşir."}],"ans":"Karbon (1s² 2s² 2p²): Aufbau dolma sırasını (1s→2s→2p), Pauli orbitallerdeki zıt spinli ikilileri, Hund ise 2p²'nin iki ayrı orbitale paralel yerleşmesini belirler."}]}},"baglar":{"ilkokul":{"kolay":[{"q":"Atomlar neden tek başına durmak yerine birbirine tutunur?","steps":[{"t":"Yalnız atom","a":"kararsız","d":"Çoğu atom tek başına rahat değildir, daha sağlam bir yapıya geçmek ister."},{"t":"Tutunma","a":"birleşir","d":"Atomlar birbirine tutunarak daha kararlı ve dayanıklı bir yapı oluşturur."}],"ans":"Atomlar daha kararlı (sağlam) bir yapıya ulaşmak için birbirine tutunur, yani bağ kurar."},{"q":"İki atomun birleşip oluşturduğu yeni yapıya ne denir?","steps":[{"t":"Birleşme","a":"atomlar yan yana","d":"İki ya da daha çok atom bir araya gelip tutunur."},{"t":"Yeni yapı","a":"molekül","d":"Birbirine bağlı bu atom topluluğuna molekül denir."}],"ans":"Birbirine bağlanan atomların oluşturduğu yapıya molekül denir."},{"q":"Su molekülünde kaç çeşit atom birleşmiştir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='90' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='95' font-size='14' text-anchor='middle' fill='#1a2b45'>O</text><circle cx='110' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='60' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>H</text><line x1='133' y1='75' x2='128' y2='68' stroke='#1a2b45' stroke-width='2'/><line x1='187' y1='75' x2='192' y2='68' stroke='#1a2b45' stroke-width='2'/><text x='160' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>su (H₂O)</text></svg>","steps":[{"t":"Atomlar","a":"hidrojen ve oksijen","d":"Su molekülünde hidrojen (H) ve oksijen (O) atomları bulunur."},{"t":"Sayı","a":"iki çeşit","d":"İki farklı çeşit atom (H ve O) birleşerek suyu oluşturur."}],"ans":"Su molekülünde hidrojen ve oksijen olmak üzere iki çeşit atom birleşmiştir."},{"q":"Atomlar bağ kurarken hangi küçük tanecikleri kullanır?","steps":[{"t":"Dış tanecik","a":"elektron","d":"Atomun en dışındaki elektronlar bağ kurmada rol oynar."},{"t":"Paylaşım","a":"elektronlarla","d":"Atomlar bu dış elektronları vererek, alarak ya da paylaşarak tutunur."}],"ans":"Atomlar bağ kurarken en dıştaki elektronlarını kullanır."},{"q":"Tuz (yemek tuzu) hangi iki atomun birleşmesiyle oluşur?","steps":[{"t":"Birinci atom","a":"sodyum","d":"Yemek tuzunda sodyum (Na) atomu bulunur."},{"t":"İkinci atom","a":"klor","d":"Sodyum, klor (Cl) atomu ile birleşerek tuzu (NaCl) oluşturur."}],"ans":"Yemek tuzu, sodyum (Na) ve klor (Cl) atomlarının birleşmesiyle oluşur."}],"zor":[{"q":"Bir atom dış elektronlarını tamamladığında ne kazanır?","steps":[{"t":"Tam dolu dış","a":"kararlı","d":"En dış katmanı dolduğunda atom daha sağlam, kararlı bir yapıya ulaşır."},{"t":"Bağ kurar","a":"birleşerek","d":"Bunu çoğu zaman başka atomlarla birleşip elektron paylaşarak ya da alıp vererek başarır."}],"ans":"Dış elektronlarını tamamlayan atom kararlı (sağlam) bir yapı kazanır."},{"q":"Neden iki hidrojen atomu birleşip H₂ oluşturur?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='80' r='24' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><line x1='144' y1='80' x2='176' y2='80' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>H₂</text></svg>","steps":[{"t":"Tek H zayıf","a":"yalnız kalmaz","d":"Tek bir hidrojen atomu kararlı değildir, eşleşmek ister."},{"t":"Paylaşım","a":"elektron ortak","d":"İki hidrojen elektronlarını paylaşarak birlikte daha kararlı bir yapı (H₂) kurar."}],"ans":"İki hidrojen atomu elektronlarını paylaşıp daha kararlı olduğu için birleşip H₂ oluşturur."},{"q":"Bir atom elektron verir, diğeri alırsa nasıl bir bağ oluşur?","steps":[{"t":"Veren ve alan","a":"aktarım","d":"Bir atom elektronunu verir, diğer atom bu elektronu alır."},{"t":"Çekim","a":"zıt yükler","d":"Veren atom artı, alan atom eksi yüklenir; zıt yükler birbirini çeker ve bağ oluşur."}],"ans":"Bir atomun elektron verip diğerinin alması, zıt yüklerin birbirini çektiği bir bağ oluşturur."},{"q":"Aynı atomlar mı yoksa farklı atomlar mı bir araya gelebilir, örnek ver?","steps":[{"t":"Aynı atomlar","a":"O₂ gibi","d":"Aynı çeşit atomlar birleşebilir; örneğin iki oksijen birleşip O₂ olur."},{"t":"Farklı atomlar","a":"H₂O gibi","d":"Farklı atomlar da birleşebilir; hidrojen ve oksijen birleşip suyu (H₂O) oluşturur."}],"ans":"Hem aynı (O₂) hem farklı (H₂O) atomlar bir araya gelip bağ kurabilir."},{"q":"Soy gazlar neden başka atomlarla kolayca birleşmez?","steps":[{"t":"Dış katman","a":"zaten dolu","d":"Helyum, neon gibi soy gazların en dış katmanı zaten doludur."},{"t":"İhtiyaç yok","a":"kararlı","d":"Dış katmanları dolu olduğu için kararlıdırlar, başka atomla birleşmeye ihtiyaç duymazlar."}],"ans":"Soy gazların dış katmanı zaten dolu ve kararlı olduğundan başka atomlarla kolayca birleşmezler."}]},"ortaokul":{"kolay":[{"q":"Atomların bağ kurmasının temel amacı nedir?","steps":[{"t":"Kararsızlık","a":"dış katman eksik","d":"Çoğu atomun en dış katmanı (değerlik katmanı) tam dolu değildir, bu durum kararsızdır."},{"t":"Kararlı yapı","a":"dış katmanı tamamlamak","d":"Atom elektron alıp vererek ya da paylaşarak dış katmanını tamamlar ve kararlı hale gelir."}],"ans":"Atomlar, en dış katmanını tamamlayıp kararlı hale gelmek için bağ kurar."},{"q":"Soy gaz (kararlı) elektron düzeni ne demektir?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='90' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='90' r='34' fill='none' stroke='#1a2b45'/><circle cx='160' cy='56' r='5' fill='#2b6be0'/><circle cx='194' cy='90' r='5' fill='#2b6be0'/><circle cx='160' cy='124' r='5' fill='#2b6be0'/><circle cx='126' cy='90' r='5' fill='#2b6be0'/><text x='160' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>dolu son katman</text></svg>","steps":[{"t":"Dolu katman","a":"8 (veya 2) elektron","d":"Son katmanında 8 elektron (ilk katmanda 2) bulunan düzen kararlıdır."},{"t":"Soy gaz benzeri","a":"hedef yapı","d":"Atomlar bağ kurarken en yakın soy gazın bu dolu düzenine ulaşmaya çalışır."}],"ans":"Soy gaz düzeni, son katmanın 8 (ilk katmanda 2) elektronla tam dolu olduğu kararlı elektron dizilimidir."},{"q":"İyonik bağ hangi tür atomlar arasında oluşur?","steps":[{"t":"Taraflar","a":"metal + ametal","d":"İyonik bağ, bir metal ile bir ametal atom arasında oluşur."},{"t":"Elektron aktarımı","a":"ver-al","d":"Metal elektron verir (+ yüklenir), ametal elektron alır (− yüklenir); zıt iyonlar çekilir."}],"ans":"İyonik bağ, metal ile ametal arasında elektron aktarımıyla oluşur."},{"q":"Kovalent bağ nasıl kurulur?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='200' cy='80' r='26' fill='#cfd8e8' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='152' cy='80' r='5' fill='#2b6be0'/><circle cx='168' cy='80' r='5' fill='#2b6be0'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>ortak elektron çifti</text></svg>","steps":[{"t":"Taraflar","a":"ametal + ametal","d":"Kovalent bağ genellikle iki ametal atom arasında oluşur."},{"t":"Paylaşım","a":"elektron ortaklığı","d":"Atomlar elektronlarını alıp vermek yerine ortak kullanarak (paylaşarak) bağ kurar."}],"ans":"Kovalent bağ, iki ametal atomun elektronlarını ortaklaşa kullanmasıyla kurulur."},{"q":"NaCl bileşiğinde sodyum ve klorun yükleri ne olur?","steps":[{"t":"Sodyum","a":"Na⁺","d":"Sodyum 1 elektron vererek Na⁺ (artı yüklü) iyona dönüşür."},{"t":"Klor","a":"Cl⁻","d":"Klor bu elektronu alarak Cl⁻ (eksi yüklü) iyona dönüşür."}],"ans":"NaCl'de sodyum Na⁺, klor ise Cl⁻ yüküne sahip olur."}],"zor":[{"q":"Bir atomun kaç elektron alıp vereceğini ne belirler?","steps":[{"t":"Değerlik elektronu","a":"son katman sayısı","d":"En dış katmandaki (değerlik) elektron sayısı atomun davranışını belirler."},{"t":"Hedef düzen","a":"oktete ulaşmak","d":"Atom, son katmanı 8'e (oktet) tamamlamak için kaç elektrona ihtiyacı varsa o kadar alıp verir veya paylaşır."}],"ans":"Atomun son katmanındaki elektron sayısı, oktete ulaşmak için kaç elektron alıp vereceğini belirler."},{"q":"İyonik bağlı bileşikler neden yüksek erime noktasına sahiptir?","steps":[{"t":"Güçlü çekim","a":"zıt iyon ağı","d":"İyonik katıda artı ve eksi iyonlar düzenli bir ağ (örgü) içinde güçlü çekimle tutulur."},{"t":"Çok enerji","a":"erimesi zor","d":"Bu güçlü çekimleri kırıp eritmek için yüksek sıcaklık (çok enerji) gerekir."}],"ans":"İyonik bileşiklerde zıt iyonlar arası çekim çok güçlü olduğundan erime noktaları yüksektir."},{"q":"O₂ molekülündeki bağ tek bağ mıdır, açıklayın?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='120' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='200' cy='80' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='200' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><line x1='148' y1='72' x2='172' y2='72' stroke='#1a2b45' stroke-width='3'/><line x1='148' y1='88' x2='172' y2='88' stroke='#1a2b45' stroke-width='3'/><text x='160' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>O=O çift bağ</text></svg>","steps":[{"t":"İhtiyaç","a":"2 elektron","d":"Her oksijen oktete ulaşmak için 2 elektron paylaşmalıdır."},{"t":"Çift bağ","a":"iki ortak çift","d":"Bu yüzden iki oksijen, iki ortak elektron çifti paylaşır; bu bir çift bağdır (O=O)."}],"ans":"Hayır; O₂'de oksijenler iki elektron çifti paylaştığı için aralarında çift bağ (O=O) vardır."},{"q":"Polar ve apolar kovalent bağ arasındaki fark nedir?","steps":[{"t":"Apolar","a":"eşit paylaşım","d":"Aynı ya da çekim gücü eşit atomlar elektronu eşit paylaşırsa bağ apolardır (örneğin H₂)."},{"t":"Polar","a":"eşitsiz paylaşım","d":"Bir atom elektronu daha güçlü çekerse ortak çift ona kayar, bağ polar olur (örneğin H–Cl)."}],"ans":"Apolar bağda elektronlar eşit, polar bağda ise bir atoma daha yakın (eşitsiz) paylaşılır."},{"q":"Metalik bağ diğer bağlardan hangi yönüyle ayrılır?","steps":[{"t":"Serbest elektron","a":"elektron denizi","d":"Metal atomları değerlik elektronlarını ortak bir 'elektron denizine' bırakır."},{"t":"Hareketli e⁻","a":"iletkenlik","d":"Bu serbest elektronlar tüm yapıda gezdiği için metaller elektriği ve ısıyı iyi iletir."}],"ans":"Metalik bağda değerlik elektronları serbestçe dolaşan bir 'elektron denizi' oluşturur; bu, metallere iletkenlik kazandırır."}]},"lise":{"kolay":[{"q":"Oktet kuralı nedir ve atomların bağ kurmasıyla nasıl ilişkilidir?","steps":[{"t":"Kural","a":"son katman 8","d":"Atomlar son katmanlarında 8 elektron (soy gaz düzeni) bulundurmaya eğilimlidir."},{"t":"Bağ ile ulaşma","a":"al-ver-paylaş","d":"Atom oktete ulaşmak için elektron alır, verir veya paylaşır; bu da bağ oluşumunu sağlar."}],"ans":"Oktet kuralı, atomların son katmanını 8 elektrona tamamlama eğilimidir; atomlar bunu bağ kurarak gerçekleştirir."},{"q":"İyonik bağ oluşumunu Na ve Cl üzerinden açıklayınız.","fig":"<svg viewBox='0 0 320 175'><circle cx='95' cy='85' r='28' fill='#cfd8e8' stroke='#1a2b45'/><text x='95' y='90' font-size='13' text-anchor='middle' fill='#1a2b45'>Na</text><circle cx='225' cy='85' r='28' fill='#9ed9a8' stroke='#1a2b45'/><text x='225' y='90' font-size='13' text-anchor='middle' fill='#1a2b45'>Cl</text><line x1='124' y1='85' x2='194' y2='85' stroke='#2b6be0' stroke-width='2'/><polygon points='194,85 184,80 184,90' fill='#2b6be0'/><text x='159' y='72' font-size='10' text-anchor='middle' fill='#1a2b45'>e⁻ aktarımı</text><text x='159' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>Na⁺ + Cl⁻ → NaCl</text></svg>","steps":[{"t":"Elektron aktarımı","a":"Na → Cl","d":"Sodyum son katmanındaki 1 elektronu klora aktarır; Na⁺ ve Cl⁻ iyonları oluşur."},{"t":"Elektrostatik çekim","a":"zıt yük","d":"Zıt yüklü Na⁺ ve Cl⁻ iyonları arasındaki elektrostatik çekim iyonik bağı oluşturur."}],"ans":"Na bir elektronunu Cl'a aktarır; oluşan Na⁺ ve Cl⁻ iyonları elektrostatik çekimle iyonik bağ kurar (NaCl)."},{"q":"Kovalent bağda bağ polaritesini ne belirler?","steps":[{"t":"Elektronegatiflik","a":"çekim gücü","d":"Bağ polaritesini atomların elektronegatiflik (ortak elektronu çekme gücü) farkı belirler."},{"t":"Fark etkisi","a":"büyük fark = polar","d":"Elektronegatiflik farkı büyüdükçe ortak çift bir atoma kayar ve bağ daha polar olur."}],"ans":"Kovalent bağda polariteyi atomların elektronegatiflik farkı belirler; fark büyüdükçe bağ polarlaşır."},{"q":"H₂O molekülünün polar olmasının nedeni nedir?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='80' r='26' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='85' font-size='13' text-anchor='middle' fill='#fff'>O</text><circle cx='110' cy='130' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='110' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='210' cy='130' r='16' fill='#cfd8e8' stroke='#1a2b45'/><text x='210' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='142' y1='98' x2='120' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='178' y1='98' x2='200' y2='118' stroke='#1a2b45' stroke-width='2'/><text x='160' y='40' font-size='11' text-anchor='middle' fill='#1a2b45'>δ⁻</text><text x='95' y='160' font-size='11' fill='#1a2b45'>δ⁺</text><text x='215' y='160' font-size='11' fill='#1a2b45'>δ⁺</text></svg>","steps":[{"t":"Polar bağ","a":"O–H","d":"Oksijen hidrojenden daha elektronegatiftir; her O–H bağı polardır ve oksijen kısmi eksi (δ⁻) yüklenir."},{"t":"Açısal geometri","a":"dipoller toplanır","d":"Molekül açısal (~104,5°) olduğu için bağ dipolleri birbirini götürmez, net bir dipol oluşur."}],"ans":"H₂O'da polar O–H bağları açısal geometride birbirini götürmediği için molekül net dipole sahiptir, yani polardır."},{"q":"Metalik bağ metallerin hangi fiziksel özelliklerini açıklar?","steps":[{"t":"Serbest elektronlar","a":"elektron denizi","d":"Metalik bağda değerlik elektronları kafes içinde serbestçe hareket eden bir 'elektron denizi' oluşturur."},{"t":"Özellikler","a":"iletkenlik, işlenebilirlik","d":"Hareketli elektronlar elektrik/ısı iletkenliğini; katmanların kayabilmesi dövülebilirlik ve tel haline gelmeyi sağlar."}],"ans":"Metalik bağdaki serbest elektronlar metallerin elektrik-ısı iletkenliğini, dövülebilirliğini ve parlaklığını açıklar."}],"zor":[{"q":"NH₃ molekülünde merkez azot atomunun bağ yapısını ve ortaklanmamış çiftini açıklayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='26' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='85' font-size='13' text-anchor='middle' fill='#fff'>N</text><circle cx='100' cy='130' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='100' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='160' cy='145' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='130' r='15' fill='#cfd8e8' stroke='#1a2b45'/><text x='220' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>H</text><line x1='142' y1='95' x2='110' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='106' x2='160' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='178' y1='95' x2='210' y2='120' stroke='#1a2b45' stroke-width='2'/><circle cx='152' cy='52' r='3' fill='#2b6be0'/><circle cx='168' cy='52' r='3' fill='#2b6be0'/><text x='160' y='40' font-size='9' text-anchor='middle' fill='#1a2b45'>ortaklanmamış çift</text></svg>","steps":[{"t":"Bağ sayısı","a":"3 N–H bağı","d":"Azotun 5 değerlik elektronundan 3'ü, üç hidrojenle birer ortak çift oluşturur (3 kovalent bağ)."},{"t":"Ortaklanmamış çift","a":"1 çift kalır","d":"Geri kalan 2 elektron, azotta ortaklanmamış (yalnız) çift olarak kalır ve molekülü üçgen piramit yapar."}],"ans":"NH₃'te azot üç hidrojenle 3 kovalent bağ kurar; üzerinde kalan 1 ortaklanmamış çift molekülü üçgen piramit yapar."},{"q":"Aynı atom sayısına sahip CO₂ apolar, H₂O polarken bunun nedeni nedir?","steps":[{"t":"Bağ dipolleri","a":"ikisinde de polar bağ","d":"Hem CO₂ hem H₂O polar bağlar içerir; fark molekül geometrisindedir."},{"t":"Geometri etkisi","a":"doğrusal vs açısal","d":"CO₂ doğrusal olduğundan zıt yönlü bağ dipolleri birbirini götürür (net dipol sıfır); H₂O açısal olduğundan dipoller toplanır."}],"ans":"CO₂ doğrusal geometride bağ dipollerini götürdüğü için apolar; H₂O açısal geometride dipoller toplandığı için polardır."},{"q":"Hidrojen bağı nedir ve suyun yüksek kaynama noktasını nasıl açıklar?","fig":"<svg viewBox='0 0 320 175'><circle cx='90' cy='70' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='75' font-size='11' text-anchor='middle' fill='#fff'>O</text><circle cx='130' cy='100' r='12' fill='#cfd8e8' stroke='#1a2b45'/><text x='130' y='104' font-size='9' text-anchor='middle' fill='#1a2b45'>H</text><circle cx='220' cy='120' r='20' fill='#e0552b' stroke='#1a2b45'/><text x='220' y='125' font-size='11' text-anchor='middle' fill='#fff'>O</text><line x1='140' y1='105' x2='205' y2='118' stroke='#2b6be0' stroke-width='2' stroke-dasharray='4 3'/><text x='175' y='100' font-size='9' text-anchor='middle' fill='#1a2b45'>hidrojen bağı</text></svg>","steps":[{"t":"Tanım","a":"H ile F/O/N çekimi","d":"Hidrojen bağı; bir moleküldeki kısmi artı H'nin, komşu molekülün elektronegatif O/N/F atomuyla yaptığı güçlü çekimdir."},{"t":"Kaynama etkisi","a":"ekstra enerji","d":"Su molekülleri arası hidrojen bağlarını koparmak fazladan enerji gerektirdiğinden kaynama noktası beklenenden yüksektir."}],"ans":"Hidrojen bağı, kısmi artı H ile komşu O/N/F arası güçlü çekimdir; bu bağları koparmak ek enerji gerektirdiğinden suyun kaynama noktası yüksektir."},{"q":"Bir kovalent bağın σ (sigma) mı π (pi) mı olduğunu ne belirler ve çift bağda dağılım nasıldır?","steps":[{"t":"Örtüşme türü","a":"eksenel vs yanal","d":"Orbitaller bağ ekseni boyunca uç uca örtüşürse σ, yanal örtüşürse π bağı oluşur."},{"t":"Çift bağ dağılımı","a":"1 σ + 1 π","d":"Çift bağ bir σ ve bir π bağından; üçlü bağ ise bir σ ve iki π bağından oluşur."}],"ans":"Eksenel (uç uca) örtüşme σ, yanal örtüşme π bağı verir; çift bağ 1 σ + 1 π, üçlü bağ 1 σ + 2 π şeklindedir."},{"q":"İyonik ve kovalent bileşiklerin elektrik iletkenliği neden farklıdır?","steps":[{"t":"İyonik","a":"erimiş/çözeltide iletir","d":"İyonik bileşikler katı halde iletmez; ancak eridiğinde veya suda çözündüğünde serbest iyonlar yükü taşır."},{"t":"Kovalent","a":"genelde iletmez","d":"Kovalent (moleküler) bileşiklerde serbest iyon/elektron olmadığından genellikle elektriği iletmezler."}],"ans":"İyonik bileşikler eriyik/çözeltide serbest iyonlarla iletir; kovalent bileşiklerde yük taşıyıcı serbest iyon olmadığından genelde iletmezler."}]}},"bohrModeli":{"ilkokul":{"kolay":[{"q":"Bohr'a göre elektronlar çekirdeğin etrafında nasıl dolaşır?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='88' r='11' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='88' r='34' fill='none' stroke='#1a2b45'/><circle cx='160' cy='88' r='60' fill='none' stroke='#1a2b45'/><circle cx='194' cy='88' r='5' fill='#2b6be0'/><circle cx='160' cy='28' r='5' fill='#2b6be0'/><text x='160' y='168' font-size='11' text-anchor='middle' fill='#1a2b45'>belirli halkalarda döner</text></svg>","steps":[{"t":"Halka yollar","a":"yörünge","d":"Bohr'a göre elektronlar çekirdeğin etrafındaki belirli halkalar (yörüngeler) üzerinde döner."},{"t":"Düzenli","a":"karışmaz","d":"Gezegenlerin Güneş'in etrafında dönmesi gibi, her elektron kendi halkasında düzenli döner."}],"ans":"Bohr'a göre elektronlar çekirdeğin etrafında belirli halkalarda (yörüngelerde) düzenli döner."},{"q":"Bohr modelinde elektronların döndüğü halkalara ne ad verilir?","steps":[{"t":"Halkanın adı","a":"katman (yörünge)","d":"Elektronların döndüğü her halkaya katman ya da enerji düzeyi denir."},{"t":"Basamak gibi","a":"sıralı","d":"Katmanlar çekirdekten dışa doğru basamak basamak sıralanır."}],"ans":"Elektronların döndüğü halkalara katman (yörünge) denir."},{"q":"Çekirdeğe en yakın katmanda mı yoksa en uzakta mı daha az enerji vardır?","steps":[{"t":"Yakın katman","a":"az enerji","d":"Çekirdeğe en yakın katmandaki elektron en düşük enerjiye sahiptir."},{"t":"Uzak katman","a":"çok enerji","d":"Çekirdekten uzaklaştıkça katmanın enerjisi artar."}],"ans":"Çekirdeğe en yakın katmanda enerji en azdır; uzaklaştıkça enerji artar."},{"q":"Bohr modeli atomu neye benzetir?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='88' r='13' fill='#f4d03f' stroke='#1a2b45'/><circle cx='160' cy='88' r='40' fill='none' stroke='#1a2b45'/><circle cx='160' cy='88' r='66' fill='none' stroke='#1a2b45'/><circle cx='200' cy='88' r='5' fill='#2b6be0'/><circle cx='160' cy='22' r='5' fill='#2b6be0'/><text x='160' y='168' font-size='11' text-anchor='middle' fill='#1a2b45'>Güneş ve gezegenler gibi</text></svg>","steps":[{"t":"Güneş","a":"çekirdek","d":"Ortadaki çekirdek, Güneş gibi merkezdedir."},{"t":"Gezegenler","a":"elektronlar","d":"Elektronlar da gezegenler gibi belirli yollarda çekirdeğin etrafında döner."}],"ans":"Bohr modeli atomu, Güneş'in etrafında dönen gezegenlere benzetir."},{"q":"Elektron kendi katmanında dönerken enerji kaybeder mi?","steps":[{"t":"Kendi yolunda","a":"kararlı","d":"Elektron kendi katmanında dönerken kararlıdır."},{"t":"Sonuç","a":"kaybetmez","d":"Bu sırada enerji kaybetmez, sürekli aynı yolda döner."}],"ans":"Hayır; elektron kendi katmanında dönerken enerji kaybetmez, kararlıdır."}],"zor":[{"q":"Bohr modeline göre bir elektron neden çekirdeğe düşmez?","steps":[{"t":"Belirli yörünge","a":"izinli yol","d":"Elektron yalnız belirli izinli yörüngelerde durabilir; arada duramaz."},{"t":"Enerji yaymaz","a":"kararlı kalır","d":"Bu yörüngelerde enerji yaymadığı için yavaşlayıp çekirdeğe düşmez."}],"ans":"Elektron belirli izinli yörüngelerde enerji yaymadan kararlı kaldığı için çekirdeğe düşmez."},{"q":"K katmanı ile L katmanı arasındaki fark nedir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='11' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='90' r='32' fill='none' stroke='#1a2b45'/><circle cx='160' cy='90' r='60' fill='none' stroke='#1a2b45'/><text x='160' y='62' font-size='11' text-anchor='middle' fill='#1a2b45'>K</text><text x='160' y='34' font-size='11' text-anchor='middle' fill='#1a2b45'>L</text></svg>","steps":[{"t":"K katmanı","a":"en içte","d":"K katmanı çekirdeğe en yakın, en düşük enerjili katmandır."},{"t":"L katmanı","a":"bir dışta","d":"L katmanı K'nin hemen dışındadır ve daha yüksek enerjilidir."}],"ans":"K katmanı çekirdeğe en yakın ve düşük enerjili, L katmanı ise bir dış katman ve daha yüksek enerjilidir."},{"q":"Her katmanın belirli sayıda elektron alması ne anlama gelir?","steps":[{"t":"Sınırlı yer","a":"belirli sayı","d":"Her katman ancak belirli sayıda elektron taşıyabilir (K en fazla 2, L en fazla 8 gibi)."},{"t":"Önce iç dolar","a":"sıralı dolma","d":"Elektronlar önce çekirdeğe yakın iç katmanları doldurur, sonra dış katmanlara geçer."}],"ans":"Her katmanın taşıyabileceği elektron sayısı sınırlıdır ve elektronlar önce iç katmanları doldurur."},{"q":"Bohr modeli, kendinden önceki Rutherford modeline göre hangi yeniliği getirdi?","steps":[{"t":"Rutherford","a":"çekirdek + boşluk","d":"Rutherford çekirdeği buldu ama elektronların nasıl döndüğünü tam açıklayamadı."},{"t":"Bohr","a":"belirli katman","d":"Bohr, elektronların belirli enerjili katmanlarda kararlı döndüğünü ekledi."}],"ans":"Bohr, elektronların belirli enerjili katmanlarda düzenli döndüğünü açıklayarak Rutherford modelini geliştirdi."},{"q":"Bir atomun ışık yayması Bohr modeline göre nasıl olur?","steps":[{"t":"Üst katmana çık","a":"enerji al","d":"Elektron enerji alıp üst (daha uzak) bir katmana çıkar."},{"t":"Geri dön","a":"ışık ver","d":"Geri alt katmana inerken aldığı enerjiyi ışık olarak dışarı verir."}],"ans":"Elektron enerji alıp üst katmana çıkar, geri inerken bu enerjiyi ışık olarak yayar."}]},"ortaokul":{"kolay":[{"q":"Bohr atom modelinin temel fikri nedir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='11' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='90' r='30' fill='none' stroke='#1a2b45'/><circle cx='160' cy='90' r='52' fill='none' stroke='#1a2b45'/><circle cx='160' cy='90' r='72' fill='none' stroke='#1a2b45'/><text x='160' y='176' font-size='10' text-anchor='middle' fill='#1a2b45'>belirli enerji düzeyleri</text></svg>","steps":[{"t":"Belirli düzeyler","a":"enerji katmanı","d":"Elektronlar yalnız belirli enerjili katmanlarda (yörüngelerde) bulunabilir."},{"t":"Kararlılık","a":"enerji yaymaz","d":"Elektron kendi katmanında dönerken enerji yaymaz, yani kararlıdır."}],"ans":"Bohr modeline göre elektronlar belirli enerjili katmanlarda kararlı şekilde döner ve bu katmanlarda enerji yaymaz."},{"q":"Bohr modelinde katmanlar nasıl adlandırılır ve hangisi en düşük enerjilidir?","steps":[{"t":"Adlandırma","a":"K, L, M, N","d":"Katmanlar çekirdekten dışa doğru K, L, M, N şeklinde adlandırılır."},{"t":"En düşük","a":"K katmanı","d":"Çekirdeğe en yakın olan K katmanı en düşük enerjiye sahiptir."}],"ans":"Katmanlar K, L, M, N olarak adlandırılır; çekirdeğe en yakın K katmanı en düşük enerjilidir."},{"q":"K, L ve M katmanları en fazla kaçar elektron alabilir?","steps":[{"t":"İç katmanlar","a":"K=2, L=8","d":"İlk katman K en fazla 2, ikinci katman L en fazla 8 elektron alır."},{"t":"M katmanı","a":"18 (ilk 8)","d":"Üçüncü katman M toplamda 18 alabilir; temel düzeyde ilk 8 elektronla dolması yeterlidir."}],"ans":"K katmanı en fazla 2, L katmanı 8, M katmanı toplamda 18 elektron alabilir."},{"q":"Bir elektron üst katmana çıkmak için ne yapmalıdır?","steps":[{"t":"Enerji gerekli","a":"enerji al","d":"Üst (daha uzak) katmana çıkmak için elektronun dışarıdan enerji alması gerekir."},{"t":"Sıçrama","a":"belirli miktar","d":"Bu enerji rastgele değildir; iki katmanın enerji farkı kadar belirli bir miktar olmalıdır."}],"ans":"Bir elektron üst katmana çıkmak için iki katman arasındaki fark kadar belirli bir enerji almalıdır."},{"q":"Bohr modeline göre 'enerji düzeyi' ne demektir?","steps":[{"t":"Belirli enerji","a":"sabit değer","d":"Her katmanın belirli, sabit bir enerji değeri vardır; elektron orada bu enerjiyle bulunur."},{"t":"Ara değer yok","a":"basamak gibi","d":"Elektron iki katman arasında ara bir enerjide bulunamaz; enerji basamaklar gibi belirlidir."}],"ans":"Enerji düzeyi, bir katmanın sahip olduğu belirli ve sabit enerjidir; elektron ancak bu düzeylerde bulunabilir."}],"zor":[{"q":"Bohr modeli, Rutherford modelindeki hangi soruna çözüm getirmiştir?","steps":[{"t":"Rutherford sorunu","a":"kararsızlık","d":"Rutherford modelinde dönen elektronun sürekli enerji kaybedip çekirdeğe düşmesi beklenir; atom kararsız görünür."},{"t":"Bohr çözümü","a":"kararlı düzey","d":"Bohr, belirli enerji düzeylerinde elektronun enerji yaymadan kararlı kaldığını öne sürerek bu sorunu çözdü."}],"ans":"Bohr, belirli enerji düzeylerinde elektronun enerji yaymadığını söyleyerek Rutherford modelinin kararsızlık sorununu çözmüştür."},{"q":"Elektronların enerji düzeylerinin 'kuantlı (kesikli)' olması ne demektir?","fig":"<svg viewBox='0 0 320 175'><line x1='70' y1='140' x2='250' y2='140' stroke='#1a2b45'/><line x1='70' y1='105' x2='250' y2='105' stroke='#1a2b45'/><line x1='70' y1='70' x2='250' y2='70' stroke='#1a2b45'/><line x1='70' y1='40' x2='250' y2='40' stroke='#1a2b45'/><circle cx='160' cy='140' r='5' fill='#2b6be0'/><text x='270' y='144' font-size='10' fill='#1a2b45'>n=1</text><text x='270' y='74' font-size='10' fill='#1a2b45'>n=3</text><text x='160' y='165' font-size='10' text-anchor='middle' fill='#1a2b45'>basamaklı enerji</text></svg>","steps":[{"t":"Belirli değerler","a":"sadece izinli","d":"Elektronun enerjisi yalnız belirli (izinli) değerler alabilir, aradaki değerler yasaktır."},{"t":"Merdiven gibi","a":"ara basamak yok","d":"Bu durum merdivene benzer; ancak basamaklarda durabilir, basamaklar arasında bir yerde duramaz."}],"ans":"Kuantlı olması, elektron enerjisinin yalnız belirli izinli değerler alabilmesi, aradaki değerlerin yasak olması demektir (merdiven basamağı gibi)."},{"q":"Bohr modeline göre bir elektron L katmanından K katmanına inerken ne olur?","steps":[{"t":"Daha düşük düzey","a":"enerji azalır","d":"K katmanı L'den daha düşük enerjilidir; elektron alt düzeye inerken fazla enerjisinden kurtulur."},{"t":"Enerji yayımı","a":"ışık (foton)","d":"Aradaki enerji farkı, belirli renkte bir ışık (foton) olarak dışarı yayılır."}],"ans":"Elektron L'den K'ye inerken aradaki enerji farkını belirli renkte bir ışık (foton) olarak yayar."},{"q":"Bohr modelinin temel bir eksikliği nedir?","steps":[{"t":"Tek elektron sınırı","a":"sadece hidrojen","d":"Bohr modeli yalnız hidrojen gibi tek elektronlu atomları doğru açıklar."},{"t":"Çok elektron sorunu","a":"yetersiz","d":"Birden çok elektronu olan atomların davranışını ve spektrumunu tam açıklayamaz."}],"ans":"Bohr modeli yalnız tek elektronlu (hidrojen gibi) atomlarda işler; çok elektronlu atomları açıklamakta yetersizdir."},{"q":"Bir atomun elektron dizilimi 2,8,1 ise bu Bohr modeline göre neyi gösterir?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='92' r='11' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='30' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='52' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='74' fill='none' stroke='#1a2b45'/><text x='160' y='66' font-size='9' text-anchor='middle' fill='#1a2b45'>2</text><text x='160' y='44' font-size='9' text-anchor='middle' fill='#1a2b45'>8</text><text x='160' y='180' font-size='10' text-anchor='middle' fill='#1a2b45'>2,8,1 dizilimi</text></svg>","steps":[{"t":"Katman doluluğu","a":"K=2, L=8","d":"İlk katmanda 2, ikinci katmanda 8 elektron vardır; bu iki katman tam doludur."},{"t":"Son katman","a":"1 elektron","d":"Üçüncü (son) katmanda 1 elektron vardır; bu, atomun toplam 11 elektronu olduğunu (sodyum) gösterir."}],"ans":"2,8,1 dizilimi K ve L katmanlarının dolu, son katmanda 1 elektron olduğunu (toplam 11 elektronlu sodyum) gösterir."}]},"lise":{"kolay":[{"q":"Bohr atom modelinin temel varsayımları nelerdir?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='92' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='28' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='50' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='72' fill='none' stroke='#1a2b45'/><text x='160' y='180' font-size='10' text-anchor='middle' fill='#1a2b45'>kararlı, kuantlı enerji düzeyleri</text></svg>","steps":[{"t":"Kararlı yörünge","a":"belirli enerji","d":"Elektron yalnız belirli (kuantlı) enerjili yörüngelerde bulunur ve bu yörüngelerde enerji yaymaz."},{"t":"Geçişte foton","a":"al/ver","d":"Elektron bir düzeyden diğerine geçerken iki düzeyin enerji farkı kadar foton soğurur veya yayar."}],"ans":"Bohr'a göre elektron belirli kararlı enerji düzeylerinde döner, bu düzeylerde enerji yaymaz ve ancak düzeyler arası geçişte foton alıp verir."},{"q":"Bohr modelinde enerji düzeylerinin kuantlanması ne anlama gelir?","steps":[{"t":"Ayrık değerler","a":"izinli enerjiler","d":"Elektronun enerjisi sürekli değil, yalnız belirli ayrık değerler (n=1, 2, 3...) alabilir."},{"t":"Sonuç","a":"ara değer yok","d":"İki izinli düzey arasında elektronun bulunabileceği bir enerji yoktur."}],"ans":"Kuantlanma, elektron enerjisinin yalnız belirli ayrık (izinli) değerler alabilmesi, ara değerlerin yasak olması demektir."},{"q":"Bohr modelinde temel hâl (taban durum) ile uyarılmış hâl arasındaki fark nedir?","steps":[{"t":"Temel hâl","a":"n=1, en kararlı","d":"Elektron en düşük enerjili düzeyde (n=1) bulunduğunda atom temel hâldedir ve en kararlıdır."},{"t":"Uyarılmış hâl","a":"üst düzey, kararsız","d":"Elektron enerji soğurup üst bir düzeye (n=2, 3...) çıktığında atom uyarılmış ve daha kararsız hâldedir."}],"ans":"Temel hâlde elektron en düşük (n=1) düzeydedir ve kararlıdır; uyarılmış hâlde enerji alıp üst düzeye çıkmış, kararsız hâldedir."},{"q":"Bohr modeli hangi deneysel gözlemi başarıyla açıklamıştır?","steps":[{"t":"Gözlem","a":"çizgi spektrumu","d":"Hidrojen gazı uyarıldığında yalnız belirli dalga boylarında kesikli ışık çizgileri yayar."},{"t":"Açıklama","a":"enerji geçişleri","d":"Bohr, bu çizgilerin elektronun belirli enerji düzeyleri arasında geçişiyle yayılan fotonlardan kaynaklandığını gösterdi."}],"ans":"Bohr modeli, hidrojenin kesikli çizgi spektrumunu elektronun enerji düzeyleri arası geçişleriyle başarıyla açıklamıştır."},{"q":"Bohr modeline göre yörünge yarıçapı arttıkça elektronun enerjisi nasıl değişir?","steps":[{"t":"Uzaklık etkisi","a":"yarıçap büyür","d":"n arttıkça (üst düzeylerde) elektronun çekirdekten uzaklığı, yani yörünge yarıçapı büyür."},{"t":"Enerji","a":"artar","d":"Çekirdeğe uzaklaştıkça elektronun enerjisi artar; düzeyler arası fark ise giderek azalır."}],"ans":"Yörünge yarıçapı (n) büyüdükçe elektronun enerjisi artar, ancak ardışık düzeyler arasındaki enerji farkı azalır."}],"zor":[{"q":"Bohr modeline göre hidrojen atomunda elektron n=3'ten n=2'ye geçerse ne tür bir olay gözlenir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='92' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='28' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='52' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='76' fill='none' stroke='#1a2b45'/><line x1='160' y1='16' x2='160' y2='44' stroke='#e0552b' stroke-width='2'/><polygon points='160,44 156,36 164,36' fill='#e0552b'/><text x='200' y='30' font-size='9' fill='#1a2b45'>n=3→n=2</text><text x='160' y='176' font-size='10' text-anchor='middle' fill='#1a2b45'>foton yayımı</text></svg>","steps":[{"t":"Alt düzeye iniş","a":"enerji açığa çıkar","d":"n=3 düzeyi n=2'den daha yüksek enerjilidir; elektron inerken fazla enerjisinden kurtulur."},{"t":"Foton yayımı","a":"belirli dalga boyu","d":"İki düzeyin enerji farkı (ΔE = E₃ − E₂) kadar enerji, belirli dalga boylu bir foton olarak yayılır ve görünür bölgede bir çizgi oluşturur."}],"ans":"Elektron n=3'ten n=2'ye inerken iki düzeyin enerji farkı kadar belirli dalga boylu bir foton (görünür çizgi) yayar; bu emisyondur."},{"q":"Bohr modeli çok elektronlu atomların spektrumunu neden tam açıklayamaz?","steps":[{"t":"Elektron etkileşimi","a":"itme kuvvetleri","d":"Çok elektronlu atomlarda elektronlar birbirini iter; Bohr modeli bu karşılıklı itmeleri hesaba katmaz."},{"t":"Sonuç","a":"sapma","d":"Bu yüzden hesaplanan enerji düzeyleri, gözlenen karmaşık spektrumla tam uyuşmaz."}],"ans":"Bohr modeli elektronlar arası itmeleri içermediği için çok elektronlu atomların karmaşık spektrumunu tam açıklayamaz."},{"q":"Bohr modelinin kabul ettiği 'kesin yörünge' varsayımı modern fizikle neden çelişir?","steps":[{"t":"Belirsizlik ilkesi","a":"konum + hız","d":"Heisenberg belirsizlik ilkesine göre elektronun konumu ve hızı (momentumu) aynı anda kesin ölçülemez."},{"t":"Çelişki","a":"yörünge anlamsız","d":"Konum ve hız birlikte kesin bilinemediğinden, elektronun çizgisel kesin bir yörüngesi olduğunu söylemek anlamını yitirir."}],"ans":"Heisenberg belirsizlik ilkesi konum ve hızın aynı anda kesin bilinemeyeceğini söylediğinden, Bohr'un kesin yörünge varsayımı modern fizikle çelişir."},{"q":"Bohr modeline göre enerji düzeyleri arasındaki fark üst düzeylere çıkıldıkça neden azalır?","fig":"<svg viewBox='0 0 320 180'><line x1='80' y1='150' x2='240' y2='150' stroke='#1a2b45'/><line x1='80' y1='95' x2='240' y2='95' stroke='#1a2b45'/><line x1='80' y1='60' x2='240' y2='60' stroke='#1a2b45'/><line x1='80' y1='42' x2='240' y2='42' stroke='#1a2b45'/><line x1='80' y1='33' x2='240' y2='33' stroke='#1a2b45'/><text x='255' y='154' font-size='9' fill='#1a2b45'>n=1</text><text x='255' y='37' font-size='9' fill='#1a2b45'>n=5</text><text x='160' y='172' font-size='10' text-anchor='middle' fill='#1a2b45'>üstte sıklaşır</text></svg>","steps":[{"t":"Enerji bağıntısı","a":"1/n² ile orantılı","d":"Düzey enerjisi yaklaşık 1/n² ile değişir; n büyüdükçe enerjideki değişim giderek yavaşlar."},{"t":"Sonuç","a":"düzeyler sıklaşır","d":"Bu nedenle üst düzeylere çıkıldıkça ardışık düzeyler birbirine yaklaşır ve aradaki enerji farkı azalır."}],"ans":"Düzey enerjisi 1/n² ile değiştiğinden n büyüdükçe düzeyler birbirine yaklaşır; bu yüzden üstlere çıkıldıkça enerji farkı azalır."},{"q":"Bohr modeli, klasik fiziğin hangi kuralını terk ederek atomun kararlılığını açıklamıştır?","steps":[{"t":"Klasik kural","a":"ivmeli yük ışır","d":"Klasik elektromanyetizmaya göre, çembersel hareket yapan (ivmeli) yüklü elektron sürekli ışıma yapıp enerji kaybetmelidir."},{"t":"Bohr varsayımı","a":"kararlı düzeyde ışımaz","d":"Bohr bu kuralı terk ederek, belirli izinli düzeylerde elektronun ışıma yapmadan kararlı kaldığını varsaydı."}],"ans":"Bohr, 'ivmeli yükün sürekli ışıması' klasik kuralını terk edip belirli düzeylerde elektronun ışımadan kararlı kaldığını varsayarak atomun kararlılığını açıkladı."}]}},"bohrSinirlilik":{"ilkokul":{"kolay":[{"q":"Bohr atom modeli, elektronları gezegenler gibi belirli halkalarda gösterir. Bu model bir oyuncak kadar basit olsa da her atom için yeterli midir?","fig":"<svg viewBox='0 0 200 180'><circle cx='100' cy='90' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='90' r='38' fill='none' stroke='#2b6be0'/><circle cx='100' cy='90' r='60' fill='none' stroke='#2b6be0'/><circle cx='138' cy='90' r='6' fill='#2b6be0'/><circle cx='100' cy='30' r='6' fill='#2b6be0'/></svg>","steps":[{"t":"Basit hidrojen","a":"tek elektron","d":"Bohr modeli, tek elektronu olan hidrojen atomunu çok iyi anlatır."},{"t":"Sonuç","a":"her atoma yetmez","d":"Ama elektronu çok olan atomlarda bu basit halka modeli <b>yetersiz kalır</b>; her atom için yeterli değildir."}],"ans":"Bohr modeli tek elektronlu hidrojeni iyi anlatır, ama elektronu çok olan atomlar için yeterli değildir."},{"q":"Bohr modeli hangi atom için en iyi sonucu verir?","steps":[{"t":"En basit atom","a":"hidrojen","d":"Hidrojen yalnızca tek elektrona sahiptir, bu yüzden en basit atomdur."},{"t":"Sonuç","a":"hidrojende başarılı","d":"Bohr modeli en iyi <b>hidrojen</b> atomunda çalışır; tek elektronlu olduğu için işler kolaydır."}],"ans":"Bohr modeli en iyi, tek elektronlu en basit atom olan hidrojende çalışır."},{"q":"Bir sınıfta tek öğrenci varken yerini takip etmek kolaydır, otuz öğrenci olunca zorlaşır. Bu durum Bohr modelinin hangi sorununa benzer?","steps":[{"t":"Benzetme","a":"tek vs çok","d":"Tek elektron tek öğrenci gibi kolay takip edilir; çok elektron kalabalık sınıf gibidir."},{"t":"Sonuç","a":"çok elektron zor","d":"Elektron çoğalınca onları halkalarda tek tek takip etmek zorlaşır; Bohr modeli bu yüzden <b>çok elektronlu</b> atomda zorlanır."}],"ans":"Tek elektron kolay, çok elektron kalabalık sınıf gibi zordur; Bohr modeli çok elektronlu atomlarda zorlanır."},{"q":"Bohr modeli yetersiz kalınca bilim insanları ne yaptı?","steps":[{"t":"Yeni model","a":"daha iyisi","d":"Bilim insanları atomu daha iyi anlatan yeni bir model geliştirdi."},{"t":"Sonuç","a":"modern model","d":"Bohr'un yerini, elektronları daha doğru anlatan <b>modern atom modeli</b> aldı."}],"ans":"Bohr modeli yetersiz kalınca bilim insanları daha iyi olan modern atom modelini geliştirdi."},{"q":"Bilimde bir model yetersiz kalırsa o model tamamen yanlış mıdır?","steps":[{"t":"Faydalı taraf","a":"bir kısmı doğru","d":"Bohr modeli hidrojeni doğru anlattığı için tamamen yanlış değildir, faydalı bir adımdır."},{"t":"Sonuç","a":"geliştirilir","d":"Yetersiz kalan kısımlar düzeltilerek model <b>geliştirilir</b>; eski model bilime basamak olur."}],"ans":"Hayır; yetersiz model tamamen yanlış değildir, eksikleri düzeltilerek daha iyi bir modele basamak olur."}],"zor":[{"q":"Bir çocuk 'Bohr modeli en basit atomda çok iyi çalışıyorsa, neden bütün atomlar için kullanmıyoruz?' diye soruyor. Ona nasıl cevap verirsin?","steps":[{"t":"Tek elektron kuralı","a":"sadece basitte iyi","d":"Bohr modeli yalnızca tek elektronlu atomda (hidrojen) iyi sonuç verir."},{"t":"Sonuç","a":"çoğunda yetersiz","d":"Elektronu çok olan diğer atomlarda doğru sonuç vermediği için her atomda <b>kullanılamaz</b>."}],"ans":"Bohr modeli sadece tek elektronlu hidrojende iyi çalışır; çok elektronlu atomlarda doğru sonuç vermediğinden her atomda kullanılamaz."},{"q":"Bohr modeli elektronu, çizgisi belli bir yolda giden tren gibi gösterir. Gerçekte elektronun yeri tam olarak bu kadar kesin bilinebilir mi?","fig":"<svg viewBox='0 0 200 160'><circle cx='100' cy='80' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='80' r='45' fill='none' stroke='#2b6be0' stroke-dasharray='4 3'/><circle cx='100' cy='80' r='62' fill='none' stroke='#5b6b85'/><circle cx='100' cy='80' r='30' fill='none' stroke='#5b6b85'/></svg>","steps":[{"t":"Kesin yol","a":"Bohr öyle der","d":"Bohr modeli elektronun yolunu, tren rayı gibi tam belli kabul eder."},{"t":"Sonuç","a":"o kadar kesin değil","d":"Gerçekte elektronun yeri bu kadar kesin bilinemez; bulunabileceği yer bir <b>bulut</b> gibidir, bu Bohr'un eksiğidir."}],"ans":"Hayır; Bohr modeli elektronu kesin bir yolda gösterir, ama gerçekte elektronun yeri o kadar kesin bilinemez."},{"q":"Bohr modelinin çizdiği düzgün halkalar, atomun gerçek hâli mi yoksa kolay anlamak için yapılmış bir basitleştirme mi?","steps":[{"t":"Kolaylaştırma","a":"basit çizim","d":"Düzgün halkalar atomu kolay anlamamız için yapılmış basit bir çizimdir."},{"t":"Sonuç","a":"gerçeğin tamamı değil","d":"Gerçek atom bu kadar basit değildir; halkalar atomun <b>tam gerçeği</b> değil, bir modelidir."}],"ans":"Düzgün halkalar atomu kolay anlatmak için yapılmış basitleştirmedir; atomun tam gerçeği değildir."},{"q":"Bohr modeli ile modern model arasında, elektronun yeri konusunda en büyük fark nedir?","steps":[{"t":"Bohr'un yeri","a":"kesin halka","d":"Bohr modeli elektronu belirli, kesin bir halka üzerinde gösterir."},{"t":"Sonuç","a":"modern: bulut","d":"Modern model ise elektronu kesin yol yerine bulunma <b>ihtimalinin yüksek olduğu bir bulut</b> bölgesi olarak gösterir."}],"ans":"Bohr elektronu kesin halkada; modern model ise bulunma ihtimalinin yüksek olduğu bir bulut bölgesinde gösterir."},{"q":"Hidrojenin yanındaki helyumun (2 elektronlu) çizgi spektrumu, Bohr modelinin tahmininden farklı çıkıyor. Bu durum bize ne söyler?","steps":[{"t":"Tahminden sapma","a":"uymuyor","d":"Bohr modeli helyumun renk çizgilerini doğru tahmin edemez, gerçek ölçümle uyuşmaz."},{"t":"Sonuç","a":"model yetersiz","d":"Tahmin tutmadığından, Bohr modelinin çok elektronlu atomlarda <b>yetersiz</b> olduğu anlaşılır."}],"ans":"Bohr modeli helyumun çizgilerini doğru tahmin edemediğinden, çok elektronlu atomlarda yetersiz olduğu anlaşılır."}]},"ortaokul":{"kolay":[{"q":"Bohr atom modeli hangi atom için doğru ve başarılı sonuçlar verir?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='42' fill='none' stroke='#2b6be0'/><circle cx='142' cy='85' r='6' fill='#2b6be0'/><text x='90' y='30' font-size='11' fill='#1a2b45'>H</text></svg>","steps":[{"t":"Tek elektron","a":"hidrojen","d":"Hidrojen tek elektrona sahiptir; Bohr modeli bu basit durumu doğru hesaplar."},{"t":"Sonuç","a":"hidrojende başarılı","d":"Bu yüzden Bohr modeli özellikle <b>hidrojen</b> (ve tek elektronlu iyonlar) için başarılıdır."}],"ans":"Bohr modeli, tek elektronlu hidrojen atomu (ve tek elektronlu iyonlar) için başarılı sonuçlar verir."},{"q":"Bohr modeli çok elektronlu atomlarda neden yetersiz kalır?","steps":[{"t":"Elektronlar arası itme","a":"hesaba katmaz","d":"Çok elektronlu atomlarda elektronlar birbirini iter; Bohr modeli bu etkileşimi hesaba katmaz."},{"t":"Sonuç","a":"yetersiz","d":"Bu nedenle çok elektronlu atomların çizgi spektrumlarını doğru veremez; model <b>yetersiz</b> kalır."}],"ans":"Bohr modeli, çok elektronlu atomlardaki elektronlar arası itmeyi hesaba katmadığından yetersiz kalır."},{"q":"Bohr modeli elektronun yörüngesini nasıl tanımlar?","steps":[{"t":"Kesin yörünge","a":"belirli yarıçap","d":"Bohr modeli, elektronun belirli yarıçaplı, kesin bir dairesel yörüngede döndüğünü kabul eder."},{"t":"Sonuç","a":"kesin yol","d":"Yani elektronun yeri ve yolu <b>kesin</b> olarak bilinebilir varsayılır; bu modern modelle çelişir."}],"ans":"Bohr modeli elektronu, belirli yarıçaplı kesin bir yörüngede döner kabul eder; yerini kesin bilinir sayar."},{"q":"Bohr modeli yetersiz kalınca yerine hangi model geldi?","steps":[{"t":"Yeni model gereksinimi","a":"daha doğru","d":"Çok elektronlu atomları açıklamak için daha gelişmiş bir modele ihtiyaç duyuldu."},{"t":"Sonuç","a":"modern (kuantum) model","d":"Bohr'un yerini, elektronları olasılıkla anlatan <b>modern (kuantum mekaniksel) atom modeli</b> aldı."}],"ans":"Bohr modelinin yerini, modern (kuantum mekaniksel) atom modeli aldı."},{"q":"Bohr modeli, elektronun hem yerini hem hızını aynı anda kesin bildiğini varsayar. Bu hangi ilkeyle çelişir?","steps":[{"t":"Kesin bilme iddiası","a":"yer + hız","d":"Bohr, elektronun konumunu ve hızını aynı anda tam bildiğini kabul eder."},{"t":"Sonuç","a":"belirsizlik ilkesi","d":"Oysa Heisenberg <b>belirsizlik ilkesine</b> göre ikisi aynı anda kesin bilinemez; Bohr bununla çelişir."}],"ans":"Bohr modeli, elektronun yer ve hızını aynı anda kesin bilinir sayar; bu Heisenberg belirsizlik ilkesiyle çelişir."}],"zor":[{"q":"Bohr modeli Eₙ = −13,6/n² bağıntısıyla hidrojen çizgilerini doğru verir, ama helyum (2 elektron) için aynı başarıyı gösteremez. Bunun temel nedeni nedir?","steps":[{"t":"Tek elektron varsayımı","a":"itme yok sayılır","d":"Bohr bağıntısı tek elektronu çekirdek çekimiyle ele alır; elektron-elektron itmesini içermez."},{"t":"Sonuç","a":"çok elektronda sapar","d":"Helyumda iki elektron birbirini iter; bu etki hesaba katılmadığından tahminler <b>gerçekten sapar</b>, model yetersiz kalır."}],"ans":"Bohr bağıntısı elektron-elektron itmesini içermediğinden, iki elektronlu helyumda gerçek çizgilerden sapar; model yetersiz kalır."},{"q":"Heisenberg belirsizlik ilkesi, Bohr modelinin hangi temel varsayımını geçersiz kılar?","fig":"<svg viewBox='0 0 200 160'><circle cx='100' cy='80' r='11' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='80' r='45' fill='none' stroke='#2b6be0' stroke-dasharray='4 3'/><circle cx='145' cy='80' r='5' fill='#2b6be0'/><text x='118' y='60' font-size='10' fill='#1a2b45'>yer=?</text><text x='118' y='110' font-size='10' fill='#1a2b45'>hız=?</text></svg>","steps":[{"t":"Bohr varsayımı","a":"kesin yörünge","d":"Bohr, elektronun belirli yarıçaplı kesin bir yörüngede, yeri ve hızı bilinir biçimde döndüğünü varsayar."},{"t":"Sonuç","a":"kesin yörünge olamaz","d":"Belirsizlik ilkesine göre konum ve hız aynı anda kesin bilinemez; bu yüzden <b>kesin yörünge varsayımı</b> geçersizdir."}],"ans":"Belirsizlik ilkesi, elektronun yeri ve hızının aynı anda kesin bilinebileceği varsayımını geçersiz kılar; bu yüzden kesin yörünge fikri terk edilir."},{"q":"'Bohr modeli tamamen yanlıştı, hiç işe yaramadı' diyen birine bilimsel olarak nasıl itiraz edersin?","steps":[{"t":"Başarılı yanı","a":"hidrojeni açıkladı","d":"Bohr modeli hidrojenin çizgi spektrumunu ilk kez doğru açıklamış ve enerji düzeylerinin kesikli (kuantize) olduğunu göstermiştir."},{"t":"Sonuç","a":"basamak oldu","d":"Eksikleri olsa da bilime önemli bir <b>basamak</b> olmuştur; tamamen yanlış değil, sınırlıdır."}],"ans":"Bohr modeli hidrojeni açıklayıp enerji düzeylerinin kesikli olduğunu gösterdiğinden tamamen yanlış değildir; sınırlı ama bilime önemli bir basamaktır."},{"q":"Bohr modeli ile modern atom modelinin elektronu tanımlama biçimini karşılaştırınız.","steps":[{"t":"Bohr","a":"kesin yörünge","d":"Bohr modeli elektronu, belirli yarıçaplı kesin bir dairesel yörüngede gösterir."},{"t":"Sonuç","a":"modern: olasılık","d":"Modern model ise elektronu kesin yol yerine, bulunma <b>olasılığının yüksek olduğu orbital</b> bölgesiyle tanımlar."}],"ans":"Bohr elektronu kesin yörüngede; modern model ise bulunma olasılığının yüksek olduğu orbital (bulut) bölgesinde tanımlar."},{"q":"Bohr modeli, atomdaki çizgilerin yakından bakıldığında ikiye ayrılması (ince yapı) gibi ayrıntıları açıklayamaz. Bu eksiklik neyi gösterir?","steps":[{"t":"İnce yapı","a":"çizgi yarılması","d":"Spektrum çizgileri yakından bakıldığında ince alt çizgilere ayrılır; Bohr modeli bunu öngöremez."},{"t":"Sonuç","a":"daha gelişmiş model","d":"Bu ayrıntıları açıklamak için spin ve orbital içeren daha gelişmiş <b>kuantum modeli</b> gerektiğini gösterir."}],"ans":"İnce yapıyı açıklayamaması, Bohr modelinin yetersiz olduğunu ve daha gelişmiş kuantum modeline ihtiyaç duyulduğunu gösterir."}]},"lise":{"kolay":[{"q":"Bohr atom modelinin başarılı olduğu durumu ve bu başarının sınırını açıklayınız.","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='30' fill='none' stroke='#2b6be0'/><circle cx='100' cy='85' r='50' fill='none' stroke='#2b6be0'/><circle cx='130' cy='85' r='5' fill='#2b6be0'/><text x='138' y='40' font-size='10' fill='#1a2b45'>tek e⁻</text></svg>","steps":[{"t":"Başarı","a":"tek elektronlu sistem","d":"Bohr modeli, hidrojen ve He⁺, Li²⁺ gibi tek elektronlu iyonların çizgi spektrumunu doğru açıklar."},{"t":"Sınır","a":"çok elektronda yetersiz","d":"Birden çok elektronlu atomlarda elektron-elektron etkileşimi nedeniyle <b>yetersiz kalır</b>; bu modelin temel sınırıdır."}],"ans":"Bohr modeli tek elektronlu sistemlerde (H, He⁺ ...) başarılıdır; çok elektronlu atomlarda elektronlar arası etkileşim nedeniyle yetersiz kalır."},{"q":"Bohr modelinin Heisenberg belirsizlik ilkesiyle çelişen varsayımını açıklayınız.","steps":[{"t":"Bohr varsayımı","a":"kesin yörünge","d":"Bohr, elektronun belirli yarıçaplı kesin bir yörüngede döndüğünü, yani konum ve hızının aynı anda bilinebildiğini varsayar."},{"t":"Çelişki","a":"belirsizlik ilkesi","d":"Heisenberg belirsizlik ilkesine göre konum ve momentum aynı anda kesin ölçülemez; bu nedenle <b>kesin yörünge</b> kavramı fiziksel olarak savunulamaz."}],"ans":"Bohr modeli elektronun konum ve hızını aynı anda kesin bilinir sayar; bu, Heisenberg belirsizlik ilkesiyle çelişir."},{"q":"Bohr modeli çok elektronlu atomların spektrumlarını neden tam açıklayamaz?","steps":[{"t":"Etkileşim ihmali","a":"e-e itmesi yok","d":"Bohr modeli yalnızca çekirdek-elektron çekimini ele alır; elektronlar arası itme ve perdeleme etkisini hesaba katmaz."},{"t":"Sonuç","a":"yanlış enerji düzeyleri","d":"Çok elektronlu atomlarda bu etkiler enerji düzeylerini değiştirdiğinden, Bohr'un öngördüğü çizgiler <b>gerçekle uyuşmaz</b>."}],"ans":"Bohr modeli elektronlar arası itme ve perdeleme etkilerini ihmal ettiğinden, çok elektronlu atomların enerji düzeylerini ve spektrumlarını tam açıklayamaz."},{"q":"Bohr modelinin açıklayamadığı 'ince yapı' ve manyetik alandaki çizgi yarılması (Zeeman olayı) eksikliklerini kısaca açıklayınız.","steps":[{"t":"İnce yapı","a":"spin-orbital ihmali","d":"Spektrum çizgilerinin yakından ikiye ayrılması (ince yapı), elektron spini ve spin-yörünge etkileşimiyle açıklanır; Bohr modeli spini içermez."},{"t":"Zeeman olayı","a":"manyetik yarılma","d":"Manyetik alanda çizgilerin yarılması (Zeeman olayı) da Bohr modeliyle açıklanamaz; bu eksiklikler <b>kuantum modelini</b> gerekli kılar."}],"ans":"Bohr modeli elektron spinini içermediğinden ince yapıyı ve manyetik alandaki çizgi yarılmasını (Zeeman olayı) açıklayamaz."},{"q":"Bohr modeli klasik fizik açısından (ivmeli yüklü parçacık ışıması) hangi çelişkiyi barındırır?","steps":[{"t":"Klasik beklenti","a":"ivmeli yük ışır","d":"Klasik elektromanyetizmaya göre dairesel yörüngede dönen (ivmeli) bir elektron sürekli enerji yayıp çekirdeğe spiral çizerek düşmeliydi."},{"t":"Bohr'un postulatı","a":"varsayımla çözer","d":"Bohr bunu 'kararlı yörüngelerde ışıma olmaz' varsayımıyla giderir; ancak bu, klasik fizikten gelmeyen, <b>nedensiz kabul edilmiş bir postulattır</b>."}],"ans":"Klasik fiziğe göre dönen elektron ışıyıp çekirdeğe düşmeliydi; Bohr bunu temellendirilmemiş bir 'kararlı yörünge' postulatıyla çözer, bu modelin zayıf yanıdır."}],"zor":[{"q":"Bohr modeli ile modern (kuantum mekaniksel) modelin elektron tanımını karşılaştırınız.","steps":[{"t":"Bohr","a":"kesin dairesel yörünge","d":"Bohr modeli elektronu, belirli yarıçaplı kesin bir dairesel yörüngede konumu bilinir parçacık olarak ele alır."},{"t":"Modern model","a":"olasılık/orbital","d":"Modern model ise elektronu Schrödinger denklemiyle, bulunma <b>olasılığının</b> tanımlandığı orbital (elektron bulutu) ile tanımlar; kesin yörünge yoktur."}],"ans":"Bohr elektronu kesin dairesel yörüngede konumlandırır; modern model ise elektronu olasılıkla tanımlanan orbital (bulut) olarak ele alır, kesin yörünge kavramını terk eder."},{"q":"Bohr modelinin bilim tarihindeki değeri nedir? Eksiklerine rağmen neden önemlidir?","steps":[{"t":"Katkısı","a":"enerji kuantlanması","d":"Bohr modeli, atomda enerji düzeylerinin kesikli (kuantize) olduğunu ortaya koyarak hidrojen spektrumunu ilk kez başarıyla açıkladı."},{"t":"Önemi","a":"kuantuma geçiş","d":"Eksiklerine rağmen klasik fizikten <b>kuantum mekaniğine geçişte</b> köprü olmuş, modern modele zemin hazırlamıştır."}],"ans":"Bohr modeli enerji düzeylerinin kuantize olduğunu gösterip hidrojen spektrumunu açıkladığından, klasik fizikten kuantum mekaniğine geçişte önemli bir köprüdür."},{"q":"Bir öğrenci 'Bohr modeli elektronun yarıçapını ve hızını tam veriyor' diyor. Bu ifadeyi modern fizik açısından değerlendirin.","steps":[{"t":"Bohr'a göre","a":"kesin değerler","d":"Bohr modeli gerçekten elektronun yörünge yarıçapını ve hızını kesin sayısal değerlerle verir."},{"t":"Modern değerlendirme","a":"fiziksel anlamı yok","d":"Ancak belirsizlik ilkesine göre konum ve hız aynı anda kesin tanımlanamaz; bu yüzden bu kesin değerlerin <b>gerçek fiziksel karşılığı yoktur</b>, model yaklaşıktır."}],"ans":"Bohr kesin yarıçap ve hız verse de, belirsizlik ilkesi gereği bu değerlerin gerçek fiziksel karşılığı yoktur; ifade modern fizik açısından geçerli değildir."},{"q":"Bohr modeli hidrojende çizgilerin yerini doğru verirken çizgilerin şiddetini (parlaklığını) neden açıklayamaz?","steps":[{"t":"Açıkladığı","a":"çizgi konumu","d":"Bohr modeli enerji farklarından çizgilerin dalga boyunu (konumunu) doğru verir."},{"t":"Açıklayamadığı","a":"geçiş olasılığı","d":"Bir geçişin ne sıklıkta olacağını (geçiş olasılığını) belirleyemediğinden çizgilerin <b>şiddetini</b> açıklayamaz; bu ancak kuantum mekaniğiyle hesaplanır."}],"ans":"Bohr modeli çizgi konumlarını verir ama geçiş olasılıklarını hesaplayamadığından çizgilerin şiddetini açıklayamaz; bunun için kuantum mekaniği gerekir."},{"q":"Bohr modelinin temel postulatlarından hangileri modern modelde korunmuş, hangileri terk edilmiştir?","steps":[{"t":"Korunan","a":"enerji kuantlanması","d":"Enerji düzeylerinin kesikli (kuantize) olması ve E_foton = E_üst − E_alt ilişkisi modern modelde de geçerlidir."},{"t":"Terk edilen","a":"kesin yörünge","d":"Belirli yarıçaplı kesin dairesel yörünge varsayımı terk edilmiş; yerine olasılıksal <b>orbital</b> kavramı gelmiştir."}],"ans":"Enerji kuantlanması ve foton enerjisi = düzey farkı fikri korunmuş; kesin dairesel yörünge varsayımı ise terk edilip yerine orbital kavramı gelmiştir."}]}},"elementModeli":{"ilkokul":{"kolay":[{"q":"Yalnızca tek çeşit atomdan oluşan saf maddeye ne denir?","steps":[{"t":"Tek çeşit atom","a":"aynı tür","d":"Bazı maddeler baştan sona aynı tür atomlardan oluşur."},{"t":"Adı","a":"element","d":"Yalnız tek çeşit atomdan oluşan bu saf maddeye element denir."}],"ans":"Tek çeşit atomdan oluşan saf maddeye element denir."},{"q":"Altın bir yüzük hangi tür atomlardan oluşur?","steps":[{"t":"Tek tür","a":"altın atomu","d":"Saf altın baştan sona altın atomlarından oluşur."},{"t":"Element","a":"altın elementi","d":"Bu yüzden altın bir elementtir."}],"ans":"Altın yüzük, yalnızca altın atomlarından oluşur; altın bir elementtir."},{"q":"Elementler kısa yazımda neyle gösterilir?","steps":[{"t":"Kısa gösterim","a":"sembol","d":"Her elementin kısa bir gösterimi (sembolü) vardır."},{"t":"Örnek","a":"O, H","d":"Örneğin oksijen O, hidrojen H harfiyle gösterilir."}],"ans":"Elementler kısa olarak sembollerle (harflerle) gösterilir; örneğin oksijen O'dur."},{"q":"Demir ile bakır aynı element midir?","steps":[{"t":"Atomları","a":"farklı","d":"Demiri demir atomları, bakırı bakır atomları oluşturur."},{"t":"Sonuç","a":"farklı element","d":"Atomları farklı olduğu için demir ve bakır farklı elementlerdir."}],"ans":"Hayır; demir ve bakır farklı atomlardan oluştuğu için farklı elementlerdir."},{"q":"Doğada tek bir çeşit atom mı yoksa çok çeşit atom mu vardır?","steps":[{"t":"Çeşitlilik","a":"çok çeşit","d":"Doğada birçok farklı atom çeşidi vardır."},{"t":"Element sayısı","a":"birçok element","d":"Her atom çeşidi bir elemente karşılık gelir, bu yüzden birçok element vardır."}],"ans":"Doğada çok çeşit atom vardır; her çeşit bir elemente karşılık gelir."}],"zor":[{"q":"Bir element ile bir bileşik arasındaki temel fark nedir?","fig":"<svg viewBox='0 0 320 160'><circle cx='55' cy='75' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='85' cy='90' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='65' cy='100' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='70' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>element</text><circle cx='220' cy='80' r='14' fill='#e0552b' stroke='#1a2b45'/><circle cx='250' cy='95' r='10' fill='#cfd8e8' stroke='#1a2b45'/><circle cx='200' cy='100' r='10' fill='#cfd8e8' stroke='#1a2b45'/><line x1='220' y1='80' x2='250' y2='95' stroke='#1a2b45'/><line x1='220' y1='80' x2='200' y2='100' stroke='#1a2b45'/><text x='225' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>bileşik</text></svg>","steps":[{"t":"Element","a":"tek tür atom","d":"Element yalnızca tek çeşit atomdan oluşur (örneğin oksijen)."},{"t":"Bileşik","a":"farklı atomlar","d":"Bileşik ise farklı çeşit atomların birleşmesiyle oluşur (örneğin su)."}],"ans":"Element tek çeşit atomdan, bileşik ise farklı çeşit atomların birleşmesinden oluşur."},{"q":"Su saf bir madde olduğu hâlde neden element değildir?","steps":[{"t":"Suyun atomları","a":"iki çeşit","d":"Su, hidrojen ve oksijen olmak üzere iki farklı atom çeşidinden oluşur."},{"t":"Sonuç","a":"bileşik","d":"Birden fazla çeşit atom içerdiği için su element değil, bileşiktir."}],"ans":"Su iki farklı atom çeşidinden (hidrojen ve oksijen) oluştuğu için element değil, bileşiktir."},{"q":"Bütün maddeler aynı atomlardan yapılsaydı dünya nasıl olurdu?","steps":[{"t":"Tek çeşit atom","a":"tek madde","d":"Eğer tek bir atom çeşidi olsaydı yalnız tek tür madde olurdu."},{"t":"Çeşitlilik","a":"farklı atomlar gerekir","d":"Etrafımızdaki binlerce farklı madde, farklı atom çeşitleri ve onların birleşimleri sayesinde vardır."}],"ans":"Tek çeşit atom olsaydı tek tür madde olurdu; çevremizdeki çeşitlilik farklı atom çeşitlerinden gelir."},{"q":"Bir elementin sembolü neden kısa harflerle yazılır?","steps":[{"t":"Kolaylık","a":"kısa yazım","d":"Element adlarını her seferinde uzun uzun yazmak yerine kısa sembol kullanmak işi kolaylaştırır."},{"t":"Ortak dil","a":"herkes anlar","d":"Bu semboller dünyanın her yerinde aynı olduğundan bütün bilim insanları aynı şeyi anlar."}],"ans":"Sembol, elementi kısa ve herkesin anlayacağı ortak bir biçimde göstermek için kullanılır."},{"q":"Bir avuç toz şekerin tamamı aynı maddeyse, bu maddenin en küçük yapı taşı için ne söyleriz?","steps":[{"t":"Aynı madde","a":"saf madde","d":"Toz şekerin her tanesi aynı maddedir."},{"t":"Yapı taşı","a":"aynı tanecik","d":"Bu maddenin tamamı aynı tür yapı taşı (taneciklerden) oluşur, bu yüzden her yerinde aynı özelliği gösterir."}],"ans":"Saf bir maddenin tamamı aynı tür yapı taşlarından oluşur, bu yüzden her tanesi aynı özelliği gösterir."}]},"ortaokul":{"kolay":[{"q":"Element nedir ve örnekleri nelerdir?","steps":[{"t":"Tanım","a":"tek tür atom","d":"Element, aynı tür atomlardan oluşan saf maddedir."},{"t":"Örnek","a":"demir, oksijen, altın","d":"Demir, oksijen, altın, hidrojen birer elementtir."}],"ans":"Element, aynı tür atomlardan oluşan saf maddedir; demir, oksijen ve altın örnek olarak verilebilir."},{"q":"Element sembolü nasıl oluşturulur?","fig":"<svg viewBox='0 0 320 150'><rect x='115' y='35' width='90' height='80' fill='#f5f7fa' stroke='#1a2b45'/><text x='160' y='90' font-size='40' text-anchor='middle' fill='#1a2b45'>Na</text><text x='160' y='135' font-size='12' text-anchor='middle' fill='#1a2b45'>sodyum sembolü</text></svg>","steps":[{"t":"İlk harf","a":"büyük yazılır","d":"Element sembolünün ilk harfi her zaman büyük yazılır."},{"t":"İkinci harf","a":"küçük yazılır","d":"İki harfli sembollerde ikinci harf küçük yazılır; örneğin sodyum Na, kalsiyum Ca."}],"ans":"Element sembolünde ilk harf büyük, varsa ikinci harf küçük yazılır; örneğin sodyum Na, kalsiyum Ca."},{"q":"Saf madde ile karışım arasındaki fark element açısından nasıldır?","steps":[{"t":"Saf madde","a":"tek tür tanecik","d":"Element gibi saf maddeler tek tür tanecikten oluşur ve belirli özellikleri vardır."},{"t":"Karışım","a":"farklı maddeler","d":"Karışım ise birden çok maddenin bir arada bulunmasıdır; kimyasal olarak birleşmemiştir."}],"ans":"Element tek tür atomdan oluşan saf maddedir; karışım ise farklı maddelerin kimyasal olarak birleşmeden bir arada bulunmasıdır."},{"q":"Periyodik tablo elementler hakkında bize ne sunar?","steps":[{"t":"İçerik","a":"tüm elementler","d":"Periyodik tablo bilinen elementlerin tamamını düzenli bir biçimde gösterir."},{"t":"Bilgi","a":"sembol ve sıra","d":"Her element için sembolünü ve atom numarasını içerir, elementler benzer özelliklerine göre sıralanır."}],"ans":"Periyodik tablo, bilinen tüm elementleri sembolleri ve atom numaralarıyla düzenli bir biçimde sunar."},{"q":"Atom çeşitliliği maddelerin çeşitliliğiyle nasıl ilişkilidir?","steps":[{"t":"Farklı atomlar","a":"farklı elementler","d":"Doğada farklı çeşit atomlar vardır ve her biri bir elemente karşılık gelir."},{"t":"Birleşmeler","a":"çok madde","d":"Bu atomların farklı sayı ve düzenlerde birleşmesi binlerce farklı madde oluşturur."}],"ans":"Farklı atom çeşitleri farklı elementleri oluşturur; bu atomların çeşitli birleşimleri ise sayısız farklı maddeyi meydana getirir."}],"zor":[{"q":"Oksijen gazı (O₂) saf madde olduğu hâlde neden molekül olarak gösterilir ama yine de elementtir?","steps":[{"t":"Tek tür atom","a":"sadece O","d":"O₂ yalnızca oksijen atomlarından oluşur; başka çeşit atom içermez."},{"t":"Element koşulu","a":"tek çeşit atom","d":"Element olmanın koşulu tek çeşit atomdan oluşmaktır; iki oksijen atomu birleşse de element olma durumu değişmez."}],"ans":"O₂ yalnızca oksijen atomlarından oluştuğu için elementtir; iki atomun molekül oluşturması bunu değiştirmez."},{"q":"Bir maddenin element mi yoksa bileşik mi olduğunu nasıl anlarız?","steps":[{"t":"Atom çeşidi","a":"tek mi çok mu","d":"Maddeyi oluşturan atomlar tek çeşitse element, birden çok çeşitse bileşiktir."},{"t":"Ayrışma","a":"basit maddelere ayrılma","d":"Element kimyasal yolla daha basit maddelere ayrılamaz; bileşik ise kendini oluşturan elementlere ayrılabilir."}],"ans":"Madde tek çeşit atomdan oluşuyor ve daha basit maddelere ayrılamıyorsa elementtir; farklı atomlardan oluşup ayrılabiliyorsa bileşiktir."},{"q":"Element sembollerinin tüm dünyada aynı kullanılması neden önemlidir?","steps":[{"t":"Ortak dil","a":"evrensel","d":"Semboller her ülkede aynı olduğundan kimya, ortak ve evrensel bir dil kazanır."},{"t":"Yarar","a":"anlaşılırlık","d":"Bu sayede farklı dilleri konuşan bilim insanları formülleri ve tepkimeleri aynı şekilde anlar, karışıklık olmaz."}],"ans":"Ortak semboller kimyaya evrensel bir dil kazandırır; farklı dilleri konuşan bilim insanları aynı formül ve tepkimeleri kolayca anlar."},{"q":"Atom numarası bir elementin kimliğini nasıl belirler?","steps":[{"t":"Atom numarası","a":"proton sayısı","d":"Atom numarası, atomun çekirdeğindeki proton sayısına eşittir."},{"t":"Kimlik","a":"proton = element","d":"Her elementin proton sayısı farklıdır; örneğin 8 protonlu her atom oksijendir, proton sayısı değişirse element de değişir."}],"ans":"Atom numarası (proton sayısı) her element için farklıdır; bu sayı atomun hangi element olduğunu belirler."},{"q":"Çok az sayıda element binlerce farklı maddeyi nasıl oluşturabilir?","steps":[{"t":"Sınırlı element","a":"az çeşit","d":"Doğada görece az sayıda farklı element vardır."},{"t":"Birleşim çeşitliliği","a":"farklı oran ve düzen","d":"Bu elementlerin atomları farklı sayı, oran ve düzenlerde birleşerek sayısız farklı bileşik oluşturur; tıpkı az sayıda harften binlerce kelime kurulması gibi."}],"ans":"Az sayıda element, atomlarının farklı sayı ve düzenlerde birleşmesiyle binlerce farklı madde oluşturur; çeşitlilik birleşim biçimlerinden gelir."}]},"lise":{"kolay":[{"q":"Element kavramı modern kimyada nasıl tanımlanır?","steps":[{"t":"Tanım","a":"aynı Z'li atomlar","d":"Element, çekirdeğindeki proton sayısı (atom numarası Z) aynı olan atomlardan oluşan saf maddedir."},{"t":"Ayrılamazlık","a":"kimyasal sınır","d":"Element, kimyasal yöntemlerle kendisinden daha basit maddelere ayrıştırılamaz."}],"ans":"Element, atom numarası (proton sayısı) aynı atomlardan oluşan ve kimyasal yolla daha basit maddelere ayrılamayan saf maddedir."},{"q":"Element sembolleri hangi kurallara göre yazılır ve örnekleri nelerdir?","steps":[{"t":"Yazım kuralı","a":"büyük + küçük harf","d":"Sembolün ilk harfi büyük, ikinci harfi (varsa) küçük yazılır."},{"t":"Köken","a":"ad/Latince","d":"Semboller elementin adından ya da Latince adından gelir; örneğin sodyum Na (natrium), demir Fe (ferrum), potasyum K (kalium)."}],"ans":"Sembolde ilk harf büyük, ikinci harf küçük yazılır; semboller elementin adından veya Latince adından türetilir (Na, Fe, K gibi)."},{"q":"Saf madde olarak element ile bileşik nasıl karşılaştırılır?","steps":[{"t":"Element","a":"tek tür atom","d":"Element tek çeşit atomdan oluşur ve sabit özelliklere sahiptir (örneğin O₂, Fe)."},{"t":"Bileşik","a":"belirli oranda farklı atom","d":"Bileşik, farklı elementlerin atomlarının belirli kütle oranlarında kimyasal bağ ile birleşmesiyle oluşur (örneğin H₂O, CO₂)."}],"ans":"Element tek tür atomdan oluşan saf maddedir; bileşik ise farklı elementlerin belirli oranlarda kimyasal bağlanmasıyla oluşan saf maddedir."},{"q":"Periyodik tablo, atom çeşitliliğini nasıl düzenli hale getirir?","fig":"<svg viewBox='0 0 320 150'><rect x='120' y='30' width='80' height='90' fill='#f5f7fa' stroke='#1a2b45'/><text x='130' y='52' font-size='12' fill='#1a2b45'>8</text><text x='160' y='88' font-size='34' text-anchor='middle' fill='#1a2b45'>O</text><text x='160' y='112' font-size='11' text-anchor='middle' fill='#1a2b45'>oksijen</text><text x='160' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>atom no = proton sayısı</text></svg>","steps":[{"t":"Sıralama","a":"artan atom numarası","d":"Elementler artan atom numarasına (proton sayısına) göre sıralanır."},{"t":"Düzen","a":"grup ve periyot","d":"Benzer kimyasal özellikteki elementler aynı düşey sütunda (grupta) toplanır; bu, atom çeşitliliğine sistematik bir düzen kazandırır."}],"ans":"Periyodik tablo elementleri artan atom numarasına göre sıralar ve benzer özelliktekileri aynı grupta toplayarak atom çeşitliliğini düzenli hale getirir."},{"q":"Bir elementin atomları arasındaki izotop farkı, elementin kimliğini neden değiştirmez?","steps":[{"t":"Ortak nokta","a":"aynı proton sayısı","d":"Bir elementin tüm izotoplarında proton sayısı aynıdır; kimliği belirleyen budur."},{"t":"Fark","a":"nötron sayısı","d":"İzotoplar yalnız nötron sayısında (kütle numarasında) farklıdır; bu kimyasal kimliği değiştirmez, sadece kütleyi etkiler."}],"ans":"İzotopların proton sayısı aynı olduğundan element kimliği değişmez; farklı olan nötron sayısı yalnızca kütleyi etkiler."}],"zor":[{"q":"Doğal bir element örneğinin atom kütlesinin ondalıklı çıkması (örneğin klor 35,5) nasıl açıklanır?","steps":[{"t":"İzotop karışımı","a":"farklı kütleli atomlar","d":"Doğal element, farklı kütle numaralı izotoplarının bir karışımıdır (örneğin Cl-35 ve Cl-37)."},{"t":"Ağırlıklı ortalama","a":"bolluk oranı","d":"Element atom kütlesi, izotopların kütlelerinin doğadaki bulunma oranlarına göre alınan ağırlıklı ortalamasıdır; bu yüzden tam sayı çıkmaz."}],"ans":"Bir element farklı izotopların karışımı olduğundan, atom kütlesi izotopların bolluk oranına göre alınan ağırlıklı ortalamadır; bu nedenle klorda 35,5 gibi ondalıklı bir değer çıkar."},{"q":"'Element kimyasal yolla ayrıştırılamaz' ifadesi, suyun elektroliz ile ayrışmasıyla nasıl bağdaştırılır?","steps":[{"t":"Su bileşiktir","a":"H ve O","d":"Su element değil, hidrojen ve oksijenden oluşan bir bileşiktir."},{"t":"Ayrışma sonucu","a":"elementler","d":"Elektrolizle su, kendisini oluşturan hidrojen ve oksijen elementlerine ayrışır; bu ayrışan suyun bileşik olduğunu doğrular, elementler daha öteye ayrışmaz."}],"ans":"Elektrolizle ayrışan su bir bileşiktir; oluşan hidrojen ve oksijen ise element olduğundan kimyasal yolla daha basit maddelere ayrışmaz, böylece ifade çelişmez."},{"q":"Aynı atom türünden oluşan ama farklı özellik gösteren elmas ve grafit durumu element kavramıyla nasıl açıklanır?","steps":[{"t":"Ortak element","a":"ikisi de karbon","d":"Hem elmas hem grafit yalnızca karbon atomlarından oluşur; ikisi de karbon elementidir."},{"t":"Dizilim farkı","a":"allotropi","d":"Farklı fiziksel özellikleri, karbon atomlarının uzayda farklı düzende bağlanmasından (allotropi) kaynaklanır; element aynı, yapı farklıdır."}],"ans":"Elmas ve grafit ikisi de yalnız karbon atomundan oluşur, yani aynı elementtir; farklı özellikleri atomların farklı dizilimi (allotropi) yüzündendir."},{"q":"Element sembolünün altına/yanına yazılan atom numarası ve kütle numarası birlikte hangi atomu kesin tanımlar?","steps":[{"t":"Atom numarası","a":"elementi belirler","d":"Atom numarası (Z) çekirdekteki proton sayısını verir ve hangi element olduğunu kesinleştirir."},{"t":"Kütle numarası","a":"izotopu belirler","d":"Kütle numarası (A) proton + nötron toplamıdır; Z ile birlikte hangi izotop olduğunu da belirler, böylece atom tam tanımlanır."}],"ans":"Atom numarası (Z) elementi, kütle numarası (A) ise nötron sayısını dolayısıyla izotopu belirler; ikisi birlikte atomun türünü ve izotopunu kesin tanımlar."},{"q":"Yaklaşık yüz farklı elementin evrendeki tüm maddesel çeşitliliği oluşturabilmesi hangi ilkeyle açıklanır?","steps":[{"t":"Sınırlı yapı taşı","a":"≈ 100 element","d":"Doğada yaklaşık yüz farklı element (atom türü) bulunur."},{"t":"Kombinatorik çeşitlilik","a":"oran, düzen, bağ","d":"Bu atomlar farklı sayı, oran, geometri ve bağ türleriyle birleşerek milyonlarca farklı bileşik oluşturur; sınırlı yapı taşından sınırsıza yakın çeşitlilik doğar."}],"ans":"Yaklaşık yüz element, atomlarının farklı oran, düzen ve bağ türleriyle birleşmesi sayesinde milyonlarca farklı madde oluşturur; çeşitlilik kombinasyon zenginliğinden gelir."}]}},"fOrbitali":{"ilkokul":{"kolay":[{"q":"Bir otoparkta 2 araç alan küçük, 6 araç alan orta, 14 araç alan çok büyük katlar olsun. En çok aracı hangi kat alır?","steps":[{"t":"Katları kıyasla","a":"en büyük kat","d":"2, 6 ve 14 sayılarından en büyüğü 14'tür; en çok aracı büyük kat alır."},{"t":"Atomda benzetme","a":"en büyük kat = f","d":"Atomda da en büyük 'kat' (f) en çok elektronu, yani <b>14</b> taneyi alır."}],"ans":"En büyük kat 14 araç alır; atomda da en büyük katmana benzeyen f, 14 elektron alabilir."},{"q":"Bir kitaplıkta küçük raf 2, orta raf 6, daha büyük raf 10, en büyük raf 14 kitap alıyor. En büyük raf kaç kitap alır?","steps":[{"t":"Sayıları gör","a":"14 kitap","d":"Raflar sırasıyla 2, 6, 10, 14 kitap alır; en büyüğü 14 kitaplıktır."},{"t":"Atomda karşılığı","a":"f rafı = 14","d":"Atomda da en büyük rafa (f) <b>14</b> elektron sığar."}],"ans":"En büyük raf 14 kitap alır; atomda buna f denir ve 14 elektron alır."},{"q":"Bir trende küçük vagon az, orta vagon biraz fazla, en büyük vagon en çok yolcu alır. Atomda en çok yolcu (elektron) alan büyük vagonun adı nedir?","steps":[{"t":"En büyük vagon","a":"en çok yolcu","d":"En büyük vagon diğerlerinden daha çok yolcu taşır."},{"t":"Atomdaki adı","a":"f vagonu","d":"Atomda bu büyük vagona <b>f</b> denir ve en çok (14) elektronu taşır."}],"ans":"Atomda en çok elektron alan büyük vagona f denir; 14 elektron taşıyabilir."},{"q":"Periyodik tablonun altında, ana tablodan ayrı duran iki uzun satır vardır. Bunlar neye benzer?","steps":[{"t":"Ayrı iki satır","a":"alttaki iki sıra","d":"Tablonun altında, ana gövdeden ayrılmış iki uzun satır bulunur."},{"t":"Neyi temsil eder","a":"özel elementler","d":"Bu iki satır, atomun en büyük 'katı' olan <b>f</b> ile dolan özel elementlerdir."}],"ans":"Tablonun altındaki iki sıra, atomun en büyük katı (f) ile dolan özel element gruplarıdır."},{"q":"Bir kutu küçük (2), bir kutu orta (6), bir kutu büyük (10), bir kutu çok büyük (14) top alıyor. Toplam kaç kutu vardır ve en büyüğü kaç alır?","steps":[{"t":"Kutuları say","a":"4 kutu","d":"2, 6, 10 ve 14 alan dört farklı boy kutu vardır."},{"t":"En büyüğü","a":"14 top","d":"En büyük kutu (atomdaki f gibi) <b>14</b> top alır."}],"ans":"Dört kutu vardır; en büyüğü 14 top alır, atomda buna f denir."}],"zor":[{"q":"Atomdaki 'odalar' 2, 6, 10, 14 kişi alıyor. Bir öğrenci bu sayıların hep 4'er arttığını fark etti. f odası neden en kalabalıktır?","steps":[{"t":"Artış kuralı","a":"4'er artıyor","d":"2, 6, 10, 14 sayıları her seferinde 4 artar; en büyüğü 14'tür."},{"t":"f en büyük","a":"14 elektron","d":"f odası bu sıranın en büyüğüdür; bu yüzden en çok, yani <b>14</b> elektron alır."}],"ans":"Sayılar 4'er artar (2, 6, 10, 14); f en büyük oda olduğu için 14 elektronla en kalabalık olandır."},{"q":"Periyodik tablonun altındaki iki sıra neden ana tablodan ayrı çizilir?","steps":[{"t":"Yer sorunu","a":"tablo çok uzar","d":"Bu elementler ana tabloya konsa tablo çok uzar ve sayfaya sığmaz."},{"t":"Ayrı gösterilir","a":"alttaki iki sıra","d":"Bu yüzden f ile dolan bu özel elementler <b>tablonun altına</b> ayrı iki sıra olarak çizilir."}],"ans":"Bu elementler tabloyu çok uzatacağından, f ile dolan iki özel sıra ana tablonun altına ayrı çizilir."},{"q":"Bir öğrenci 's 2, p 6, d 10' diye ezberledi. Sıradaki 'f' kaç olmalıdır ve neden?","steps":[{"t":"Örüntüyü gör","a":"4'er artış","d":"2, 6, 10 sayıları 4'er artar; bir sonraki 14 olmalıdır."},{"t":"f değeri","a":"14 elektron","d":"Bu örüntüye göre <b>f</b>, 14 elektron alır."}],"ans":"Örüntü 4'er arttığı için s 2, p 6, d 10, f ise 14 elektron alır."},{"q":"Atomda en büyük 'kat' olan f dolarken neden çok sayıda komşu element ortaya çıkar?","steps":[{"t":"Çok yer var","a":"14 elektron","d":"f katı 14 elektron aldığından, dolması için 14 farklı elemente ihtiyaç olur."},{"t":"Sıra elementleri","a":"14 element","d":"Bu yüzden f dolarken birbirine çok benzeyen <b>14 element</b> bir sıra oluşturur."}],"ans":"f katı 14 elektron aldığından, dolması sırasında birbirine benzeyen 14 element ortaya çıkar ve bir sıra oluşturur."},{"q":"İki sıranın biri 'kâğıt çağı' (4f), diğeri 'maden çağı' (5f) gibi düşünülürse, bunların ortak yönü nedir?","steps":[{"t":"İki büyük sıra","a":"alttaki iki sıra","d":"Tablonun altında 4f ve 5f ile dolan iki uzun sıra vardır."},{"t":"Ortak yön","a":"ikisi de f doldurur","d":"İkisinin de ortak yönü, atomun en büyük katı olan <b>f</b>'yi (her biri 14 elektron) doldurmasıdır."}],"ans":"İki sıranın ortak yönü, ikisinin de atomun en büyük katı f'yi (her biri 14 elektronluk) doldurmasıdır."}]},"ortaokul":{"kolay":[{"q":"f alt kabuğu en fazla kaç elektron alır?","steps":[{"t":"Örüntü","a":"s2 p6 d10 f14","d":"Alt kabuk kapasiteleri s=2, p=6, d=10 şeklinde 4'er artar; sıradaki f=14'tür."},{"t":"Sonuç","a":"14 elektron","d":"f alt kabuğunda 7 orbital bulunur, her biri 2 elektron alır; toplam <b>14</b> elektron."}],"ans":"f alt kabuğu en fazla 14 elektron alır (7 orbital × 2 elektron)."},{"q":"Periyodik tablonun altındaki iki sıraya genel olarak ne ad verilir?","steps":[{"t":"İki sıra","a":"lantanit ve aktinit","d":"Üstteki sıra lantanitler, alttaki sıra aktinitler olarak adlandırılır."},{"t":"Ortak ad","a":"iç geçiş elementleri","d":"Bu iki sıraya birlikte <b>iç geçiş elementleri</b> (f bloku) denir."}],"ans":"Bu iki sıraya lantanitler ve aktinitler denir; ikisine birden iç geçiş elementleri (f bloku) adı verilir."},{"q":"Lantanitlerde dolan alt kabuk hangisidir?","steps":[{"t":"Lantanit sırası","a":"6. periyot altı","d":"Lantanitler periyodik tablonun altındaki birinci sırayı oluşturur."},{"t":"Dolan kabuk","a":"4f","d":"Bu elementlerde elektronlar <b>4f</b> alt kabuğuna yerleşir."}],"ans":"Lantanitlerde 4f alt kabuğu dolar."},{"q":"Aktinitlerde dolan alt kabuk hangisidir?","steps":[{"t":"Aktinit sırası","a":"7. periyot altı","d":"Aktinitler periyodik tablonun altındaki ikinci sırayı oluşturur."},{"t":"Dolan kabuk","a":"5f","d":"Bu elementlerde elektronlar <b>5f</b> alt kabuğuna yerleşir."}],"ans":"Aktinitlerde 5f alt kabuğu dolar."},{"q":"f alt kabuğunda kaç orbital vardır?","steps":[{"t":"Kapasite","a":"14 elektron","d":"f alt kabuğu en fazla 14 elektron alır."},{"t":"Orbital sayısı","a":"7 orbital","d":"Her orbital 2 elektron aldığından 14 ÷ 2 = <b>7 orbital</b> vardır."}],"ans":"f alt kabuğunda 7 orbital bulunur; her biri 2 elektron taşır."}],"zor":[{"q":"Neden 4f ve 5f alt kabuklarıyla dolan elementler ana tablodan ayrı, altta gösterilir?","steps":[{"t":"Çok sayıda element","a":"her sıra 14 element","d":"f 14 elektron aldığından, her f sırası 14 elemente karşılık gelir."},{"t":"Yer kazanmak için","a":"alta taşınır","d":"Bu 14'er element ana tabloya yerleştirilse tablo çok genişler; bu yüzden 4f ve 5f sıraları <b>tablonun altına</b> taşınır."}],"ans":"Her f sırası 14 element içerdiğinden tabloyu çok genişletir; bu nedenle 4f (lantanit) ve 5f (aktinit) sıraları ana tablonun altına ayrı çizilir."},{"q":"Lantanitler ve aktinitlerin kimyasal özellikleri neden birbirine çok benzer?","steps":[{"t":"İç kabuğun dolması","a":"4f / 5f iç kabuk","d":"Bu elementlerde elektronlar dıştaki kabuğa değil, daha içte kalan 4f veya 5f alt kabuğuna eklenir."},{"t":"Değerlik aynı kalır","a":"dış kabuk değişmez","d":"Dış (değerlik) kabuk neredeyse aynı kaldığından, kimyasal davranışları <b>çok benzer</b> olur."}],"ans":"Elektronlar dış kabuğa değil iç 4f/5f kabuğuna eklendiğinden değerlik kabuğu hemen hemen sabit kalır; bu yüzden lantanit ve aktinitlerin özellikleri birbirine çok benzer."},{"q":"Bir periyotta f bloku doldurulduğunda kaç element sıralanır ve neden?","steps":[{"t":"f kapasitesi","a":"14 elektron","d":"f alt kabuğu 14 elektron alır."},{"t":"Element sayısı","a":"14 element","d":"Her yeni elektron yeni bir elemente karşılık geldiğinden, f bloku <b>14 element</b> içerir."}],"ans":"f bloku 14 elektron aldığından, doldurulurken 14 element sıralanır."},{"q":"4f ve 5f alt kabukları arasındaki temel fark nedir?","steps":[{"t":"Baş kuantum sayısı","a":"n farkı","d":"4f'te ana enerji düzeyi 4, 5f'te ise 5'tir; 5f daha yüksek (dış) bir düzeydedir."},{"t":"Element grupları","a":"lantanit / aktinit","d":"4f lantanitlerde, 5f ise <b>aktinitlerde</b> dolar; aktinitlerin birçoğu radyoaktiftir."}],"ans":"4f, ana düzeyi 4 olan lantanitlerde; 5f ise ana düzeyi 5 olan aktinitlerde dolar. 5f daha dış bir düzeydir ve aktinitlerin çoğu radyoaktiftir."},{"q":"İç geçiş elementleri adı nereden gelir?","steps":[{"t":"Geçiş elementi","a":"d bloku","d":"d alt kabuğunun dolduğu elementlere geçiş elementleri denir."},{"t":"İç kısımda dolma","a":"f kabuğu","d":"f elementlerinde dolan kabuk daha <b>içte</b> (4f/5f) kaldığından bunlara iç geçiş elementleri denir."}],"ans":"d bloku geçiş elementleridir; f bloğunda dolan kabuk daha içte (4f/5f) kaldığı için bu elementlere iç geçiş elementleri denir."}]},"lise":{"kolay":[{"q":"f alt kabuğunun orbital sayısı ve elektron kapasitesi nedir?","steps":[{"t":"Manyetik kuantum sayısı","a":"ℓ = 3, mℓ = −3…+3","d":"f için yan kuantum sayısı ℓ = 3'tür; mℓ değerleri −3, −2, −1, 0, +1, +2, +3 olmak üzere 7 tanedir."},{"t":"Kapasite","a":"7 orbital, 14 elektron","d":"7 orbitalin her biri 2 elektron alır; f alt kabuğu en fazla <b>14 elektron</b> taşır."}],"ans":"f alt kabuğunda 7 orbital vardır (ℓ = 3) ve en fazla 14 elektron alır.","fig":"<svg viewBox='0 0 360 110'><text x='10' y='30' font-size='13' fill='#1a2b45'>f alt kabuğu (7 orbital)</text><rect x='14' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='62' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='110' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='158' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='206' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='254' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='302' y='44' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='180' y='98' font-size='12' text-anchor='middle' fill='#2b6be0'>7 × 2 = 14 elektron</text></svg>"},{"q":"Lantanitler ve aktinitler periyodik tabloda hangi blokta ve hangi periyotlarda yer alır?","steps":[{"t":"Blok","a":"f bloku","d":"Her iki seri de son elektronun f alt kabuğuna yerleştiği f blokunda yer alır."},{"t":"Periyotlar","a":"6. ve 7. periyot","d":"Lantanitler 6. periyotta (4f), aktinitler 7. periyotta (5f) bulunur; tabloda <b>altta iki ayrı sıra</b> olarak gösterilir."}],"ans":"Lantanitler 6. periyot 4f, aktinitler 7. periyot 5f elementleridir; ikisi de f blokundadır ve tablonun altında iki ayrı sıra olarak gösterilir.","fig":"<svg viewBox='0 0 360 140'><rect x='20' y='14' width='320' height='44' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='180' y='40' font-size='13' text-anchor='middle' fill='#1a2b45'>Ana periyodik tablo</text><rect x='40' y='80' width='280' height='20' fill='none' stroke='#e0552b' stroke-width='2'/><text x='180' y='95' font-size='11' text-anchor='middle' fill='#e0552b'>Lantanitler (4f) — 14 element</text><rect x='40' y='106' width='280' height='20' fill='none' stroke='#2b6be0' stroke-width='2'/><text x='180' y='121' font-size='11' text-anchor='middle' fill='#2b6be0'>Aktinitler (5f) — 14 element</text></svg>"},{"q":"Lantanitlerde dolan alt kabuk hangisidir ve kaç element içerir?","steps":[{"t":"Dolan kabuk","a":"4f","d":"Lantanitlerde (La'dan sonra Ce → Lu) elektronlar 4f alt kabuğuna eklenir."},{"t":"Element sayısı","a":"14 element","d":"4f 14 elektron aldığından, bu seri <b>14 element</b> içerir."}],"ans":"Lantanitlerde 4f alt kabuğu dolar ve seri 14 element içerir."},{"q":"Aktinitlerin birçoğunun ortak fiziksel özelliği nedir?","steps":[{"t":"Seri","a":"5f elementleri","d":"Aktinitler 7. periyotta 5f alt kabuğunun dolduğu elementlerdir."},{"t":"Özellik","a":"radyoaktiflik","d":"Uranyumdan sonraki aktinitlerin tamamı ve birçoğu <b>radyoaktiftir</b>; bazıları yapay olarak elde edilir."}],"ans":"Aktinitlerin birçoğu radyoaktiftir; uranyum ötesi elementler genellikle yapay olarak üretilir."},{"q":"Sezyumdan sonra gelen elementlerde 4f alt kabuğunun dolmaya başlamasının nedeni Aufbau'a göre nedir?","steps":[{"t":"Enerji sırası","a":"6s < 4f < 5d","d":"Aufbau'a göre 6s dolduktan sonra enerjisi düşük olan 4f alt kabuğu dolmaya başlar."},{"t":"Sonuç","a":"4f doldurma","d":"Bu yüzden 6. periyotta lantan sonrası elementlerde elektronlar <b>4f</b> alt kabuğuna yerleşir."}],"ans":"Aufbau enerji sırasına göre 6s'ten sonra 4f gelir; bu nedenle 6. periyotta lantan sonrası elementlerde 4f alt kabuğu dolmaya başlar."}],"zor":[{"q":"f alt kabuğunun 14 elektron kapasitesini kuantum sayılarıyla (ℓ, mℓ, mₛ) gerekçelendirin.","steps":[{"t":"Yan kuantum sayısı","a":"ℓ = 3","d":"f orbitali için ℓ = 3'tür; mℓ değerleri −ℓ'den +ℓ'ye 7 farklı değer alır (−3, −2, −1, 0, +1, +2, +3)."},{"t":"Spin ile çarpım","a":"7 × 2 = 14","d":"Her mℓ değerine (orbitale) Pauli ilkesine göre mₛ = +1/2 ve −1/2 olan 2 elektron sığar; 7 orbital × 2 = <b>14 elektron</b>."}],"ans":"f için ℓ = 3 olduğundan 7 farklı mℓ (orbital) vardır; her orbital 2 elektron aldığından f alt kabuğu 7 × 2 = 14 elektron alır."},{"q":"Lantanit ve aktinitlerin tek bir grup hücresine (3B grubu civarına) sıkıştırılıp tablonun altında gösterilmesinin elektron dizilimiyle ilişkisini açıklayın.","steps":[{"t":"İç kabuğun dolması","a":"4f / 5f iç kabuk","d":"Bu elementlerde son elektron dış değerlik kabuğuna değil, bir alt enerji düzeyindeki 4f veya 5f alt kabuğuna eklenir."},{"t":"Benzer değerlik","a":"aynı blok hücresi","d":"Dış kabuk neredeyse sabit kaldığından kimyasal özellikleri çok benzer; bu nedenle ana tabloda <b>tek bir hücreye</b> karşılık gelirler ve detayları altta gösterilir."}],"ans":"Elektronlar iç 4f/5f kabuğuna eklendiğinden değerlik kabuğu hemen hemen sabit kalır ve özellikleri çok benzeşir; bu yüzden 14'er element ana tabloda tek hücreye karşılık gelir ve ayrıntıları altta iki sıra olarak gösterilir."},{"q":"4f ve 5f alt kabuklarının dolma sırasını Aufbau enerji sıralamasına (n + ℓ kuralına) dayanarak açıklayın.","steps":[{"t":"n + ℓ değerleri","a":"4f: 7, 5f: 8","d":"4f için n + ℓ = 4 + 3 = 7; 5f için n + ℓ = 5 + 3 = 8'dir. Küçük n + ℓ önce dolar."},{"t":"Doldurma sırası","a":"6s→4f, 7s→5f","d":"6. periyotta 6s'ten sonra 4f (n + ℓ = 7), 7. periyotta 7s'ten sonra 5f (n + ℓ = 8) dolmaya başlar; eşit n + ℓ'de küçük n önce gelir."}],"ans":"n + ℓ kuralına göre 4f'in toplamı 7, 5f'in 8'dir; bu yüzden 4f (6. periyot, lantanitler) 5f'ten (7. periyot, aktinitler) önce dolmaya başlar."},{"q":"Lantanit daralması (lantanit büzülmesi) nedir ve f orbitalinin perdeleme özelliğiyle nasıl ilişkilidir?","steps":[{"t":"4f perdelemesi zayıf","a":"yetersiz perdeleme","d":"4f orbitalleri yayvan ve içte olduğundan çekirdek yükünü dış elektronlardan yeterince perdeleyemez."},{"t":"Yarıçap azalması","a":"lantanit daralması","d":"Lantanit serisi boyunca etkin çekirdek yükü kademeli arttığından atom ve iyon yarıçapları beklenenden fazla küçülür; buna <b>lantanit daralması</b> denir."}],"ans":"4f elektronları çekirdek yükünü zayıf perdelediğinden, lantanit serisi boyunca etkin çekirdek yükü artar ve atom/iyon yarıçapları kademeli olarak küçülür; bu olaya lantanit daralması denir."},{"q":"Aktinitlerde 5f ve 6d enerjilerinin yakınlığının, bu elementlerin değişken yükseltgenme basamaklarına etkisini açıklayın.","steps":[{"t":"Enerji yakınlığı","a":"5f ≈ 6d","d":"Aktinitlerde 5f ve 6d alt kabuklarının enerjileri birbirine çok yakındır, elektronlar her ikisinden de kolayca alınıp verilebilir."},{"t":"Değişken basamaklar","a":"çok sayıda yükseltgenme basamağı","d":"Bu yakınlık nedeniyle aktinitler (örneğin U: +3, +4, +5, +6) <b>birden çok yükseltgenme basamağı</b> gösterir; lantanitlerde 4f daha içte olduğundan çoğunlukla +3 baskındır."}],"ans":"Aktinitlerde 5f ve 6d enerjileri çok yakın olduğundan elektronlar her iki kabuktan da kullanılabilir; bu da uranyum gibi elementlerde birden çok yükseltgenme basamağına (+3 ile +6) yol açar, oysa lantanitlerde 4f daha içte olduğu için genelde +3 baskındır."}]}},"iyonOlusumu":{"ilkokul":{"kolay":[{"q":"Bir atom dışarıdan elektron alırsa yükü ne olur? Basitçe düşün.","steps":[{"t":"Eksi taneler eklendi","a":"daha eksi","d":"Elektron eksi yüklüdür; atom fazladan eksi tane aldığında biraz eksi olur."},{"t":"Sonuç","a":"eksi (−) iyon","d":"Eksi yük kazanan atoma eksi yüklü tanecik (anyon) denir, tıpkı bir mıknatısın eksi ucu gibi."}],"ans":"Elektron alan atom eksi (−) yüklü bir iyon olur."},{"q":"Bir atom elektron verirse (kaybederse) yükü ne olur?","steps":[{"t":"Eksi tane gitti","a":"daha az eksi","d":"Atom eksi yüklü bir elektronunu kaybedince geride artı yük ağır basar."},{"t":"Sonuç","a":"artı (+) iyon","d":"Elektron veren atom artı (+) yüklü bir iyon olur."}],"ans":"Elektron veren atom artı (+) yüklü bir iyon olur."},{"q":"İyon ne demektir? En basit haliyle söyle.","steps":[{"t":"Yüklü tanecik","a":"artı ya da eksi","d":"İyon, elektron alıp vererek artı ya da eksi yük kazanmış atomdur."},{"t":"Nötr değil","a":"yüklü","d":"Normal atom yüksüzdür; iyon ise yük taşıyan bir tanecik gibidir."}],"ans":"İyon, elektron alıp vererek artı ya da eksi yük kazanmış atomdur."},{"q":"Sofra tuzundaki sodyum bir elektron verir. Sodyumun yükü ne olur?","steps":[{"t":"Bir elektron verdi","a":"eksi azaldı","d":"Sodyum bir tane eksi elektronunu verince artı yükü öne çıkar."},{"t":"Sonuç","a":"+1 yük","d":"Bir elektron veren atom +1 yüklü olur, yani Na⁺ olur."}],"ans":"Bir elektron veren sodyum +1 yüklü iyon (Na⁺) olur."},{"q":"İki zıt yüklü iyon (artı ve eksi) karşılaşınca ne olur?","fig":"<svg viewBox='0 0 320 150'><circle cx='95' cy='75' r='30' fill='#e0552b' stroke='#1a2b45'/><text x='95' y='80' font-size='18' text-anchor='middle' fill='#fff'>+</text><circle cx='225' cy='75' r='30' fill='#2b6be0' stroke='#1a2b45'/><text x='225' y='82' font-size='20' text-anchor='middle' fill='#fff'>−</text><line x1='125' y1='75' x2='195' y2='75' stroke='#1a2b45' stroke-dasharray='4 3'/><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>zıt yükler çekilir</text></svg>","steps":[{"t":"Zıt yük","a":"çekim","d":"Artı ve eksi yükler birbirini çeker, tıpkı mıknatısın zıt uçları gibi."},{"t":"Birleşme","a":"yapışırlar","d":"Bu çekim sayesinde iyonlar birbirine tutunup bir madde oluşturur."}],"ans":"Zıt yüklü iyonlar birbirini çeker ve birbirine tutunarak madde oluşturur."}],"zor":[{"q":"Bir atom 2 elektron verirse yükü kaç olur?","steps":[{"t":"İki eksi gitti","a":"+2","d":"Her verilen elektron atomu bir basamak daha artı yapar; 2 elektron verince +2 olur."},{"t":"Örnek","a":"Ca → Ca²⁺","d":"Kalsiyum 2 elektron verince Ca²⁺ (+2 yüklü iyon) olur."}],"ans":"2 elektron veren atom +2 yüklü (örneğin Ca²⁺) iyon olur."},{"q":"Klor atomu bir elektron alır. Klorun yükü ne olur?","steps":[{"t":"Bir elektron aldı","a":"eksi arttı","d":"Klor dışarıdan bir eksi elektron alınca eksi yük öne çıkar."},{"t":"Sonuç","a":"−1 yük","d":"Bir elektron alan klor −1 yüklü olur, yani Cl⁻ olur."}],"ans":"Bir elektron alan klor −1 yüklü iyon (Cl⁻) olur."},{"q":"Metaller (demir, sodyum gibi) genelde elektron mu alır yoksa verir mi?","steps":[{"t":"Metal davranışı","a":"verir","d":"Metaller elektronlarını kolayca verir; bu yüzden çoğunlukla artı yük kazanır."},{"t":"Sonuç","a":"artı iyon","d":"Elektron veren metaller artı (+) yüklü iyon olur."}],"ans":"Metaller genelde elektron verir ve artı (+) yüklü iyon olur."},{"q":"Ametaller (klor, oksijen gibi) genelde elektron mu alır yoksa verir mi?","steps":[{"t":"Ametal davranışı","a":"alır","d":"Ametaller dışarıdan elektron almayı sever; bu yüzden eksi yük kazanır."},{"t":"Sonuç","a":"eksi iyon","d":"Elektron alan ametaller eksi (−) yüklü iyon olur."}],"ans":"Ametaller genelde elektron alır ve eksi (−) yüklü iyon olur."},{"q":"Sodyum (+1) ile klor (−1) birleşince ne oluşur?","fig":"<svg viewBox='0 0 320 150'><circle cx='95' cy='70' r='28' fill='#e0552b' stroke='#1a2b45'/><text x='95' y='75' font-size='13' text-anchor='middle' fill='#fff'>Na⁺</text><circle cx='225' cy='70' r='28' fill='#2b6be0' stroke='#1a2b45'/><text x='225' y='75' font-size='13' text-anchor='middle' fill='#fff'>Cl⁻</text><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>NaCl (tuz)</text></svg>","steps":[{"t":"Yük dengesi","a":"+1 ve −1","d":"+1 yüklü sodyum ile −1 yüklü klor birbirini tam dengeler."},{"t":"Birleşme","a":"tuz","d":"Bu iki iyon birbirine tutunarak yemek tuzunu (NaCl) oluşturur."}],"ans":"Sodyum (+1) ile klor (−1) birleşip yemek tuzunu (NaCl) oluşturur."}]},"ortaokul":{"kolay":[{"q":"İyon nasıl oluşur? Temel olarak açıkla.","steps":[{"t":"Elektron alışverişi","a":"al ya da ver","d":"Atom kararlı olmak için son katmanını doldurmak ister; bunun için elektron alır ya da verir."},{"t":"Yük oluşumu","a":"iyon","d":"Elektron sayısı proton sayısından farklı olunca atom yük kazanır ve iyona dönüşür."}],"ans":"Atom elektron alıp vererek elektron–proton dengesini bozar ve yüklü iyon hâline gelir."},{"q":"Katyon nedir, hangi yüke sahiptir?","steps":[{"t":"Elektron verme","a":"e⁻ kaybı","d":"Bir atom elektron verdiğinde elektron sayısı azalır, proton sayısı sabit kalır."},{"t":"Artı yük","a":"katyon (+)","d":"Proton fazla geldiği için atom artı yüklü olur; bu artı iyona katyon denir."}],"ans":"Katyon, elektron vererek artı (+) yük kazanmış iyondur."},{"q":"Anyon nedir, hangi yüke sahiptir?","steps":[{"t":"Elektron alma","a":"e⁻ kazancı","d":"Bir atom elektron aldığında elektron sayısı proton sayısından fazla olur."},{"t":"Eksi yük","a":"anyon (−)","d":"Elektron fazla olduğu için atom eksi yüklü olur; bu eksi iyona anyon denir."}],"ans":"Anyon, elektron alarak eksi (−) yük kazanmış iyondur."},{"q":"Genelde metaller katyon mu yoksa anyon mu oluşturur?","steps":[{"t":"Metalin davranışı","a":"e⁻ verir","d":"Metallerin son katmanında az elektron vardır; bunları vermek onlara kolaydır."},{"t":"Sonuç","a":"katyon","d":"Elektron veren metaller artı yüklü katyon oluşturur (Na⁺, Mg²⁺ gibi)."}],"ans":"Metaller elektron vererek katyon (artı yüklü iyon) oluşturur."},{"q":"Magnezyum atomu 2 elektron verirse yükü ve gösterimi nasıl olur?","steps":[{"t":"Verilen elektron","a":"2 e⁻","d":"Magnezyum son katmanındaki 2 elektronu verir."},{"t":"Yük","a":"+2","d":"2 elektron kaybı +2 yük demektir; iyon Mg²⁺ olarak yazılır."}],"ans":"2 elektron veren magnezyum +2 yüklü olur ve Mg²⁺ ile gösterilir."}],"zor":[{"q":"Oksijen atomunun 8 elektronu vardır. Kaç elektron alıp hangi yükü kazanır?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='85' r='30' fill='none' stroke='#1a2b45'/><circle cx='160' cy='85' r='58' fill='none' stroke='#1a2b45'/><circle cx='160' cy='55' r='4' fill='#2b6be0'/><circle cx='160' cy='115' r='4' fill='#2b6be0'/><circle cx='160' cy='27' r='4' fill='#2b6be0'/><circle cx='160' cy='143' r='4' fill='#2b6be0'/><circle cx='102' cy='85' r='4' fill='#2b6be0'/><circle cx='218' cy='85' r='4' fill='#2b6be0'/><circle cx='120' cy='50' r='4' fill='#16a34a'/><circle cx='200' cy='50' r='4' fill='#16a34a'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>son katman: 6 e⁻, 2 e⁻ alır</text></svg>","steps":[{"t":"Son katman","a":"6 e⁻","d":"Oksijenin son katmanında 6 elektron vardır; 8'e (oktete) ulaşmak için 2 elektrona ihtiyacı var."},{"t":"Yük","a":"−2","d":"2 elektron alınca elektron sayısı protondan 2 fazla olur, yük −2 olur (O²⁻)."}],"ans":"Oksijen 2 elektron alarak oktete ulaşır ve −2 yüklü O²⁻ iyonu olur."},{"q":"Bir atomun proton sayısı 11, elektron sayısı 10 ise yükü nedir?","steps":[{"t":"Yük hesabı","a":"p − e","d":"İyonun yükü = proton sayısı − elektron sayısı = 11 − 10 = +1 bulunur."},{"t":"Yorum","a":"katyon","d":"Elektron sayısı protondan az olduğu için atom artı yüklü katyondur (Na⁺ gibi)."}],"ans":"Yük = 11 − 10 = +1; bu atom +1 yüklü katyondur."},{"q":"Alüminyum (13 proton) 3 elektron verince yükü ve oktet durumu ne olur?","steps":[{"t":"Verilen elektron","a":"3 e⁻","d":"Alüminyumun son katmanında 3 elektron vardır; bunları verir."},{"t":"Sonuç","a":"Al³⁺, oktet tamam","d":"3 elektron kaybıyla yük +3 olur (Al³⁺) ve bir önceki dolu katman ortaya çıkıp oktet sağlanır."}],"ans":"Alüminyum 3 elektron vererek Al³⁺ olur ve dolu katmana inerek oktete ulaşır."},{"q":"Atomların elektron alıp verme amacı (oktet kuralı) nedir?","steps":[{"t":"Hedef","a":"son katman dolu","d":"Atomlar, soygazlar gibi son katmanında 8 elektron (oktet) bulundurup kararlı olmak ister."},{"t":"Yol","a":"al/ver","d":"Bu kararlılığı sağlamak için en yakın oktete ulaşacak şekilde elektron alır ya da verir."}],"ans":"Atomlar son katmanlarını 8 elektrona (oktete) tamamlayıp kararlı olmak için elektron alıp verir."},{"q":"Florun yükü −1, kalsiyumun yükü +2'dir. Kararlı bileşik oluşturmak için kaç florun bir kalsiyuma gerektiğini bul.","steps":[{"t":"Yük dengesi","a":"toplam = 0","d":"Bileşik nötr olmalı; artı ve eksi yüklerin toplamı sıfır olmalıdır."},{"t":"Oran","a":"1 Ca, 2 F","d":"Bir Ca²⁺ (+2) için iki F⁻ (her biri −1) gerekir; 2·(−1) + (+2) = 0 olur (CaF₂)."}],"ans":"Bir Ca²⁺ için iki F⁻ gerekir; bileşik CaF₂'dir (toplam yük sıfır)."}]},"lise":{"kolay":[{"q":"İyonlaşmada bir atomun yükü nasıl hesaplanır?","steps":[{"t":"Tanım","a":"yük = p⁺ − e⁻","d":"İyon yükü, proton sayısı ile elektron sayısının farkına eşittir."},{"t":"İşaret","a":"+ ya da −","d":"e⁻ < p⁺ ise yük artı (katyon), e⁻ > p⁺ ise yük eksi (anyon) olur."}],"ans":"İyon yükü = proton sayısı − elektron sayısı; elektron eksikse +, fazlaysa − çıkar."},{"q":"Bir element neden katyon, bir başkası neden anyon oluşturmaya eğilimlidir?","steps":[{"t":"İyonlaşma enerjisi","a":"metalde düşük","d":"Metallerin değerlik elektronu zayıf bağlıdır; düşük enerjiyle elektron vererek katyon olur."},{"t":"Elektron ilgisi","a":"ametalde yüksek","d":"Ametaller dışarıdan elektron çekme eğilimindedir (yüksek elektron ilgisi); elektron alıp anyon olur."}],"ans":"Düşük iyonlaşma enerjili metaller elektron verip katyon, yüksek elektron ilgili ametaller elektron alıp anyon oluşturur."},{"q":"Sodyumun (₁₁Na) elektron dizilimi 2,8,1'dir. Hangi iyonu oluşturur?","steps":[{"t":"Değerlik","a":"1 e⁻","d":"Son katmanında tek elektron vardır; bunu vermek oktete ulaşmanın en kolay yoludur."},{"t":"İyon","a":"Na⁺","d":"1 elektron verince geride 2,8 dizilimi (neon oktetine benzer) kalır ve Na⁺ oluşur."}],"ans":"Sodyum 1 değerlik elektronunu vererek Na⁺ katyonu oluşturur ve oktete ulaşır."},{"q":"Kükürt (₁₆S) elektron dizilimi 2,8,6'dır. Hangi iyonu oluşturur?","steps":[{"t":"Eksik elektron","a":"2 e⁻","d":"Son katmanda 6 elektron vardır; oktete (8) ulaşmak için 2 elektrona ihtiyaç duyar."},{"t":"İyon","a":"S²⁻","d":"2 elektron alınca son katman 8 olur ve −2 yüklü S²⁻ anyonu oluşur."}],"ans":"Kükürt 2 elektron alarak S²⁻ anyonu oluşturur ve oktete ulaşır."},{"q":"Soygazlar neden kolay kolay iyon oluşturmaz?","steps":[{"t":"Dolu katman","a":"oktet hazır","d":"Soygazların son katmanı zaten 8 elektronla (helyumda 2) doludur, yani kararlıdır."},{"t":"Eğilim yok","a":"al/ver gerekmez","d":"Kararlı oldukları için elektron alıp verme eğilimleri çok düşüktür; iyon oluşturmaları zordur."}],"ans":"Soygazların son katmanı dolu (oktet) ve kararlı olduğundan elektron alıp verme eğilimleri yoktur, iyon oluşturmazlar."}],"zor":[{"q":"Bir iyonun proton sayısı 20, kütle numarası 40 ve yükü +2 ise nötron ve elektron sayısı kaçtır?","steps":[{"t":"Nötron","a":"40 − 20 = 20","d":"Nötron sayısı = kütle numarası − proton sayısı = 40 − 20 = 20 bulunur."},{"t":"Elektron","a":"20 − 2 = 18","d":"+2 yük, atomun 2 elektron verdiğini gösterir; elektron = proton − yük = 20 − 2 = 18 olur."}],"ans":"Nötron sayısı 20, elektron sayısı 18'dir (Ca²⁺)."},{"q":"Mg²⁺ ile O²⁻ neden 1:1 oranında birleşir, ama Mg²⁺ ile Cl⁻ neden 1:2 oranında birleşir?","steps":[{"t":"Yük denkliği ilkesi","a":"toplam yük = 0","d":"İyonik bileşik nötr olmalı; katyon ve anyonun toplam yükü sıfıra eşitlenir."},{"t":"Oran çıkarımı","a":"1:1 ve 1:2","d":"Mg²⁺ (+2) ile O²⁻ (−2) tek tek dengelenir (MgO). Mg²⁺ (+2) için iki Cl⁻ (−1) gerekir (MgCl₂)."}],"ans":"Yük denkliği gereği Mg²⁺ ve O²⁻ 1:1 (MgO), Mg²⁺ ve Cl⁻ 1:2 (MgCl₂) oranında birleşir."},{"q":"Demir hem Fe²⁺ hem Fe³⁺ iyonu oluşturabilir. Bu durumun nedeni nedir?","steps":[{"t":"Geçiş metali","a":"d orbitali","d":"Demir bir geçiş metalidir; hem 4s hem 3d orbitalindeki elektronlar değerliğe katılabilir."},{"t":"İki yük","a":"Fe²⁺ ve Fe³⁺","d":"4s²'deki 2 elektronu verirse Fe²⁺, ayrıca 3d'den 1 elektron daha verirse Fe³⁺ oluşur; bu yüzden birden çok yükü vardır."}],"ans":"Demir geçiş metali olduğundan 4s ve 3d elektronlarını farklı sayıda verebilir; bu nedenle hem Fe²⁺ hem Fe³⁺ oluşturur."},{"q":"Bir ametalin elektron alarak anyon oluşturması neden ekzotermik (enerji açığa çıkaran) bir süreçtir?","steps":[{"t":"Elektron ilgisi","a":"çekirdek çekimi","d":"Ametalin çekirdeği, gelen elektronu güçlü çeker; bu çekim kararlılık (düşük enerji) sağlar."},{"t":"Enerji salınımı","a":"ekzotermik","d":"Daha kararlı, daha düşük enerjili anyon oluşurken fark enerji olarak dışarı verilir, süreç ekzotermiktir."}],"ans":"Ametal çekirdeği gelen elektronu çekip daha kararlı (düşük enerjili) bir anyon oluşturduğundan, fark enerji açığa çıkar; süreç ekzotermiktir."},{"q":"Ardışık iyonlaşma enerjileri 738; 1451; 7733 kJ/mol olan bir elementin hangi grupta olduğunu açıkla.","steps":[{"t":"Sıçramayı bul","a":"3. enerjide büyük artış","d":"2. ve 3. iyonlaşma enerjisi arasında çok büyük bir sıçrama vardır (1451 → 7733)."},{"t":"Değerlik yorumu","a":"2 değerlik e⁻","d":"Büyük sıçramadan önce 2 elektron rahat koparılır; bu, değerlik elektron sayısının 2 olduğunu, yani elementin 2A grubunda (Mg gibi) olduğunu gösterir."}],"ans":"3. iyonlaşmadaki büyük sıçrama 2 değerlik elektronu gösterir; element 2A grubundadır (örneğin Mg, Mg²⁺ oluşturur)."}]}},"katmanDizilimi":{"ilkokul":{"kolay":[{"q":"Elektronlar atomda çekirdeğin çevresinde nereye dizilir?","fig":"<svg viewBox='0 0 300 170'><circle cx='150' cy='85' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='85' r='32' fill='none' stroke='#1a2b45'/><circle cx='150' cy='85' r='58' fill='none' stroke='#1a2b45'/><circle cx='182' cy='85' r='5' fill='#2b6be0'/><circle cx='150' cy='27' r='5' fill='#2b6be0'/><text x='150' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>katmanlar</text></svg>","steps":[{"t":"Çevredeki halkalar","a":"katmanlar","d":"Elektronlar çekirdeğin çevresindeki katman denilen halkalara yerleşir."},{"t":"Sıra","a":"içten dışa","d":"Önce içteki katman dolar, sonra dıştaki katmana geçilir."}],"ans":"Elektronlar çekirdeğin çevresindeki katmanlara içten dışa doğru sırayla dizilir."},{"q":"Çekirdeğe en yakın ilk katmana en çok kaç elektron sığar?","steps":[{"t":"İlk katman","a":"en içteki","d":"Çekirdeğe en yakın katman ilk dolan katmandır."},{"t":"Kapasite","a":"2 elektron","d":"Bu ilk katmana en çok 2 elektron yerleşir."}],"ans":"Çekirdeğe en yakın ilk katmana en çok 2 elektron sığar."},{"q":"İkinci katmana en çok kaç elektron sığar?","steps":[{"t":"İkinci katman","a":"dıştaki halka","d":"İlk katman dolduktan sonra elektronlar ikinci katmana yerleşir."},{"t":"Kapasite","a":"8 elektron","d":"İkinci katmana en çok 8 elektron sığar."}],"ans":"İkinci katmana en çok 8 elektron sığar."},{"q":"En dış katmandaki elektronlara ne ad verilir?","steps":[{"t":"En dış katman","a":"dıştaki halka","d":"Atomun en dışındaki katmandaki elektronlar özeldir."},{"t":"Adı","a":"değerlik elektronu","d":"Bu elektronlara değerlik elektronu denir."}],"ans":"En dış katmandaki elektronlara değerlik elektronu denir."},{"q":"Bir atomun en dış katmanı tamamen dolu olduğunda atom nasıl olur?","fig":"<svg viewBox='0 0 300 170'><circle cx='150' cy='85' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='85' r='50' fill='none' stroke='#1a2b45'/><circle cx='200' cy='85' r='4' fill='#2b6be0'/><circle cx='100' cy='85' r='4' fill='#2b6be0'/><circle cx='150' cy='35' r='4' fill='#2b6be0'/><circle cx='150' cy='135' r='4' fill='#2b6be0'/><text x='150' y='162' font-size='11' text-anchor='middle' fill='#1a2b45'>dolu katman = kararlı</text></svg>","steps":[{"t":"Dış katman dolu","a":"tam","d":"En dış katman elektronla tamamen dolduğunda atom istediği duruma ulaşır."},{"t":"Durum","a":"kararlı","d":"Bu durumda atom kararlıdır, kolay kolay tepkimeye girmez."}],"ans":"En dış katmanı dolu olan atom kararlı (mutlu) hale gelir ve kolay tepkimeye girmez."}],"zor":[{"q":"8 elektronlu bir atomun katman dizilimi nasıldır?","steps":[{"t":"İlk katman","a":"2 elektron","d":"İlk katmana önce 2 elektron yerleşir."},{"t":"Kalan","a":"6 dışta","d":"Geriye kalan 6 elektron ikinci katmana yerleşir; dizilim 2, 6 olur."}],"ans":"8 elektronlu atomun dizilimi 2, 6'dır."},{"q":"Elektronlar katmanlara dizilirken hangi sırayı izler?","fig":"<svg viewBox='0 0 300 175'><circle cx='150' cy='90' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='90' r='30' fill='none' stroke='#1a2b45'/><circle cx='150' cy='90' r='56' fill='none' stroke='#1a2b45'/><text x='150' y='66' font-size='10' text-anchor='middle' fill='#1a2b45'>2</text><text x='150' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>8</text><text x='150' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>önce iç katman dolar</text></svg>","steps":[{"t":"İçten başla","a":"en yakın","d":"Elektronlar önce çekirdeğe en yakın katmana yerleşir."},{"t":"Dolunca geç","a":"sonra dışa","d":"İç katman (2) dolunca sonraki katmana (8) geçilir."}],"ans":"Elektronlar önce içteki katmanı doldurur, dolunca dıştaki katmana geçer (2, 8 ...)."},{"q":"Değerlik elektronu az olan bir atom kararlı olmak için ne yapar?","steps":[{"t":"Az değerlik","a":"1-2 elektron","d":"En dış katmanında 1-2 elektronu olan atom için bunları vermek kolaydır."},{"t":"Yol","a":"elektron verir","d":"Bu az elektronu vererek altındaki dolu katmanı en dış katman yapar ve kararlı olur."}],"ans":"Değerlik elektronu az olan atom, bu elektronları vererek kararlı (dolu dış katmanlı) hale gelir."},{"q":"Çoğu atom için kararlılık kaç değerlik elektronuyla sağlanır (oktet)?","steps":[{"t":"Hedef sayı","a":"8 elektron","d":"Çoğu atom en dış katmanında 8 elektron olunca kararlı olur."},{"t":"Adı","a":"oktet","d":"En dış katmanda 8 elektronla sağlanan bu kararlılığa oktet denir."}],"ans":"Çoğu atom en dış katmanında 8 elektronla (oktet) kararlı hale gelir."},{"q":"Hidrojen ve helyum gibi küçük atomlar kaç elektronla kararlı olur (dublet)?","steps":[{"t":"Küçük atom","a":"ilk katman","d":"Çok küçük atomlar yalnızca ilk katmanı kullanır; bu katmana en çok 2 elektron sığar."},{"t":"Adı","a":"dublet","d":"En dış katmanda 2 elektronla sağlanan kararlılığa dublet denir."}],"ans":"Hidrojen ve helyum gibi küçük atomlar en dış katmanlarında 2 elektronla (dublet) kararlı olur."}]},"ortaokul":{"kolay":[{"q":"İlk üç elektron katmanına en fazla kaçar elektron sığar?","fig":"<svg viewBox='0 0 300 180'><circle cx='150' cy='90' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='90' r='26' fill='none' stroke='#1a2b45'/><circle cx='150' cy='90' r='50' fill='none' stroke='#1a2b45'/><circle cx='150' cy='90' r='74' fill='none' stroke='#1a2b45'/><text x='150' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>2</text><text x='150' y='46' font-size='10' text-anchor='middle' fill='#1a2b45'>8</text><text x='150' y='22' font-size='10' text-anchor='middle' fill='#1a2b45'>8</text></svg>","steps":[{"t":"İlk katman","a":"2","d":"Birinci katmana en çok 2 elektron sığar."},{"t":"Sonraki ikisi","a":"8 ve 8","d":"İkinci ve üçüncü katmanlara (temel düzeyde) en çok 8'er elektron yerleşir."}],"ans":"İlk üç katmanın en çok kapasitesi sırasıyla 2, 8, 8 elektrondur."},{"q":"Değerlik elektronu nedir ve neden önemlidir?","steps":[{"t":"Tanım","a":"en dış katman e⁻","d":"Değerlik elektronu, atomun en dış katmanındaki elektronlardır."},{"t":"Önemi","a":"kimyasal davranış","d":"Atomun başka atomlarla nasıl birleşeceğini değerlik elektronları belirler."}],"ans":"Değerlik elektronu en dış katmandaki elektrondur; atomun kimyasal davranışını belirler."},{"q":"Oktet ve dublet kuralı arasındaki fark nedir?","steps":[{"t":"Oktet","a":"8 elektron","d":"Çoğu atom en dış katmanında 8 elektronla (oktet) kararlı olur."},{"t":"Dublet","a":"2 elektron","d":"H ve He gibi küçük atomlar en dış katmanlarında 2 elektronla (dublet) kararlı olur."}],"ans":"Oktet en dış katmanda 8, dublet ise 2 elektronla sağlanan kararlılıktır."},{"q":"Sodyum atomunun (11 elektron) katman dizilimi nasıldır?","fig":"<svg viewBox='0 0 300 185'><circle cx='150' cy='95' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='95' r='26' fill='none' stroke='#1a2b45'/><circle cx='150' cy='95' r='49' fill='none' stroke='#1a2b45'/><circle cx='150' cy='95' r='72' fill='none' stroke='#1a2b45'/><text x='150' y='76' font-size='10' text-anchor='middle' fill='#1a2b45'>2</text><text x='150' y='53' font-size='10' text-anchor='middle' fill='#1a2b45'>8</text><circle cx='222' cy='95' r='4' fill='#2b6be0'/><text x='150' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>Na: 2, 8, 1</text></svg>","steps":[{"t":"Dolum","a":"2 + 8","d":"İlk katmana 2, ikinci katmana 8 elektron yerleşir; toplam 10 olur."},{"t":"Kalan","a":"1 dışta","d":"Geriye kalan 1 elektron üçüncü katmana yerleşir; dizilim 2, 8, 1 olur."}],"ans":"Sodyumun (11 elektron) katman dizilimi 2, 8, 1'dir."},{"q":"Bir atomun değerlik elektronu sayısı 8 ise (en dış katman dolu) atom nasıl davranır?","steps":[{"t":"Dolu dış katman","a":"oktet sağlandı","d":"En dış katmanda 8 elektron varsa oktet zaten sağlanmıştır."},{"t":"Davranış","a":"tepkimeye girmez","d":"Atom kararlı olduğundan elektron alıp vermeye ihtiyaç duymaz; soygazlar buna örnektir."}],"ans":"En dış katmanı 8 elektronlu (oktet) atom kararlıdır ve genelde tepkimeye girmez (soygaz gibi)."}],"zor":[{"q":"19 elektronlu potasyumun katman dizilimi nasıldır ve değerlik elektronu kaçtır?","steps":[{"t":"Dolum","a":"2, 8, 8","d":"İlk üç katman 2 + 8 + 8 = 18 elektronla dolar."},{"t":"Kalan","a":"1 → değerlik","d":"Geriye 1 elektron kalır, 4. katmana yerleşir; dizilim 2, 8, 8, 1, değerlik elektronu 1'dir."}],"ans":"Potasyumun dizilimi 2, 8, 8, 1'dir; değerlik elektronu sayısı 1'dir."},{"q":"Sodyum (2, 8, 1) neden 1 elektron vererek kararlı olmayı tercih eder?","fig":"<svg viewBox='0 0 320 175'><circle cx='80' cy='85' r='7' fill='#e0552b'/><circle cx='80' cy='85' r='22' fill='none' stroke='#1a2b45'/><circle cx='80' cy='85' r='40' fill='none' stroke='#1a2b45'/><circle cx='120' cy='85' r='4' fill='#2b6be0'/><text x='80' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Na 2,8,1</text><line x1='150' y1='85' x2='200' y2='85' stroke='#1a2b45' stroke-width='2'/><polygon points='200,85 191,81 191,89' fill='#1a2b45'/><circle cx='250' cy='85' r='7' fill='#e0552b'/><circle cx='250' cy='85' r='22' fill='none' stroke='#1a2b45'/><text x='250' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Na⁺ 2,8</text></svg>","steps":[{"t":"Tek değerlik","a":"1 vermek kolay","d":"Sodyumun en dış katmanında 1 elektron vardır; bunu vermek 7 elektron almaktan çok daha kolaydır."},{"t":"Sonuç","a":"2, 8 oktet","d":"1 elektron verince alttaki dolu katman (2, 8) en dış katman olur ve oktete ulaşılır."}],"ans":"Sodyum tek değerlik elektronunu vererek alttaki dolu 2, 8 katmanını dış katman yapar ve kolayca oktete ulaşır."},{"q":"Bir atomun değerlik elektronu sayısı ile oluşturacağı iyon yükü arasında nasıl bir ilişki vardır?","steps":[{"t":"1-3 değerlik","a":"verir, (+)","d":"En dış katmanında 1, 2 veya 3 elektron olan atom bunları verme eğilimindedir ve +1, +2, +3 yüklü olur."},{"t":"5-7 değerlik","a":"alır, (−)","d":"En dış katmanında 5, 6, 7 elektron olan atom oktete tamamlamak için elektron alır; −3, −2, −1 yüklü olur."}],"ans":"Az değerlikli atom elektron verip artı, oktete yakın atom elektron alıp eksi yüklü olur; yük değerlik sayısıyla belirlenir."},{"q":"Klor (2, 8, 7) ve magnezyum (2, 8, 2) oktete ulaşmak için ne yapar?","steps":[{"t":"Klor","a":"1 e⁻ alır","d":"Klorun en dış katmanında 7 elektron vardır; 1 elektron alarak 2, 8, 8 oktetine ulaşır (Cl⁻)."},{"t":"Magnezyum","a":"2 e⁻ verir","d":"Magnezyumun en dış katmanında 2 elektron vardır; bunları vererek 2, 8 düzenine iner (Mg²⁺)."}],"ans":"Klor 1 elektron alarak Cl⁻ (2, 8, 8), magnezyum 2 elektron vererek Mg²⁺ (2, 8) olur; ikisi de oktete ulaşır."},{"q":"Aynı grupta yer alan Li, Na ve K'nin benzer davranmasının nedeni katman dizilimiyle nasıl açıklanır?","steps":[{"t":"Ortak değerlik","a":"hepsi 1","d":"Li (2, 1), Na (2, 8, 1), K (2, 8, 8, 1) hepsinin en dış katmanında 1 değerlik elektronu vardır."},{"t":"Aynı eğilim","a":"hepsi 1 e⁻ verir","d":"Hepsi bu tek elektronu verip kararlı düzene ulaşır; bu yüzden hepsi benzer biçimde +1 yüklü iyon oluşturur."}],"ans":"Li, Na, K'nin tümünün değerlik elektronu 1 olduğundan birini verip +1 yüklü iyon oluşturur; benzer davranışları katman diziliminden gelir."}]},"lise":{"kolay":[{"q":"Bir atomun katman (kabuk) elektron dağılımı hangi sırayla yapılır?","fig":"<svg viewBox='0 0 300 185'><circle cx='150' cy='95' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='150' cy='95' r='25' fill='none' stroke='#1a2b45'/><circle cx='150' cy='95' r='47' fill='none' stroke='#1a2b45'/><circle cx='150' cy='95' r='69' fill='none' stroke='#1a2b45'/><text x='150' y='78' font-size='9' text-anchor='middle' fill='#1a2b45'>K:2</text><text x='150' y='56' font-size='9' text-anchor='middle' fill='#1a2b45'>L:8</text><text x='150' y='34' font-size='9' text-anchor='middle' fill='#1a2b45'>M:8</text></svg>","steps":[{"t":"Düşük enerji","a":"içten dışa","d":"Elektronlar en düşük enerjili (çekirdeğe en yakın) katmandan başlayarak dışa doğru dizilir."},{"t":"Kapasite","a":"2, 8, 8","d":"K katmanına 2, L'ye 8, M'ye (temel düzeyde) 8 elektron sığacak şekilde sırayla doldurulur."}],"ans":"Elektronlar en düşük enerjili katmandan dışa doğru, 2, 8, 8 kapasitelerine göre sırayla dizilir."},{"q":"Değerlik elektronu sayısı ile bir atomun kimyasal davranışı arasında nasıl bir ilişki vardır?","steps":[{"t":"Değerlik sayısı","a":"dış katman e⁻","d":"En dış katmandaki elektron sayısı atomun elektron alma/verme eğilimini belirler."},{"t":"Eğilim","a":"oktete yakınlık","d":"Az değerlikli atomlar elektron vermeye (metalik), oktete yakınlar almaya (ametalik) eğilimlidir."}],"ans":"Değerlik elektronu sayısı atomun elektron alma/verme eğilimini ve dolayısıyla kimyasal davranışını belirler."},{"q":"Oktet kuralı nedir ve hangi atomlar için dublet geçerlidir?","steps":[{"t":"Oktet","a":"8 değerlik e⁻","d":"Atomlar en dış katmanlarında 8 elektrona ulaşarak soygaz düzenine (kararlılığa) erişme eğilimindedir."},{"t":"Dublet","a":"H, He","d":"Yalnız ilk katmanı kullanabilen küçük atomlar (H, He) 2 elektronla (dublet) kararlı olur."}],"ans":"Oktet en dış katmanda 8 elektronla kararlılıktır; H ve He gibi küçük atomlar için 2 elektronlu dublet geçerlidir."},{"q":"Baş grup (A grubu) elementlerinde değerlik elektronu ile grup numarası arasındaki ilişki nedir?","steps":[{"t":"İlişki","a":"grup = değerlik","d":"Baş gruplarda grup numarası, atomun değerlik elektronu sayısına eşittir."},{"t":"Örnek","a":"2A → 2 e⁻","d":"1A grubunun 1, 2A grubunun 2, 7A grubunun 7 değerlik elektronu vardır."}],"ans":"Baş gruplarda grup numarası değerlik elektronu sayısına eşittir; örneğin 2A grubunun 2 değerlik elektronu vardır."},{"q":"Kalsiyum (20 elektron) atomunun katman dağılımı nasıldır ve değerlik elektronu kaçtır?","steps":[{"t":"Dağılım","a":"2, 8, 8, 2","d":"20 elektron sırayla yerleşince 2 + 8 + 8 dolar, geriye 2 elektron kalır; dağılım 2, 8, 8, 2'dir."},{"t":"Değerlik","a":"2 elektron","d":"En dış katmanda (4. katman) 2 elektron vardır; değerlik elektronu sayısı 2'dir."}],"ans":"Kalsiyumun dağılımı 2, 8, 8, 2'dir; değerlik elektronu sayısı 2'dir."}],"zor":[{"q":"Sodyumun iyon oluşumunu katman dizilimi değişimiyle açıklayınız (Na → Na⁺).","fig":"<svg viewBox='0 0 320 175'><circle cx='80' cy='85' r='7' fill='#e0552b'/><circle cx='80' cy='85' r='20' fill='none' stroke='#1a2b45'/><circle cx='80' cy='85' r='38' fill='none' stroke='#1a2b45'/><circle cx='118' cy='85' r='4' fill='#2b6be0'/><text x='80' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Na: 2,8,1</text><line x1='150' y1='85' x2='200' y2='85' stroke='#1a2b45' stroke-width='2'/><polygon points='200,85 191,81 191,89' fill='#1a2b45'/><circle cx='250' cy='85' r='7' fill='#e0552b'/><circle cx='250' cy='85' r='20' fill='none' stroke='#1a2b45'/><text x='250' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Na⁺: 2,8</text></svg>","steps":[{"t":"Nötr dizilim","a":"2, 8, 1","d":"Nötr sodyumun dizilimi 2, 8, 1'dir; en dış katmanda 1 değerlik elektronu vardır."},{"t":"İyon dizilimi","a":"2, 8 → Na⁺","d":"1 elektron verince dizilim 2, 8 olur (neon düzeni); yük +1, yani Na⁺ olur."}],"ans":"Sodyum 1 elektron vererek dizilimini 2, 8, 1'den 2, 8'e indirir ve Na⁺ iyonu oluşturur."},{"q":"S²⁻ iyonu (kükürt 16 elektron) kaç elektrona sahiptir ve dizilimi nedir?","steps":[{"t":"Elektron sayısı","a":"16 + 2 = 18","d":"Kükürt 16 elektronludur; −2 yüklü olması 2 elektron aldığını gösterir, toplam 18 elektron olur."},{"t":"Dizilim","a":"2, 8, 8","d":"18 elektron 2, 8, 8 şeklinde dizilir; bu argon ile izoelektronik kararlı düzendir."}],"ans":"S²⁻ iyonu 18 elektrona sahiptir ve dizilimi 2, 8, 8'dir (argon düzeni)."},{"q":"Na⁺ ile Ne'nin izoelektronik olması ne anlama gelir?","steps":[{"t":"Tanım","a":"eşit elektron","d":"İzoelektronik tanecikler aynı elektron sayısı ve dizilimine sahiptir, proton sayıları farklı olabilir."},{"t":"Örnek","a":"Na⁺ ≡ Ne","d":"Na⁺ (10 elektron, 2, 8) ile Ne (10 elektron, 2, 8) aynı dizilime sahiptir; ikisi de izoelektroniktir."}],"ans":"Na⁺ ve Ne'nin ikisi de 10 elektronlu ve 2, 8 dizilimindedir; aynı elektron diziliminde olmaları onları izoelektronik yapar."},{"q":"2. periyot ametalleri N, O ve F oktete ulaşmak için kaç elektron alır?","steps":[{"t":"Değerlik eksiği","a":"8 − değerlik","d":"Bir ametalin alacağı elektron sayısı, oktete tamamlamak için gereken eksik kadardır (8 − değerlik)."},{"t":"Karşılaştırma","a":"N:3, O:2, F:1","d":"Azot (2, 5) 3, oksijen (2, 6) 2, flor (2, 7) 1 elektron alarak sırasıyla N³⁻, O²⁻, F⁻ oluşturur."}],"ans":"Her ametal oktete eksiği kadar elektron alır: N 3 (N³⁻), O 2 (O²⁻), F 1 (F⁻) elektron alır."},{"q":"Değerlik elektronu 4 olan karbon neden elektron alıp vermek yerine ortaklaşma (kovalent) eğilimindedir?","steps":[{"t":"Eşit zorluk","a":"4 ver/4 al zor","d":"4 değerlik elektronu için hem 4 elektron vermek hem 4 elektron almak enerjice çok güçtür."},{"t":"Çözüm","a":"ortaklaşma","d":"Karbon oktete ulaşmak için elektronları başka atomlarla paylaşır (kovalent bağ)."}],"ans":"4 değerlik elektronlu karbon, 4 elektron vermek de almak da çok zor olduğundan elektronları paylaşır (kovalent bağ kurar)."}]}},"kuantumSayilari":{"ilkokul":{"kolay":[{"q":"Bir okul binasında her öğrencinin sınıfı, sırası ve yeri bellidir. Atomda elektronların yerini de buna benzer sayılarla anlatabilir miyiz?","steps":[{"t":"Okul benzetmesi","a":"belli bir yer","d":"Okulda her öğrencinin kat, sınıf ve sıra numarası gibi belli bir yeri vardır."},{"t":"Atomda karşılığı","a":"sayılarla adres","d":"Atomda da elektronun yerini anlatan sayılar vardır; bunlara <b>kuantum sayıları</b> denir."}],"ans":"Evet; tıpkı bir öğrencinin okuldaki yerini sayılarla anlatmak gibi, elektronun yerini de kuantum sayılarıyla anlatırız."},{"q":"Çekirdeğe yakın bir basamakta duran elektron mu, yoksa uzak basamakta duran elektron mu çekirdeğe daha yakındır?","steps":[{"t":"Basamakları düşün","a":"yakın basamak","d":"Çekirdeğe yakın basamak, çekirdeğe daha yakın bölgedir."},{"t":"Karşılaştır","a":"yakındaki","d":"Yakın basamaktaki elektron, uzaktakinden çekirdeğe daha yakındır."}],"ans":"Çekirdeğe yakın basamaktaki elektron, uzak basamaktakinden çekirdeğe daha yakındır."},{"q":"İki elektronun yerinin ve durumunun tıpatıp aynı olması mümkün müdür?","steps":[{"t":"Adresi düşün","a":"herkese özel","d":"Bir sınıfta iki öğrenci aynı sıraya aynı anda oturamaz; herkesin yeri ayrıdır."},{"t":"Atomda kural","a":"aynı olamaz","d":"Atomda da iki elektronun tüm sayıları tıpatıp aynı olamaz."}],"ans":"Hayır; her elektronun durumu kendine özeldir, iki elektron tamamen aynı olamaz."},{"q":"Elektronlar küçük bir topaç gibi kendi etrafında döner diye düşünülür. Bu dönüş kaç farklı yönde olabilir?","steps":[{"t":"Topaç benzetmesi","a":"iki yön","d":"Bir topaç saat yönünde ya da tersine dönebilir; iki ayrı yön vardır."},{"t":"Elektron için","a":"iki dönüş","d":"Elektronun bu dönüşü de iki ayrı durumdan biri olabilir."}],"ans":"İki farklı yönde; elektronun dönüşü tıpkı bir topaç gibi iki durumdan biri olur."},{"q":"Bir apartmanda kat numarası bir aileyi bulmaya yarar. Atomda elektronun hangi katta (enerji basamağında) olduğunu söyleyen sayı en az kaç olur?","steps":[{"t":"İlk kat","a":"1. kat","d":"Çekirdeğe en yakın basamak 1. basamaktır, daha küçüğü yoktur."},{"t":"En küçük değer","a":"1","d":"Bu sayı 0 olamaz; en küçük değeri 1'dir."}],"ans":"Elektronun bulunduğu kat (enerji basamağı) en az 1 olur; sıfırıncı kat yoktur."}],"zor":[{"q":"Çekirdekten uzak basamak mı, yakın basamak mı daha geniştir ve daha çok elektron alır?","steps":[{"t":"Uzak basamak geniş","a":"uzak basamak","d":"Çekirdekten uzak basamaklar daha geniştir, daha çok yer içerir."},{"t":"Sonuç","a":"uzak çok alır","d":"Geniş olduğu için uzak basamak daha çok elektron alabilir."}],"ans":"Çekirdekten uzak basamak daha geniş olduğundan daha çok elektron alır."},{"q":"Bir orbital (elektronun evi) en fazla 2 elektron alıyorsa, bu iki elektronu birbirinden neyle ayırırız?","steps":[{"t":"Aynı ev","a":"iki elektron","d":"Bir orbitalde (elektronun evinde) en çok 2 elektron bulunur."},{"t":"Ayırt etme","a":"dönüş yönü","d":"Aynı evdeki iki elektron, ters dönüş yönleriyle birbirinden ayrılır."}],"ans":"Aynı orbitaldeki iki elektronu, biri bir yöne biri ters yöne döndüğü için ayırırız."},{"q":"Çekirdeğe yakın basamaktaki elektron mu, uzak basamaktaki elektron mu daha çok enerjiye sahiptir?","steps":[{"t":"Uzaklık ve enerji","a":"uzak = yüksek","d":"Çekirdekten uzaklaşmak daha çok enerji gerektirir."},{"t":"Karşılaştır","a":"uzaktaki","d":"Bu yüzden uzak basamaktaki elektronun enerjisi daha yüksektir."}],"ans":"Çekirdekten uzak basamaktaki elektron, yakındakine göre daha yüksek enerjilidir."},{"q":"İki elektron aynı basamakta, aynı evde (orbitalde) ve aynı dönüş yönünde olabilir mi?","steps":[{"t":"Durumu karşılaştır","a":"tümü aynı olur","d":"Aynı basamak, aynı orbital ve aynı dönüş yönü olsaydı iki elektron tıpatıp aynı olurdu."},{"t":"Kural","a":"olamaz","d":"İki elektron tamamen aynı olamayacağı için en az dönüş yönleri farklı olmalıdır."}],"ans":"Hayır; aynı orbitalde bile dönüş yönleri farklı olmak zorundadır, hepsi aynı olamaz."},{"q":"Bir atomdaki elektronu tarif etmek için bir tek sayı mı yeterlidir, yoksa birkaç sayı mı gerekir?","steps":[{"t":"Tek sayı yetmez","a":"birden çok","d":"Sadece bir sayı, elektronun hangi evde olduğunu ve nasıl döndüğünü anlatmaya yetmez."},{"t":"Birkaç sayı","a":"adres takımı","d":"Elektronu tam tarif etmek için birkaç sayıdan oluşan bir takım gerekir."}],"ans":"Birkaç sayı gerekir; elektronun yerini ve durumunu ancak bir sayı takımı tam tarif eder."}]},"ortaokul":{"kolay":[{"q":"Bir elektronun atom içindeki yerini ve durumunu tarif eden sayılara ne ad verilir?","steps":[{"t":"Elektronun durumu","a":"sayılarla tarif","d":"Bir elektronun hangi enerji düzeyinde ve nasıl bir bölgede olduğu sayılarla belirtilir."},{"t":"Adlandır","a":"kuantum sayıları","d":"Bu sayıların tümüne <b>kuantum sayıları</b> denir."}],"ans":"Bir elektronun yerini ve durumunu tarif eden sayılara kuantum sayıları denir."},{"q":"Baş kuantum sayısı (n) bir elektron hakkında bize en çok neyi söyler?","steps":[{"t":"n neyi gösterir","a":"enerji düzeyi","d":"Baş kuantum sayısı n, elektronun bulunduğu temel enerji düzeyini (kabuğu) gösterir."},{"t":"Uzaklıkla ilişki","a":"çekirdek uzaklığı","d":"n büyüdükçe elektron çekirdekten ortalama olarak daha uzakta ve daha yüksek enerjilidir."}],"ans":"Baş kuantum sayısı n, elektronun enerji düzeyini (kabuğu) ve çekirdeğe ortalama uzaklığını gösterir."},{"q":"Bir orbitalde en fazla kaç elektron bulunabilir?","steps":[{"t":"Orbital kapasitesi","a":"sınırlı","d":"Her orbital sınırlı sayıda elektron alabilir."},{"t":"Sayıyı söyle","a":"2 elektron","d":"Bir orbitalde en fazla 2 elektron bulunur; bunlar ters dönüş yönlüdür."}],"ans":"Bir orbitalde en fazla 2 elektron bulunabilir ve bu iki elektronun dönüş yönü zıttır."},{"q":"Spin kuantum sayısı (mₛ) bir elektronun hangi özelliğiyle ilgilidir?","steps":[{"t":"Spin nedir","a":"dönüş yönü","d":"Spin, elektronun kendi etrafındaki dönüş yönü gibi düşünülen özelliğidir."},{"t":"İki değer","a":"+½ ve −½","d":"Spin kuantum sayısı yalnızca iki değer alır: +½ veya −½."}],"ans":"Spin kuantum sayısı mₛ, elektronun dönüş yönüyle ilgilidir ve yalnızca +½ ya da −½ değerini alır."},{"q":"Bir atomdaki iki elektronun dört kuantum sayısının tamamı aynı olabilir mi?","steps":[{"t":"Benzersizlik","a":"her elektron özel","d":"Her elektronun kuantum sayılarından oluşan takımı kendine özeldir."},{"t":"Kural","a":"aynı olamaz","d":"İki elektronun dört kuantum sayısı aynı anda aynı olamaz."}],"ans":"Hayır; bir atomda iki elektronun dört kuantum sayısının tamamı aynı olamaz."}],"zor":[{"q":"Baş kuantum sayısı n = 1 olan kabukta en fazla 2, n = 2 olan kabukta en fazla 8 elektron bulunur. Bu sayılar arasında nasıl bir kural vardır?","steps":[{"t":"Değerleri yaz","a":"2 ve 8","d":"1. kabukta 2, 2. kabukta 8 elektron bulunur."},{"t":"Kuralı bul","a":"2n²","d":"Bu sayılar 2·1² = 2 ve 2·2² = 8 olarak çıkar; kapasite 2n² ile bulunur."}],"ans":"Bir kabuğun en fazla elektron sayısı 2n² kuralıyla bulunur: n=1 için 2, n=2 için 8 elektrondur."},{"q":"Aynı orbitalde bulunan iki elektronun spin kuantum sayıları (mₛ) nasıl olmalıdır?","steps":[{"t":"Aynı orbital","a":"diğerleri aynı","d":"Aynı orbitaldeki iki elektronun ilk üç kuantum sayısı (n, ℓ, mₗ) aynıdır."},{"t":"Ayrım gereği","a":"zıt spin","d":"İkisinin durumu tıpatıp aynı olamayacağı için spinleri zıt olmalıdır: biri +½, biri −½."}],"ans":"Aynı orbitaldeki iki elektronun spinleri zıttır; biri +½ ise diğeri −½ olmak zorundadır."},{"q":"Bir atomda iki elektronun dört kuantum sayısının aynı olamayacağını söyleyen kuralın adı nedir?","steps":[{"t":"Benzersizlik fikri","a":"her elektron özel","d":"Her elektronun dört kuantum sayısından oluşan takımı kendine özeldir."},{"t":"İlkeyi adlandır","a":"Pauli ilkesi","d":"Bu kurala <b>Pauli dışarlama ilkesi</b> denir."}],"ans":"Bu kurala Pauli dışarlama ilkesi denir; iki elektronun dört kuantum sayısı aynı anda aynı olamaz."},{"q":"3. kabukta (n = 3) en fazla kaç elektron bulunabilir?","steps":[{"t":"Kuralı yaz","a":"2n²","d":"Bir kabuğun kapasitesi 2n² ile bulunur."},{"t":"Yerine koy","a":"2·3²","d":"n = 3 için: 2 × 9 = 18."}],"ans":"3. kabukta en fazla 2n² = 2·3² = 18 elektron bulunabilir."},{"q":"Bir elektronu tam olarak tanımlamak için kaç tane kuantum sayısı gerekir ve bunlar nelerdir?","steps":[{"t":"Sayıyı bul","a":"4 tane","d":"Bir elektronun durumunu tam tanımlamak için dört kuantum sayısı gerekir."},{"t":"İsimlerini say","a":"n, ℓ, mₗ, mₛ","d":"Bunlar baş (n), açısal (ℓ), manyetik (mₗ) ve spin (mₛ) kuantum sayılarıdır."}],"ans":"Bir elektron dört kuantum sayısıyla tanımlanır: baş (n), açısal (ℓ), manyetik (mₗ) ve spin (mₛ)."}]},"lise":{"kolay":[{"q":"Dört kuantum sayısı (n, ℓ, mₗ, mₛ) sırasıyla hangi özellikleri belirler?","steps":[{"t":"n ve ℓ","a":"düzey ve alt kabuk","d":"Baş kuantum sayısı n enerji düzeyini, açısal kuantum sayısı ℓ alt kabuğun türünü (s, p, d, f) belirler."},{"t":"mₗ ve mₛ","a":"yönelim ve spin","d":"Manyetik kuantum sayısı mₗ orbitalin uzaydaki yönelimini, spin kuantum sayısı mₛ elektronun dönüş yönünü belirler."}],"ans":"n enerji düzeyini, ℓ alt kabuğu (orbital türünü), mₗ orbitalin yönelimini, mₛ ise elektronun spinini belirler."},{"q":"Açısal kuantum sayısı ℓ'nin alabileceği değerler baş kuantum sayısı n'ye nasıl bağlıdır?","steps":[{"t":"Bağıntıyı yaz","a":"ℓ = 0 ... n−1","d":"ℓ, 0'dan başlayıp n−1'e kadar tam sayı değerler alır."},{"t":"Örnek ver","a":"n=3 → ℓ=0,1,2","d":"n = 3 için ℓ değerleri 0, 1 ve 2 olur; yani s, p ve d alt kabukları bulunur."}],"ans":"Açısal kuantum sayısı ℓ, 0'dan n−1'e kadar değer alır; örneğin n=3 için ℓ = 0, 1, 2'dir (s, p, d)."},{"q":"Açısal kuantum sayısı ℓ = 0, 1, 2, 3 değerleri hangi alt kabuklara (orbital türlerine) karşılık gelir?","steps":[{"t":"Eşleştir","a":"s, p, d, f","d":"ℓ = 0 → s, ℓ = 1 → p, ℓ = 2 → d, ℓ = 3 → f alt kabuğuna karşılık gelir."},{"t":"Sıralama","a":"artan ℓ","d":"ℓ büyüdükçe alt kabuk türü s, p, d, f sırasıyla değişir."}],"ans":"ℓ = 0 s, ℓ = 1 p, ℓ = 2 d, ℓ = 3 f alt kabuğuna karşılık gelir."},{"q":"Manyetik kuantum sayısı mₗ'nin alabileceği değerler hangi aralıktadır?","steps":[{"t":"Aralığı yaz","a":"−ℓ ... +ℓ","d":"mₗ, −ℓ'den +ℓ'ye kadar tam sayı değerler alır (0 dahil)."},{"t":"Örnek","a":"ℓ=1 → −1,0,+1","d":"ℓ = 1 (p) için mₗ = −1, 0, +1 olur; yani 3 yönelim vardır."}],"ans":"Manyetik kuantum sayısı mₗ, −ℓ'den +ℓ'ye kadar (0 dahil) tam sayı değerler alır."},{"q":"Bir alt kabuktaki orbital sayısı açısal kuantum sayısı ℓ'ye nasıl bağlıdır?","fig":"<svg viewBox='0 0 320 110'><rect x='20' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='34' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>s</text><text x='34' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>1</text><rect x='90' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><rect x='120' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='134' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>p</text><text x='134' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>3</text><rect x='210' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><rect x='240' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><rect x='270' y='40' width='28' height='28' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='254' y='90' font-size='11' text-anchor='middle' fill='#1a2b45'>d</text><text x='254' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>5</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"2ℓ + 1","d":"Bir alt kabuktaki orbital sayısı 2ℓ + 1 ile bulunur (mₗ'nin değer sayısı kadar)."},{"t":"Örnekle","a":"s=1, p=3, d=5","d":"ℓ=0 için 1 (s), ℓ=1 için 3 (p), ℓ=2 için 5 (d) orbital olur."}],"ans":"Bir alt kabuktaki orbital sayısı 2ℓ + 1'dir: s'de 1, p'de 3, d'de 5 orbital bulunur."}],"zor":[{"q":"n = 3 enerji düzeyinde bulunan alt kabukları, her birinin orbital sayısını ve düzeyin toplam elektron kapasitesini bulunuz.","steps":[{"t":"Alt kabukları yaz","a":"3s, 3p, 3d","d":"n = 3 için ℓ = 0, 1, 2 olur; yani 3s, 3p ve 3d alt kabukları bulunur."},{"t":"Orbital sayıları","a":"1, 3, 5","d":"2ℓ+1'den 3s'de 1, 3p'de 3, 3d'de 5 orbital; toplam 9 orbital."},{"t":"Kapasite","a":"2·9 = 18","d":"Her orbital 2 elektron aldığından toplam 18 elektron; bu 2n² = 2·3² = 18 ile uyumludur."}],"ans":"n = 3'te 3s (1), 3p (3) ve 3d (5) toplam 9 orbital bulunur; kapasite 2·9 = 18 = 2n² elektrondur."},{"q":"Bir elektronun kuantum sayıları n = 4, ℓ = 2, mₗ = +1 olarak verilmiştir. Bu elektron hangi alt kabuktadır ve mₛ'nin olası değerleri nelerdir?","steps":[{"t":"Alt kabuğu belirle","a":"4d","d":"n = 4 ve ℓ = 2 olduğundan elektron 4d alt kabuğundadır."},{"t":"mₗ kontrolü","a":"geçerli","d":"ℓ = 2 için mₗ = −2,−1,0,+1,+2 aralığındadır; +1 bu aralıktadır, geçerlidir."},{"t":"mₛ değerleri","a":"+½ veya −½","d":"Spin her zaman iki değerden birini alır: +½ ya da −½."}],"ans":"Elektron 4d alt kabuğundadır; mₗ = +1 geçerlidir ve mₛ değeri +½ veya −½ olabilir."},{"q":"Aşağıdaki dört kuantum sayısı dörtlüsünden hangileri olanaksızdır, gerekçesiyle belirtiniz: (a) n=2, ℓ=1, mₗ=−1, mₛ=+½  (b) n=3, ℓ=3, mₗ=0, mₛ=−½  (c) n=1, ℓ=0, mₗ=0, mₛ=−½","steps":[{"t":"(a)'yı denetle","a":"geçerli","d":"n=2 için ℓ=1 izinli (ℓ≤n−1), mₗ=−1 (−1..+1) aralığında, mₛ=+½ geçerli."},{"t":"(b)'yi denetle","a":"olanaksız","d":"n=3 için ℓ en çok 2 olabilir; ℓ=3 izinli değildir, bu dörtlü olanaksızdır."},{"t":"(c)'yi denetle","a":"geçerli","d":"n=1 için ℓ=0, mₗ=0, mₛ=−½: tüm değerler kurallara uygundur."}],"ans":"Yalnızca (b) olanaksızdır; çünkü n = 3 için ℓ en fazla 2 olabilir, ℓ = 3 izin verilen aralık dışındadır. (a) ve (c) geçerlidir."},{"q":"ℓ = 2 (d alt kabuğu) için manyetik kuantum sayısı mₗ'nin tüm değerlerini ve bu alt kabuğun en fazla elektron sayısını bulunuz.","fig":"<svg viewBox='0 0 320 90'><rect x='30' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='45' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>−2</text><rect x='80' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='95' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>−1</text><rect x='130' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='145' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>0</text><rect x='180' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='195' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>+1</text><rect x='230' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='245' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>+2</text></svg>","steps":[{"t":"mₗ değerleri","a":"−2..+2","d":"ℓ = 2 için mₗ = −2, −1, 0, +1, +2 olmak üzere 5 değer alır."},{"t":"Orbital sayısı","a":"5 orbital","d":"2ℓ+1 = 5 orbital vardır."},{"t":"Elektron sayısı","a":"2·5 = 10","d":"Her orbital 2 elektron aldığından d alt kabuğu en fazla 10 elektron alır."}],"ans":"ℓ = 2 için mₗ = −2, −1, 0, +1, +2'dir (5 orbital); d alt kabuğu en fazla 2·5 = 10 elektron alır."},{"q":"Bir orbitaldeki iki elektron için n = 2, ℓ = 1, mₗ = 0 ortaktır. Pauli dışarlama ilkesine göre bu iki elektronu yalnızca hangi kuantum sayısı ayırır ve değerleri ne olur?","fig":"<svg viewBox='0 0 320 90'><rect x='130' y='30' width='60' height='32' fill='none' stroke='#1a2b45' stroke-width='1.5'/><line x1='150' y1='38' x2='150' y2='56' stroke='#2b6be0' stroke-width='2'/><polygon points='150,38 146,45 154,45' fill='#2b6be0'/><line x1='170' y1='56' x2='170' y2='38' stroke='#e0552b' stroke-width='2'/><polygon points='170,56 166,49 174,49' fill='#e0552b'/><text x='160' y='80' font-size='10' text-anchor='middle' fill='#1a2b45'>spin zit</text></svg>","steps":[{"t":"Ortak değerler","a":"n,ℓ,mₗ aynı","d":"İki elektronun n = 2, ℓ = 1, mₗ = 0 değerleri ortaktır; ilk üç sayı aynıdır."},{"t":"Pauli gereği","a":"spin farklı","d":"Dört sayının tümü aynı olamayacağından, ayırt eden tek sayı spin mₛ'dir."},{"t":"Değerleri yaz","a":"+½ ve −½","d":"Biri +½, diğeri −½ spinlidir (zıt yönlü)."}],"ans":"İki elektronu yalnızca spin kuantum sayısı mₛ ayırır; biri +½, diğeri −½ değerini alır."}]}},"kureselSimetri":{"ilkokul":{"kolay":[{"q":"Bir yumurta kartonundaki gözlerin her birine birer yumurta koymak mı, bazı gözleri tıka basa doldurup bazılarını boş bırakmak mı daha düzenli görünür?","steps":[{"t":"Eşit doldurma","a":"her göze birer","d":"Her göze birer yumurta koymak kartonu düzenli ve dengeli gösterir."},{"t":"Atomdaki benzetme","a":"dengeli yerleşim","d":"Atomda da küçük taneler (elektronlar) gözlere <b>eşit</b> dağılınca yapı daha dengeli olur."}],"ans":"Her göze eşit dağıtmak daha düzenlidir; atomda da tanelerin eşit dağılması yapıyı daha dengeli yapar."},{"q":"Bir dönme dolabın koltuklarına insanların eşit oturması mı, hepsinin bir tarafa toplanması mı daha dengeli olur?","steps":[{"t":"Eşit oturma","a":"dengeli dolap","d":"İnsanlar koltuklara eşit dağılırsa dönme dolap dengeli döner, bir yana yatmaz."},{"t":"Atomda da öyle","a":"dengeli dağılım","d":"Atomda da taneler her yöne <b>eşit</b> dağıldığında yapı dengeli ve düzenli olur."}],"ans":"Eşit dağılım dönme dolabı dengeler; atomda da tanelerin eşit dağılması dengeli bir yapı oluşturur."},{"q":"Bir pizzayı dilimlere eşit bölmek neden herkesi daha mutlu eder ve daha düzenli görünür?","steps":[{"t":"Eşit bölme","a":"adil ve düzenli","d":"Pizza eşit dilimlere bölününce her dilim aynı olur, görünüm düzenli ve dengelidir."},{"t":"Atomda eşitlik","a":"dengeli düzen","d":"Atomda da taneler <b>eşit</b> paylaşılınca düzenli ve dengeli bir yapı oluşur."}],"ans":"Eşit bölme daha düzenli ve adildir; atomda da tanelerin eşit dağılımı dengeli bir yapı verir."},{"q":"Bir bilezik üzerine boncukları eşit aralıkla dizmek neden her yönden aynı ve güzel görünür?","steps":[{"t":"Eşit aralık","a":"her yönden aynı","d":"Boncuklar eşit aralıkla dizilince bilezik döndürülse bile her yönden aynı (simetrik) görünür."},{"t":"Atomdaki denge","a":"dengeli yapı","d":"Atomda da taneler <b>eşit</b> dağıldığında yapı her yönden benzer ve dengeli olur."}],"ans":"Eşit aralıklı dizim her yönden aynı görünür; atomda da tanelerin eşit dağılımı dengeli, düzenli bir yapı oluşturur."},{"q":"Bir terazinin iki kefesine eşit ağırlık koymak neden dengeyi sağlar?","steps":[{"t":"Eşit ağırlık","a":"terazi dengede","d":"İki kefeye eşit ağırlık konunca terazi yatay durur, hiçbir yana eğilmez."},{"t":"Atomda denge","a":"eşit dağılım","d":"Atomda da taneler <b>eşit</b> dağıldığında yapı dengede kalır ve daha sağlam olur."}],"ans":"Eşit ağırlık teraziyi dengeler; atomda da tanelerin eşit dağılımı yapıyı dengeli ve sağlam yapar."}],"zor":[{"q":"Bir oyuncu, takım daha dengeli olsun diye kendi yerinden komşu boş bir yere geçer. Atomdaki küçük tanelerin de bazen benzer bir şey yapması neyi sağlar?","steps":[{"t":"Denge için yer değişimi","a":"daha dengeli takım","d":"Bir oyuncunun yer değiştirmesi takımın tümünü daha dengeli hâle getirebilir."},{"t":"Tanenin geçişi","a":"daha dengeli atom","d":"Atomda da bir tane komşu yere geçip dağılımı <b>eşit</b> yaparsa yapı daha dengeli olur."}],"ans":"Takımı dengeleyen oyuncu gibi, bir tane de yer değiştirip dağılımı eşitleyerek atomu daha dengeli yapabilir."},{"q":"İki yumurta kartonundan birinde tüm gözler yarıya kadar eşit dolu, diğerinde gözler karışık dolu. Hangisi daha düzenli görünür?","steps":[{"t":"Eşit yarı dolu","a":"düzenli görünüm","d":"Tüm gözleri eşit (yarı) dolu karton her yönden dengeli ve düzenli görünür."},{"t":"Atomda denge","a":"yarı dolu düzen","d":"Atomda da gözler <b>eşit yarı dolu</b> olduğunda özel bir denge oluşur."}],"ans":"Eşit yarı dolu karton daha düzenlidir; atomda da gözlerin eşit yarı dolu olması özel bir denge sağlar."},{"q":"Tek bir tanenin komşu boş göze geçmesiyle bütün gözler eşit hâle geliyorsa, atom bu geçişi neden daha çok ister?","steps":[{"t":"Eşitlik sağlanır","a":"dengeli dağılım","d":"Tek bir tanenin geçişiyle tüm gözler eşit (dengeli) dolabilir."},{"t":"Dengeyi kazanır","a":"daha dengeli atom","d":"Eşit dağılım atomu <b>daha dengeli</b> yaptığı için atom bu geçişi tercih eder."}],"ans":"Tek tanenin geçişiyle gözler eşitlenip atom daha dengeli olduğundan, atom bu geçişi tercih eder."},{"q":"Tamamen dolu bir kutu ile her gözü eşit dolu bir kutu mu, yoksa yarısı karışık dolu bir kutu mu daha düzenli sayılır?","steps":[{"t":"Tam veya eşit dolu","a":"düzenli","d":"Tamamen dolu ya da her gözü eşit dolu kutular düzenli ve dengelidir."},{"t":"Atomda karşılığı","a":"tam dolu denge","d":"Atomda da bir göz grubu <b>tam dolu</b> olduğunda özel bir denge ortaya çıkar."}],"ans":"Tam dolu ya da eşit dolu düzen daha dengelidir; atomda da göz grubunun tam dolması özel bir denge sağlar."},{"q":"Bir salıncak takımında çocukların eşit ağırlıkta ikişerli oturması neden en dengeli durumdur?","steps":[{"t":"Eşit ikişerli","a":"her salıncak dengede","d":"Her salıncağa eşit ağırlıkta ikişer çocuk oturunca takım hiçbir yana yatmaz."},{"t":"Atomda eşleşme","a":"tam dolu denge","d":"Atomda da taneler <b>ikişerli (eşleşmiş)</b> ve eşit dağıldığında yapı en dengeli hâle gelir."}],"ans":"Eşit ikişerli oturma salıncağı dengeler; atomda da tanelerin eşleşmiş ve eşit dağılması en dengeli yapıyı oluşturur."}]},"ortaokul":{"kolay":[{"q":"Bir alt kabuğun yarısının her gözüne birer elektron gelmesi atoma ne kazandırır?","steps":[{"t":"Yarı dolu düzen","a":"simetrik dağılım","d":"Alt kabuğun her orbitaline birer elektron gelince eşit (simetrik) bir dağılım oluşur."},{"t":"Kararlılık","a":"ekstra denge","d":"Bu <b>yarı dolu</b> simetrik düzen atoma fazladan kararlılık kazandırır."}],"ans":"Bir alt kabuğun yarı dolu (simetrik) olması atoma fazladan kararlılık kazandırır."},{"q":"Tam dolu bir alt kabuk neden kararlı kabul edilir?","steps":[{"t":"Tam dolu düzen","a":"hepsi eşleşmiş","d":"Tam dolu alt kabukta her orbital ikişer (eşleşmiş) elektron taşır, dağılım simetriktir."},{"t":"Düşük enerji","a":"kararlı yapı","d":"Bu simetrik, <b>tam dolu</b> düzen düşük enerjili olduğu için kararlıdır."}],"ans":"Tam dolu alt kabuk simetrik ve düşük enerjili olduğu için kararlı kabul edilir."},{"q":"Krom atomu elektron dağılımında küçük bir 'kayma' yapar. Bunun amacı nedir?","steps":[{"t":"Kayma olur","a":"bir elektron yer değiştirir","d":"Kromda bir elektron, beklenenden farklı bir alt kabuğa geçer."},{"t":"Amaç kararlılık","a":"yarı dolu düzen","d":"Bu kayma, d alt kabuğunu <b>yarı dolu (simetrik)</b> yaparak atomu daha kararlı kılmak içindir."}],"ans":"Krom, bir elektronu kaydırarak d alt kabuğunu yarı dolu simetrik düzene getirir ve böylece daha kararlı olur."},{"q":"Elektronların bir alt kabukta eşit (simetrik) dağılması neden tercih edilir?","steps":[{"t":"Eşit dağılım","a":"simetrik düzen","d":"Elektronlar bir alt kabukta eşit dağıldığında simetrik bir düzen oluşur."},{"t":"Düşük enerji","a":"kararlılık","d":"Simetrik düzen genellikle daha <b>düşük enerjili</b> ve kararlı olduğundan tercih edilir."}],"ans":"Simetrik (eşit) dağılım daha düşük enerjili ve kararlı olduğu için elektronlar bu düzeni tercih eder."},{"q":"Yarı dolu ve tam dolu alt kabukların ortak özelliği nedir?","steps":[{"t":"İkisi de simetrik","a":"dengeli dağılım","d":"Yarı dolu (her orbitalde 1 elektron) ve tam dolu (hepsi eşleşmiş) düzenlerin ikisi de simetriktir."},{"t":"Ekstra kararlılık","a":"daha dengeli","d":"Bu simetri her ikisine de <b>fazladan kararlılık</b> kazandırır."}],"ans":"Yarı dolu ve tam dolu alt kabukların ikisi de simetrik olduğundan fazladan kararlılık kazandırır."}],"zor":[{"q":"Krom atomu, dağılımını değiştirip d alt kabuğunu yarı dolu hâle getirerek neden daha kararlı olur?","steps":[{"t":"Yarı dolu düzen","a":"simetrik dağılım","d":"Krom bir elektronu kaydırarak d alt kabuğunu yarı dolu (her orbitalde birer elektron) yapar."},{"t":"Kararlılık artar","a":"düşük enerji","d":"Bu <b>simetrik yarı dolu</b> düzen daha düşük enerjili ve kararlı olduğundan krom bunu tercih eder."}],"ans":"Krom bir elektron kaydırarak yarı dolu simetrik düzene geçer; bu düzen düşük enerjili olduğundan atom daha kararlı olur."},{"q":"Bakır atomunun d alt kabuğunu tam dolu hâle getirmesi atomu nasıl etkiler?","steps":[{"t":"Tam dolu düzen","a":"simetrik dağılım","d":"Bakır bir elektron kaydırarak d alt kabuğunu tam dolu (hepsi eşleşmiş) hâle getirir."},{"t":"Kararlılık","a":"düşük enerji","d":"Bu <b>tam dolu simetrik</b> düzen düşük enerjili ve kararlıdır; bu yüzden bakır onu tercih eder."}],"ans":"Bakır bir elektron kaydırarak tam dolu simetrik düzene geçer; bu düşük enerjili düzen atomu daha kararlı yapar."},{"q":"İki atomdan birinde alt kabuk eşit olmayan biçimde dolu, diğerinde tam dolu. Hangisi daha kararlıdır, neden?","steps":[{"t":"Eşit olmayan dolu","a":"daha az dengeli","d":"Eşit olmayan dolu alt kabuk simetrik değildir, enerjisi daha yüksektir."},{"t":"Tam dolu","a":"simetrik ve kararlı","d":"Tam dolu alt kabuk <b>simetriktir</b> ve düşük enerjili olduğundan daha kararlıdır."}],"ans":"Tam dolu olan daha kararlıdır; çünkü simetrik ve düşük enerjili bir düzendir, eşit olmayan dolu ise değildir."},{"q":"Bir elektronun küçük bir geçiş yapması atomu nasıl daha kararlı hâle getirebilir?","steps":[{"t":"Geçişin sonucu","a":"simetrik düzen","d":"Bir elektronun komşu alt kabuğa geçmesi, kabuğu yarı dolu veya tam dolu (simetrik) yapabilir."},{"t":"Kararlılık kazancı","a":"daha düşük enerji","d":"Oluşan <b>simetrik</b> düzen daha düşük enerjili olduğundan atom bu geçişle daha kararlı hâle gelir."}],"ans":"Bir elektronun geçişiyle alt kabuk simetrik (yarı/tam dolu) hâle gelir; bu düşük enerjili düzen atomu daha kararlı yapar."},{"q":"Krom ile bakırın ortak özelliği, ikisinin de elektron dağılımında 'beklenenden farklı' davranmasıdır. Bu davranışın temel nedeni nedir?","steps":[{"t":"Ortak amaç","a":"simetrik kabuk","d":"Hem krom hem bakır bir elektron kaydırarak d kabuğunu simetrik (krom yarı dolu, bakır tam dolu) yapar."},{"t":"Temel neden","a":"ekstra kararlılık","d":"Her ikisi de bu kaymayı <b>fazladan kararlılık</b> kazanmak için yapar."}],"ans":"Her ikisi de bir elektron kaydırıp d kabuğunu simetrik (yarı/tam dolu) yaparak fazladan kararlılık kazanmak için bu farklı davranışı gösterir."}]},"lise":{"kolay":[{"q":"Yarı dolu (d⁵) ve tam dolu (d¹⁰) alt kabukların atoma kazandırdığı özellik nedir?","steps":[{"t":"Simetrik dağılım","a":"küresel simetri","d":"d⁵ (her orbitalde 1 elektron) ve d¹⁰ (hepsi eşleşmiş) düzenleri küresel simetriye sahiptir."},{"t":"Kararlılık","a":"ekstra kararlılık","d":"Bu simetrik düzenler atoma <b>fazladan kararlılık</b> (düşük enerji) kazandırır."}],"ans":"Yarı dolu (d⁵) ve tam dolu (d¹⁰) alt kabuklar küresel simetri sayesinde atoma fazladan kararlılık kazandırır."},{"q":"Kromun (Z = 24) beklenen ve gerçek elektron dizilimi nedir?","steps":[{"t":"Beklenen dizilim","a":"[Ar]3d⁴4s²","d":"Aufbau kuralına göre kromun beklenen dizilimi [Ar]3d⁴4s²'dir."},{"t":"Gerçek dizilim","a":"[Ar]3d⁵4s¹","d":"Gerçekte 4s'ten 3d'ye bir elektron geçer; dizilim <b>[Ar]3d⁵4s¹</b> olur (3d yarı dolu)."}],"ans":"Kromun beklenen dizilimi [Ar]3d⁴4s², gerçek dizilimi ise [Ar]3d⁵4s¹'dir.","fig":"<svg viewBox='0 0 360 150'><rect x='20' y='50' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='62' y='50' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='104' y='50' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='146' y='50' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='188' y='50' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='40' y='73' font-size='18' text-anchor='middle' fill='#2b6be0'>↑</text><text x='82' y='73' font-size='18' text-anchor='middle' fill='#2b6be0'>↑</text><text x='124' y='73' font-size='18' text-anchor='middle' fill='#2b6be0'>↑</text><text x='166' y='73' font-size='18' text-anchor='middle' fill='#2b6be0'>↑</text><text x='208' y='73' font-size='18' text-anchor='middle' fill='#2b6be0'>↑</text><rect x='270' y='50' width='40' height='34' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='285' y='73' font-size='16' fill='#2b6be0'>↑</text><text x='124' y='110' font-size='13' text-anchor='middle' fill='#1a2b45'>3d⁵ (yarı dolu)</text><text x='290' y='110' font-size='13' text-anchor='middle' fill='#1a2b45'>4s¹</text></svg>"},{"q":"Bakırın (Z = 29) beklenen ve gerçek elektron dizilimi nedir?","steps":[{"t":"Beklenen dizilim","a":"[Ar]3d⁹4s²","d":"Aufbau kuralına göre bakırın beklenen dizilimi [Ar]3d⁹4s²'dir."},{"t":"Gerçek dizilim","a":"[Ar]3d¹⁰4s¹","d":"Gerçekte 4s'ten 3d'ye bir elektron geçer; dizilim <b>[Ar]3d¹⁰4s¹</b> olur (3d tam dolu)."}],"ans":"Bakırın beklenen dizilimi [Ar]3d⁹4s², gerçek dizilimi ise [Ar]3d¹⁰4s¹'dir.","fig":"<svg viewBox='0 0 360 130'><text x='10' y='30' font-size='13' fill='#1a2b45'>3d¹⁰</text><rect x='20' y='40' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='56' y='40' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='92' y='40' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='40' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='164' y='40' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='30' y='62' font-size='14' fill='#2b6be0'>↑</text><text x='42' y='62' font-size='14' fill='#e0552b'>↓</text><text x='66' y='62' font-size='14' fill='#2b6be0'>↑</text><text x='78' y='62' font-size='14' fill='#e0552b'>↓</text><text x='102' y='62' font-size='14' fill='#2b6be0'>↑</text><text x='114' y='62' font-size='14' fill='#e0552b'>↓</text><text x='138' y='62' font-size='14' fill='#2b6be0'>↑</text><text x='150' y='62' font-size='14' fill='#e0552b'>↓</text><text x='174' y='62' font-size='14' fill='#2b6be0'>↑</text><text x='186' y='62' font-size='14' fill='#e0552b'>↓</text><rect x='250' y='40' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='260' y='62' font-size='14' fill='#2b6be0'>↑</text><text x='240' y='95' font-size='13' fill='#1a2b45'>4s¹</text><text x='90' y='95' font-size='13' fill='#1a2b45'>tam dolu (d¹⁰)</text></svg>"},{"q":"Kromda 4s elektronunun 3d'ye geçmesinin nedeni nedir?","steps":[{"t":"Geçişin sonucu","a":"3d⁵ ve 4s¹","d":"Bir 4s elektronu 3d'ye geçince 3d⁵ (yarı dolu) ve 4s¹ düzeni oluşur."},{"t":"Kararlılık kazancı","a":"küresel simetri","d":"Yarı dolu 3d⁵ <b>küresel simetri</b> sağlar; bu düşük enerjili düzen atomu daha kararlı yapar."}],"ans":"Krom, 4s'ten 3d'ye bir elektron aktararak yarı dolu (d⁵) küresel simetrik düzene ulaşır; bu daha kararlı olduğu için bu geçiş gerçekleşir.","fig":"<svg viewBox='0 0 360 110'><rect x='30' y='30' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='40' y='51' font-size='14' fill='#2b6be0'>↑</text><text x='34' y='80' font-size='11' fill='#1a2b45'>4s²</text><text x='80' y='50' font-size='18' fill='#e0552b'>→</text><text x='72' y='80' font-size='11' fill='#e0552b'>geçiş</text><rect x='130' y='30' width='34' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='142' y='51' font-size='14' fill='#2b6be0'>↑</text><text x='132' y='80' font-size='11' fill='#1a2b45'>4s¹</text><rect x='200' y='30' width='130' height='30' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='210' y='51' font-size='13' fill='#2b6be0'>↑ ↑ ↑ ↑ ↑</text><text x='210' y='80' font-size='11' fill='#1a2b45'>3d⁵ (yarı dolu)</text></svg>"},{"q":"Bakırda 4s elektronunun 3d'ye geçmesinin nedeni nedir?","steps":[{"t":"Geçişin sonucu","a":"3d¹⁰ ve 4s¹","d":"Bir 4s elektronu 3d'ye geçince 3d¹⁰ (tam dolu) ve 4s¹ düzeni oluşur."},{"t":"Kararlılık kazancı","a":"tam dolu simetri","d":"Tam dolu 3d¹⁰ <b>küresel simetrik</b> ve düşük enerjilidir; bu yüzden bakır bu düzeni tercih eder."}],"ans":"Bakır, 4s'ten 3d'ye bir elektron aktararak tam dolu (d¹⁰) küresel simetrik düzene ulaşır; bu daha kararlı olduğu için geçiş gerçekleşir."}],"zor":[{"q":"Kromun temel hâl diziliminin [Ar]3d⁴4s² yerine [Ar]3d⁵4s¹ olmasını küresel simetri ve enerji açısından gerekçelendirin.","steps":[{"t":"İki düzenin karşılaştırması","a":"3d⁵4s¹ daha kararlı","d":"[Ar]3d⁴4s² simetrik değildir; bir 4s elektronu 3d'ye geçince 3d⁵ yarı dolu (simetrik) olur."},{"t":"Enerji kazancı","a":"değiş-tokuş enerjisi","d":"Yarı dolu d⁵'teki paralel spinli 5 elektron arasındaki <b>değiş-tokuş (exchange) enerjisi</b> en yükseğe çıkar; bu, küçük 4s-3d enerji farkını telafi edip düzeni daha kararlı kılar."}],"ans":"[Ar]3d⁵4s¹'de 3d yarı dolu ve küresel simetriktir; paralel spinlerin değiş-tokuş enerjisi en yüksek olduğundan bu düzen [Ar]3d⁴4s²'den daha kararlıdır, bu yüzden krom bu dizilimi alır."},{"q":"Bakırın [Ar]3d⁹4s² yerine [Ar]3d¹⁰4s¹ dizilimini tercih etmesinin enerjisel temelini açıklayın.","steps":[{"t":"İki düzen","a":"3d¹⁰4s¹ daha kararlı","d":"[Ar]3d⁹4s²'de 3d simetrik değildir; bir 4s elektronu 3d'ye geçince 3d¹⁰ tam dolu (simetrik) olur."},{"t":"Kararlılık nedeni","a":"tam dolu simetri","d":"Tam dolu d¹⁰ küresel simetriktir; tüm elektronlar eşleşip <b>en düşük enerjili</b> simetrik düzeni verir, bu küçük 4s-3d farkını telafi eder."}],"ans":"[Ar]3d¹⁰4s¹'de 3d tam dolu ve küresel simetriktir; bu düşük enerjili simetrik düzen, 4s-3d enerji farkını telafi ederek [Ar]3d⁹4s²'den daha kararlı olduğundan bakır bu dizilimi alır."},{"q":"Cr ve Cu istisnalarında geçişin neden 4s'ten 3d'ye doğru olduğunu (tersinin değil) açıklayın.","steps":[{"t":"Enerji yakınlığı","a":"4s ≈ 3d","d":"Geçiş metallerinde 4s ve 3d enerjileri birbirine çok yakındır, küçük bir kazanç dengeyi değiştirebilir."},{"t":"Simetri sağlayan yön","a":"4s → 3d","d":"3d'yi d⁵ ya da d¹⁰ yapan yön <b>4s'ten 3d'ye</b> geçiştir; ters yön simetri kazandırmayacağından gerçekleşmez."}],"ans":"4s ve 3d enerjileri çok yakın olduğundan, simetrik d⁵/d¹⁰ düzenini sağlayan 4s'ten 3d'ye geçiş gerçekleşir; ters yön kararlılık kazandırmadığı için olmaz."},{"q":"Cr⁺ ve Cu⁺ iyonları oluşurken hangi orbitalden elektron koptuğunu ve sonuç dizilimlerini açıklayın.","steps":[{"t":"Nötr dizilimler","a":"Cr:[Ar]3d⁵4s¹, Cu:[Ar]3d¹⁰4s¹","d":"Kromun nötr dizilimi [Ar]3d⁵4s¹, bakırınki [Ar]3d¹⁰4s¹'dir; her ikisinde de tek 4s elektronu vardır."},{"t":"İyonlaşma","a":"4s kopar","d":"En dıştaki tek 4s elektronu koptuğunda Cr⁺ → <b>[Ar]3d⁵</b>, Cu⁺ → <b>[Ar]3d¹⁰</b> olur; her ikisi de küresel simetrik kalır."}],"ans":"Her iki iyonda da tek 4s elektronu kopar: Cr⁺ [Ar]3d⁵ (yarı dolu), Cu⁺ [Ar]3d¹⁰ (tam dolu) olur; her iki iyon da küresel simetrik kararlı düzendedir."},{"q":"Değiş-tokuş (exchange) enerjisi kavramını kullanarak yarı dolu d⁵ düzeninin neden ekstra kararlı olduğunu açıklayın.","steps":[{"t":"Paralel spin eşleşmeleri","a":"çok sayıda etkileşim","d":"d⁵'te 5 elektron paralel spinlidir; aynı spinli elektron çiftleri arasında kararlılık sağlayan değiş-tokuş etkileşimleri oluşur."},{"t":"Maksimum kazanç","a":"en yüksek exchange enerjisi","d":"Yarı dolu d⁵'te paralel spinli çift sayısı en yüksektir; bu da <b>değiş-tokuş enerjisini</b> en üst düzeye çıkararak düzeni özel kararlı yapar."}],"ans":"d⁵ düzeyindeki 5 paralel spinli elektron en fazla sayıda değiş-tokuş etkileşimi oluşturur; bu enerji kazancı yarı dolu kabuğu özel kararlı kılar."}]}},"modernAtom":{"ilkokul":{"kolay":[{"q":"Modern atom modeli elektronu, çizgisi belli bir yörünge yerine nasıl gösterir? Sinek benzetmesiyle düşün.","fig":"<svg viewBox='0 0 200 180'><circle cx='100' cy='90' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='90' r='55' fill='#2b6be0' opacity='0.18'/><circle cx='100' cy='90' r='40' fill='#2b6be0' opacity='0.22'/><circle cx='80' cy='75' r='2' fill='#1a2b45'/><circle cx='120' cy='100' r='2' fill='#1a2b45'/><circle cx='100' cy='60' r='2' fill='#1a2b45'/><circle cx='115' cy='85' r='2' fill='#1a2b45'/></svg>","steps":[{"t":"Kesin yer yok","a":"bulut gibi","d":"Elektron tek bir çizgide gitmez; bir ışığın etrafında uçuşan sinek gibi her an farklı yerde olabilir."},{"t":"Sonuç","a":"elektron bulutu","d":"Elektronun bulunabileceği bölge bir <b>bulut</b> gibidir; nerede daha çok bulunduğunu söyleriz, kesin yerini değil."}],"ans":"Modern model elektronu kesin yörünge yerine, sinek bulutu gibi bulunabileceği bir bölge (elektron bulutu) olarak gösterir."},{"q":"Elektronun çekirdek etrafında en çok bulunduğu bölgeye modern atom modelinde ne diyebiliriz?","steps":[{"t":"En sık yer","a":"bulunma bölgesi","d":"Elektronun en çok zaman geçirdiği, bulunma ihtimalinin yüksek olduğu bir bölge vardır."},{"t":"Sonuç","a":"orbital","d":"Bu bölgeye <b>orbital</b> denir; elektronun yuvası gibidir ama kesin bir çizgi değildir."}],"ans":"Elektronun en çok bulunduğu bölgeye orbital denir."},{"q":"Modern atom modelinde elektronun yerini tam tutturup 'tam burada' diyebilir miyiz?","steps":[{"t":"Kesin yer yok","a":"diyemeyiz","d":"Elektron çok hızlı ve her an farklı yerde olabildiği için tam yerini tutturamayız."},{"t":"Sonuç","a":"ihtimal söyleriz","d":"Sadece 'şurada bulunma <b>ihtimali</b> yüksek' deriz; kesin yerini söyleyemeyiz."}],"ans":"Hayır; elektronun kesin yerini söyleyemeyiz, sadece nerede bulunma ihtimalinin yüksek olduğunu söyleriz."},{"q":"Bir lambanın etrafında uçuşan pervaneleri fotoğraflasak, çoğunun lambaya yakın olduğunu görürüz. Bu, modern atomdaki neye benzer?","steps":[{"t":"Yoğunluk","a":"sık olan yer","d":"Pervaneler en çok lambaya yakın bulunur; elektron da çekirdek çevresinde belirli bölgelerde daha sık bulunur."},{"t":"Sonuç","a":"elektron bulutu","d":"Elektronun sık bulunduğu bu yoğun bölge bir <b>elektron bulutu</b> gibidir."}],"ans":"Pervanelerin lamba çevresinde yoğunlaşması gibi, elektron da çekirdek çevresinde yoğun bir elektron bulutu oluşturur."},{"q":"Modern atom modeli mi yoksa eski Bohr modeli mi atomu gerçeğe daha yakın anlatır?","steps":[{"t":"Daha gelişmiş","a":"modern model","d":"Modern model elektronları daha doğru, bulut (olasılık) olarak anlatır."},{"t":"Sonuç","a":"modern daha yakın","d":"Bu yüzden <b>modern atom modeli</b> gerçeğe daha yakındır; Bohr modeli daha basit ve eksiktir."}],"ans":"Modern atom modeli, elektronları olasılık bulutu olarak anlattığından atomu gerçeğe daha yakın açıklar."}],"zor":[{"q":"İki çocuktan biri 'elektron tam şu noktada' diyor, diğeri 'şu bölgede bulunma ihtimali yüksek' diyor. Modern modele göre hangisi haklı?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='50' fill='#2b6be0' opacity='0.18'/><circle cx='85' cy='70' r='2' fill='#1a2b45'/><circle cx='118' cy='95' r='2' fill='#1a2b45'/><circle cx='100' cy='115' r='2' fill='#1a2b45'/><circle cx='75' cy='95' r='2' fill='#1a2b45'/></svg>","steps":[{"t":"Kesin nokta yok","a":"ihtimal var","d":"Modern modele göre elektronun kesin yeri bilinemez, sadece bulunma ihtimali bilinir."},{"t":"Sonuç","a":"ikinci haklı","d":"'Bölgede bulunma ihtimali yüksek' diyen <b>ikinci çocuk</b> haklıdır."}],"ans":"Modern modele göre elektronun kesin yeri bilinemez; 'bölgede bulunma ihtimali yüksek' diyen ikinci çocuk haklıdır."},{"q":"Bohr modeli elektronu ince bir çizgi (ray) üzerinde, modern model ise bir bölge (bulut) içinde gösterir. Aradaki temel fark nedir?","steps":[{"t":"Bohr: çizgi","a":"kesin yol","d":"Bohr modeli elektronu, tren rayı gibi belirli kesin bir yolda gösterir."},{"t":"Sonuç","a":"modern: bulut","d":"Modern model ise elektronu kesin yol yerine bulunabileceği bir <b>bulut bölgesi</b> olarak gösterir."}],"ans":"Bohr elektronu kesin bir çizgi (yörünge) üzerinde; modern model ise bulunabileceği bir bulut bölgesi içinde gösterir."},{"q":"Modern modelde bir orbital çizilirken neden kesin bir çember yerine bulanık bir bulut çizilir?","steps":[{"t":"Belirsizlik","a":"kesin yer yok","d":"Elektronun yeri kesin bilinemediği için onu kesin bir çizgiyle gösteremeyiz."},{"t":"Sonuç","a":"yoğunluk bulutu","d":"Bunun yerine bulunma ihtimalinin çok olduğu yerleri koyu, az olduğu yerleri açık gösteren bir <b>bulut</b> çizilir."}],"ans":"Elektronun kesin yeri bilinemediğinden, bulunma ihtimalini gösteren bulanık bir yoğunluk bulutu çizilir."},{"q":"Bir orbitalin koyu (yoğun) bölgesi ile açık (seyrek) bölgesi neyi anlatır?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='14' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='30' fill='#2b6be0' opacity='0.35'/><circle cx='100' cy='85' r='55' fill='#2b6be0' opacity='0.12'/></svg>","steps":[{"t":"Koyu yer","a":"sık bulunur","d":"Koyu bölge elektronun en çok bulunduğu, ihtimalin yüksek olduğu yerdir."},{"t":"Sonuç","a":"açık yer seyrek","d":"Açık bölge ise elektronun <b>az</b> bulunduğu yerdir; koyuluk bulunma sıklığını gösterir."}],"ans":"Koyu bölge elektronun sık (yüksek ihtimalle), açık bölge ise seyrek bulunduğu yeri gösterir."},{"q":"Modern atom modeli neden Bohr modelinden daha güvenilir kabul edilir?","steps":[{"t":"Daha çok açıklar","a":"çok elektron da","d":"Modern model sadece hidrojeni değil, çok elektronlu atomları da doğru açıklar."},{"t":"Sonuç","a":"daha güvenilir","d":"Daha çok atomu ve ayrıntıyı doğru anlattığı için modern model daha <b>güvenilirdir</b>."}],"ans":"Modern model çok elektronlu atomları da doğru açıkladığından Bohr modelinden daha güvenilir kabul edilir."}]},"ortaokul":{"kolay":[{"q":"Modern atom modelinde elektronun çekirdek çevresinde bulunma ihtimalinin yüksek olduğu bölgeye ne ad verilir?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='13' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='48' fill='#2b6be0' opacity='0.2'/><circle cx='100' cy='85' r='32' fill='#2b6be0' opacity='0.25'/></svg>","steps":[{"t":"Bulunma bölgesi","a":"ihtimal yüksek","d":"Modern modelde elektronun çekirdek çevresinde en çok bulunduğu, ihtimalin yüksek olduğu bir bölge vardır."},{"t":"Sonuç","a":"orbital","d":"Bu bölgeye <b>orbital</b> denir; kesin yörünge değil, olasılık bölgesidir."}],"ans":"Elektronun bulunma ihtimalinin yüksek olduğu bölgeye orbital denir."},{"q":"Modern atom modeli, elektronun yerini neden 'kesin' değil 'olasılıkla' belirtir?","steps":[{"t":"Belirsizlik","a":"yer-hız","d":"Elektronun yeri ve hızı aynı anda kesin bilinemez (belirsizlik ilkesi)."},{"t":"Sonuç","a":"olasılık","d":"Bu yüzden modern model elektronun kesin yeri yerine, bir bölgede bulunma <b>olasılığını</b> verir."}],"ans":"Belirsizlik nedeniyle elektronun yeri kesin bilinemez; bu yüzden modern model olasılık (bulunma ihtimali) kullanır."},{"q":"Modern atom modelinde çekirdek çevresindeki yoğun elektron bölgesine günlük dilde ne denir?","steps":[{"t":"Yoğun bölge","a":"elektron çok","d":"Elektronun sık bulunduğu, ihtimalin yüksek olduğu bölge yoğun görünür."},{"t":"Sonuç","a":"elektron bulutu","d":"Bu yoğun bölgeye <b>elektron bulutu</b> denir; bulut, elektronun bulunma yoğunluğunu temsil eder."}],"ans":"Elektronun yoğun bulunduğu bölgeye elektron bulutu denir."},{"q":"Bohr modeli ile modern atom modeli arasındaki en temel fark nedir?","steps":[{"t":"Bohr","a":"kesin yörünge","d":"Bohr modeli elektronu, belirli yarıçaplı kesin bir yörüngede gösterir."},{"t":"Sonuç","a":"modern: olasılık/orbital","d":"Modern model ise elektronu kesin yörünge yerine bulunma <b>olasılığının</b> tanımlandığı orbital ile gösterir."}],"ans":"Bohr elektronu kesin yörüngede; modern model ise olasılıkla tanımlanan orbital (bulut) içinde gösterir."},{"q":"Modern atom modeli, Bohr modelinin açıklayamadığı hangi tür atomları da başarıyla açıklar?","steps":[{"t":"Bohr'un eksiği","a":"çok elektron","d":"Bohr modeli çok elektronlu atomlarda yetersiz kalır."},{"t":"Sonuç","a":"modern: çok elektron","d":"Modern model çok elektronlu atomların yapısını ve spektrumunu da <b>başarıyla</b> açıklar."}],"ans":"Modern atom modeli, Bohr modelinin açıklayamadığı çok elektronlu atomları da başarıyla açıklar."}],"zor":[{"q":"Modern atom modeli neden 'olasılık modeli' olarak da adlandırılır?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='50' fill='#2b6be0' opacity='0.15'/><circle cx='82' cy='68' r='2' fill='#1a2b45'/><circle cx='120' cy='98' r='2' fill='#1a2b45'/><circle cx='100' cy='112' r='2' fill='#1a2b45'/><circle cx='72' cy='92' r='2' fill='#1a2b45'/><circle cx='112' cy='70' r='2' fill='#1a2b45'/></svg>","steps":[{"t":"Kesin yer yok","a":"ihtimal verilir","d":"Model elektronun kesin yerini değil, bir bölgede bulunma olasılığını (ihtimalini) verir."},{"t":"Sonuç","a":"olasılık modeli","d":"Elektronu olasılıklarla tanımladığı için modern modele <b>olasılık modeli</b> de denir."}],"ans":"Modern model elektronun kesin yerini değil bulunma olasılığını verdiğinden, ona olasılık modeli de denir."},{"q":"Orbital ile Bohr'un yörüngesi arasındaki fark nedir?","steps":[{"t":"Yörünge","a":"kesin çizgi","d":"Bohr'un yörüngesi, elektronun üzerinde döndüğü kesin yarıçaplı bir çizgidir."},{"t":"Orbital","a":"olasılık bölgesi","d":"Orbital ise elektronun bulunma ihtimalinin yüksek olduğu bir <b>bölgedir</b>, kesin bir çizgi değildir."}],"ans":"Yörünge kesin bir çizgidir; orbital ise elektronun bulunma ihtimalinin yüksek olduğu bir bölgedir."},{"q":"Modern atom modeline göre bir orbitalin sınırını kesin bir çizgiyle çizmek neden doğru değildir?","steps":[{"t":"İhtimal asla sıfır olmaz","a":"uzakta bile az ihtimal","d":"Elektronun çok uzakta bile bulunma ihtimali tam sıfır olmadığından net bir dış sınır yoktur."},{"t":"Sonuç","a":"yaklaşık sınır","d":"Bu yüzden orbital, ihtimalin örneğin %90 olduğu bölgeyi gösteren <b>yaklaşık bir sınırla</b> çizilir; kesin çizgi yanlıştır."}],"ans":"Elektronun bulunma ihtimali hiçbir yerde tam sıfır olmadığından orbitalin kesin sınırı yoktur; ancak %90 ihtimal gibi yaklaşık bir sınırla çizilir."},{"q":"Modern atom modelinin temelinde, elektronu olasılıkla tanımlayan denklem kim tarafından ortaya konmuştur?","steps":[{"t":"Olasılık fikri","a":"dalga denklemi","d":"Elektronun bulunma olasılığını veren dalga denklemi geliştirilmiştir."},{"t":"Sonuç","a":"Schrödinger","d":"Bu denklemi <b>Schrödinger</b> ortaya koymuştur; çözümleri elektronun orbitallerini (bulunma olasılığını) verir."}],"ans":"Modern atom modelinin temelindeki olasılık (dalga) denklemini Schrödinger ortaya koymuştur."},{"q":"Bir atomda elektron bulutunun çekirdeğe yakın yerlerde daha koyu, uzaklaştıkça daha açık çizilmesi neyi gösterir?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='14' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='26' fill='#2b6be0' opacity='0.4'/><circle cx='100' cy='85' r='42' fill='#2b6be0' opacity='0.2'/><circle cx='100' cy='85' r='60' fill='#2b6be0' opacity='0.08'/></svg>","steps":[{"t":"Koyuluk = ihtimal","a":"yoğunluk","d":"Bulutun koyuluğu, elektronun o bölgede bulunma ihtimalini (yoğunluğunu) gösterir."},{"t":"Sonuç","a":"yakında ihtimal yüksek","d":"Çekirdeğe yakın koyu bölgede elektronun bulunma ihtimali <b>yüksek</b>, uzakta açık bölgede düşüktür."}],"ans":"Bulutun koyuluğu bulunma ihtimalini gösterir; çekirdeğe yakın yerlerde elektronun bulunma ihtimali yüksek, uzaklaştıkça düşüktür."}]},"lise":{"kolay":[{"q":"Modern (kuantum mekaniksel) atom modeli, elektronu Bohr modelinden farklı olarak nasıl tanımlar?","fig":"<svg viewBox='0 0 200 170'><circle cx='100' cy='85' r='12' fill='#e0552b' stroke='#1a2b45'/><circle cx='100' cy='85' r='50' fill='#2b6be0' opacity='0.16'/><circle cx='100' cy='85' r='34' fill='#2b6be0' opacity='0.22'/><circle cx='84' cy='70' r='2' fill='#1a2b45'/><circle cx='116' cy='98' r='2' fill='#1a2b45'/></svg>","steps":[{"t":"Kesin yörünge yok","a":"olasılık","d":"Modern model, elektronun kesin yörüngesini reddeder; konumu yerine bulunma olasılığını tanımlar."},{"t":"Sonuç","a":"orbital (bulut)","d":"Elektron, bulunma olasılığının tanımlandığı <b>orbital (elektron bulutu)</b> ile ifade edilir."}],"ans":"Modern model elektronu kesin yörünge yerine, bulunma olasılığının tanımlandığı orbital (elektron bulutu) olarak tanımlar."},{"q":"Modern atom modelinde 'orbital' kavramını tanımlayınız.","steps":[{"t":"Tanım","a":"olasılık bölgesi","d":"Orbital, elektronun çekirdek çevresinde bulunma olasılığının yüksek (genellikle %90) olduğu üç boyutlu bölgedir."},{"t":"Sonuç","a":"yörünge değil","d":"Orbital, Bohr'un kesin yörüngesinden farklıdır; belirli bir yol değil, bir <b>olasılık dağılımıdır</b>."}],"ans":"Orbital, elektronun bulunma olasılığının yüksek olduğu üç boyutlu bölgedir; kesin bir yörünge değil, olasılık dağılımıdır."},{"q":"Modern atom modelinin matematiksel temelini oluşturan denklem nedir ve çözümü neyi verir?","steps":[{"t":"Denklem","a":"Schrödinger denklemi","d":"Modern modelin temeli Schrödinger dalga denklemidir; elektronu bir dalga fonksiyonu (ψ) ile tanımlar."},{"t":"Çözüm","a":"|ψ|² = olasılık","d":"Dalga fonksiyonunun karesi |ψ|², elektronun belirli bir noktada bulunma <b>olasılık yoğunluğunu</b> verir; bu da orbitalleri belirler."}],"ans":"Temeli Schrödinger denklemidir; çözümündeki dalga fonksiyonunun karesi (|ψ|²) elektronun bulunma olasılık yoğunluğunu, yani orbitalleri verir."},{"q":"Modern atom modeli neden Heisenberg belirsizlik ilkesiyle uyumludur?","steps":[{"t":"Belirsizlik ilkesi","a":"yer-hız kesin değil","d":"Belirsizlik ilkesine göre elektronun konumu ve momentumu aynı anda kesin bilinemez."},{"t":"Uyum","a":"olasılık kullanır","d":"Modern model kesin konum yerine bulunma <b>olasılığını</b> kullandığından, belirsizlik ilkesiyle çelişmez; onunla uyumludur."}],"ans":"Modern model kesin konum yerine bulunma olasılığını kullandığından, konum ve hızın aynı anda kesin bilinemeyeceğini söyleyen belirsizlik ilkesiyle uyumludur."},{"q":"Atom modellerinin tarihsel gelişim sırasını ve modern modelin bu sıradaki yerini belirtiniz.","steps":[{"t":"Sıralama","a":"Dalton→...→modern","d":"Sıra: Dalton → Thomson → Rutherford → Bohr → modern (kuantum mekaniksel) modeldir."},{"t":"Sonuç","a":"en gelişmiş model","d":"Modern model bu sıranın <b>en sonunda</b> ve bugün kabul edilen, en gelişmiş atom modelidir."}],"ans":"Sıra Dalton → Thomson → Rutherford → Bohr → modern modeldir; modern model en sonda yer alan, bugün kabul edilen modeldir."}],"zor":[{"q":"Bir dalga fonksiyonu ψ verildiğinde elektronun belirli bir bölgede bulunma olasılığı hangi büyüklükle hesaplanır? Açıklayınız.","steps":[{"t":"Olasılık yoğunluğu","a":"|ψ|²","d":"Bir noktadaki elektron bulunma olasılık yoğunluğu, dalga fonksiyonunun karesi |ψ|² ile verilir."},{"t":"Bölge olasılığı","a":"|ψ|² hacim toplamı","d":"Belirli bir bölgedeki bulunma olasılığı, o bölge boyunca |ψ|²'nin toplamıdır (integrali)."},{"t":"Sonuç","a":"orbital sınırı","d":"Bu olasılık %90 olan yüzey, orbitalin <b>sınır yüzeyi</b> olarak çizilir."}],"ans":"Elektronun bir noktadaki bulunma olasılık yoğunluğu |ψ|² ile verilir; bir bölgedeki olasılık ise |ψ|²'nin o bölge boyunca toplamıdır (integrali)."},{"q":"Modern atom modeli ile Bohr modelinin elektron tanımını üç noktada karşılaştırınız.","steps":[{"t":"Konum","a":"kesin vs olasılık","d":"Bohr: kesin yörünge/konum; modern: olasılık (orbital)."},{"t":"Geometri","a":"daire vs çeşitli şekil","d":"Bohr: dairesel düzlem yörünge; modern: s küresel, p loblu gibi üç boyutlu orbital şekilleri."},{"t":"Kapsam","a":"H vs tüm atomlar","d":"Bohr yalnız tek elektronlu sistemlerde başarılı; modern model <b>tüm atomları</b> açıklar."}],"ans":"Konum (kesin yörünge ↔ olasılık), geometri (dairesel ↔ üç boyutlu orbital şekilleri) ve kapsam (yalnız H ↔ tüm atomlar) bakımından modern model Bohr'dan üstündür."},{"q":"Modern atom modelinde orbitallerin doldurulmasını yöneten üç temel ilkeyi (Aufbau, Pauli, Hund) açıklayınız.","steps":[{"t":"Aufbau","a":"düşük enerjiden","d":"Aufbau ilkesine göre elektronlar önce en düşük enerjili orbitalleri doldurur."},{"t":"Pauli","a":"orbitalde zıt spin","d":"Pauli dışarlama ilkesine göre bir orbitalde en çok 2 elektron, zıt spinli (↑↓) bulunur."},{"t":"Hund","a":"önce tek tek","d":"Hund kuralına göre eş enerjili orbitaller önce birer elektronla (aynı spinli) doldurulur, sonra eşleşir."}],"ans":"Aufbau: en düşük enerjiden başla; Pauli: bir orbitalde en çok 2 zıt spinli elektron; Hund: eş enerjili orbitalleri önce tek tek doldur, sonra eşleştir."},{"q":"Heisenberg belirsizlik ilkesi (Δx·Δp ≥ h/4π), modern atom modelinin neden 'yörünge' yerine 'orbital' kavramını kullandığını nasıl gerektirir?","steps":[{"t":"İlke","a":"Δx·Δp ≥ h/4π","d":"Konumdaki belirsizlik Δx ile momentumdaki belirsizlik Δp aynı anda sıfır olamaz; ikisinin çarpımı h/4π'den küçük olamaz."},{"t":"Yörünge çelişkisi","a":"kesin yol imkansız","d":"Kesin yörünge, hem konumun hem hızın aynı anda tam bilinmesini gerektirir; bu ilkeyle çelişir."},{"t":"Sonuç","a":"orbital gerekir","d":"Bu yüzden kesin yol yerine, bulunma <b>olasılığını</b> tanımlayan orbital kavramı kullanılır."}],"ans":"Δx·Δp ≥ h/4π gereği konum ve hız aynı anda kesin bilinemez; bu, kesin yörüngeyi imkansız kılar, bu yüzden modern model olasılığı tanımlayan orbital kavramını kullanır."},{"q":"de Broglie ilişkisi λ = h/(m·v) bağlamında, elektronun dalga özelliği modern atom modelini nasıl temellendirir?","steps":[{"t":"Dalga boyu","a":"λ = h/(m·v)","d":"de Broglie'ye göre kütlesi m, hızı v olan elektronun dalga boyu λ = h/(m·v)'dir."},{"t":"Dalga davranışı","a":"durağan dalga","d":"Atom içindeki elektron bir durağan dalga gibi davranır; konumu ancak bir dalga fonksiyonuyla tanımlanabilir."},{"t":"Sonuç","a":"olasılık modeli","d":"Bu dalga doğası, Schrödinger denklemine ve elektronu olasılıkla tanımlayan <b>orbital modeline</b> temel oluşturur."}],"ans":"λ = h/(m·v) ile elektronun dalga boyu vardır; atom içinde durağan dalga gibi davranan elektron ancak dalga fonksiyonuyla tanımlanabilir, bu da olasılığa dayalı modern (orbital) modeli temellendirir."}]}},"orbitaller":{"ilkokul":{"kolay":[{"q":"Elektronlar çekirdeğin çevresinde belli bölgelerde bulunur. Bu bölgeleri elektronun <b>evi</b> gibi düşünebilir miyiz?","steps":[{"t":"Elektronun yeri","a":"belli bölge","d":"Elektronlar rastgele değil, kendilerine ait belli bölgelerde dolaşır."},{"t":"Ev benzetmesi","a":"evet, ev gibi","d":"Bu bölgelere orbital denir; elektronun en çok bulunduğu 'evi' gibidir."}],"ans":"Evet; orbital, elektronun en çok bulunduğu bölgedir, tıpkı elektronun evi gibi düşünülür."},{"q":"Bir top yuvarlaktır, bir balon ise iki ucu şişkin olabilir. Orbitallerin de farklı şekilleri var mıdır?","steps":[{"t":"Şekilleri düşün","a":"farklı şekiller","d":"Topun şekli ile balonun şekli farklıdır; her birinin biçimi başkadır."},{"t":"Orbitaller","a":"evet farklı","d":"Orbitallerin de top gibi yuvarlak ya da başka şekilleri olabilir."}],"ans":"Evet; orbitaller farklı şekillerde olabilir, kimisi top gibi yuvarlaktır."},{"q":"En basit orbital olan s orbitali hangi şekle benzer: bir topa mı, bir kaleme mi?","steps":[{"t":"Şekilleri karşılaştır","a":"yuvarlak olan","d":"Top yuvarlaktır, kalem ise uzun ve incedir."},{"t":"s orbitali","a":"top gibi","d":"s orbitali her yöne eşit, top (küre) gibi yuvarlaktır."}],"ans":"s orbitali bir topa (küreye) benzer; her yöne doğru eşit ve yuvarlaktır."},{"q":"Bir orbitalde (elektronun evinde) en fazla kaç elektron oturabilir?","steps":[{"t":"Ev kapasitesi","a":"sınırlı","d":"Bir orbital sınırlı sayıda elektron alabilir."},{"t":"Sayıyı söyle","a":"2 elektron","d":"Bir orbitalde en fazla 2 elektron bulunur."}],"ans":"Bir orbitalde en fazla 2 elektron oturabilir."},{"q":"Yuvarlak top şeklindeki orbitale s, iki ucu şişkin (halter gibi) orbitale ise p denir. Halter şekline benzeyen hangisidir?","steps":[{"t":"Şekilleri eşle","a":"p halter","d":"p orbitali iki ucu şişkin halter (dambıl) gibidir."},{"t":"Karşılaştır","a":"s top, p halter","d":"s top gibi yuvarlak, p ise halter gibidir."}],"ans":"Halter (dambıl) şekline benzeyen p orbitalidir; s ise top gibi yuvarlaktır."}],"zor":[{"q":"Bir s orbitali her yöne aynı, top gibi yuvarlaktır. Bu yüzden bir yöne mi, yoksa tüm yönlere mi eşit yayılır?","steps":[{"t":"Top şeklini düşün","a":"her yöne eşit","d":"Top her yöne aynı uzaklıkta yuvarlaktır."},{"t":"s orbitali","a":"tüm yönlere","d":"s orbitali de top gibi tüm yönlere eşit yayılır."}],"ans":"s orbitali top gibi tüm yönlere eşit yayılır, belli bir yönü yoktur."},{"q":"p orbitalleri halter gibidir ve uzayda farklı yönlere bakar. Kaç farklı p orbitali olduğunu düşünürsün: 1 mi, 3 mü?","steps":[{"t":"Yönleri düşün","a":"3 yön","d":"Bir halter sağ-sol, ön-arka, yukarı-aşağı gibi 3 farklı yöne yerleşebilir."},{"t":"p sayısı","a":"3 tane","d":"Bu yüzden 3 farklı p orbitali vardır."}],"ans":"3 farklı p orbitali vardır; her biri uzayda ayrı bir yöne bakar."},{"q":"Bir orbital 2 elektron alıyorsa, 3 tane p orbitali toplam kaç elektron alır?","steps":[{"t":"Tek orbital","a":"2 elektron","d":"Her orbital en fazla 2 elektron alır."},{"t":"3 orbital","a":"3 × 2 = 6","d":"3 p orbitalinin her biri 2 elektron alırsa toplam 6 olur."}],"ans":"3 p orbitali toplam 6 elektron alır (3 × 2 = 6)."},{"q":"s orbitali top gibi yuvarlak, d orbitali ise yonca yaprağına benzetilir. Daha karmaşık şekilli olan hangisidir?","steps":[{"t":"Şekilleri karşılaştır","a":"yonca daha karmaşık","d":"Top basit bir yuvarlak, yonca ise birden çok yapraklı, daha karmaşık bir şekildir."},{"t":"Sonuç","a":"d orbitali","d":"d orbitali yonca gibi olduğundan s'ten daha karmaşıktır."}],"ans":"Daha karmaşık şekilli olan d orbitalidir; s top gibi basitken d yonca gibidir."},{"q":"Bir elektronun evi olan orbitalde elektron çekirdeğin tam yerine mi, yoksa çevresindeki bir bölgeye mi dağılmıştır?","steps":[{"t":"Çekirdeği düşün","a":"merkezde","d":"Çekirdek atomun ortasındadır; elektron çekirdeğin içinde durmaz."},{"t":"Elektronun yeri","a":"çevredeki bölge","d":"Elektron, çekirdeğin çevresindeki bir bölgeye (orbitale) dağılmış olarak bulunur."}],"ans":"Elektron, çekirdeğin çevresindeki bir bölgeye (orbitale) dağılmıştır, tek bir noktada durmaz."}]},"ortaokul":{"kolay":[{"q":"Orbital kavramı bir elektron için neyi ifade eder?","steps":[{"t":"Orbital nedir","a":"bulunma bölgesi","d":"Orbital, elektronun büyük olasılıkla bulunduğu bölgedir."},{"t":"Anlamı","a":"olasılık bölgesi","d":"Elektronun tam yeri kesin bilinemez; orbital onun en çok bulunduğu bölgeyi gösterir."}],"ans":"Orbital, bir elektronun büyük olasılıkla bulunduğu, belli şekli olan bölgedir."},{"q":"s ve p orbitalleri hangi şekillere benzetilir?","steps":[{"t":"s şekli","a":"küre","d":"s orbitali küre (top) şeklindedir, her yöne eşittir."},{"t":"p şekli","a":"halter","d":"p orbitali iki loblu halter (dambıl) şeklindedir."}],"ans":"s orbitali küre (top), p orbitali ise halter (dambıl) şekline benzetilir."},{"q":"Bir orbitalde en fazla kaç elektron bulunabilir?","steps":[{"t":"Orbital kapasitesi","a":"sınırlı","d":"Her orbital sınırlı sayıda elektron alır."},{"t":"Sayıyı söyle","a":"2 elektron","d":"Bir orbitalde en fazla 2 elektron bulunur; bunların dönüş yönü zıttır."}],"ans":"Bir orbitalde en fazla 2 elektron bulunabilir ve bunların spinleri zıttır."},{"q":"p alt kabuğunda kaç tane orbital vardır ve bu alt kabuk en fazla kaç elektron alır?","steps":[{"t":"Orbital sayısı","a":"3 orbital","d":"p alt kabuğunda px, py, pz olmak üzere 3 orbital bulunur."},{"t":"Elektron sayısı","a":"3 × 2 = 6","d":"Her orbital 2 elektron aldığından p alt kabuğu en fazla 6 elektron alır."}],"ans":"p alt kabuğunda 3 orbital vardır ve en fazla 6 elektron alır."},{"q":"s alt kabuğunda kaç orbital bulunur ve en fazla kaç elektron alır?","steps":[{"t":"Orbital sayısı","a":"1 orbital","d":"s alt kabuğunda yalnızca 1 orbital bulunur."},{"t":"Elektron sayısı","a":"2 elektron","d":"Tek orbital 2 elektron aldığından s alt kabuğu en fazla 2 elektron alır."}],"ans":"s alt kabuğunda 1 orbital bulunur ve en fazla 2 elektron alır."}],"zor":[{"q":"s, p, d ve f alt kabuklarının orbital sayılarını ve en fazla elektron kapasitelerini sıralayınız.","steps":[{"t":"Orbital sayıları","a":"1, 3, 5, 7","d":"s'de 1, p'de 3, d'de 5, f'de 7 orbital bulunur."},{"t":"Kapasiteler","a":"2, 6, 10, 14","d":"Her orbital 2 elektron aldığından kapasiteler 2, 6, 10, 14 olur."}],"ans":"s(1 orbital, 2 e⁻), p(3 orbital, 6 e⁻), d(5 orbital, 10 e⁻), f(7 orbital, 14 e⁻)."},{"q":"d alt kabuğu en fazla kaç elektron alır ve bunu hangi orbital sayısıyla açıklarsınız?","steps":[{"t":"Orbital sayısı","a":"5 orbital","d":"d alt kabuğunda 5 orbital bulunur."},{"t":"Elektron sayısı","a":"5 × 2 = 10","d":"Her orbital 2 elektron aldığından d alt kabuğu en fazla 10 elektron alır."}],"ans":"d alt kabuğu 5 orbital içerir ve en fazla 5 × 2 = 10 elektron alır."},{"q":"Bir orbitalin yalnızca 2 elektron alabilmesinin sebebi nedir?","steps":[{"t":"Spin sınırı","a":"iki spin var","d":"Bir orbitaldeki elektronları yalnızca spinleri (+½ ve −½) ayırabilir."},{"t":"Sonuç","a":"en çok 2","d":"İki farklı spin olduğundan bir orbitalde en fazla 2 elektron bulunabilir."}],"ans":"Spin yalnızca iki değer (+½, −½) aldığından bir orbital en fazla 2 elektron alabilir."},{"q":"f alt kabuğu kaç orbital içerir ve tam dolduğunda kaç elektron bulunur?","steps":[{"t":"Orbital sayısı","a":"7 orbital","d":"f alt kabuğunda 7 orbital bulunur."},{"t":"Elektron sayısı","a":"7 × 2 = 14","d":"Her orbital 2 elektron aldığından f alt kabuğu tam dolduğunda 14 elektron içerir."}],"ans":"f alt kabuğu 7 orbital içerir ve tam dolduğunda 14 elektron (f¹⁴) bulunur."},{"q":"Bir orbital ile bir alt kabuk arasındaki fark nedir?","steps":[{"t":"Orbital","a":"tek bölge","d":"Orbital, en fazla 2 elektron alan tek bir bulunma bölgesidir."},{"t":"Alt kabuk","a":"orbital grubu","d":"Alt kabuk (s, p, d, f) aynı türden bir veya birden çok orbitalin oluşturduğu gruptur."}],"ans":"Orbital tek bir bölgedir (2 e⁻); alt kabuk ise aynı türden orbitallerin oluşturduğu gruptur (örneğin p'de 3 orbital)."}]},"lise":{"kolay":[{"q":"Modern atom modelinde orbital nasıl tanımlanır?","steps":[{"t":"Olasılık fikri","a":"bulunma olasılığı","d":"Modern modelde elektronun yeri kesin değildir; orbital, bulunma olasılığının yüksek olduğu bölgedir."},{"t":"Tanım","a":"olasılık bölgesi","d":"Orbital, bir elektronun bulunma olasılığının (yaklaşık %90) yüksek olduğu uzaysal bölgedir."}],"ans":"Orbital, bir elektronun bulunma olasılığının yüksek olduğu (yaklaşık %90'lık) uzaysal bölgedir."},{"q":"s, p, d ve f orbitallerinin şekilleri nasıl tanımlanır?","steps":[{"t":"s ve p","a":"küre, halter","d":"s orbitali küresel, p orbitali iki loblu (halter) biçimdedir."},{"t":"d ve f","a":"yonca, karmaşık","d":"d orbitali çoğunlukla dört loblu (yonca) biçimde, f orbitali ise daha karmaşık çok loblu yapıdadır."}],"ans":"s küresel, p iki loblu (halter), d genelde dört loblu (yonca), f ise daha karmaşık çok loblu biçimdedir."},{"q":"Her orbitalde en fazla kaç elektron bulunabilir ve bu hangi ilkeyle sınırlanır?","steps":[{"t":"Sayı","a":"2 elektron","d":"Bir orbitalde en fazla 2 elektron bulunabilir."},{"t":"İlke","a":"Pauli ilkesi","d":"Bu sınır Pauli dışarlama ilkesinden gelir; iki elektron yalnızca zıt spinle (+½, −½) aynı orbitalde bulunabilir."}],"ans":"Her orbital en fazla 2 elektron alır; bu sınır Pauli dışarlama ilkesinden gelir (elektronlar zıt spinli olmalıdır)."},{"q":"s, p, d, f alt kabuklarının elektron kapasiteleri sırasıyla nelerdir?","fig":"<svg viewBox='0 0 320 90'><text x='40' y='30' font-size='12' fill='#1a2b45'>s</text><text x='40' y='55' font-size='11' fill='#2b6be0'>2</text><text x='110' y='30' font-size='12' fill='#1a2b45'>p</text><text x='110' y='55' font-size='11' fill='#2b6be0'>6</text><text x='180' y='30' font-size='12' fill='#1a2b45'>d</text><text x='180' y='55' font-size='11' fill='#2b6be0'>10</text><text x='250' y='30' font-size='12' fill='#1a2b45'>f</text><text x='250' y='55' font-size='11' fill='#2b6be0'>14</text></svg>","steps":[{"t":"Orbital sayıları","a":"1,3,5,7","d":"s'de 1, p'de 3, d'de 5, f'de 7 orbital bulunur (2ℓ+1)."},{"t":"Kapasiteler","a":"2,6,10,14","d":"Her orbital 2 elektron aldığından kapasiteler 2, 6, 10, 14 olur."}],"ans":"Kapasiteler: s = 2, p = 6, d = 10, f = 14 elektrondur."},{"q":"p alt kabuğunda kaç orbital vardır ve bunlar uzayda nasıl yerleşir?","steps":[{"t":"Orbital sayısı","a":"3 orbital","d":"p alt kabuğunda 3 orbital bulunur (2ℓ+1 = 3)."},{"t":"Yönelimler","a":"px, py, pz","d":"Bu üç orbital uzayda x, y ve z eksenleri boyunca birbirine dik yerleşir."}],"ans":"p alt kabuğunda 3 orbital (px, py, pz) vardır; bunlar uzayda birbirine dik üç eksen boyunca yerleşir."}],"zor":[{"q":"d alt kabuğunun orbital sayısını, elektron kapasitesini ve hangi açısal kuantum sayısına karşılık geldiğini açıklayınız.","steps":[{"t":"Açısal kuantum","a":"ℓ = 2","d":"d alt kabuğu ℓ = 2 değerine karşılık gelir."},{"t":"Orbital sayısı","a":"2ℓ+1 = 5","d":"ℓ = 2 için 2·2+1 = 5 orbital bulunur (mₗ = −2..+2)."},{"t":"Kapasite","a":"5 × 2 = 10","d":"Her orbital 2 elektron aldığından d alt kabuğu 10 elektron alır."}],"ans":"d alt kabuğu ℓ = 2'ye karşılık gelir; 5 orbital içerir ve en fazla 2·5 = 10 elektron alır."},{"q":"Bir küresel s orbitali ile halter biçimli p orbitalinin çekirdeğe göre simetrisini karşılaştırınız.","fig":"<svg viewBox='0 0 320 120'><circle cx='80' cy='60' r='30' fill='none' stroke='#e0552b' stroke-width='1.5'/><circle cx='80' cy='60' r='2' fill='#1a2b45'/><text x='80' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>s (kuresel)</text><ellipse cx='220' cy='38' rx='12' ry='24' fill='none' stroke='#2b6be0' stroke-width='1.5'/><ellipse cx='220' cy='82' rx='12' ry='24' fill='none' stroke='#2b6be0' stroke-width='1.5'/><circle cx='220' cy='60' r='2' fill='#1a2b45'/><text x='220' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>p (halter)</text></svg>","steps":[{"t":"s simetrisi","a":"küresel simetri","d":"s orbitali her yöne eşittir; çekirdek etrafında küresel simetriye sahiptir, belirgin bir yönü yoktur."},{"t":"p simetrisi","a":"eksen yönlü","d":"p orbitali iki loblu olup belli bir eksen boyunca uzanır; loblar arasında çekirdekte düğüm düzlemi bulunur."}],"ans":"s orbitali küresel simetriktir (yönsüz), p orbitali ise belli bir eksen boyunca uzanan iki lobludur ve çekirdekte bir düğüm düzlemi içerir."},{"q":"f alt kabuğunun orbital sayısını ve kapasitesini, açısal kuantum sayısı üzerinden hesaplayınız.","steps":[{"t":"Açısal kuantum","a":"ℓ = 3","d":"f alt kabuğu ℓ = 3 değerine karşılık gelir."},{"t":"Orbital sayısı","a":"2ℓ+1 = 7","d":"ℓ = 3 için mₗ = −3..+3 olmak üzere 7 orbital bulunur."},{"t":"Kapasite","a":"7 × 2 = 14","d":"Her orbital 2 elektron aldığından f alt kabuğu 14 elektron alır."}],"ans":"f alt kabuğu ℓ = 3'tür; 2ℓ+1 = 7 orbital içerir ve en fazla 2·7 = 14 elektron (f¹⁴) alır."},{"q":"Bir orbitalde düğüm (node) ne anlama gelir ve 2p orbitalinde neden bir düğüm düzlemi vardır?","steps":[{"t":"Düğüm tanımı","a":"olasılık sıfır","d":"Düğüm, elektronun bulunma olasılığının sıfır olduğu bölge ya da düzlemdir."},{"t":"2p durumu","a":"çekirdekte düğüm","d":"2p orbitali iki lobdan oluşur; loblar arasında, çekirdeğin bulunduğu yerde elektron yoğunluğu sıfırdır, yani bir düğüm düzlemi vardır."}],"ans":"Düğüm, elektron bulunma olasılığının sıfır olduğu yerdir; 2p orbitalinin iki lobu arasında, çekirdekten geçen bir düğüm düzlemi bulunur."},{"q":"3d alt kabuğu için orbital sayısını, manyetik kuantum sayısının değerlerini ve toplam elektron kapasitesini bulunuz.","fig":"<svg viewBox='0 0 320 90'><rect x='25' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='40' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>−2</text><rect x='75' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='90' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>−1</text><rect x='125' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='140' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>0</text><rect x='175' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='190' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>+1</text><rect x='225' y='35' width='30' height='30' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='240' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>+2</text><text x='280' y='55' font-size='11' fill='#2b6be0'>10 e</text></svg>","steps":[{"t":"mₗ değerleri","a":"−2..+2","d":"3d için ℓ = 2 olduğundan mₗ = −2, −1, 0, +1, +2 olmak üzere 5 değer alır."},{"t":"Orbital sayısı","a":"5 orbital","d":"2ℓ+1 = 5 orbital bulunur."},{"t":"Kapasite","a":"5 × 2 = 10","d":"Her orbital 2 elektron aldığından 3d en fazla 10 elektron alır."}],"ans":"3d alt kabuğunda mₗ = −2, −1, 0, +1, +2 (5 orbital) bulunur ve en fazla 2·5 = 10 elektron alır."}]}},"parcacikYuk":{"ilkokul":{"kolay":[{"q":"Atomun içinde hangi üç küçük tanecik bulunur?","steps":[{"t":"Çekirdektekiler","a":"proton ve nötron","d":"Atomun ortasındaki çekirdekte proton ve nötron bulunur."},{"t":"Çevredeki","a":"elektron","d":"Çekirdeğin etrafında ise elektronlar dolaşır."}],"ans":"Atomda proton, nötron ve elektron adı verilen üç tanecik bulunur."},{"q":"Proton hangi yüke sahiptir?","steps":[{"t":"Proton","a":"artı yük","d":"Proton artı (+) yüklü bir taneciktir."},{"t":"Yer","a":"çekirdekte","d":"Proton, atomun çekirdeğinde bulunur."}],"ans":"Proton artı (+) yüklüdür."},{"q":"Elektron hangi yüke sahiptir?","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='90' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='95' font-size='11' text-anchor='middle' fill='#fff'>+</text><circle cx='160' cy='90' r='45' fill='none' stroke='#1a2b45'/><circle cx='205' cy='90' r='8' fill='#2b6be0'/><text x='205' y='94' font-size='9' text-anchor='middle' fill='#fff'>−</text><text x='160' y='155' font-size='11' text-anchor='middle' fill='#1a2b45'>elektron (−)</text></svg>","steps":[{"t":"Elektron","a":"eksi yük","d":"Elektron eksi (−) yüklü küçük bir taneciktir."},{"t":"Yer","a":"çekirdek çevresinde","d":"Elektron, çekirdeğin etrafında dolaşır."}],"ans":"Elektron eksi (−) yüklüdür."},{"q":"Nötronun yükü nedir?","steps":[{"t":"Nötron","a":"yüksüz","d":"Nötronun yükü yoktur, yani yüksüzdür (nötr)."},{"t":"Yer","a":"çekirdekte","d":"Nötron, protonlarla birlikte çekirdekte bulunur."}],"ans":"Nötron yüksüzdür (nötrdür), yükü yoktur."},{"q":"Atomun en hafif taneciği hangisidir?","steps":[{"t":"Karşılaştırma","a":"elektron çok hafif","d":"Elektron, proton ve nötrona göre çok çok hafiftir."},{"t":"Sonuç","a":"elektron","d":"Bu yüzden atomun en hafif taneciği elektrondur."}],"ans":"Atomun en hafif taneciği elektrondur."}],"zor":[{"q":"Bir atomda artı ve eksi yükler eşitse atomun yükü ne olur?","steps":[{"t":"Eşit yük","a":"proton = elektron","d":"Artı yüklü proton sayısı, eksi yüklü elektron sayısına eşittir."},{"t":"Denge","a":"birbirini götürür","d":"Eşit sayıda artı ve eksi yük birbirini dengeler, atom yüksüz kalır."}],"ans":"Proton ve elektron sayısı eşitse atom nötrdür, yani yüksüzdür."},{"q":"Proton ile nötron arasındaki en önemli benzerlik ve fark nedir?","steps":[{"t":"Benzerlik","a":"ağırlık ve yer","d":"İkisi de çekirdekte bulunur ve kütleleri (ağırlıkları) birbirine çok yakındır."},{"t":"Fark","a":"yük","d":"Proton artı yüklüyken nötronun yükü yoktur."}],"ans":"Proton ve nötron çekirdekte olup benzer kütledeyken; proton artı yüklü, nötron ise yüksüzdür."},{"q":"Elektron neden proton kadar ağır değildir, sonucu nedir?","steps":[{"t":"Kütle farkı","a":"çok hafif","d":"Elektronun kütlesi protonun kütlesinin yanında çok küçüktür."},{"t":"Sonuç","a":"kütleye katkı az","d":"Bu yüzden atomun kütlesini neredeyse sadece çekirdekteki proton ve nötronlar oluşturur."}],"ans":"Elektron çok hafif olduğu için atomun kütlesini neredeyse tümüyle çekirdekteki proton ve nötronlar belirler."},{"q":"Bir atomdaki yükleri taşıyan tanecikler hangileridir?","fig":"<svg viewBox='0 0 320 175'><circle cx='150' cy='85' r='22' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='90' font-size='11' text-anchor='middle' fill='#fff'>+</text><circle cx='172' cy='85' r='22' fill='#5b6b85' stroke='#1a2b45'/><text x='172' y='90' font-size='11' text-anchor='middle' fill='#fff'>0</text><circle cx='160' cy='85' r='62' fill='none' stroke='#1a2b45'/><circle cx='222' cy='85' r='9' fill='#2b6be0'/><text x='222' y='89' font-size='9' text-anchor='middle' fill='#fff'>−</text><text x='160' y='165' font-size='10' text-anchor='middle' fill='#1a2b45'>+ proton, 0 nötron, − elektron</text></svg>","steps":[{"t":"Yüklüler","a":"proton ve elektron","d":"Proton artı, elektron eksi yük taşır; bunlar atomun yüklü tanecikleridir."},{"t":"Yüksüz","a":"nötron","d":"Nötron yük taşımaz, yani yük dengesine katkısı yoktur."}],"ans":"Atomda yükü proton (+) ve elektron (−) taşır; nötron yüksüzdür."},{"q":"Bir atom elektron kaybederse yükü nasıl değişir?","steps":[{"t":"Eksi azalır","a":"e⁻ kaybı","d":"Elektron eksi yüklüdür; atom elektron kaybedince eksi yükü azalır."},{"t":"Sonuç","a":"artı yüklenir","d":"Geriye protonların fazlası kaldığı için atom artı (+) yüklü hale gelir."}],"ans":"Elektron kaybeden atom eksi yükünü kaybettiği için artı (+) yüklü hale gelir."}]},"ortaokul":{"kolay":[{"q":"Atomun temel taneciklerinin yük ve konumlarını sıralayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='88' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='150' y='84' font-size='10' fill='#fff'>p⁺</text><text x='168' y='98' font-size='10' fill='#fff'>n⁰</text><circle cx='160' cy='88' r='58' fill='none' stroke='#1a2b45'/><circle cx='218' cy='88' r='7' fill='#2b6be0'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>çekirdek: p⁺,n⁰ — çevre: e⁻</text></svg>","steps":[{"t":"Çekirdek","a":"p⁺ ve n⁰","d":"Çekirdekte artı yüklü proton (p⁺) ve yüksüz nötron (n⁰) bulunur."},{"t":"Çevre","a":"e⁻","d":"Çekirdeğin çevresinde eksi yüklü elektronlar (e⁻) bulunur."}],"ans":"Proton (+) ve nötron (0) çekirdekte; elektron (−) ise çekirdeğin çevresinde bulunur."},{"q":"Nötr bir atomda proton ve elektron sayıları arasındaki ilişki nedir?","steps":[{"t":"Yük dengesi","a":"eşitlik","d":"Nötr atomda artı yükler (proton) ile eksi yükler (elektron) birbirini dengelemelidir."},{"t":"Sonuç","a":"p = e","d":"Bu nedenle nötr atomda proton sayısı elektron sayısına eşittir (p = e)."}],"ans":"Nötr atomda proton sayısı elektron sayısına eşittir (p = e)."},{"q":"Proton sayısı bir element için neyi belirler?","steps":[{"t":"Kimlik","a":"atom numarası","d":"Proton sayısı atom numarasıdır ve elementin kimliğini belirler."},{"t":"Ayırt edici","a":"element değişir","d":"Proton sayısı değişirse element de değişir; örneğin 1 proton hidrojen, 2 proton helyumdur."}],"ans":"Proton sayısı atom numarasıdır ve hangi element olduğunu (elementin kimliğini) belirler."},{"q":"Kütle numarası hangi taneciklerin toplamıdır?","steps":[{"t":"Ağır tanecikler","a":"çekirdektekiler","d":"Atomun kütlesini çekirdekteki proton ve nötronlar oluşturur."},{"t":"Toplam","a":"p + n","d":"Kütle numarası, proton sayısı ile nötron sayısının toplamına eşittir."}],"ans":"Kütle numarası, çekirdekteki proton ve nötron sayılarının toplamıdır (kütle no = p + n)."},{"q":"Elektronun kütlesi proton ve nötrona göre nasıldır?","steps":[{"t":"Karşılaştırma","a":"çok küçük","d":"Elektronun kütlesi, proton ve nötronun kütlesine göre yaklaşık 1836 kat daha küçüktür."},{"t":"Sonuç","a":"ihmal edilir","d":"Bu yüzden atom kütlesi hesaplanırken elektronun kütlesi çoğu zaman ihmal edilir."}],"ans":"Elektron, proton ve nötrondan çok daha hafiftir; kütlesi atom kütlesi yanında ihmal edilir."}],"zor":[{"q":"Atom numarası 11 olan nötr sodyum atomunda kaç proton ve elektron vardır?","steps":[{"t":"Proton","a":"11 proton","d":"Atom numarası proton sayısını verir; sodyumun atom numarası 11 olduğundan 11 protonu vardır."},{"t":"Elektron","a":"11 elektron","d":"Nötr atomda elektron sayısı proton sayısına eşit olduğundan elektron sayısı da 11'dir."}],"ans":"Nötr sodyumda 11 proton ve 11 elektron bulunur (p = e = 11)."},{"q":"Kütle numarası 23, atom numarası 11 olan sodyumda kaç nötron vardır?","steps":[{"t":"İlişki","a":"kütle no = p + n","d":"Kütle numarası proton ile nötron sayısının toplamıdır."},{"t":"Hesap","a":"23 − 11 = 12","d":"Nötron sayısı = kütle no − proton no = 23 − 11 = 12 bulunur."}],"ans":"Sodyumda 12 nötron bulunur (23 − 11 = 12)."},{"q":"Bir atom 2 elektron alırsa hangi iyon ve yük oluşur?","steps":[{"t":"Eksi artar","a":"e⁻ kazancı","d":"Atom 2 elektron aldığında eksi yük sayısı, proton sayısından 2 fazla olur."},{"t":"Sonuç","a":"2− anyon","d":"Net yük 2− olur; bu negatif yüklü taneciğe anyon denir (örneğin O²⁻)."}],"ans":"2 elektron alan atom 2− yüklü bir anyon olur (örneğin O²⁻)."},{"q":"Na⁺ iyonunda proton ve elektron sayısı eşit midir, açıklayınız.","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='85' r='24' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='90' font-size='10' text-anchor='middle' fill='#fff'>11 p⁺</text><circle cx='160' cy='85' r='56' fill='none' stroke='#1a2b45'/><circle cx='216' cy='85' r='7' fill='#2b6be0'/><text x='160' y='165' font-size='10' text-anchor='middle' fill='#1a2b45'>Na⁺: 11 p⁺, 10 e⁻</text></svg>","steps":[{"t":"Elektron kaybı","a":"1 e⁻ verir","d":"Na atomu 1 elektron vererek Na⁺ olur; elektron sayısı 11'den 10'a düşer."},{"t":"Karşılaştırma","a":"p ≠ e","d":"Proton sayısı hâlâ 11, elektron 10'dur; eşit olmadığı için net yük +1'dir."}],"ans":"Hayır; Na⁺ iyonunda 11 proton ama 10 elektron vardır, eşit olmadığından net yük +1'dir."},{"q":"Aynı elementin iki atomu farklı nötron sayısına sahip olabilir mi?","steps":[{"t":"Proton sabit","a":"aynı element","d":"Bir elementin tüm atomlarında proton sayısı aynıdır; bu kimliklerini belirler."},{"t":"Nötron değişebilir","a":"izotop","d":"Nötron sayısı farklı olabilir; bu atomlara birbirinin izotopu denir (örneğin karbon-12 ve karbon-14)."}],"ans":"Evet; aynı elementin atomları aynı protona ama farklı nötron sayısına sahip olabilir, bunlara izotop denir."}]},"lise":{"kolay":[{"q":"Temel taneciklerin bağıl kütle ve yüklerini karşılaştırınız.","steps":[{"t":"Proton-nötron","a":"≈1 akb","d":"Proton ve nötronun kütlesi yaklaşık 1 atomik kütle birimidir; yükleri sırasıyla +1 ve 0'dır."},{"t":"Elektron","a":"≈1/1836","d":"Elektronun kütlesi protonun yaklaşık 1/1836'sıdır ve yükü −1'dir."}],"ans":"Proton (+1) ve nötron (0) ≈1 akb kütleli; elektron (−1) ise ≈1/1836 akb ile çok daha hafiftir."},{"q":"Atom numarası (Z) ve kütle numarası (A) neyi ifade eder?","steps":[{"t":"Atom numarası","a":"Z = proton","d":"Z proton sayısıdır ve elementin kimliğini belirler; nötr atomda elektron sayısına da eşittir."},{"t":"Kütle numarası","a":"A = p + n","d":"A, çekirdekteki proton ve nötron sayılarının toplamıdır."}],"ans":"Z proton sayısıdır (element kimliği), A ise proton ile nötron toplamıdır (A = Z + n)."},{"q":"Nötr atomda p = e eşitliği hangi temel ilkeden gelir?","steps":[{"t":"Yük korunumu","a":"net yük sıfır","d":"Nötr atomun net yükü sıfırdır; toplam artı yük toplam eksi yüke eşit olmalıdır."},{"t":"Eşitlik","a":"p = e","d":"Her proton +1, her elektron −1 taşıdığından net yükün sıfır olması için proton sayısı elektron sayısına eşit olmalıdır."}],"ans":"Nötr atomda net yükün sıfır olması ilkesi gereği proton sayısı elektron sayısına eşittir (p = e)."},{"q":"₁₇³⁵Cl atomunda proton, nötron ve elektron sayılarını bulunuz.","fig":"<svg viewBox='0 0 320 170'><rect x='110' y='45' width='100' height='80' fill='#f5f7fa' stroke='#1a2b45'/><text x='160' y='75' font-size='13' text-anchor='middle' fill='#1a2b45'>Cl</text><text x='95' y='60' font-size='11' fill='#1a2b45'>35</text><text x='95' y='118' font-size='11' fill='#1a2b45'>17</text><text x='160' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>üst: kütle no, alt: atom no</text></svg>","steps":[{"t":"Proton ve elektron","a":"17","d":"Atom numarası 17 olduğundan 17 proton vardır; nötr olduğundan elektron sayısı da 17'dir."},{"t":"Nötron","a":"35 − 17 = 18","d":"Nötron sayısı = kütle no − atom no = 35 − 17 = 18 bulunur."}],"ans":"₁₇³⁵Cl atomunda 17 proton, 17 elektron ve 18 nötron bulunur."},{"q":"İyon oluşurken hangi tanecik sayısı değişir, hangisi sabit kalır?","steps":[{"t":"Değişen","a":"elektron","d":"İyon oluşumunda atom yalnız elektron alır veya verir; bu yüzden elektron sayısı değişir."},{"t":"Sabit","a":"proton (ve nötron)","d":"Çekirdek korunduğundan proton (ve nötron) sayısı sabit kalır; element kimliği değişmez."}],"ans":"İyon oluşurken elektron sayısı değişir; proton (ve nötron) sayısı sabit kalır, element kimliği korunur."}],"zor":[{"q":"Bir Al³⁺ iyonu nasıl oluşur ve içinde kaç elektron bulunur (Al atom no = 13)?","steps":[{"t":"Elektron kaybı","a":"3 e⁻ verir","d":"Alüminyum atomu 3 değerlik elektronunu vererek Al³⁺ iyonuna dönüşür."},{"t":"Elektron sayısı","a":"13 − 3 = 10","d":"Proton sayısı 13 sabit kalır; elektron sayısı 13 − 3 = 10 olur, net yük +3'tür."}],"ans":"Al, 3 elektron vererek Al³⁺ olur; iyonda 13 proton ve 10 elektron bulunur (net yük +3)."},{"q":"İzotop, izoton ve izoelektronik kavramlarını tanecik sayıları üzerinden ayırt ediniz.","steps":[{"t":"İzotop ve izoton","a":"aynı p / aynı n","d":"İzotoplar aynı proton, farklı nötron sayılıdır; izotonlar ise aynı nötron, farklı proton sayılıdır."},{"t":"İzoelektronik","a":"aynı e⁻","d":"İzoelektronik tanecikler aynı elektron sayısına sahiptir (örneğin Na⁺, Ne, F⁻ hepsi 10 elektronludur)."}],"ans":"İzotop: aynı proton; izoton: aynı nötron; izoelektronik: aynı elektron sayısı (örneğin Na⁺, Ne, F⁻)."},{"q":"O²⁻ ve Mg²⁺ iyonlarının elektron sayıları neden eşittir?","steps":[{"t":"O²⁻","a":"8 + 2 = 10","d":"Oksijenin 8 protonu vardır; 2 elektron alarak O²⁻ olur ve 10 elektrona ulaşır."},{"t":"Mg²⁺","a":"12 − 2 = 10","d":"Magnezyumun 12 protonu vardır; 2 elektron vererek Mg²⁺ olur ve 10 elektrona düşer."}],"ans":"O²⁻ (8+2) ve Mg²⁺ (12−2) iyonlarının ikisi de 10 elektrona sahiptir; bu yüzden izoelektroniktirler."},{"q":"Bir atomun kütlesinin neredeyse tamamı neden çekirdekte toplanmıştır?","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='88' r='16' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='92' font-size='9' text-anchor='middle' fill='#fff'>p,n</text><circle cx='160' cy='88' r='62' fill='none' stroke='#1a2b45'/><circle cx='222' cy='88' r='5' fill='#2b6be0'/><circle cx='98' cy='88' r='5' fill='#2b6be0'/><text x='160' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>kütle çekirdekte, çevre boşluk</text></svg>","steps":[{"t":"Ağır tanecikler","a":"p ve n çekirdekte","d":"Kütlesi büyük olan proton ve nötronların tamamı çekirdekte toplanmıştır."},{"t":"Elektron katkısı","a":"ihmal","d":"Çevredeki elektronlar çok hafif (≈1/1836) olduğundan kütleye katkıları ihmal edilebilir."}],"ans":"Kütleli proton ve nötronlar çekirdekte bulunup elektronlar çok hafif olduğundan atom kütlesinin neredeyse tamamı çekirdektedir."},{"q":"Bir tanecikte 16 proton, 18 elektron varsa yükü ve türü nedir?","steps":[{"t":"Yük hesabı","a":"16 − 18 = −2","d":"Net yük = proton − elektron = 16 − 18 = −2 olur."},{"t":"Tür","a":"anyon (S²⁻)","d":"Eksi yüklü olduğundan bu bir anyondur; 16 protonlu element kükürt olduğu için tanecik S²⁻'dir."}],"ans":"Net yük −2'dir; tanecik bir anyon olup kükürt iyonudur (S²⁻)."}]}},"periyodikBloklar":{"ilkokul":{"kolay":[{"q":"Bir kütüphanede kitaplar konularına göre bölümlere ayrılır. Periyodik tabloda da elementler benzerliklerine göre bölgelere ayrılır mı?","steps":[{"t":"Bölümlere ayırma","a":"benzerler bir arada","d":"Kütüphanede benzer kitaplar aynı bölümde toplanır; aramak kolaylaşır."},{"t":"Tabloda bölgeler","a":"bloklar","d":"Periyodik tabloda da benzer elementler aynı <b>bölge (blok)</b> içinde toplanır."}],"ans":"Evet; tıpkı kütüphane bölümleri gibi, periyodik tabloda da benzer elementler bloklara ayrılır."},{"q":"Bir sınıfta öğrenciler sıra sıra ve grup grup oturur. Periyodik tablodaki yatay sıralara ne ad verilir?","steps":[{"t":"Yatay sıra","a":"satır","d":"Tabloda soldan sağa giden yatay sıralar vardır."},{"t":"Adı","a":"periyot","d":"Bu yatay sıralara <b>periyot</b> denir."}],"ans":"Periyodik tablodaki yatay sıralara periyot denir."},{"q":"Periyodik tablodaki dik (yukarıdan aşağı) sütunlara ne ad verilir?","steps":[{"t":"Dik sütun","a":"yukarıdan aşağı","d":"Tabloda yukarıdan aşağı inen dik sütunlar vardır."},{"t":"Adı","a":"grup","d":"Bu dik sütunlara <b>grup</b> denir; aynı gruptaki elementler benzer davranır."}],"ans":"Periyodik tablodaki dik sütunlara grup denir."},{"q":"Elementlerin renkli bölgelere ayrılması bize ne kolaylığı sağlar?","steps":[{"t":"Bölgeler","a":"benzerler bir arada","d":"Benzer özellikli elementler aynı renkli bölgede toplanır."},{"t":"Kolaylık","a":"hızlı tanıma","d":"Bu sayede bir elementin nasıl davranacağını <b>bölgesine bakarak</b> tahmin etmek kolaylaşır."}],"ans":"Bölgelere ayırma, benzer elementleri bir arada gösterir ve bir elementi bölgesine bakarak tanımayı kolaylaştırır."},{"q":"Bir markette ürünler reyonlara ayrılır. Periyodik tablonun reyonlarına benzeyen ana bölgelere ne ad verilir?","steps":[{"t":"Reyonlar","a":"ürün grupları","d":"Markette benzer ürünler aynı reyonda toplanır."},{"t":"Tablodaki adı","a":"blok","d":"Periyodik tablonun reyonlarına benzeyen ana bölgelere <b>blok</b> denir."}],"ans":"Periyodik tablonun ana bölgelerine (reyonlarına) blok denir."}],"zor":[{"q":"Bir oyun parkı kaydırak, salıncak, tahterevalli bölgelerine ayrılmış. Periyodik tablonun da farklı bölgelere ayrılmasının yararı nedir?","steps":[{"t":"Bölgelere ayırma","a":"benzerler bir arada","d":"Parktaki gibi tabloda da benzer elementler aynı bölgede toplanır."},{"t":"Yarar","a":"kolay tahmin","d":"Bir elementin hangi <b>blokta</b> olduğunu bilmek, onun nasıl davranacağını tahmin etmeyi sağlar."}],"ans":"Bölgelere (bloklara) ayırmak benzer elementleri bir araya getirir; böylece bir elementin davranışını bulunduğu bloğa bakarak tahmin etmek kolaylaşır."},{"q":"Bir kitabın hem sayfa numarası hem bölüm adıyla yeri belirtilir. Bir elementin yeri de iki bilgiyle gösterilir mi?","steps":[{"t":"İki bilgi","a":"sıra ve sütun","d":"Bir elementin yeri yatay sıra (periyot) ve dik sütun (grup) ile belirtilir."},{"t":"Tam adres","a":"periyot + grup","d":"Tıpkı sayfa ve bölüm gibi, <b>periyot ve grup</b> birlikte elementin yerini verir."}],"ans":"Evet; bir elementin yeri periyot (yatay sıra) ve grup (dik sütun) ile, tıpkı sayfa ve bölüm gibi iki bilgiyle gösterilir."},{"q":"Aynı dik sütundaki (grup) elementlerin birbirine benzemesi neye benzer?","steps":[{"t":"Aynı sütun","a":"benzer aile","d":"Aynı gruptaki elementler bir aile gibi birbirine benzer özellikler taşır."},{"t":"Benzetme","a":"aynı meslekten kişiler","d":"Aynı meslekten insanların benzer iş yapması gibi, aynı <b>gruptaki</b> elementler de benzer davranır."}],"ans":"Aynı gruptaki elementler bir aile gibi benzer davranır; aynı meslekten kişilerin benzer iş yapmasına benzer."},{"q":"Periyodik tablo neden düzenli sıralar ve sütunlar hâlinde çizilmiştir?","steps":[{"t":"Düzen amacı","a":"benzerleri toplama","d":"Düzenli sıra ve sütunlar, benzer elementlerin alt alta ve yan yana gelmesini sağlar."},{"t":"Kolay kullanım","a":"hızlı bulma","d":"Bu düzen sayesinde elementlerin yerini ve özelliğini <b>hızlıca</b> bulmak mümkün olur."}],"ans":"Periyodik tablo, benzer elementleri bir araya getirip yerlerini ve özelliklerini hızlıca bulmayı sağlamak için düzenli sıra ve sütunlar hâlinde çizilmiştir."},{"q":"Bir öğrenci 'soldaki bölge', 'ortadaki bölge', 'sağdaki bölge' diye tabloyu üçe ayırdı. Bu bölgelerin elementleri neden farklı davranır?","steps":[{"t":"Farklı bölgeler","a":"farklı dolan kısım","d":"Her bölgede elementlerin son elektronları farklı bir 'odaya' yerleşir."},{"t":"Davranış farkı","a":"blok farkı","d":"Son elektronun yerleştiği <b>blok</b> farklı olduğundan elementlerin davranışı da farklı olur."}],"ans":"Her bölgede son elektron farklı bir bloğa (odaya) yerleştiğinden, o bölgedeki elementlerin davranışları birbirinden farklı olur."}]},"ortaokul":{"kolay":[{"q":"Periyodik tablo kaç ana bloğa ayrılır ve adları nelerdir?","steps":[{"t":"Bölge sayısı","a":"4 blok","d":"Tablo dört ana bölgeye ayrılır."},{"t":"Adları","a":"s, p, d, f","d":"Bu bloklar son dolan alt kabuğa göre <b>s, p, d ve f</b> blokları olarak adlandırılır."}],"ans":"Periyodik tablo s, p, d ve f olmak üzere dört ana bloğa ayrılır."},{"q":"Bir elementin bloğu neye göre belirlenir?","steps":[{"t":"Son elektron","a":"son dolan orbital","d":"Elementin elektron dizilimindeki en son dolan alt kabuğa bakılır."},{"t":"Blok adı","a":"o orbitalin harfi","d":"Son elektron hangi alt kabuğa (s, p, d, f) girdiyse element o <b>blokta</b> yer alır."}],"ans":"Bir elementin bloğu, elektron diziliminde son dolan orbitalin türüne (s, p, d, f) göre belirlenir."},{"q":"Tablonun en solundaki iki sütun hangi bloktadır?","steps":[{"t":"Sol bölge","a":"s alt kabuğu","d":"En soldaki iki sütunda son elektron s alt kabuğuna yerleşir."},{"t":"Blok","a":"s bloku","d":"Bu yüzden bu sütunlar <b>s bloku</b> olarak adlandırılır."}],"ans":"Tablonun en solundaki iki sütun s blokundadır."},{"q":"Tablonun en sağındaki altı sütun hangi bloktadır?","steps":[{"t":"Sağ bölge","a":"p alt kabuğu","d":"En sağdaki altı sütunda son elektron p alt kabuğuna yerleşir."},{"t":"Blok","a":"p bloku","d":"Bu yüzden bu sütunlar <b>p bloku</b> olarak adlandırılır."}],"ans":"Tablonun en sağındaki altı sütun p blokundadır."},{"q":"Tablonun ortasındaki geçiş elementleri hangi bloktadır?","steps":[{"t":"Orta bölge","a":"d alt kabuğu","d":"Ortadaki geçiş elementlerinde son elektron d alt kabuğuna yerleşir."},{"t":"Blok","a":"d bloku","d":"Bu yüzden ortadaki bu elementler <b>d bloku</b> (geçiş metalleri) olarak adlandırılır."}],"ans":"Tablonun ortasındaki geçiş elementleri d blokundadır."}],"zor":[{"q":"Bir elementin değerlik elektron sayısı ile grubu arasında nasıl bir ilişki vardır?","steps":[{"t":"Değerlik elektronu","a":"dış kabuk elektronları","d":"En dıştaki kabukta bulunan elektronlara değerlik elektronu denir."},{"t":"Grup ilişkisi","a":"grubu belirler","d":"Baş gruplarda değerlik elektron sayısı, elementin <b>grup numarasını</b> belirler (örneğin 2 değerlik elektronu → 2A grubu)."}],"ans":"Değerlik elektron sayısı elementin grubunu belirler; örneğin 2 değerlik elektronu olan bir element 2A grubunda yer alır."},{"q":"Bir elementin periyodu elektron diziliminden nasıl bulunur?","steps":[{"t":"En yüksek kabuk","a":"en büyük n","d":"Elektron dizilimindeki en yüksek baş enerji düzeyi (en büyük n) bulunur."},{"t":"Periyot","a":"o sayı periyottur","d":"Bu en yüksek <b>n değeri</b> doğrudan elementin periyot numarasını verir."}],"ans":"Elementin periyodu, elektron dizilimindeki en yüksek baş enerji düzeyine (en büyük n) eşittir."},{"q":"Dizilimi 1s² 2s² 2p⁴ olan bir element hangi blokta, periyotta ve kaç değerlik elektronludur?","steps":[{"t":"Son orbital","a":"2p (p bloku)","d":"Son elektron 2p alt kabuğuna girdiğinden element p blokundadır."},{"t":"Periyot ve değerlik","a":"2. periyot, 6 değerlik","d":"En yüksek n = 2 olduğundan 2. periyot; 2s² + 2p⁴ = <b>6 değerlik elektronu</b> vardır."}],"ans":"Bu element p blokunda, 2. periyotta yer alır ve 6 değerlik elektronu vardır (oksijen)."},{"q":"Son elektron dizilimi ...4s² olan bir elementin bloğu nedir, neden?","steps":[{"t":"Son orbital","a":"4s","d":"Son elektron s alt kabuğuna (4s) yerleşmiştir."},{"t":"Blok","a":"s bloku","d":"Son dolan alt kabuk s olduğundan element <b>s blokunda</b> yer alır."}],"ans":"Son elektron 4s'e girdiğinden element s blokundadır."},{"q":"Neden tablonun ortasındaki geçiş elementleri d bloku, en sağdaki ametaller p bloku sayılır?","steps":[{"t":"Geçiş elementleri","a":"son elektron d'de","d":"Ortadaki geçiş elementlerinde son elektron d alt kabuğuna girer, bu yüzden d blokudur."},{"t":"Sağdaki ametaller","a":"son elektron p'de","d":"En sağdaki ametallerde son elektron p alt kabuğuna girer; bu yüzden <b>p bloku</b> sayılırlar."}],"ans":"Blok, son dolan alt kabuğa göre belirlenir: geçiş elementlerinde son elektron d'ye girdiği için d bloku, sağdaki ametallerde p'ye girdiği için p blokudur."}]},"lise":{"kolay":[{"q":"Periyodik tablodaki s, p, d, f blokları neye göre belirlenir?","steps":[{"t":"Son dolan orbital","a":"değerlik alt kabuğu","d":"Bir elementin bloğu, temel hâl elektron diziliminde en son dolan (en yüksek enerjili) alt kabuğun türüne göre belirlenir."},{"t":"Blok adları","a":"s, p, d, f","d":"Son elektron s'e girerse s bloku, p'ye girerse p bloku, d'ye girerse d bloku, f'ye girerse <b>f bloku</b> olur."}],"ans":"Bloklar, elementin elektron diziliminde son dolan alt kabuğun türüne (s, p, d, f) göre belirlenir."},{"q":"Her blok kaç sütun (grup) genişliğindedir ve neden?","steps":[{"t":"Kapasiteler","a":"s:2, p:6, d:10, f:14","d":"s 2, p 6, d 10, f 14 elektron alır; her elektron bir sütuna karşılık gelir."},{"t":"Sütun sayısı","a":"2, 6, 10, 14","d":"Bu yüzden s bloku 2, p bloku 6, d bloku 10, f bloku <b>14 sütun</b> genişliğindedir."}],"ans":"Alt kabuk kapasiteleri kadar: s bloku 2, p bloku 6, d bloku 10, f bloku 14 sütun genişliğindedir.","fig":"<svg viewBox='0 0 360 120'><rect x='10' y='40' width='26' height='40' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='23' y='30' font-size='13' text-anchor='middle' fill='#1a2b45'>s</text><text x='23' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>2</text><rect x='250' y='40' width='90' height='40' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='295' y='30' font-size='13' text-anchor='middle' fill='#1a2b45'>p</text><text x='295' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>6</text><rect x='120' y='52' width='120' height='28' fill='none' stroke='#2b6be0' stroke-width='2'/><text x='180' y='46' font-size='13' text-anchor='middle' fill='#2b6be0'>d</text><text x='180' y='100' font-size='11' text-anchor='middle' fill='#2b6be0'>10</text><rect x='40' y='88' width='200' height='22' fill='none' stroke='#e0552b' stroke-width='2'/><text x='140' y='104' font-size='12' text-anchor='middle' fill='#e0552b'>f (14)</text></svg>"},{"q":"Bir elementin periyodu ve grubu elektron diziliminden nasıl bulunur?","steps":[{"t":"Periyot","a":"en yüksek n","d":"Elektron dizilimindeki en büyük baş kuantum sayısı (en yüksek n) periyodu verir."},{"t":"Grup","a":"değerlik elektronları","d":"Baş gruplarda en dış kabuktaki değerlik elektron sayısı grubu (örneğin ns²np³ → 5A) belirler; <b>n</b> periyot, değerlik elektronu grup demektir."}],"ans":"Periyot en yüksek n değerine, grup ise değerlik (en dış) elektron sayısına göre bulunur."},{"q":"Dizilimi 1s² 2s² 2p⁶ 3s² 3p⁴ olan kükürdün bloğu, periyodu ve grubu nedir?","steps":[{"t":"Blok ve periyot","a":"p bloku, 3. periyot","d":"Son elektron 3p'ye girdiğinden p bloku; en yüksek n = 3 olduğundan 3. periyot."},{"t":"Grup","a":"6A grubu","d":"Değerlik elektronları 3s² + 3p⁴ = 6 olduğundan element <b>6A</b> grubundadır."}],"ans":"Kükürt p blokunda, 3. periyotta ve 6A grubunda yer alır.","fig":"<svg viewBox='0 0 360 110'><text x='10' y='30' font-size='13' fill='#1a2b45'>3s</text><rect x='40' y='18' width='30' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='49' y='37' font-size='13' fill='#2b6be0'>↑</text><text x='58' y='37' font-size='13' fill='#e0552b'>↓</text><text x='90' y='30' font-size='13' fill='#1a2b45'>3p</text><rect x='120' y='18' width='30' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='152' y='18' width='30' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='184' y='18' width='30' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='129' y='37' font-size='13' fill='#2b6be0'>↑</text><text x='138' y='37' font-size='13' fill='#e0552b'>↓</text><text x='161' y='37' font-size='13' fill='#2b6be0'>↑</text><text x='170' y='37' font-size='13' fill='#e0552b'>↓</text><text x='195' y='37' font-size='13' fill='#2b6be0'>↑</text><text x='10' y='80' font-size='12' fill='#1a2b45'>Değerlik: 3s² 3p⁴ → 6 elektron → 6A grubu</text></svg>"},{"q":"He (helyum) p bloğunda değil de neden s bloğunda yer alır?","steps":[{"t":"Dizilim","a":"1s²","d":"Helyumun elektron dizilimi 1s²'dir; son elektron s alt kabuğuna girer."},{"t":"Blok","a":"s bloku","d":"Son dolan orbital s olduğundan He, soygaz olmasına rağmen <b>s blokunda</b> yer alır; tabloda davranışı gereği 8A üstünde gösterilir."}],"ans":"Helyumun dizilimi 1s² olduğundan son elektron s'e girer; bu nedenle p değil s blokundadır, ancak soygaz davranışı nedeniyle 8A üzerinde gösterilir."}],"zor":[{"q":"Dizilimi [Ar]3d⁶4s² olan demirin (Z = 26) bloğunu, periyodunu ve grubunu belirleyip gerekçelendirin.","steps":[{"t":"Blok ve periyot","a":"d bloku, 4. periyot","d":"Değerlik düzeyinde son elektronlar 3d'ye girer; geçiş elementi olduğundan d bloku. En yüksek n = 4 (4s) olduğundan 4. periyot."},{"t":"Grup","a":"8B (8. grup)","d":"d bloku elementlerinde grup, (n−1)d + ns elektronlarının toplamıyla bulunur: 3d⁶ + 4s² = 8 → <b>8. grup (8B)</b>."}],"ans":"Demir d blokunda, 4. periyotta ve 8. grupta (8B) yer alır; çünkü son elektronlar 3d'ye girer, en yüksek n = 4'tür ve 3d⁶ + 4s² = 8 değerlik benzeri elektron verir.","fig":"<svg viewBox='0 0 360 110'><text x='10' y='28' font-size='13' fill='#1a2b45'>3d</text><rect x='34' y='16' width='28' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='64' y='16' width='28' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='16' width='28' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='124' y='16' width='28' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='154' y='16' width='28' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='40' y='34' font-size='12' fill='#2b6be0'>↑</text><text x='48' y='34' font-size='12' fill='#e0552b'>↓</text><text x='72' y='34' font-size='12' fill='#2b6be0'>↑</text><text x='102' y='34' font-size='12' fill='#2b6be0'>↑</text><text x='132' y='34' font-size='12' fill='#2b6be0'>↑</text><text x='162' y='34' font-size='12' fill='#2b6be0'>↑</text><text x='220' y='28' font-size='13' fill='#1a2b45'>4s</text><rect x='244' y='16' width='28' height='26' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='250' y='34' font-size='12' fill='#2b6be0'>↑</text><text x='258' y='34' font-size='12' fill='#e0552b'>↓</text><text x='10' y='75' font-size='12' fill='#1a2b45'>3d⁶ + 4s² = 8 → 8B grubu, 4. periyot, d bloku</text></svg>"},{"q":"d bloku elementlerinde grup numarasının (n−1)d + ns elektron toplamıyla bulunmasının nedenini açıklayın.","steps":[{"t":"Değerlik benzeri elektronlar","a":"(n−1)d ve ns","d":"Geçiş elementlerinde hem en dış ns hem de bir alt düzeydeki (n−1)d elektronları kimyasal davranışa (değerliğe) katılabilir."},{"t":"Grup toplamı","a":"d + s toplamı","d":"Bu yüzden grup numarası, bu iki alt kabuktaki elektronların toplamına eşittir; örneğin 3d⁵4s² → 7 → <b>7B grubu</b> (mangan)."}],"ans":"Geçiş elementlerinde hem (n−1)d hem de ns elektronları değerliğe katılabildiğinden, grup numarası bu iki alt kabuktaki elektronların toplamına eşittir (örn. 3d⁵4s² → 7B)."},{"q":"İki element ([Ne]3s² ve [Ar]4s²) aynı grupta olmasına rağmen farklı periyotlardadır. Bunu blok ve dizilimle açıklayın.","steps":[{"t":"Aynı blok ve grup","a":"s bloku, 2A","d":"Her ikisinde de son elektron s'e girer (s bloku) ve değerlik elektronu 2'dir; bu yüzden aynı grupta (2A) yer alırlar."},{"t":"Farklı periyot","a":"n = 3 ve n = 4","d":"İlkinin en yüksek n'i 3, ikincisinin 4 olduğundan biri 3. diğeri 4. periyottadır; <b>aynı grup, farklı periyot</b>."}],"ans":"İkisi de s blokunda ve 2 değerlik elektronlu olduğundan 2A grubundadır; ancak en yüksek n değerleri (3 ve 4) farklı olduğundan farklı periyotlarda (3. ve 4.) yer alırlar."},{"q":"Galyumun (Z = 31, [Ar]3d¹⁰4s²4p¹) bloğunu belirlerken 3d¹⁰ neden dikkate alınmaz?","steps":[{"t":"Son dolan orbital","a":"4p","d":"En yüksek enerjili son elektron 4p'ye girer; 3d alt kabuğu daha önce tamamen dolmuştur."},{"t":"Blok kararı","a":"p bloku","d":"Blok, en son dolan değerlik alt kabuğuna göre belirlenir; dolu 3d¹⁰ iç kabuk gibi davrandığından galyum <b>p blokundadır</b> (3A grubu, 4. periyot)."}],"ans":"Galyumda son elektron 4p'ye girdiğinden element p blokundadır; tam dolu 3d¹⁰ iç kabuk gibi davranıp değerliğe katılmadığından blok belirlemede dikkate alınmaz (3A grubu, 4. periyot)."},{"q":"Kromun [Ar]3d⁵4s¹ istisnai dizilimi, onun blok ve grup belirlemesini nasıl etkiler?","steps":[{"t":"Blok ve periyot","a":"d bloku, 4. periyot","d":"İstisnaya rağmen son elektronlar 3d düzeyinde olduğundan krom d blokundadır; en yüksek n = 4 olduğundan 4. periyot."},{"t":"Grup","a":"6B (6. grup)","d":"Grup yine (n−1)d + ns toplamıyla bulunur: 3d⁵ + 4s¹ = 6 → <b>6. grup (6B)</b>; istisnai dizilim toplam değerlik elektron sayısını değiştirmez."}],"ans":"Kromun [Ar]3d⁵4s¹ dizilimi istisnai olsa da son elektronlar d'de olduğundan d blokunda, 4. periyottadır; 3d⁵ + 4s¹ = 6 toplamı onu 6. grupta (6B) tutar, çünkü toplam değerlik elektron sayısı değişmez."}]}},"rutherford":{"ilkokul":{"kolay":[{"q":"Rutherford altın levha deneyinde levhaya doğru ne gönderilmiştir?","steps":[{"t":"Gönderilen tanecik","a":"küçük tanecikler","d":"Rutherford, çok ince altın levhanın üzerine pozitif yüklü küçük tanecikler (alfa) gönderdi."},{"t":"Amaç","a":"içini anlamak","d":"Bu taneciklerin nasıl davrandığına bakarak atomun içinin nasıl olduğunu anlamak istedi."}],"ans":"Rutherford ince altın levhaya doğru pozitif yüklü küçük tanecikler (alfa) gönderdi."},{"q":"Rutherford deneyindeki taneciklerin çoğu altın levhadan nasıl geçti?","fig":"<svg viewBox='0 0 320 160'><rect x='150' y='25' width='10' height='110' fill='#ffd54a' stroke='#1a2b45'/><text x='155' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>altın levha</text><line x1='30' y1='80' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='80' x2='290' y2='80' stroke='#e0552b' stroke-width='2'/><polygon points='290,80 281,76 281,84' fill='#e0552b'/><text x='80' y='70' font-size='10' fill='#1a2b45'>tanecik</text></svg>","steps":[{"t":"Çoğunun yolu","a":"düz geçti","d":"Taneciklerin büyük çoğunluğu levhadan hiç sapmadan düz bir şekilde geçip gitti."},{"t":"Anlamı","a":"içerisi boş","d":"Bu, atomun büyük bölümünün boş olduğunu gösterdi."}],"ans":"Taneciklerin çoğu altın levhadan sapmadan düz geçti; bu atomun çoğunun boşluk olduğunu gösterdi."},{"q":"Bazı tanecikler neden geri sekti veya yön değiştirdi?","steps":[{"t":"Sebep","a":"sert bir yere çarptı","d":"Az sayıda tanecik atomun ortasındaki çok küçük ve yoğun bir yere çarpıp geri seke geldi."},{"t":"O yer","a":"çekirdek","d":"Bu küçük, sert ve pozitif yüklü bölgeye çekirdek denir."}],"ans":"Bazı tanecikler atomun ortasındaki küçük, yoğun ve pozitif çekirdeğe çarptığı için geri sekti."},{"q":"Rutherford deneyiyle atomun ortasında ne olduğunu keşfetti?","steps":[{"t":"Keşfedilen yapı","a":"çekirdek","d":"Rutherford, atomun tam ortasında küçük ama ağır bir çekirdek olduğunu buldu."},{"t":"Yükü","a":"pozitif (+)","d":"Bu çekirdek pozitif (artı) yüklüdür."}],"ans":"Rutherford atomun ortasında küçük, ağır ve pozitif yüklü bir çekirdek olduğunu keşfetti."},{"q":"Atomun büyük kısmı neyle doludur?","fig":"<svg viewBox='0 0 300 160'><circle cx='150' cy='80' r='60' fill='none' stroke='#1a2b45'/><circle cx='150' cy='80' r='7' fill='#e0552b'/><text x='150' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>küçük çekirdek, geniş boşluk</text></svg>","steps":[{"t":"İç yapı","a":"çoğu boş","d":"Atomun çok büyük kısmı boşluktur, içinde madde yoktur."},{"t":"Küçük çekirdek","a":"ortada","d":"Sadece ortadaki minik çekirdek doludur, geri kalan yer neredeyse boştur."}],"ans":"Atomun büyük kısmı boşluktur; sadece ortadaki küçük çekirdek doludur."}],"zor":[{"q":"Rutherford deneyinde taneciklerin çok azının geri sekmesi neyi kanıtlar?","steps":[{"t":"Az sekme","a":"çekirdek küçük","d":"Çok az tanecik geri seksesi, çarptıkları yoğun çekirdeğin atoma göre çok küçük olduğunu gösterir."},{"t":"Çoğu geçer","a":"boşluk çok","d":"Geri kalan çok sayıda tanecik geçtiği için atomun büyük kısmı boştur."}],"ans":"Taneciklerin çok azının geri sekmesi, atomdaki pozitif çekirdeğin çok küçük, geri kalanın ise boşluk olduğunu kanıtlar."},{"q":"Rutherford'dan önce atomun nasıl olduğu düşünülüyordu ve onun deneyi bunu nasıl değiştirdi?","steps":[{"t":"Eski düşünce","a":"her yeri dolu","d":"Önceden atomun içinin her yerinin eşit biçimde dolu olduğu sanılıyordu."},{"t":"Yeni bilgi","a":"boş + çekirdek","d":"Rutherford, atomun ortasında küçük bir çekirdek, çevresinde ise geniş boşluk olduğunu gösterdi."}],"ans":"Önceden atomun her yerinin dolu olduğu sanılırdı; Rutherford ortada küçük çekirdek, çevresinde boşluk olduğunu gösterdi."},{"q":"Çekirdek pozitif yüklü olduğu için tanecikler ona yaklaşınca ne olur?","steps":[{"t":"İki artı yük","a":"birbirini iter","d":"Gönderilen tanecikler de çekirdek de pozitiftir; aynı yükler birbirini iter."},{"t":"Sonuç","a":"sapma/sekme","d":"Çekirdeğe yaklaşan tanecik bu itme yüzünden yön değiştirir veya geri seker."}],"ans":"Pozitif çekirdek, pozitif tanecikleri iter; bu yüzden çekirdeğe yaklaşan tanecikler sapar ya da geri seker."},{"q":"Atomun kütlesinin büyük kısmı nerede toplanmıştır ve bunu deneyden nasıl anlarız?","steps":[{"t":"Kütle yeri","a":"çekirdekte","d":"Atomun kütlesinin neredeyse tamamı küçük çekirdekte toplanmıştır."},{"t":"Kanıt","a":"sekme","d":"Hızlı tanecikleri geri sektirebilecek kadar ağır olması, kütlenin çekirdekte yoğunlaştığını gösterir."}],"ans":"Atomun kütlesinin büyük kısmı çekirdektedir; hızlı tanecikleri geri sektirebilmesi çekirdeğin çok ağır olduğunu gösterir."},{"q":"Rutherford modelinde çekirdeğin çevresinde ne bulunur?","fig":"<svg viewBox='0 0 300 170'><circle cx='150' cy='85' r='8' fill='#e0552b'/><circle cx='150' cy='85' r='55' fill='none' stroke='#1a2b45' stroke-dasharray='4 3'/><circle cx='205' cy='85' r='5' fill='#2b6be0'/><text x='150' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>çekirdek + dış elektron</text></svg>","steps":[{"t":"Dış bölge","a":"elektronlar","d":"Pozitif çekirdeğin çevresindeki boşlukta eksi yüklü elektronlar dolaşır."},{"t":"Denge","a":"artı + eksi","d":"Pozitif çekirdek ile eksi elektronlar birlikte atomu oluşturur."}],"ans":"Rutherford modelinde pozitif çekirdeğin çevresindeki boşlukta eksi yüklü elektronlar bulunur."}]},"ortaokul":{"kolay":[{"q":"Rutherford altın levha (saçılma) deneyinde hangi tür ışın kullanılmıştır?","steps":[{"t":"Kullanılan ışın","a":"alfa taneciği","d":"Rutherford, pozitif yüklü ve hızlı hareket eden alfa taneciklerini ince altın levhaya gönderdi."},{"t":"Gözlem yöntemi","a":"floresan ekran","d":"Taneciklerin levhadan sonra nereye gittiği, çevredeki ışıldayan ekran üzerinde gözlendi."}],"ans":"Rutherford deneyinde pozitif yüklü, hızlı alfa tanecikleri kullanılmış ve sapmaları ışıldayan ekranda izlenmiştir."},{"q":"Deneyde gözlenen üç farklı tanecik davranışı nedir?","fig":"<svg viewBox='0 0 320 170'><rect x='150' y='20' width='9' height='130' fill='#ffd54a' stroke='#1a2b45'/><line x1='30' y1='60' x2='290' y2='60' stroke='#e0552b' stroke-width='2'/><line x1='30' y1='95' x2='154' y2='95' stroke='#e0552b' stroke-width='2'/><line x1='159' y1='95' x2='250' y2='130' stroke='#e0552b' stroke-width='2'/><line x1='30' y1='125' x2='150' y2='125' stroke='#e0552b' stroke-width='2'/><line x1='150' y1='125' x2='60' y2='150' stroke='#e0552b' stroke-width='2'/><text x='250' y='155' font-size='10' fill='#1a2b45'>levha</text></svg>","steps":[{"t":"Çoğu düz","a":"sapmadan geçer","d":"Taneciklerin çoğu hiç sapmadan levhadan düz geçer."},{"t":"Az sapan/sekenler","a":"saparlar","d":"Bazıları açıyla sapar, çok azı ise geri seker."}],"ans":"Tanecikler ya düz geçer, ya açıyla sapar ya da çok azı geri seker; bu üç farklı davranış gözlenir."},{"q":"Taneciklerin çoğunun düz geçmesi atom hakkında ne söyler?","steps":[{"t":"Düz geçiş","a":"engelle karşılaşmaz","d":"Taneciklerin çoğu yolda bir engelle karşılaşmadan geçer."},{"t":"Sonuç","a":"atom çoğunlukla boş","d":"Bu da atomun büyük bir kısmının boşluktan oluştuğunu gösterir."}],"ans":"Taneciklerin çoğunun düz geçmesi, atomun büyük kısmının boşluk olduğunu gösterir."},{"q":"Çekirdeğin yükü nedir ve bunu hangi gözlem gösterir?","steps":[{"t":"Yük","a":"pozitif","d":"Çekirdek pozitif (artı) yüklüdür."},{"t":"Gözlem","a":"pozitif tanecik sapması","d":"Pozitif alfa taneciklerinin saparak/geri sekerek itilmesi, çekirdeğin de pozitif olduğunu gösterir."}],"ans":"Çekirdek pozitif yüklüdür; pozitif alfa taneciklerini itip saptırması bunu gösterir."},{"q":"Rutherford deneyinde alfa taneciklerinin geri sekmesi neyi gösterir?","steps":[{"t":"Geri sekme","a":"sert ve yoğun","d":"Geri sekme, taneciklerin çok yoğun ve sert bir bölgeye çarptığını gösterir."},{"t":"O bölge","a":"çekirdek","d":"Bu bölge, atomun kütlesinin toplandığı küçük çekirdektir."}],"ans":"Geri sekme, taneciklerin atomdaki küçük, yoğun ve ağır çekirdeğe çarptığını gösterir."}],"zor":[{"q":"Rutherford'un saçılma deneyi, Thomson'un üzümlü kek modelini neden çürütmüştür?","steps":[{"t":"Thomson modeli","a":"yük dağınık","d":"Thomson'a göre pozitif yük atoma eşit yayılmış, elektronlar içine gömülüydü; büyük sapma beklenmezdi."},{"t":"Deney sonucu","a":"büyük sapma var","d":"Bazı taneciklerin geri sekmesi, yükün dağınık değil küçük bir çekirdekte toplandığını gösterdi."}],"ans":"Bazı taneciklerin geri sekmesi, yükün dağınık olmadığını, küçük bir çekirdekte toplandığını gösterdi; bu Thomson modelini çürüttü."},{"q":"Sadece çok az taneciğin büyük açıyla sapması, çekirdeğin boyutu hakkında ne söyler?","steps":[{"t":"Az sayı","a":"hedef küçük","d":"Yalnızca çok az tanecik büyük açıyla sapıyorsa, çarptıkları çekirdeğin atoma göre çok küçük olması gerekir."},{"t":"Oran","a":"çekirdek minik","d":"Çekirdek, atomun yanında bilye yanındaki bir toz tanesi kadar küçüktür."}],"ans":"Çok az taneciğin büyük açıyla sapması, çekirdeğin atoma göre çok küçük bir hedef olduğunu gösterir."},{"q":"Bir alfa taneciği çekirdeğe ne kadar yakından geçerse sapma açısı nasıl değişir?","fig":"<svg viewBox='0 0 320 160'><circle cx='160' cy='80' r='8' fill='#e0552b'/><text x='160' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>çekirdek</text><line x1='30' y1='40' x2='160' y2='40' stroke='#2b6be0' stroke-width='2'/><line x1='160' y1='40' x2='270' y2='25' stroke='#2b6be0' stroke-width='2'/><line x1='30' y1='75' x2='150' y2='75' stroke='#e0552b' stroke-width='2'/><line x1='150' y1='75' x2='90' y2='130' stroke='#e0552b' stroke-width='2'/></svg>","steps":[{"t":"Uzak geçiş","a":"az sapma","d":"Çekirdekten uzaktan geçen tanecik az itilir, bu yüzden küçük açıyla sapar."},{"t":"Yakın geçiş","a":"çok sapma","d":"Çekirdeğe çok yaklaşan tanecik daha güçlü itilir, büyük açıyla sapar veya geri seker."}],"ans":"Tanecik çekirdeğe ne kadar yakın geçerse itme o kadar güçlü olur ve sapma açısı o kadar büyür."},{"q":"Rutherford modeli atomun kütle ve hacim dağılımını nasıl açıklar?","steps":[{"t":"Kütle","a":"çekirdekte yoğun","d":"Atomun kütlesinin neredeyse tamamı çok küçük çekirdekte toplanmıştır."},{"t":"Hacim","a":"boşlukta","d":"Atomun hacminin büyük kısmı ise çekirdek çevresindeki boş bölgedir; bu yüzden çekirdek çok yoğundur."}],"ans":"Rutherford modeline göre kütle küçük çekirdekte yoğunlaşmıştır, hacmin büyük kısmı ise çevredeki boşluktur."},{"q":"Deneyde altın levhanın çok ince seçilmesi neden önemlidir?","steps":[{"t":"İnce levha","a":"birkaç atom kalınlık","d":"Levha çok ince olursa tanecikler yalnızca birkaç atom katmanından geçer."},{"t":"Sebep","a":"tek çarpışmayı görmek","d":"Böylece her taneciğin tek bir çekirdekle nasıl etkileştiği net biçimde gözlenebilir; çok katlı çarpışma karmaşası önlenir."}],"ans":"İnce levha taneciklerin az sayıda atomdan geçmesini sağlar; böylece tek çekirdek çarpışmasının etkisi net görülür."}]},"lise":{"kolay":[{"q":"Rutherford altın levha deneyinde ince levhaya gönderilen tanecik ve bunun gözlenmesinin amacı nedir?","steps":[{"t":"Gönderilen tanecik","a":"alfa (²⁺)","d":"Pozitif yüklü alfa tanecikleri (helyum çekirdeği) yüksek hızla ince altın levhaya gönderildi."},{"t":"Amaç","a":"yük dağılımı","d":"Taneciklerin sapma açıları incelenerek atomdaki pozitif yükün ve kütlenin nasıl dağıldığı araştırıldı."}],"ans":"Pozitif yüklü alfa tanecikleri ince altın levhaya gönderildi; amaç sapmalardan atomdaki yük ve kütle dağılımını belirlemekti."},{"q":"Deneyde gözlenen sonuçlar ve her birinin atom yapısı için anlamı nedir?","steps":[{"t":"Çoğu sapmasız","a":"boşluk","d":"Taneciklerin büyük çoğunluğunun sapmadan geçmesi, atomun büyük kısmının boş olduğunu gösterdi."},{"t":"Az sayı sapma/sekme","a":"küçük yoğun çekirdek","d":"Az sayıda taneciğin sapması ve çok azının geri sekmesi, kütle ve pozitif yükün küçük bir çekirdekte yoğunlaştığını gösterdi."}],"ans":"Çoğu tanecik sapmadan geçti (atom çoğunlukla boş); az kısmı saptı, çok azı geri sekti (kütle ve artı yük küçük çekirdekte yoğun)."},{"q":"Rutherford modeli, Thomson modelinden hangi temel noktada ayrılır?","steps":[{"t":"Thomson","a":"yük yayılmış","d":"Thomson modelinde pozitif yük atoma düzgün yayılmış, elektronlar bu kütleye gömülüydü."},{"t":"Rutherford","a":"yük çekirdekte","d":"Rutherford'da pozitif yük ve kütle merkezdeki küçük çekirdekte toplanmış, elektronlar çevrede dolaşır."}],"ans":"Thomson'da yük atoma yayılmıştır; Rutherford'da ise pozitif yük ve kütle merkezdeki küçük çekirdekte toplanmıştır."},{"q":"Çekirdeğin atom hacmine oranla çok küçük olduğu deney sonucundan nasıl çıkarılır?","steps":[{"t":"Sapma oranı","a":"çok düşük","d":"Binlerce tanecikten yalnızca çok azının büyük açıyla sapması, çekirdeğin küçük bir hedef olduğunu gösterir."},{"t":"Hacim oranı","a":"çok büyük fark","d":"Bu oran, çekirdeğin atom çapına göre on binlerce kat küçük olduğunu gösterir; atom büyük oranda boştur."}],"ans":"Taneciklerin çok azının saptığı gözleminden, çekirdeğin atom hacmine göre çok küçük olduğu çıkarılır."},{"q":"Rutherford modeline göre atomdaki elektronların konumu ve görevi nedir?","fig":"<svg viewBox='0 0 300 170'><circle cx='150' cy='85' r='9' fill='#e0552b'/><circle cx='150' cy='85' r='40' fill='none' stroke='#1a2b45' stroke-dasharray='4 3'/><circle cx='150' cy='85' r='62' fill='none' stroke='#1a2b45' stroke-dasharray='4 3'/><circle cx='190' cy='85' r='5' fill='#2b6be0'/><circle cx='150' cy='23' r='5' fill='#2b6be0'/><text x='150' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>çekirdek + dolaşan elektronlar</text></svg>","steps":[{"t":"Konum","a":"çekirdek çevresinde","d":"Eksi yüklü elektronlar, pozitif çekirdeğin çevresindeki geniş boşlukta dolaşır."},{"t":"Görev","a":"yük dengesi","d":"Elektronların eksi yükü, çekirdeğin artı yükünü dengeleyerek atomu nötr tutar."}],"ans":"Elektronlar pozitif çekirdek çevresindeki boşlukta dolaşır ve eksi yükleriyle atomun yük dengesini sağlar."}],"zor":[{"q":"Rutherford modeli klasik fiziğe göre neden kararsızdır ve bu eksiklik nasıl giderilmiştir?","steps":[{"t":"Klasik sorun","a":"enerji ışıması","d":"Klasik fiziğe göre çekirdek çevresinde dolaşan (ivmeli) elektron sürekli enerji yayar ve çekirdeğe düşmelidir."},{"t":"Çözüm","a":"Bohr modeli","d":"Bohr, elektronların yalnızca belirli (kararlı) enerji düzeylerinde dolaştığını öne sürerek bu çökme sorununu giderdi."}],"ans":"Rutherford modelinde dolaşan elektron sürekli enerji yayıp çekirdeğe düşmelidir; bu eksiklik Bohr'un kararlı enerji düzeyleri modeliyle giderilmiştir."},{"q":"Alfa taneciğinin sapma açısı ile çekirdeğe yaklaşma uzaklığı (çarpma parametresi) arasındaki ilişki nedir?","fig":"<svg viewBox='0 0 320 170'><circle cx='170' cy='85' r='9' fill='#e0552b'/><text x='170' y='110' font-size='10' text-anchor='middle' fill='#1a2b45'>çekirdek (+)</text><line x1='25' y1='45' x2='170' y2='45' stroke='#2b6be0' stroke-width='2'/><line x1='170' y1='45' x2='285' y2='35' stroke='#2b6be0' stroke-width='2'/><line x1='25' y1='80' x2='158' y2='80' stroke='#e0552b' stroke-width='2'/><line x1='158' y1='80' x2='110' y2='150' stroke='#e0552b' stroke-width='2'/><text x='40' y='38' font-size='9' fill='#1a2b45'>uzak: az sapma</text></svg>","steps":[{"t":"Büyük uzaklık","a":"küçük açı","d":"Çekirdeğe büyük uzaklıktan (büyük çarpma parametresi) geçen tanecik zayıf itilir, küçük açıyla sapar."},{"t":"Küçük uzaklık","a":"büyük açı","d":"Çekirdeğe çok yaklaşan tanecik güçlü Coulomb itmesiyle büyük açıyla sapar, tam üzerine gidenler geri seker."}],"ans":"Çarpma parametresi (yaklaşma uzaklığı) küçüldükçe Coulomb itmesi artar ve sapma açısı büyür; uzaktan geçenler az, yakından geçenler çok sapar."},{"q":"Çekirdeğin yoğunluğunun olağanüstü büyük olduğu, deney verileriyle nasıl açıklanır?","steps":[{"t":"Kütle ve hacim","a":"büyük kütle/küçük hacim","d":"Atomun kütlesinin neredeyse tamamı çekirdekte, ama çekirdeğin hacmi atomun çok küçük bir kesridir."},{"t":"Yoğunluk","a":"aşırı yüksek","d":"Yoğunluk = kütle/hacim olduğundan, büyük kütlenin küçük hacme sığması çekirdek yoğunluğunu olağanüstü büyük yapar."}],"ans":"Kütlenin tamamına yakını çok küçük çekirdek hacmine sığdığından, yoğunluk (kütle/hacim) olağanüstü büyük çıkar."},{"q":"Rutherford deneyinde sapan taneciklerin pozitif çekirdek tarafından itildiğini hangi kuvvet açıklar?","steps":[{"t":"Kuvvet türü","a":"Coulomb itmesi","d":"Pozitif alfa taneciği ile pozitif çekirdek arasında elektriksel (Coulomb) itme kuvveti vardır."},{"t":"Uzaklıkla değişim","a":"yakınken güçlü","d":"Bu kuvvet uzaklığın karesiyle ters orantılıdır; çekirdeğe yaklaşıldıkça hızla güçlenir ve büyük sapmaya yol açar."}],"ans":"Sapma, pozitif alfa taneciği ile pozitif çekirdek arasındaki Coulomb (elektriksel) itme kuvvetiyle açıklanır; bu kuvvet yaklaşınca güçlenir."},{"q":"Rutherford'un atom modeli hangi parçacığı öngörmüş, hangisini açıklayamamıştır?","steps":[{"t":"Öngördüğü","a":"proton (çekirdek yükü)","d":"Çekirdekteki pozitif yükü taşıyan parçacık olan protonun varlığı bu modelden anlaşıldı."},{"t":"Açıklayamadığı","a":"nötron","d":"Çekirdekteki kütlenin yalnızca protonla açıklanamayan fazlası, sonradan keşfedilen nötronla anlaşıldı; Rutherford bunu modelinde gösteremedi."}],"ans":"Rutherford modeli çekirdekteki pozitif protonu öngördü, ancak çekirdek kütlesinin fazlasını veren yüksüz nötronu açıklayamadı."}]}},"spektrum":{"ilkokul":{"kolay":[{"q":"Bir ampul ışığını cam bir üçgenden (prizma) geçirince gökkuşağı renkleri çıkar. Bazı gazların ışığı ise sadece birkaç ayrı renk çizgisi verir. Bu ayrı çizgilere ne diyebiliriz?","fig":"<svg viewBox='0 0 240 120'><rect x='20' y='30' width='200' height='60' fill='#1a2b45'/><line x1='60' y1='30' x2='60' y2='90' stroke='#7ad' stroke-width='3'/><line x1='115' y1='30' x2='115' y2='90' stroke='#5f5' stroke-width='3'/><line x1='175' y1='30' x2='175' y2='90' stroke='#f55' stroke-width='3'/></svg>","steps":[{"t":"Işığı ayırmak","a":"renklere ayrılır","d":"Işık prizmadan geçince içindeki renklere ayrılır; gaz ışığında sadece birkaç renk çıkar."},{"t":"Sonuç","a":"çizgi spektrumu","d":"Bu ayrı ayrı renk çizgilerine <b>çizgi spektrumu</b> denir; bir elementin yaydığı renk desenidir."}],"ans":"Bir gazın ışığını ayırınca çıkan ayrı renk çizgilerine çizgi spektrumu denir."},{"q":"Her elementin çizgi spektrumu birbirinden farklıdır. Bu desen, insanlardaki neye benzetilebilir?","steps":[{"t":"Herkese özel","a":"parmak izi","d":"Nasıl her insanın parmak izi kendine özgüyse, her elementin renk çizgileri de kendine özgüdür."},{"t":"Sonuç","a":"elementin parmak izi","d":"Bu yüzden çizgi spektrumu elementin <b>parmak izi</b> gibidir; ona bakarak hangi element olduğu anlaşılır."}],"ans":"Çizgi spektrumu, her element için farklı olduğundan elementin parmak izi gibidir."},{"q":"Sokak lambalarında turuncu-sarı, tabela ışıklarında kırmızı renkler görürüz. Bu renkler neden değişir?","steps":[{"t":"Farklı gaz","a":"farklı element","d":"Lambaların içinde farklı gazlar (örneğin sodyum, neon) vardır; her gaz farklı renkte ışık verir."},{"t":"Sonuç","a":"özgü renk","d":"Her elementin kendine <b>özgü rengi</b> olduğundan lambaların rengi de değişir."}],"ans":"Lambaların içindeki gazlar farklı element olduğundan, her biri kendine özgü renkte ışık verir."},{"q":"Bir atom ışık saçıyorsa içindeki elektrona daha önce ne yapılmış olmalıdır?","steps":[{"t":"Önce enerji","a":"enerji verilir","d":"Elektron önce ısı, ışık ya da elektrik gibi bir yolla enerji almış olmalıdır."},{"t":"Sonuç","a":"sonra ışır","d":"Enerji alıp yukarı çıkan elektron geri inerken <b>ışık</b> saçar; önce enerji alması gerekir."}],"ans":"Atom ışık saçabilmesi için içindeki elektrona önce enerji verilmiş olmalıdır."},{"q":"İki farklı gaz lambasının renk çizgileri birbirinin tıpatıp aynısı olabilir mi?","steps":[{"t":"Her element ayrı","a":"farklı desen","d":"Her elementin çizgi deseni kendine özgüdür, başka elementinkine benzemez."},{"t":"Sonuç","a":"aynı olamaz","d":"Farklı iki gazın çizgileri <b>aynı olamaz</b>; çünkü her elementin parmak izi farklıdır."}],"ans":"Farklı iki elementin çizgi spektrumu aynı olamaz; her elementin deseni kendine özgüdür."}],"zor":[{"q":"Bir bilim insanı gökyüzünden gelen bir gazın ışığına bakıp 'bu sodyum' diyebiliyor. Bunu nasıl anlıyor olabilir?","steps":[{"t":"Renk desenine bakar","a":"çizgileri karşılaştırır","d":"Gelen ışığın renk çizgilerini, bilinen elementlerin çizgileriyle karşılaştırır."},{"t":"Sonuç","a":"parmak izinden tanır","d":"Çizgiler sodyumun bilinen <b>desenine</b> uyuyorsa, o gazın sodyum olduğunu anlar."}],"ans":"Işığın renk çizgilerini bilinen elementlerin desenleriyle karşılaştırıp parmak izinden tanır."},{"q":"Bir atomda elektron yukarı basamağa çıkıp geri iniyor. Çıkan ışığın rengini ne belirler?","fig":"<svg viewBox='0 0 220 160'><line x1='40' y1='130' x2='180' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='40' y1='60' x2='180' y2='60' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='60' r='6' fill='#2b6be0'/><path d='M145 67 L78 124' stroke='#e0552b' stroke-width='2'/><circle cx='72' cy='130' r='6' fill='#2b6be0'/><path d='M116 95 l16 -6 l-4 11 z' fill='#ffd54a'/></svg>","steps":[{"t":"Basamak farkı","a":"ne kadar indiği","d":"Elektronun kaç basamak indiği, yani enerji farkının büyüklüğü rengi belirler."},{"t":"Sonuç","a":"enerji farkı→renk","d":"Büyük düşüş bir renk, küçük düşüş başka renk verir; yani <b>enerji farkı</b> rengi belirler."}],"ans":"Çıkan ışığın rengini, elektronun indiği basamaklar arasındaki enerji farkı belirler."},{"q":"Aynı elementin lambası her yandığında hep aynı renkleri verir. Bunun nedeni nedir?","steps":[{"t":"Basamaklar sabit","a":"hep aynı yer","d":"Bir elementin enerji basamakları hep aynı yerdedir, değişmez."},{"t":"Sonuç","a":"aynı renkler","d":"Atlama hep aynı basamaklar arasında olduğundan ışık da hep <b>aynı renklerde</b> çıkar."}],"ans":"Elementin enerji basamakları değişmediği için lambası her zaman aynı renkleri verir."},{"q":"Beyaz ışığı soğuk bir gazın içinden geçirince renk şeridinde bazı renklerin yerinde siyah çizgiler oluşuyor. Gaz bu renklere ne yapmış olabilir?","fig":"<svg viewBox='0 0 240 120'><rect x='20' y='30' width='200' height='60' fill='url(#g)'/><defs><linearGradient id='g'><stop offset='0' stop-color='#a3f'/><stop offset='0.5' stop-color='#5f5'/><stop offset='1' stop-color='#f55'/></linearGradient></defs><rect x='80' y='30' width='4' height='60' fill='#1a2b45'/><rect x='150' y='30' width='4' height='60' fill='#1a2b45'/></svg>","steps":[{"t":"Renk yutma","a":"gaz emer","d":"Gaz, kendine uyan bazı renkleri ışıktan emer (yutar), bu yüzden o renkler kaybolur."},{"t":"Sonuç","a":"siyah çizgi","d":"Yutulan renklerin yerinde <b>siyah çizgiler</b> kalır; gaz o renkleri soğurmuştur."}],"ans":"Gaz, kendine uyan renkleri yutar (soğurur); o renklerin yerinde siyah çizgiler oluşur."},{"q":"Bir lambanın içinde hangi gazın olduğunu, lambayı açmadan içine bakmadan anlayabilir miyiz?","steps":[{"t":"Işığa bakmak","a":"renk çizgileri","d":"Lambayı yakıp ışığını prizmadan geçirir, çıkan renk çizgilerine bakarız."},{"t":"Sonuç","a":"desenden anlarız","d":"Çizgi deseni hangi elemente aitse, içindeki gaz odur; <b>desenden</b> anlayabiliriz."}],"ans":"Lambanın ışığını ayırıp renk çizgilerine bakarak, desenden içindeki gazı anlayabiliriz."}]},"ortaokul":{"kolay":[{"q":"Bir elementin yaydığı ışığın ayrı renk çizgilerinden oluşan desene ne ad verilir?","fig":"<svg viewBox='0 0 240 120'><rect x='20' y='30' width='200' height='60' fill='#1a2b45'/><line x1='55' y1='30' x2='55' y2='90' stroke='#7ad' stroke-width='3'/><line x1='100' y1='30' x2='100' y2='90' stroke='#5f5' stroke-width='3'/><line x1='150' y1='30' x2='150' y2='90' stroke='#fd5' stroke-width='3'/><line x1='190' y1='30' x2='190' y2='90' stroke='#f55' stroke-width='3'/></svg>","steps":[{"t":"Ayrı çizgiler","a":"belirli renkler","d":"Bir gaz uyarılınca yalnızca belirli renklerde ışık yayar, sürekli bir şerit değil."},{"t":"Sonuç","a":"çizgi spektrumu","d":"Bu ayrı renk çizgilerinden oluşan desene <b>çizgi spektrumu</b> denir."}],"ans":"Bir elementin yaydığı ayrı renk çizgilerinden oluşan desene çizgi spektrumu denir."},{"q":"Çizgi spektrumunun her element için farklı olması ne işe yarar?","steps":[{"t":"Elemente özgü","a":"benzersiz desen","d":"Her elementin çizgileri kendine özgüdür, başka elementinkiyle karışmaz."},{"t":"Sonuç","a":"element tanıma","d":"Bu yüzden çizgi spektrumu bir elementi <b>tanımak (teşhis etmek)</b> için kullanılır."}],"ans":"Her elementin çizgi spektrumu farklı olduğundan, bilinmeyen bir elementi tanımakta kullanılır."},{"q":"Bir atomun ışık yayması (emisyon) için elektrona ne olması gerekir?","steps":[{"t":"Önce uyarılma","a":"enerji alır","d":"Elektron önce enerji alıp üst enerji düzeyine çıkmalı (uyarılmalı)."},{"t":"Sonuç","a":"geri inince ışır","d":"Sonra alt düzeye geri inerken enerji farkını ışık (foton) olarak yayar; buna <b>emisyon</b> denir."}],"ans":"Önce uyarılan elektron, alt düzeye geri inerken ışık yayar; bu olaya emisyon denir."},{"q":"Beyaz ışık bir gazdan geçerken bazı renklerin yutulması ile oluşan, siyah çizgili spektruma ne ad verilir?","steps":[{"t":"Renk yutulması","a":"foton soğurulur","d":"Gaz, kendi enerji düzeylerine uyan renkleri yutar (soğurur); o renkler şeritten eksilir."},{"t":"Sonuç","a":"soğurma spektrumu","d":"Eksilen renklerin yerinde siyah çizgiler oluşur; buna <b>soğurma (absorpsiyon) spektrumu</b> denir."}],"ans":"Bazı renklerin yutulmasıyla siyah çizgiler oluşturan spektruma soğurma (absorpsiyon) spektrumu denir."},{"q":"Sodyum lambasının sarı, neon tüpünün kırmızı-turuncu renk vermesinin sebebi nedir?","steps":[{"t":"Farklı element","a":"farklı düzey","d":"Sodyum ve neon farklı elementlerdir; enerji düzeyleri ve aralarındaki farklar farklıdır."},{"t":"Sonuç","a":"farklı renk","d":"Farklı enerji farkları farklı renkte ışık verdiğinden lambaların rengi <b>farklı</b> olur."}],"ans":"Sodyum ve neon farklı elementler olduğundan, farklı enerji düzeyleri farklı renkte ışık verir."}],"zor":[{"q":"Bir yıldızdan gelen ışığın spektrumunda hidrojenin bilinen çizgileri görülüyor. Bu gözlemden ne çıkarılır?","steps":[{"t":"Çizgi eşleşmesi","a":"hidrojen deseni","d":"Yıldız ışığının çizgileri hidrojenin laboratuvarda bilinen çizgileriyle aynı yerdedir."},{"t":"Sonuç","a":"yıldızda hidrojen var","d":"Çizgiler eşleştiğinden, o yıldızın yapısında <b>hidrojen bulunduğu</b> anlaşılır; spektrum element teşhisinde kullanılır."}],"ans":"Çizgiler hidrojeninkiyle eşleştiğinden, yıldızın yapısında hidrojen bulunduğu anlaşılır."},{"q":"Aynı elementin emisyon (yayma) spektrumundaki parlak çizgiler ile soğurma spektrumundaki siyah çizgiler neden aynı yerlerde (aynı renklerde) çıkar?","steps":[{"t":"Aynı enerji düzeyleri","a":"aynı geçişler","d":"Bir atom, soğururken ve yayarken aynı enerji düzeyleri arasında geçiş yapar."},{"t":"Sonuç","a":"aynı renkler","d":"Aynı geçişler aynı enerji farkına, dolayısıyla aynı renge karşılık geldiğinden çizgiler <b>aynı yerlerdedir</b>."}],"ans":"Soğurma ve yayma aynı enerji düzeyleri arasındaki geçişlere ait olduğundan çizgiler aynı renklerde çıkar."},{"q":"Bir elementin çizgi spektrumunda çizgilerin renk (dalga boyu) konumlarını ne belirler?","fig":"<svg viewBox='0 0 220 160'><line x1='40' y1='135' x2='180' y2='135' stroke='#1a2b45' stroke-width='2'/><text x='185' y='139' font-size='10' fill='#1a2b45'>n=1</text><line x1='40' y1='90' x2='180' y2='90' stroke='#1a2b45' stroke-width='2'/><text x='185' y='94' font-size='10' fill='#1a2b45'>n=2</text><line x1='40' y1='55' x2='180' y2='55' stroke='#1a2b45' stroke-width='2'/><text x='185' y='59' font-size='10' fill='#1a2b45'>n=3</text><path d='M90 55 L90 135' stroke='#e0552b' stroke-width='2'/><path d='M140 90 L140 135' stroke='#2b6be0' stroke-width='2'/></svg>","steps":[{"t":"Düzeyler arası fark","a":"enerji farkı","d":"Her çizgi, iki enerji düzeyi arasındaki geçişe karşılık gelir; rengi bu enerji farkı belirler."},{"t":"Sonuç","a":"fark→renk","d":"Büyük enerji farkı mora yakın, küçük fark kırmızıya yakın renk verir; yani <b>enerji farkı</b> çizginin yerini belirler."}],"ans":"Çizgilerin renk konumlarını, atomun enerji düzeyleri arasındaki enerji farkları belirler."},{"q":"Bir karışım gazın spektrumunda hem hidrojen hem helyum çizgileri görülüyor. Bu nasıl mümkündür?","steps":[{"t":"Her element kendi çizgisi","a":"ayrı desen","d":"Karışımdaki her element kendi çizgi spektrumunu ayrı ayrı yayar."},{"t":"Sonuç","a":"çizgiler üst üste","d":"Çizgiler aynı spektrumda üst üste görüldüğünden, hem hidrojen hem helyumun <b>birlikte bulunduğu</b> anlaşılır."}],"ans":"Karışımdaki her element kendi çizgilerini yaydığından, spektrumda iki elementin çizgileri bir arada görünür."},{"q":"Elektron 3. düzeyden 1. düzeye doğrudan inerse mi yoksa 2. düzeyden 1. düzeye inerse mi daha mora yakın (yüksek enerjili) renk yayılır?","fig":"<svg viewBox='0 0 220 160'><line x1='40' y1='135' x2='180' y2='135' stroke='#1a2b45' stroke-width='2'/><text x='185' y='139' font-size='10' fill='#1a2b45'>n=1</text><line x1='40' y1='90' x2='180' y2='90' stroke='#1a2b45' stroke-width='2'/><text x='185' y='94' font-size='10' fill='#1a2b45'>n=2</text><line x1='40' y1='55' x2='180' y2='55' stroke='#1a2b45' stroke-width='2'/><text x='185' y='59' font-size='10' fill='#1a2b45'>n=3</text><path d='M80 55 L80 135' stroke='#e0552b' stroke-width='2'/><path d='M140 90 L140 135' stroke='#2b6be0' stroke-width='2'/></svg>","steps":[{"t":"Enerji farkı","a":"3→1 büyük","d":"n=3→n=1 enerji farkı, n=2→n=1 farkından daha büyüktür."},{"t":"Sonuç","a":"3→1 mora yakın","d":"Büyük enerji farkı daha yüksek enerjili (mora yakın) renk verdiğinden <b>3→1</b> geçişi daha enerjiklidir."}],"ans":"n=3→n=1 enerji farkı daha büyük olduğundan daha yüksek enerjili (mora yakın) renk yayılır."}]},"lise":{"kolay":[{"q":"Çizgi (kesikli) spektrum ile sürekli spektrum arasındaki temel farkı açıklayınız.","fig":"<svg viewBox='0 0 240 130'><rect x='20' y='20' width='200' height='40' fill='url(#cs)'/><defs><linearGradient id='cs'><stop offset='0' stop-color='#a3f'/><stop offset='0.5' stop-color='#5f5'/><stop offset='1' stop-color='#f55'/></linearGradient></defs><rect x='20' y='75' width='200' height='40' fill='#1a2b45'/><line x1='60' y1='75' x2='60' y2='115' stroke='#7ad' stroke-width='3'/><line x1='130' y1='75' x2='130' y2='115' stroke='#5f5' stroke-width='3'/><line x1='185' y1='75' x2='185' y2='115' stroke='#f55' stroke-width='3'/></svg>","steps":[{"t":"Sürekli spektrum","a":"kesintisiz renk","d":"Akkor katı/sıvı kaynaklar tüm renkleri kesintisiz içeren sürekli spektrum verir."},{"t":"Sonuç","a":"çizgi=kesikli","d":"Uyarılmış gaz atomları ise yalnızca belirli renklerde, ayrı ayrı çizgiler hâlinde <b>kesikli (çizgi) spektrum</b> verir."}],"ans":"Sürekli spektrum tüm renkleri kesintisiz içerir; çizgi spektrum yalnızca belirli, ayrı dalga boylarında çizgilerden oluşur (kesiklidir)."},{"q":"Bir atomun emisyon (yayma) çizgi spektrumunun oluşum mekanizmasını açıklayınız.","steps":[{"t":"Uyarılma","a":"enerji alır","d":"Atom dışarıdan enerji alınca elektron üst enerji düzeyine çıkar (uyarılır)."},{"t":"Geri iniş","a":"foton yayar","d":"Elektron alt düzeye geri inerken enerji farkını foton olarak yayar; her geçiş bir çizgi verir, böylece <b>çizgi spektrumu</b> oluşur."}],"ans":"Uyarılan elektronlar alt düzeylere inerken enerji farklarına eşit fotonlar yayar; her geçiş belirli bir çizgi oluşturur."},{"q":"Çizgi spektrumunun her element için benzersiz olmasının nedenini açıklayınız.","steps":[{"t":"Elemente özgü düzeyler","a":"farklı ΔE","d":"Her elementin çekirdek yükü ve elektron yapısı farklı olduğundan enerji düzeyleri ve aralarındaki farklar (ΔE) kendine özgüdür."},{"t":"Sonuç","a":"benzersiz çizgiler","d":"Farklı ΔE değerleri farklı dalga boyları verdiğinden her elementin çizgileri <b>benzersizdir</b>; spektrum bir tür parmak izidir."}],"ans":"Her elementin enerji düzeyleri ve ΔE değerleri farklı olduğundan çizgi spektrumu benzersizdir (parmak izi gibi)."},{"q":"Emisyon (yayma) ve absorpsiyon (soğurma) spektrumları arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Soğurma","a":"foton yutulur","d":"Atom, düzey farklarına uyan fotonları soğurarak elektronu uyarır; spektrumda o renkler eksik (siyah çizgi) görünür."},{"t":"İlişki","a":"aynı dalga boyları","d":"Aynı atom geri inerken aynı enerji farklarını yaydığından, soğurma çizgileri ile yayma çizgileri <b>aynı dalga boylarındadır</b>."}],"ans":"Soğurma ve yayma aynı enerji düzeyleri arasındaki geçişlere ait olduğundan, çizgiler aynı dalga boylarında oluşur."},{"q":"Bir fotonun enerjisi E = h·c/λ ile verilir. Çizgi spektrumunda mavi çizginin mi yoksa kırmızı çizginin mi enerjisi büyüktür?","steps":[{"t":"Bağıntı","a":"E ∝ 1/λ","d":"Foton enerjisi dalga boyu ile ters orantılıdır: E = h·c/λ."},{"t":"Sonuç","a":"mavi enerjik","d":"Mavi ışığın dalga boyu kısa olduğundan enerjisi büyüktür; <b>mavi çizgi</b> kırmızıdan daha enerjiklidir."}],"ans":"Mavi ışığın dalga boyu kısa olduğundan (E = h·c/λ) mavi çizginin enerjisi kırmızıdan büyüktür."}],"zor":[{"q":"Hidrojende enerji düzeyleri Eₙ = −13,6/n² eV ile verilir. Elektron n=3 düzeyinden n=2 düzeyine inerken yayılan çizginin foton enerjisini bulunuz.","fig":"<svg viewBox='0 0 240 160'><line x1='40' y1='130' x2='200' y2='130' stroke='#1a2b45' stroke-width='2'/><text x='205' y='134' font-size='10' fill='#1a2b45'>n=2</text><line x1='40' y1='60' x2='200' y2='60' stroke='#1a2b45' stroke-width='2'/><text x='205' y='64' font-size='10' fill='#1a2b45'>n=3</text><circle cx='150' cy='60' r='6' fill='#2b6be0'/><path d='M145 67 L80 124' stroke='#e0552b' stroke-width='2'/><circle cx='74' cy='130' r='6' fill='#2b6be0'/></svg>","steps":[{"t":"Düzey enerjileri","a":"E₂=−3,4 ; E₃≈−1,51 eV","d":"E₂ = −13,6/4 = −3,4 eV ve E₃ = −13,6/9 ≈ −1,51 eV."},{"t":"Foton enerjisi","a":"E_f = E₃ − E₂","d":"E_f = (−1,51) − (−3,4) eV işlemini yaparız."},{"t":"Sonuç","a":"E_f ≈ 1,89 eV","d":"E_f = −1,51 + 3,4 ≈ 1,89 eV; Balmer serisinin görünür kırmızı (Hα) çizgisidir."}],"ans":"E_f = E₃ − E₂ = −1,51 − (−3,4) ≈ 1,89 eV; Balmer serisi görünür kırmızı çizgi."},{"q":"Enerjisi 1,89 eV olan bir spektrum çizgisinin dalga boyunu bulunuz. (1 eV = 1,6·10⁻¹⁹ J, h = 6,63·10⁻³⁴ J·s, c = 3·10⁸ m/s)","steps":[{"t":"Enerjiyi J'e çevir","a":"E ≈ 3,02·10⁻¹⁹ J","d":"E = 1,89 · 1,6·10⁻¹⁹ ≈ 3,02·10⁻¹⁹ J."},{"t":"Dalga boyu","a":"λ = h·c/E","d":"λ = (6,63·10⁻³⁴ · 3·10⁸) / 3,02·10⁻¹⁹; pay = 1,989·10⁻²⁵."},{"t":"Sonuç","a":"λ ≈ 6,6·10⁻⁷ m","d":"λ ≈ 1,989·10⁻²⁵ / 3,02·10⁻¹⁹ ≈ 6,6·10⁻⁷ m = 660 nm; görünür kırmızı çizgi."}],"ans":"λ = h·c/E ≈ 6,6·10⁻⁷ m (yaklaşık 660 nm, kırmızı)."},{"q":"Bir atomun emisyon spektrumunda 410 nm, 486 nm ve 656 nm çizgileri görülüyor. Hangi çizginin fotonu en enerjiklidir? (E = h·c/λ)","steps":[{"t":"Bağıntı","a":"E ∝ 1/λ","d":"E = h·c/λ olduğundan en kısa dalga boylu çizgi en enerjiklidir."},{"t":"Karşılaştırma","a":"410 < 486 < 656","d":"410 nm en kısa dalga boyudur."},{"t":"Sonuç","a":"410 nm en enerjik","d":"En kısa dalga boylu <b>410 nm</b> (mor) çizgisinin fotonu en enerjiklidir."}],"ans":"En kısa dalga boylu 410 nm (mor) çizginin fotonu en enerjiklidir."},{"q":"Hidrojen spektrumunda Lyman serisi (n→1) ile Balmer serisi (n→2) çizgileri elektromanyetik spektrumun hangi bölgelerinde yer alır? Nedenini açıklayınız.","steps":[{"t":"Lyman enerjisi","a":"büyük ΔE","d":"Lyman serisinde geçişler n=1'de biter; enerji farkları büyüktür, kısa dalga boyu verir."},{"t":"Sonuç","a":"Lyman UV, Balmer görünür","d":"Büyük enerji morötesi demektir; bu yüzden Lyman <b>morötesi (UV)</b>, daha küçük enerjili Balmer ise <b>görünür</b> bölgededir."}],"ans":"Lyman serisi büyük enerji farkları nedeniyle morötesi (UV), Balmer serisi ise görünür bölgede yer alır."},{"q":"Hidrojende elektron n=4'ten n=2'ye iniyor (E₄=−0,85 eV, E₂=−3,4 eV). Yayılan çizginin foton enerjisini bulunuz ve hangi seriye ait olduğunu belirtiniz.","fig":"<svg viewBox='0 0 240 180'><line x1='40' y1='150' x2='200' y2='150' stroke='#1a2b45' stroke-width='2'/><text x='205' y='154' font-size='10' fill='#1a2b45'>n=2</text><line x1='40' y1='95' x2='200' y2='95' stroke='#1a2b45' stroke-width='2'/><text x='205' y='99' font-size='10' fill='#1a2b45'>n=3</text><line x1='40' y1='55' x2='200' y2='55' stroke='#1a2b45' stroke-width='2'/><text x='205' y='59' font-size='10' fill='#1a2b45'>n=4</text><circle cx='150' cy='55' r='6' fill='#2b6be0'/><path d='M145 62 L80 144' stroke='#e0552b' stroke-width='2'/><circle cx='74' cy='150' r='6' fill='#2b6be0'/></svg>","steps":[{"t":"Foton enerjisi","a":"E_f = E₄ − E₂","d":"E_f = (−0,85) − (−3,4) eV."},{"t":"Hesap","a":"E_f = 2,55 eV","d":"E_f = −0,85 + 3,4 = 2,55 eV."},{"t":"Seri","a":"Balmer (n→2)","d":"Geçiş n=2'de bittiğinden bu çizgi <b>Balmer serisine</b> aittir; görünür mavi-yeşil bölgededir."}],"ans":"E_f = −0,85 − (−3,4) = 2,55 eV; n=2'de bittiğinden Balmer serisindendir (görünür mavi-yeşil)."}]}},"uyarilmaEmisyon":{"ilkokul":{"kolay":[{"q":"Bir elektron enerji alınca ne olur? Basitçe düşün.","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='92' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='28' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='56' fill='none' stroke='#1a2b45'/><line x1='160' y1='64' x2='160' y2='40' stroke='#f4a020' stroke-width='2'/><polygon points='160,36 156,46 164,46' fill='#f4a020'/><text x='160' y='168' font-size='11' text-anchor='middle' fill='#1a2b45'>üst basamağa çıkar</text></svg>","steps":[{"t":"Enerji al","a":"yukarı çık","d":"Elektron enerji alınca dış (uzak) bir katmana, yani üst basamağa çıkar."},{"t":"Adı","a":"uyarılma","d":"Bu olaya elektronun uyarılması denir."}],"ans":"Enerji alan elektron üst bir katmana çıkar; buna uyarılma denir."},{"q":"Üst katmana çıkan elektron geri dönerken ne yapar?","steps":[{"t":"Geri iner","a":"alt basamak","d":"Elektron uzun süre yukarıda kalamaz, alt katmana geri iner."},{"t":"Işık verir","a":"parlama","d":"Geri inerken aldığı enerjiyi ışık olarak dışarı verir."}],"ans":"Geri inen elektron, aldığı enerjiyi ışık olarak dışarı verir."},{"q":"Bazı maddelerin ısıtılınca renkli ışık vermesinin sebebi nedir?","steps":[{"t":"Elektron uyarılır","a":"enerji alır","d":"Isı, maddedeki elektronları uyarıp üst katmanlara çıkarır."},{"t":"Işık çıkar","a":"renkli ışık","d":"Geri inen elektronlar enerjiyi renkli ışık olarak yayar."}],"ans":"Isıtılınca elektronlar uyarılır, geri inerken renkli ışık yayar."},{"q":"Havai fişeklerin renkli olmasının nedeni atomlarla ilgili midir?","fig":"<svg viewBox='0 0 320 160'><circle cx='160' cy='80' r='6' fill='#e0552b'/><line x1='160' y1='80' x2='160' y2='30' stroke='#f4a020' stroke-width='2'/><line x1='160' y1='80' x2='210' y2='50' stroke='#2b6be0' stroke-width='2'/><line x1='160' y1='80' x2='110' y2='50' stroke='#16a34a' stroke-width='2'/><line x1='160' y1='80' x2='205' y2='110' stroke='#f4a020' stroke-width='2'/><text x='160' y='145' font-size='11' text-anchor='middle' fill='#1a2b45'>uyarılan atomlar ışık verir</text></svg>","steps":[{"t":"Atom uyarılır","a":"enerji alır","d":"Patlama enerjisi atomların elektronlarını uyarır."},{"t":"Renk çıkar","a":"ışık yayar","d":"Geri inen elektronlar her maddeye özgü renkte ışık yayar."}],"ans":"Evet; havai fişekteki atomlar uyarılıp geri inerken renkli ışık yaydığı için renkli görünür."},{"q":"Elektronun en alt, en rahat olduğu duruma ne denir?","steps":[{"t":"En düşük basamak","a":"taban durum","d":"Elektron en alt (çekirdeğe en yakın) katmanda en rahat ve kararlı haldedir."},{"t":"Adı","a":"taban (temel) durum","d":"Bu en kararlı duruma taban durum denir."}],"ans":"Elektronun en kararlı, en alt durumuna taban (temel) durum denir."}],"zor":[{"q":"Uyarılma ile emisyon (ışık yayma) arasındaki fark nedir?","steps":[{"t":"Uyarılma","a":"enerji alma","d":"Uyarılma, elektronun enerji alıp üst katmana çıkmasıdır."},{"t":"Emisyon","a":"enerji verme","d":"Emisyon ise elektronun geri inerken enerjiyi ışık olarak vermesidir."}],"ans":"Uyarılma enerji almak (yukarı çıkmak), emisyon ise enerji verip ışık yaymaktır (aşağı inmek)."},{"q":"Bir elektron çok enerji alırsa daha yakın mı yoksa daha uzak bir katmana mı çıkar?","steps":[{"t":"Çok enerji","a":"daha uzak","d":"Aldığı enerji ne kadar çoksa elektron çekirdekten o kadar uzak bir katmana çıkar."},{"t":"Sonuç","a":"yüksek basamak","d":"Yani fazla enerji, elektronu daha yüksek bir basamağa taşır."}],"ans":"Çok enerji alan elektron daha uzak (yüksek) bir katmana çıkar."},{"q":"Yayılan ışığın rengi neye bağlıdır?","steps":[{"t":"Enerji farkı","a":"katmanlar arası","d":"Yayılan ışığın rengi, elektronun indiği iki katman arasındaki enerji farkına bağlıdır."},{"t":"Her madde özel","a":"farklı renk","d":"Her maddenin katman farkları farklı olduğu için yaydığı renk de farklıdır."}],"ans":"Yayılan ışığın rengi, elektronun indiği katmanlar arasındaki enerji farkına bağlıdır ve her maddede farklıdır."},{"q":"Uyarılmış (yukarı çıkmış) elektron neden kararsızdır?","steps":[{"t":"Yüksek enerji","a":"fazla enerji","d":"Üst katmandaki elektron fazla enerjiye sahiptir."},{"t":"Geri dönme isteği","a":"alt katmana iner","d":"Madde en düşük enerjili (en kararlı) hale dönmek ister, bu yüzden elektron kısa sürede geri iner."}],"ans":"Uyarılmış elektron fazla enerjili olduğu için kararsızdır ve hızla alt katmana geri inerek kararlı hale döner."},{"q":"Gece parlayan bazı oyuncakların ışık vermesi hangi olaya benzer?","steps":[{"t":"Enerji depolama","a":"gündüz uyarılır","d":"Gündüz ışıktan aldığı enerjiyle oyuncağın elektronları uyarılır."},{"t":"Yavaş ışıma","a":"gece ışık verir","d":"Karanlıkta bu elektronlar yavaşça geri inerek ışık yayar; bu emisyona benzer."}],"ans":"Gündüz enerji alıp uyarılan elektronların gece geri inerken ışık yayması, emisyona benzer bir olaydır."}]},"ortaokul":{"kolay":[{"q":"Bir elektronun uyarılması ne demektir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='92' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='28' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='56' fill='none' stroke='#1a2b45'/><circle cx='188' cy='92' r='5' fill='#2b6be0'/><line x1='180' y1='80' x2='200' y2='44' stroke='#f4a020' stroke-width='2'/><polygon points='200,44 192,50 199,54' fill='#f4a020'/><text x='160' y='172' font-size='10' text-anchor='middle' fill='#1a2b45'>üst düzeye geçiş</text></svg>","steps":[{"t":"Enerji soğurma","a":"enerji alır","d":"Elektron dışarıdan (ısı, ışık vb.) enerji aldığında bunu soğurur."},{"t":"Üst düzeye çıkış","a":"uyarılma","d":"Aldığı enerjiyle daha yüksek bir enerji düzeyine çıkar; bu olaya uyarılma denir."}],"ans":"Uyarılma, elektronun dışarıdan enerji soğurup daha yüksek bir enerji düzeyine çıkmasıdır."},{"q":"Emisyon (ışık yayma) nasıl gerçekleşir?","steps":[{"t":"Geri iniş","a":"alt düzeye döner","d":"Uyarılmış elektron kararsızdır ve daha düşük bir enerji düzeyine geri döner."},{"t":"Foton yayımı","a":"ışık verir","d":"Geri dönerken iki düzeyin enerji farkını ışık (foton) olarak dışarı yayar."}],"ans":"Emisyon, uyarılmış elektronun alt düzeye dönerken enerji farkını ışık (foton) olarak yaymasıdır."},{"q":"Taban (temel) durum ile uyarılmış durum arasındaki fark nedir?","steps":[{"t":"Taban durum","a":"en düşük enerji","d":"Elektronların en düşük enerji düzeylerinde bulunduğu, atomun en kararlı hâline taban durum denir."},{"t":"Uyarılmış durum","a":"yüksek enerji","d":"Elektron enerji alıp üst düzeye çıktığında atom uyarılmış duruma geçer; bu hâl daha kararsızdır."}],"ans":"Taban durumda atom en düşük enerjili ve kararlıdır; uyarılmış durumda elektron üst düzeye çıkmış, atom daha kararsızdır."},{"q":"Yayılan ışığın enerjisi neye eşittir?","steps":[{"t":"Düzey farkı","a":"iki düzey arası","d":"Yayılan ışığın enerjisi, elektronun geçtiği iki enerji düzeyi arasındaki farka eşittir."},{"t":"Belirli değer","a":"sabit miktar","d":"Düzeyler belirli olduğu için yayılan enerji de belirli, sabit bir değerdir."}],"ans":"Yayılan ışığın (fotonun) enerjisi, elektronun indiği iki enerji düzeyi arasındaki farka eşittir."},{"q":"Atomların belirli renklerde ışık yayması neyi gösterir?","steps":[{"t":"Belirli renkler","a":"kesikli","d":"Her atom yalnız belirli renklerde (kesikli çizgilerde) ışık yayar, her renkte değil."},{"t":"Kanıt","a":"enerji düzeyleri","d":"Bu, atomdaki enerji düzeylerinin belirli (kuantlı) olduğunun kanıtıdır."}],"ans":"Atomların yalnız belirli renklerde ışık yayması, enerji düzeylerinin belirli (kuantlı) olduğunu gösterir."}],"zor":[{"q":"Bir elektronun n=1 düzeyinden n=3 düzeyine çıkması için enerji soğurması mı yoksa yayması mı gerekir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='92' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='92' r='26' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='48' fill='none' stroke='#1a2b45'/><circle cx='160' cy='92' r='70' fill='none' stroke='#1a2b45'/><line x1='160' y1='66' x2='160' y2='28' stroke='#2b6be0' stroke-width='2'/><polygon points='160,24 156,34 164,34' fill='#2b6be0'/><text x='200' y='30' font-size='9' fill='#1a2b45'>soğurma</text></svg>","steps":[{"t":"Yön","a":"alttan üste","d":"n=1 düzeyi n=3'ten daha düşük enerjilidir; elektron alt düzeyden üst düzeye çıkmaktadır."},{"t":"Enerji ihtiyacı","a":"soğurur","d":"Üst düzeye çıkmak için dışarıdan enerji alınması (soğurulması) gerekir; bu uyarılmadır."}],"ans":"Elektron n=1'den n=3'e çıkarken enerji soğurur (uyarılma); çünkü üst düzeye çıkmak enerji gerektirir."},{"q":"Bir madde sürekli (kesintisiz) değil, yalnız belirli renklerde ışık yayıyorsa bunun nedeni nedir?","steps":[{"t":"Kuantlı düzeyler","a":"belirli enerji","d":"Atomdaki enerji düzeyleri belirli (kuantlı) olduğu için düzeyler arası farklar da belirlidir."},{"t":"Belirli foton","a":"belirli renk","d":"Yalnız bu belirli enerji farkları kadar foton yayılabildiğinden, ışık sadece belirli renklerde (çizgilerde) çıkar."}],"ans":"Enerji düzeyleri kuantlı olduğundan yalnız belirli enerji farkları kadar foton yayılır; bu yüzden ışık kesintisiz değil belirli renklerde (çizgilerde) çıkar."},{"q":"Uyarılan bir elektronun yaydığı ışığın rengi hangi geçişte daha yüksek enerjili (mora yakın) olur?","steps":[{"t":"Büyük düzey farkı","a":"çok enerji","d":"Elektron birbirinden çok uzak düzeyler arasında inerse (örneğin n=4'ten n=1'e), enerji farkı büyük olur."},{"t":"Renk","a":"yüksek enerji","d":"Büyük enerji farkı, daha yüksek enerjili (mora/mor ötesine yakın) ışık demektir; küçük fark ise kırmızıya yakın olur."}],"ans":"Düzeyler arası fark ne kadar büyükse (örneğin n=4→n=1) yayılan ışık o kadar yüksek enerjili (mora yakın) olur; küçük farkta ışık kırmızıya yakındır."},{"q":"Atomun yaydığı ışığı inceleyerek hangi element olduğunu anlayabilir miyiz? Neden?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='50' width='240' height='40' fill='#1a2b45'/><rect x='80' y='50' width='3' height='40' fill='#16a34a'/><rect x='140' y='50' width='3' height='40' fill='#f4a020'/><rect x='200' y='50' width='3' height='40' fill='#2b6be0'/><rect x='235' y='50' width='3' height='40' fill='#7c3aed'/><text x='160' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>çizgi spektrumu = parmak izi</text></svg>","steps":[{"t":"Kendine özgü düzeyler","a":"her element farklı","d":"Her elementin enerji düzeyleri kendine özgüdür, bu yüzden yaydığı renk çizgileri de kendine özgüdür."},{"t":"Parmak izi","a":"tanımlama","d":"Bu çizgi deseni, elementin parmak izi gibidir; ışığını inceleyerek hangi element olduğu belirlenebilir."}],"ans":"Evet; her elementin enerji düzeyleri farklı olduğundan yaydığı çizgi spektrumu bir parmak izi gibidir ve element bu desenden tanınabilir."},{"q":"Bir elektron önce n=3'ten n=2'ye, sonra n=2'den n=1'e iniyorsa kaç foton yayılır?","steps":[{"t":"Her geçiş bir foton","a":"basamaklı iniş","d":"Elektron her enerji düzeyi geçişinde o farka karşılık bir foton yayar."},{"t":"Toplam","a":"2 foton","d":"İki ayrı geçiş (n=3→n=2 ve n=2→n=1) olduğu için toplam 2 foton yayılır."}],"ans":"İki ayrı geçiş olduğundan toplam 2 foton yayılır (her enerji düzeyi geçişi bir foton verir)."}]},"lise":{"kolay":[{"q":"Bir elektronun uyarılması olayını enerji açısından açıklayın.","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='95' r='10' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='95' r='26' fill='none' stroke='#1a2b45'/><circle cx='160' cy='95' r='50' fill='none' stroke='#1a2b45'/><line x1='160' y1='69' x2='160' y2='45' stroke='#2b6be0' stroke-width='2'/><polygon points='160,41 156,51 164,51' fill='#2b6be0'/><text x='205' y='52' font-size='9' fill='#1a2b45'>foton soğurma</text><text x='160' y='180' font-size='10' text-anchor='middle' fill='#1a2b45'>uyarılma</text></svg>","steps":[{"t":"Enerji soğurma","a":"belirli foton","d":"Elektron, iki enerji düzeyinin farkına tam eşit enerjili bir foton (ya da ısı) soğurur."},{"t":"Üst düzeye geçiş","a":"uyarılmış hâl","d":"Bu enerjiyle daha yüksek bir enerji düzeyine çıkar; atom uyarılmış (kararsız) hâle geçer."}],"ans":"Uyarılma, elektronun iki düzeyin enerji farkı kadar enerji soğurarak daha yüksek bir enerji düzeyine geçmesi ve atomun uyarılmış hâle gelmesidir."},{"q":"Emisyon (ışıma) olayı sırasında ne gerçekleşir?","steps":[{"t":"Alt düzeye dönüş","a":"kararlılaşma","d":"Uyarılmış elektron kararsızdır; daha düşük bir enerji düzeyine kendiliğinden geri döner."},{"t":"Foton yayımı","a":"ΔE = E_foton","d":"İki düzey arasındaki enerji farkı (ΔE), belirli dalga boylu bir foton olarak yayılır."}],"ans":"Emisyonda uyarılmış elektron alt düzeye döner ve iki düzeyin enerji farkı kadar enerjiyi belirli dalga boylu bir foton olarak yayar."},{"q":"Çizgi (kesikli) spektrumun oluşması atomdaki enerji düzeyleri hakkında neyi kanıtlar?","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='55' width='240' height='38' fill='#1a2b45'/><rect x='85' y='55' width='3' height='38' fill='#7c3aed'/><rect x='135' y='55' width='3' height='38' fill='#2b6be0'/><rect x='185' y='55' width='3' height='38' fill='#16a34a'/><rect x='235' y='55' width='3' height='38' fill='#e0552b'/><text x='160' y='122' font-size='11' text-anchor='middle' fill='#1a2b45'>hidrojen çizgi spektrumu</text></svg>","steps":[{"t":"Kesikli çizgiler","a":"belirli enerji","d":"Spektrumda yalnız belirli dalga boylarında çizgiler görülür; her çizgi belirli bir enerji farkına karşılık gelir."},{"t":"Kanıt","a":"kuantlanma","d":"Enerji sürekli olsaydı kesintisiz spektrum çıkardı; çizgiler enerji düzeylerinin kuantlı (ayrık) olduğunu kanıtlar."}],"ans":"Çizgi spektrum, yalnız belirli enerji farkları kadar foton yayıldığını, dolayısıyla atomdaki enerji düzeylerinin kuantlı (ayrık) olduğunu kanıtlar."},{"q":"Soğurma (absorpsiyon) spektrumu ile emisyon spektrumu arasındaki ilişki nedir?","steps":[{"t":"Soğurma","a":"foton soğrulur","d":"Elektron alt düzeyden üst düzeye çıkarken belirli enerjili fotonları soğurur; bu dalga boylarında karanlık çizgiler oluşur."},{"t":"Emisyon","a":"aynı enerjiler yayılır","d":"Elektron geri inerken aynı enerji farklarını foton olarak yayar; emisyon çizgileri soğurma çizgileriyle aynı dalga boylarındadır."}],"ans":"Bir atomun soğurduğu ve yaydığı fotonların enerjileri aynı düzey farklarına karşılık gelir; bu yüzden emisyon ve soğurma çizgileri aynı dalga boylarında görülür."},{"q":"Taban durum ile uyarılmış durum arasındaki temel fark nedir?","steps":[{"t":"Taban durum","a":"en düşük enerji","d":"Elektronlar mümkün olan en düşük enerji düzeylerinde bulunur; atom en kararlı hâldedir."},{"t":"Uyarılmış durum","a":"yüksek enerji, kısa ömür","d":"En az bir elektron üst düzeye çıkmıştır; atom daha yüksek enerjili, kararsız ve kısa ömürlüdür, kısa sürede taban duruma döner."}],"ans":"Taban durumda atom en düşük enerjili ve kararlıdır; uyarılmış durumda elektron üst düzeye çıkmış, atom yüksek enerjili ve kararsızdır."}],"zor":[{"q":"Hidrojen atomunda elektron n=4'ten n=2'ye ve n=3'ten n=2'ye inerse hangi geçiş daha yüksek enerjili foton yayar?","fig":"<svg viewBox='0 0 320 185'><circle cx='160' cy='95' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='160' cy='95' r='24' fill='none' stroke='#1a2b45'/><circle cx='160' cy='95' r='44' fill='none' stroke='#1a2b45'/><circle cx='160' cy='95' r='64' fill='none' stroke='#1a2b45'/><circle cx='160' cy='95' r='84' fill='none' stroke='#1a2b45'/><line x1='160' y1='11' x2='160' y2='51' stroke='#7c3aed' stroke-width='2'/><line x1='180' y1='31' x2='180' y2='51' stroke='#16a34a' stroke-width='2'/><text x='160' y='178' font-size='9' text-anchor='middle' fill='#1a2b45'>n=4→2 vs n=3→2</text></svg>","steps":[{"t":"Enerji farkını karşılaştır","a":"E ∝ 1/n²","d":"Düzey enerjisi 1/n² ile değişir; n=4 ile n=2 arasındaki fark, n=3 ile n=2 arasındaki farktan büyüktür."},{"t":"Sonuç","a":"n=4→2 daha enerjili","d":"Daha büyük enerji farkı daha yüksek enerjili (daha kısa dalga boylu) foton demektir; bu yüzden n=4→2 geçişi daha enerjilidir."}],"ans":"n=4→n=2 geçişi daha büyük enerji farkı içerdiğinden daha yüksek enerjili (daha kısa dalga boylu) foton yayar."},{"q":"Bir gazın emisyon spektrumunun, o elementin 'parmak izi' sayılmasının nedeni nedir?","steps":[{"t":"Kendine özgü düzeyler","a":"benzersiz enerji seti","d":"Her elementin çekirdek yükü ve elektron yapısı farklı olduğundan enerji düzeyleri benzersizdir."},{"t":"Benzersiz çizgi deseni","a":"tanımlayıcı","d":"Bu benzersiz düzeyler, yalnız o elemente özgü dalga boylarında çizgiler oluşturur; desen başka hiçbir elementle aynı değildir."}],"ans":"Her elementin enerji düzeyleri benzersiz olduğundan emisyon çizgilerinin dalga boyu deseni de benzersizdir; bu desen elementi kesin tanımladığı için parmak izi gibidir."},{"q":"Elektron n=3'ten taban duruma inerken bunu doğrudan ya da n=2 üzerinden basamaklı yapabilir. İki yolda yayılan toplam enerji nasıl karşılaştırılır?","steps":[{"t":"Enerjinin korunumu","a":"toplam fark sabit","d":"Yayılan toplam enerji, başlangıç (n=3) ile bitiş (n=1) düzeyleri arasındaki farka eşittir ve yoldan bağımsızdır."},{"t":"Çizgi sayısı farkı","a":"foton sayısı değişir","d":"Doğrudan iniş 1 foton verir; n=2 üzerinden basamaklı iniş 2 foton verir ama bunların enerji toplamı yine aynıdır."}],"ans":"İki yolda da yayılan toplam enerji aynıdır (E₃ − E₁); fark, basamaklı yolda enerjinin iki ayrı (daha düşük enerjili) fotona bölünmesidir."},{"q":"İyonlaşma, uyarılmadan nasıl ayrılır? Enerji açısından açıklayın.","fig":"<svg viewBox='0 0 320 175'><circle cx='110' cy='90' r='9' fill='#e0552b' stroke='#1a2b45'/><circle cx='110' cy='90' r='24' fill='none' stroke='#1a2b45'/><circle cx='110' cy='90' r='44' fill='none' stroke='#1a2b45'/><circle cx='154' cy='90' r='4' fill='#2b6be0'/><line x1='154' y1='90' x2='245' y2='50' stroke='#2b6be0' stroke-width='2'/><polygon points='245,50 236,52 240,59' fill='#2b6be0'/><text x='160' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>elektron atomdan kopar</text></svg>","steps":[{"t":"Uyarılma","a":"üst düzeye çıkar","d":"Uyarılmada elektron yalnız üst bir enerji düzeyine çıkar ama hâlâ atoma bağlıdır."},{"t":"İyonlaşma","a":"atomdan ayrılır","d":"İyonlaşmada elektrona, atomdan tamamen kopacak kadar (iyonlaşma enerjisi) büyük enerji verilir; elektron atomu terk eder ve katyon oluşur."}],"ans":"Uyarılmada elektron üst düzeye çıkıp atoma bağlı kalır; iyonlaşmada ise elektron, atomdan kopacak kadar büyük enerji (iyonlaşma enerjisi) alıp atomu tamamen terk eder."},{"q":"Floresan (örneğin floresan lamba) maddelerin ışık vermesi uyarılma–emisyon ile nasıl açıklanır?","steps":[{"t":"Uyarılma","a":"yüksek enerji soğurur","d":"Madde, mor ötesi gibi yüksek enerjili ışınları soğurur ve elektronları üst düzeylere uyarılır."},{"t":"Basamaklı emisyon","a":"görünür ışık","d":"Elektronlar bir miktar enerjiyi ısı olarak kaybedip ara düzeylere düşer, sonra görünür bölgede daha düşük enerjili foton yayar; böylece gözle görülür ışık çıkar."}],"ans":"Floresan maddeler yüksek enerjili (mor ötesi) ışığı soğurup uyarılır, ardından basamaklı inişle daha düşük enerjili görünür ışık yayar; bu uyarılma–emisyon olayının bir uygulamasıdır."}]}}};
